_PREFERENCE_SIGNALS = {
    "goes by", "go by",
    "prefers to be called", "prefer to be called",
    "preferred name", "my preferred name",
    "please call me", "call me",
    "known as", "also known as",
    "my name is", "i prefer", "i go by",
}

# Query-side NAME-INTENT signals (recall presentation gate, NOT ingest).
# Non-preferred / legal / also-known-as names stay GROUNDED on the entity UUID
# (identity resolution + dead-name avoidance still work) but are held in reserve:
# excluded from normal recall and surfaced ONLY when the query is explicitly about
# an entity's name(s). Small, hardcoded, commented per spec (no broad intent infra
# exists for this read-time presentation decision). Lowercased substring match.
_NAME_INTENT_SIGNALS = (
    "full name", "real name", "legal name", "actual name", "proper name",
    "also known as", "aka", "goes by", "go by", "other name", "other names",
    "what is.*name", "what's.*name", "actually called", "really called",
    "what do.*call", "what are.*called", "birth name", "given name", "maiden name",
)


def _query_has_name_intent(query_text: str) -> bool:
    """
    True when the recall query is asking about an entity's name(s) — the only case
    where non-preferred (legal / also-known-as) aliases should be surfaced. Cheap
    substring + a couple of split-phrase patterns ("what is X's name"). Presentation
    gate only; never affects stored data.
    """
    if not query_text:
        return False
    q = query_text.lower()
    for sig in _NAME_INTENT_SIGNALS:
        if "." in sig or "*" in sig:  # tiny regex-y patterns (split phrases)
            try:
                if re.search(sig, q):
                    return True
            except re.error:
                continue
        elif sig in q:
            return True
    return False


def _synthesize_user_name_facts(db_conn, user_id: str, preferred_user_name: str = None) -> list[dict]:
    """PIECE 2 — NAME-INTENT SURFACING (read-time presentation, fail-safe).

    The schema owner's names land MULTI-VALUED in entity_aliases (the registry) but the
    registry-centric design mints NO also_known_as/pref_name FACT for the user — so the
    recall walk over `facts` returns nothing on "what is my name". This helper reads the
    owner's surfaceable registry aliases and returns them as synthesized fact dicts that
    the normal resolution + convert_to_prose pipeline can render ("you go by X").

    It is the "asked" branch the existing name-intent gate (CLAUDE.md: recall HIDES
    also_known_as until asked) has lacked — detection stays the EXISTING
    _query_has_name_intent gate (caller-gated); this only supplies the answer.

    Subject is the user UUID and rel_type is the registry-grounded identity rel
    (pref_name for the preferred name, also_known_as for the rest). Object is the alias
    STRING (scalar identity rel → STRING object, never a UUID). Every alias is filtered
    by _is_surfaceable_user_name so junk ("worried"/"thinking") is never surfaced as a
    name. Slug/placeholder aliases are excluded at the SQL layer.

    Fail-safe: any error → [] (caller degrades to exactly today's behavior).
    """
    out: list[dict] = []
    if not user_id or user_id == "anonymous":
        return out
    try:
        _pref = (preferred_user_name or "").strip().lower() or None
        with db_conn.cursor() as cur:
            cur.execute(
                "SELECT alias, is_preferred FROM entity_aliases "
                "WHERE entity_id = %s "
                "AND preference_source != 'provisioned' "
                "AND NOT (alias ~ '^[0-9a-f]{8}_[0-9a-f]{4}_[0-9a-f]{4}_[0-9a-f]{4}_[0-9a-f]{12}$') "
                "ORDER BY is_preferred DESC, alias",
                (user_id,),
            )
            rows = cur.fetchall()
        _seen: set = set()
        for alias, is_pref in rows:
            a = (alias or "").strip()
            if not a:
                continue
            al = a.lower()
            if al in _seen:
                continue
            if not _is_surfaceable_user_name(a):
                continue
            _seen.add(al)
            # The PREFERRED name (or the alias matching the already-resolved owner name)
            # renders via pref_name ("you go by X"); the rest as also_known_as.
            rel = "pref_name" if (is_pref or (_pref and al == _pref)) else "also_known_as"
            out.append({
                "subject": user_id,
                "subject_id": user_id,
                "rel_type": rel,
                "object": a,
                "confidence": 1.0,
                "fact_class": "A",
                "source": "registry",
                "category": _get_rel_type_category(rel),
                "valid_from": None,
                "valid_until": None,
            })
    except Exception as e:
        log.warning("query.name_intent_surfacing.failed",
                    user_id=user_id[:8] if user_id else "", error=str(e)[:120])
        return []
    return out


# Identity patterns capture the trailing token after an EXPLICIT naming construction only.
# The greedy copula `i am X` / `i'm X` was RETIRED (2026-06-15): it DECIDED "the complement
# is a name" from a regex alone and was the single source of every junk-name leak
# ("i am worried"→worried, "i'm feeling"→feeling, "i'm thinking"→thinking). Bare-copula
# self-statements are now routed through the self-predication GROUNDING router
# (_ground_self_predication) — LOCATE → LLM grounds the complement → assign rel — never a
# regex guessing. Only UNAMBIGUOUS explicit-naming constructions remain here; these mint
# also_known_as directly (no grounding needed). Registration stays LOOSE ON INPUT (no casing
# gate); the capture group is (\w+) so source casing survives.
_IDENTITY_PATTERNS = [
    re.compile(r"\bmy name is (\w+)", re.IGNORECASE),
    re.compile(r"\bcall me (\w+)", re.IGNORECASE),
    re.compile(r"\bpeople call me (\w+)", re.IGNORECASE),
]

# Closed common-word/state set. This is the SINGLE discernment list used at READ
# time (_is_surfaceable_user_name) to refuse surfacing a junk alias as the user's
# name. It is a bounded LANGUAGE PRIMITIVE — feelings/states/gerunds and function
# words that the loose ingest path may have captured after "I'm …"/"my name is …"
# — NOT a domain/world list and NOT a claim about which names exist. Aliases are
# stored lowercased; all entries are lowercase and the check case-folds.
_IDENTITY_STOPWORDS = {
    "a", "an", "the", "not", "just", "also", "here", "happy", "glad", "sorry",
    "married", "single", "divorced", "engaged", "here", "ready", "trying",
    "going", "looking", "back", "home", "out", "in", "on", "at", "to",
    "very", "really", "so", "too", "quite", "sure", "afraid", "aware",
    "excited", "sorry", "glad", "grateful", "proud", "tired", "done",
    # Words commonly falsely captured by preference/identity patterns
    "prefer", "prefers", "preferred", "called", "name", "named",
    "family", "children", "kids", "wife", "husband", "spouse",
    "she", "he", "they", "them", "her", "him", "his",
    "goes", "known", "likes", "like", "want", "wants",
    # Common feeling/state/gerund words that the LOOSE ingest path may register as
    # an alias after "I'm …" — must never be SURFACED as the user's name.
    "worried", "thinking", "hosting", "selling", "working", "feeling",
    "wondering", "hoping", "waiting", "leaving", "staying", "moving",
    "running", "sitting", "standing", "busy", "free", "available", "fine",
    "okay", "ok", "good", "great", "bad", "well", "stressed", "anxious",
    "confused", "lost", "stuck", "curious", "interested", "bored",
}


def _is_surfaceable_user_name(alias: str) -> bool:
    """READ-TIME (tight-on-return) filter: may this stored alias be SURFACED as the
    user's display name?

    LOOSE ON INPUT, TIGHT ON RETURN (CLAUDE.md "dumb registry / smart query"): the
    registry accepts any candidate alias at ingest — "worried"/"thinking" from
    "I'm worried…"/"I'm thinking…" may land as a raw also_known_as/preferred alias.
    They cost nothing in storage (hundreds of aliases hang off the one user). The
    discernment lives HERE, at the moment the user's name is surfaced for recall: a
    junk alias that is just a common function/state/gerund word must NOT be presented
    as "your name" — the caller should fall back to a better alias or to "you".

    Aliases are stored LOWERCASED, so capitalization is NOT available at read time —
    this filter therefore uses ONLY the closed common-word/state stopword set
    (`_IDENTITY_STOPWORDS`), a bounded language primitive, NOT a caps assumption and
    NOT a brittle domain/world list. It makes no claim about *which* names exist —
    only that a known common-word state ("worried", "married", "going") is not a name.
    No LLM, no network, <1µs. Fail-safe: empty/None → not surfaceable (so the caller
    falls through to its existing fallback, i.e. today's behavior on a missing name).
    """
    if not alias:
        return False
    a = alias.strip().lower()
    if not a:
        return False
    if a in _IDENTITY_STOPWORDS:
        return False
    return True


# ── AFFECTIVE / FEELING CAPTURE (the seam GLiNER2 deliberately doesn't cover) ──────
# Extraction is GLiNER2 entity-pair-bound; a feeling ("worried") is not an entity GLiNER2
# will surface (Pitfall 11 — it MUST NOT be), so feeling statements get dropped or mis-filed
# as names. This is the ONE irreducible deterministic primitive: a grammatical CONSTRUCTION
# that SEES the self-predication and grabs the complement — because the complement is not a
# GLiNER2 entity, nothing else surfaces it to ground. It is NOT a feeling word-list and makes
# NO claim that the complement is an emotion: it emits (user, feels, X) and the re_embedder
# "what is X" grounding (embedder.py _query_llm_what_is / classify_unknown_concepts) DISCERNS
# that X is a feeling and BUILDS the is-a ladder (X subclass_of fear subclass_of emotion) —
# self-assembling, no seeded lexicon, no pre-baked basic emotions. Spec:
# DEV/DESIGN-feeling-and-temporal-capture.md.
#
# Only the feel-VERB construction is unambiguous (the verb "feel" marks an affective
# complement) — so it is the list-free synchronous capture, guarded only against function-word
# junk. The bare copula ("I am X") is genuinely ambiguous (name vs role vs feeling) and CANNOT
# be sorted synchronously without a list; it is routed through grounding instead (capture the
# self-predication → "what is X" assigns the rel: emotion→feels, name→also_known_as, …).
# That grounding-router is the general self-predication mechanism (next build); a seeded word-
# list to disambiguate the copula was deliberately REMOVED (it was the brittle thing we avoid).
_FEELING_FEELVERB_BOOTSTRAP = re.compile(
    r"\bi\s*(?:'m|\s+am)?\s*(?:feel(?:ing|s)?|felt)\s+"
    r"(?:like\s+|really\s+|so\s+|very\s+|quite\s+|kinda\s+|kind\s+of\s+|"
    r"a\s+bit\s+|a\s+little\s+|pretty\s+|super\s+)*"
    r"(not\s+)?([a-z]+)",
    re.IGNORECASE,
)
# Function-word junk a bare "I feel ‹X›" might capture ("I feel that…", "I feel it…").
# Tiny closed grammatical guard — NOT a feeling/domain list.
_FEELING_COMPLEMENT_STOP = frozenset({
    "that", "it", "this", "the", "a", "an", "as", "so", "like", "they",
    "we", "you", "he", "she", "i", "to", "for", "and", "but", "if",
})

# ── SELF-PREDICATION GROUNDING ROUTER ─────────────────────────────────────────────
# The principled replacement for the greedy `i am X` name regex (the source of every
# junk-name leak). A bare copula "I am X" / "I'm X" is genuinely ambiguous — name vs
# feeling vs role — so a regex must NEVER decide it. Instead: LOCATE the self-predication
# deterministically (the detector below — one grammar gate, no name-deciding), then the
# LLM GROUNDS the complement on the entity-match layer (the L-layer the LLM legitimately
# owns — see feedback "L-layer separation") and routes it to the best-fit relation. The
# user's stated content stays their authoritative fact; only the classification/placement
# is the LLM's. Subject-agnostic: the SAME what-is/which-relation call handles name, feeling,
# role — no per-domain code. STATEMENT/ingest paths only (NOT recall — no latency on recall).
SELF_PREDICATION_GROUNDING = os.getenv("SELF_PREDICATION_GROUNDING", "1") not in ("0", "false", "False")
# Routing TARGETS = existing rel_types the LLM may pick (NOT a name/feeling word-list — these
# are relations, and the LLM does the discernment). SEED set; should grow from
# rel_types WHERE 'Person' = ANY(head_types) so novel self-attribute rels route too (TODO).
_SELF_PREDICATION_RELS = ("feels", "also_known_as", "occupation")
# DETECTOR (gate only): does a bare copula self-predication appear? Deterministic, no decision.
_SELF_PREDICATION_COPULA = re.compile(r"\bi(?:\s+am|'m)\s+\w", re.IGNORECASE)


def _detect_feeling_states(text: str, db_conn=None) -> list[dict]:
    """Deterministic affective-state detector (NO LLM, NO GLiNER2 — the seam GLiNER2 does
    not cover). Returns [{subject:'user', rel_type:'feels', object:<complement>}] so feelings
    are CAPTURED instead of dropped, then GROUNDED by the re_embedder "what is X" pushback,
    which discerns X is a feeling and self-builds the emotion is-a ladder (NO seeded lexicon).

    Only the feel-VERB construction ("I feel/I'm feeling/I felt X") is captured here: the verb
    is unambiguous, so it fires for ANY non-junk complement (incl. novel feelings → grounded →
    the map grows itself). The bare copula ("I am X") is ambiguous and routed through grounding
    instead (no word-list disambiguation). Negated feelings are SKIPPED (negation/absence
    modeling deferred — DEV/DESIGN-negation-and-absence-facts.md; no junk does_not_feel).
    DB-overridable via extraction_patterns (category='affective_construction' regexes whose
    LAST group is the complement, optional penultimate negation group). Fail-safe: any error
    → []. Never resolves the object itself (strong ingest, lean query)."""
    import re as _re_feel
    if not text:
        return []

    feelverb_res = [_FEELING_FEELVERB_BOOTSTRAP]
    if db_conn:
        try:
            with db_conn.cursor() as _cur:
                _cur.execute(
                    "SELECT pattern_regex FROM extraction_patterns"
                    " WHERE category = 'affective_construction' AND is_active = true"
                )
                rows = [r[0] for r in _cur.fetchall()]
            if rows:
                compiled = []
                for rx in rows:
                    try:
                        compiled.append(_re_feel.compile(rx, _re_feel.IGNORECASE))
                    except Exception:
                        continue
                if compiled:
                    feelverb_res = compiled
        except Exception:
            pass

    out: list[dict] = []
    seen: set = set()

    def _emit(complement: str, start: int):
        c = (complement or "").strip().lower()
        if not c or len(c) < 3 or c in _FEELING_COMPLEMENT_STOP or c in seen:
            return
        # Negation guard: a negator within the short window before the match → skip
        # (Phase 1 does not model negative feelings).
        pre = text[max(0, start - 14):start].lower()
        if any(neg in pre for neg in (" not ", "n't ", " never ", " no ")):
            return
        seen.add(c)
        out.append({"subject": "user", "rel_type": "feels", "object": c})

    # feel-verb: unambiguous → any non-junk complement. The last group is the complement;
    # an optional penultimate group captures an inline negation ("I feel not great").
    for rx in feelverb_res:
        try:
            for m in rx.finditer(text):
                groups = m.groups()
                negated = bool(groups[-2]) if len(groups) >= 2 else False
                complement = groups[-1] if groups else None
                if negated:
                    continue
                _emit(complement, m.start())
        except Exception:
            continue

    return out


def _detect_preference_states(text: str) -> list[dict]:
    r"""Deterministic 1st-person POSSESSIVE-predication detector (RC1 preference seam).

    Captures "my <X> is <Y>" ("my favorite color is blue", "my favorite editor is vim") as a
    preference fact so the scalar/preference VALUE is NOT lost. The fix to ``analyze_copula``
    stops "my favorite color is blue" from mis-firing as ``(user, feels, blue)``; this seam is
    the constructive counterpart that CAPTURES it correctly.

    Subject-agnostic + grammatical (NO keyword/attribute word-list): uses the spaCy dependency
    parse (``analyze_possessive_predication``) — a NOUN subject possessed by a genuine 1st-person
    possessive determiner ("my"/"our" — Person=1 ∧ Poss=Yes) with a copula complement. The
    possessed-noun PHRASE is the attribute X; the complement is the value Y.

    Returns growth-ready edges ``[{subject:'user', rel_type:'favorite_<x>'|'<x>', object:<y>}]``
    routed through the EXISTING source="mcp"/user_stated /ingest growth path (the same mechanism
    "favorite color/food" already grows by) — NO new rel_type is hardcoded; ``normalize_rel`` just
    snake_cases the user's own possessed-noun phrase into the predicate. Negated possessives are
    SKIPPED (negation/absence modeling deferred). Fail-safe: any error → []. Never resolves the
    object (strong ingest, lean query)."""
    if not text or not text.strip():
        return []
    try:
        from src.extraction.linguistics import analyze_possessive_predication, linguistics_available
        if not linguistics_available():
            return []
        pp = analyze_possessive_predication(text)
    except Exception as e:  # noqa: BLE001 — fail-safe: never break ingest
        log.warning("detect_preference_states.failed", error=str(e)[:120])
        return []
    if pp is None or pp.negated:
        return []
    possessed = (pp.possessed or "").strip().lower()
    value = (pp.value or "").strip().lower()
    if not possessed or not value or len(value) < 2:
        return []
    # Build the predicate from the user's OWN possessed-noun phrase via the deterministic
    # morphology rung (normalize_rel snake_cases; "favorite color" → "favorite_color"). This is
    # exactly how "favorite color/food" already grows — NO `if attr == ...` and NO new rel constant.
    try:
        from src.ontology.canonical import normalize_rel
        rel = normalize_rel(possessed) or possessed.replace(" ", "_")
    except Exception:
        rel = possessed.replace(" ", "_")
    if not rel:
        return []
    log.info("detect_preference_states.captured", rel=rel[:32], obj=value[:24])
    return [{"subject": "user", "rel_type": rel, "object": value,
             "fact_provenance": "user_stated"}]


def _detect_naming_states(text: str) -> list[dict]:
    r"""Deterministic NAMING-construction detector (RC2 naming seam).

    Captures "<noun> named/called <ProperName>" ("I have a dog named Rex", "a server called
    Apollo", "my dog is named Rex") as a VALID naming edge so the proper name is not lost and
    the verb-lift "nam" junk (``(noun, nam, ProperName)``) is eliminated. Mirrors the proven-live
    ``_detect_preference_states`` / ``_detect_feeling_states`` harvest seams.

    Subject-agnostic + grammatical (NO noun/pronoun/keyword word-list): uses the spaCy dependency
    parse (``analyze_naming``) to recover the HEAD NOUN being named and the PROPER NAME. The name
    binds to the HEAD NOUN ("dog"/"server"), NEVER to the user. ``also_known_as`` is the existing
    naming rel_type (migration 099 maps "named"→also_known_as) — looked up by SEMANTICS, not a
    hardcoded ``if rel_type==``; the seam simply emits the canonical naming rel the ontology owns.

    Returns ``[{subject:<head-noun>, rel_type:'also_known_as', object:<ProperName>,
    fact_provenance:'user_stated'}]`` routed through the EXISTING source="mcp"/user_stated /ingest
    path (entity resolution + grounding happen there — strong ingest, lean query). Negated naming
    is SKIPPED (absence modeling deferred). Fail-safe: any error → []. Never resolves the object."""
    if not text or not text.strip():
        return []
    try:
        from src.extraction.linguistics import analyze_naming, linguistics_available
        if not linguistics_available():
            return []
        na = analyze_naming(text)
    except Exception as e:  # noqa: BLE001 — fail-safe: never break ingest
        log.warning("detect_naming_states.failed", error=str(e)[:120])
        return []
    if na is None or na.negated:
        return []
    named = (na.named or "").strip().lower()
    proper = (na.proper_name or "").strip()
    if not named or not proper or len(proper) < 2:
        return []
    # ``also_known_as`` is the canonical naming rel (the named→also_known_as alias bridge,
    # migration 099). The subject is the user's OWN head noun surface; /ingest resolves it to the
    # entity (dog/server) and the proper name becomes its alias — exactly the naming construction.
    log.info("detect_naming_states.captured", named=named[:24], name=proper[:24])
    return [{"subject": named, "rel_type": "also_known_as", "object": proper,
             "fact_provenance": "user_stated"}]


def _detect_named_instance_states(text: str) -> list[dict]:
    r"""Deterministic NAMED-INSTANCE copula+appositive detector (the "Rex/poodle" seam).

    Captures "My dog Rex is a poodle." / "My cat Whiskers is a tabby." / "My car Betsy is a
    Subaru." — the appositive-name + copula type-predication construction the live LLM relation
    extractor (/extract/rewrite) drops (returns []) and the GLiNER2 lane only half-captures
    ("my dog" → owns dog), losing the named instance, its type, and the type→kind rung.

    Subject-agnostic + grammatical (NO noun/name/breed/keyword word-list): uses the spaCy
    dependency parse (``analyze_named_instance``) to recover the broad KIND (head noun "dog"),
    the instance NAME (appositive "Rex"), the specific TYPE (det-introduced complement
    "poodle"), and whether the head noun is 1st-person possessed.

    Emits, per THE HARD LINE (a NAME never enters L4; the type/kind do):
      • ``(<name>, also_known_as, <Name>)``        — the NAME in the NAMING layer (the user memory).
      • ``(<name>, instance_of, <type>)``          — the named instance IS-AN-INSTANCE of its type.
      • ``(<type>, subclass_of, <kind>)``          — the L4 TYPE rung ("poodle" subclass_of "dog").
      • ``(user, has_pet, <name>)``                — the ownership/pet relation at the NAMED instance
                                                     (ONLY when the head noun is 1st-person possessed;
                                                     the rel binds to "Rex", never a bare type).

    ``instance_of``/``subclass_of`` are the canonical classification rels the ontology owns (read by
    semantics, not a hardcoded ``if rel_type==``); ``also_known_as`` is the canonical naming rel; the
    ownership rel is emitted as ``has_pet`` only when grammatically a possessed head — entity
    resolution + L4 placement happen at /ingest (strong ingest, lean query). The named-instance
    subject SURFACE is the lowercased name so the proper name resolves to ONE instance entity that
    every edge hangs off (the alias registers it, instance_of types it, has_pet points at it).

    Negated constructions are SKIPPED (absence modeling deferred). Fail-safe: any error → []. Never
    resolves any object itself."""
    if not text or not text.strip():
        return []
    try:
        from src.extraction.linguistics import analyze_named_instance, linguistics_available
        if not linguistics_available():
            return []
        ni = analyze_named_instance(text)
    except Exception as e:  # noqa: BLE001 — fail-safe: never break ingest
        log.warning("detect_named_instance_states.failed", error=str(e)[:120])
        return []
    if ni is None or ni.negated:
        return []
    kind = (ni.kind or "").strip().lower()
    name = (ni.name or "").strip()
    name_key = name.lower()
    inst_type = (ni.instance_type or "").strip().lower()
    if not kind or not name or not inst_type:
        return []
    # Distinctness guard (parity with the analyzer's own check, defensive).
    if name_key in (kind, inst_type) or kind == inst_type:
        return []
    edges: list[dict] = [
        # NAMING layer — the proper name is the user's memory, filed via also_known_as. THE HARD
        # LINE: "Rex" is NEVER classified into L4; it is the alias of the named instance.
        {"subject": name_key, "rel_type": "also_known_as", "object": name,
         "fact_provenance": "user_stated"},
        # The named instance IS-AN-INSTANCE of its specific type ("Rex" instance_of "poodle").
        {"subject": name_key, "rel_type": "instance_of", "object": inst_type,
         "fact_provenance": "user_stated"},
        # The L4 TYPE rung — the specific type is a subclass of the broad kind ("poodle" subclass_of
        # "dog"). This grows the hierarchy where the named instance is FILED; never the name.
        {"subject": inst_type, "rel_type": "subclass_of", "object": kind,
         "fact_provenance": "user_stated"},
    ]
    if ni.possessor_is_self:
        # The pet/ownership relation points at the NAMED instance ("Rex"), never a bare type.
        edges.append(
            {"subject": "user", "rel_type": "has_pet", "object": name_key,
             "fact_provenance": "user_stated"})
    log.info("detect_named_instance_states.captured",
             name=name[:24], inst_type=inst_type[:24], kind=kind[:24],
             possessor_self=ni.possessor_is_self)
    return edges


def _acquisition_lane_edges(text: str, iso: str | None, gran: str | None) -> list[dict] | None:
    r"""SHARED Q4 ACQUISITION LANE (transfer-of-possession) — EXPOSE the user→device ownership.

    "I got a Samsung Galaxy S22 at the mall on Feb 20." is a CROSS-SECTION (who/what/where/when),
    NOT a participated_in occurrence. The occurrence seam would reject the device dobj (PROPN
    possession) and PROMOTE the locative ("mall") to the event slot — losing the PRIMARY linkage.
    This lane recovers the acquisition and EXPOSES the inferred (user, owns, <device>) edge —
    Class B (llm_inferred → the gate computes confidence/class from the owns rel_type), carrying
    the acquisition event_date — PLUS the device's clean alias and the locative kept as a co-bound
    LOCATION (located_in), never promoted to the event and never deleted.

    Called from BOTH the legacy fast-path (``_detect_event_states``) and the LIVE reified harvest
    path (``_detect_event_states_reified``) so the lane fires regardless of OCCURRENCE_REIFY. The
    ``iso``/``gran`` are the SAME date the caller already peeled (date-free residue passed as ``text``).

    Returns the acquisition edge list (possibly empty if the device is too short to keep) when an
    acquisition FIRED — the caller must SUPPRESS its occurrence lanes for that clause. Returns
    ``None`` when NO acquisition was detected (the clause is NOT an acquisition → caller proceeds to
    its occurrence lanes unchanged). Subject-agnostic (the only closed set is the DB-grown
    ``_acquisition_verbs`` cue rail inside ``analyze_acquisition``; everything else is grammar).
    Fail-safe: any error → ``None`` (never break ingest; clause falls through to occurrence lanes)."""
    try:
        from src.extraction.linguistics import analyze_acquisition
    except Exception:  # noqa: BLE001 — linguistics unavailable → no acquisition lane
        return None
    _acq = None
    try:
        _acq = analyze_acquisition(text)
    except Exception as e:  # noqa: BLE001 — fail-safe: never break ingest on the acquisition lane
        log.warning("acquisition_lane.failed", error=str(e)[:120])
        return None
    if _acq is None or _acq.negated:
        return None  # not an acquisition (or negated absence) → caller runs occurrence lanes
    out: list[dict] = []
    _device = (_acq.device or "").strip().lower()
    if _device and len(_device) >= 2:
        # PRIMARY binding: user --owns--> <device>, INFERRED (Class B), dated, EXPOSED as an
        # explicit fact (the comparison/operand lane reaches the device as the owns OBJECT).
        _owns = {"subject": "user", "rel_type": "owns", "object": _device,
                 "fact_provenance": "llm_inferred"}
        if iso:
            _owns["event_date"] = iso
            _owns["event_date_granularity"] = gran or "day"
        out.append(_owns)
        log.info("acquisition_lane.owns", device=_device[:48],
                 date=iso, location=(_acq.location or "")[:32])
        # ALIAS: the appositive proper name ("Dell XPS 13") → also_known_as of the device so
        # the comparison operand resolves by either surface. NAMING layer, never L4.
        _alias = (_acq.alias or "").strip()
        if _alias and _alias.lower() != _device:
            out.append({"subject": _device, "rel_type": "also_known_as", "object": _alias,
                        "fact_provenance": "user_stated"})
        # LOCATION: co-bound WHERE — bound to the DEVICE (the acquired thing was located_in the
        # mall at acquisition). Kept, NOT promoted to the event and NOT the owns object. Rel is
        # the canonical spatial rel the ontology owns (located_in), looked up by semantics.
        _loc = (_acq.location or "").strip().lower()
        if _loc and _loc != _device:
            out.append({"subject": _device, "rel_type": "located_in", "object": _loc,
                        "fact_provenance": "llm_inferred"})
    # FIRED (even if the device was too short to keep an edge): the caller must SUPPRESS its
    # occurrence lane for this clause — an acquisition is NOT a participated_in event, and the only
    # thing the occurrence lane would mint here is the bogus locative-as-event.
    return out


def _detect_event_states(text: str, reference=None) -> list[dict]:
    r"""Deterministic EVENT-capture FAST-PATH (event-capture seam, Option A).

    This is the ZERO-SHOT, NO-LLM fast-path of the occurrence seam: when the construction is a
    recognizable light-verb + eventive-noun shape it fires deterministically with no model call.
    The TAIL it cannot cover (a verb outside the bounded support-verb class — "underwent surgery",
    "scheduled a meeting") is closed by the GROWTH-WIRED residue classifier
    ``_classify_occurrence_residue`` (a targeted LLM detect+classify on a dateful-but-hostless
    span). Both emit the SAME backbone edge ``(user, participated_in, <eventive-noun>)``.

    Captures a light-verb + eventive-noun construction ("I had a dentist visit", "I went to a
    concert", "I attended a workshop") as a reified-occurrence edge so the EVENT and its DATE are
    not dropped. This is the SAME structural gap ``feels`` solved: the eventive noun ("visit") is
    the semantic head and "had" is an empty support verb, so the verb-lift (which needs a GLiNER2
    entity PAIR) never mints an edge — the parsed ``event_date`` then has nothing to attach to.
    Mirrors the proven-live ``_detect_feeling_states`` / ``_detect_naming_states`` harvest seams.

    Subject-agnostic + grammatical (NO event-noun word-list, NO event-verb word-list): uses the
    spaCy dependency parse (``analyze_event``) to detect the LIGHT-VERB (a grammatical support-verb
    class, NOT a bespoke event list) governing an eventive direct-object noun phrase with the user
    as subject. Emits ``(user, participated_in, <eventive-noun-phrase>)``; ``participated_in`` is the canonical
    occurrence rel (migration: ``temporal_class='event'``) — looked up by SEMANTICS, NOT a
    hardcoded ``if rel_type==``; the seam simply emits the relation the ontology owns. The
    event-noun grounds into the ``event`` taxonomy via the existing re_embedder "what is X"
    pushback (same as ``anxious→emotion``); the DATE rides the existing per-edge ``event_date``
    gate (no change there).

    THE HARD LINE: event-TYPE is a PLACE (a node in L4), the DATE is a SCALAR leaf — never
    conflated; this seam only emits the type edge. Returns ``[{subject:'user',
    rel_type:'participated_in', object:<eventive-noun>, fact_provenance:'user_stated'}]`` routed through
    the EXISTING source="mcp"/user_stated /ingest path. Does NOT fire on feelings/preferences/
    naming (those have their own seams; copula clauses have head lemma "be", not a support verb).
    Negated occurrences are SKIPPED (absence modeling deferred). Fail-safe: any error → []. Never
    resolves the object (strong ingest, lean query)."""
    if not text or not text.strip():
        return []
    # PEEL THE DATE FIRST → date-free residue (legacy-fallback parity with the reified seam). A date
    # is an event_date SCALAR, never the event: when a reference is supplied, DROP this text's date
    # span out BEFORE analyze_event so the eventive-noun detector cannot grab "February 20th" as the
    # occurrence, and attach the peeled date to the emitted participated_in edge. reference=None →
    # exactly today's behavior (no peel, no date attached) for any caller that doesn't thread it.
    _es_iso, _es_gran, _es_text = (None, None, text)
    if reference is not None:
        try:
            from src.extraction.linguistics import extract_event_date_and_residue as _es_peel
            _es_iso, _es_gran, _es_text = _es_peel(text, reference)
        except Exception:  # noqa: BLE001 — peel miss → undated occurrence on the full text
            _es_iso, _es_gran, _es_text = (None, None, text)
        # FIX #1 (legacy-flat parity) — DATE-ONLY SPAN → NO EVENT. A resolved date (``_es_iso``) with
        # an UNCHANGED residue (== the original text) means the excision emptied the span and the
        # peel's fail-safe restored the original (the text was essentially just the date). Emit
        # NOTHING — the date belongs to a host edge elsewhere, never its own eventified occurrence
        # (the 2026 february-20th bug). reference=None callers are unaffected (no peel, no date).
        if _es_iso and _es_text is not None and _es_text.strip() == (text or "").strip():
            log.info("detect_event_states.date_only_span_skipped",
                     date=_es_iso, span=(text or "")[:48])
            return []
        if not _es_text or not _es_text.strip():
            _es_text = text
        if _es_iso and not _es_gran:
            _es_gran = "day"
    out: list[dict] = []
    try:
        from src.extraction.linguistics import (
            analyze_events, analyze_inchoative, linguistics_available,
        )
        if not linguistics_available():
            return []
        # ── Q4 ACQUISITION LANE (transfer-of-possession) — EXPOSE the user→device ownership ──────
        # Shared with the LIVE reified path (_detect_event_states_reified) via _acquisition_lane_edges.
        # A non-None return means the clause WAS an acquisition: emit its edges and SUPPRESS the LVC
        # occurrence lane (an acquisition is not a participated_in event; the lane would only mint the
        # bogus locative-as-event). None → not an acquisition → fall through to the occurrence lanes.
        _acq_edges = _acquisition_lane_edges(_es_text, _es_iso, _es_gran)
        if _acq_edges is not None:
            out.extend(_acq_edges)
            return out
        # MULTIPLE OCCURRENCES PER CLAUSE (Q2 PRIMARY): enumerate EVERY eventive head so a titled
        # sibling occurrence ("…workshops, like the workshop on 'Effective Time Management'") is no
        # longer dropped. analyze_event used to return only the first head.
        _evs = analyze_events(_es_text)
        # INCHOATIVE FALLBACK (q7 gap): "I started <item> on DATE" / "I began <item>" — the event
        # meaning is on the VERB (ingressive aspect), not an eventive noun, so the LVC lane misses
        # it. analyze_inchoative recognizes the ingressive-verb + concrete-direct-object shape and
        # emits the SAME (user, participated_in, <item>) backbone the residue classifier emits for an
        # ACTION-on-a-thing ("washed my car"), but DETERMINISTICALLY (no LLM). Only when the LVC lane
        # produced nothing, so the two lanes never double-capture the same clause.
        if not _evs:
            _inch = analyze_inchoative(_es_text)
            _evs = [_inch] if _inch is not None else []
    except Exception as e:  # noqa: BLE001 — fail-safe: never break ingest
        log.warning("detect_event_states.failed", error=str(e)[:120])
        return []
    _seen_events: set[str] = set()
    for ev in _evs:
        if ev is None or ev.negated:
            continue
        event = (ev.event or "").strip().lower()
        if not event or len(event) < 3:
            continue
        _backbone = {"subject": "user", "rel_type": "participated_in", "object": event,
                     "fact_provenance": "user_stated"}
        if _es_iso:
            _backbone["event_date"] = _es_iso
            _backbone["event_date_granularity"] = _es_gran or "day"
        # Dedup the bare participation backbone across occurrences (a redundant duplicate head must
        # not emit a second identical (user, participated_in, <type>) — titles/concerns still ride).
        if event not in _seen_events:
            _seen_events.add(event)
            out.append(_backbone)
        # Q8 CROP ANCHORS: emit one DATED occurrence per specific crop the start is about (+ its plural
        # alias) so a comparison operand ("tomatoes"/"marigolds") reaches the start, not just the generic
        # head ("seeds"). HARD LINE: crop = type/entity (occurrence object); date = scalar on the edge.
        for _canon, _plural in (getattr(ev, "anchors", ()) or ()):
            if not _canon or _canon == event:
                continue
            _crop_edge = {"subject": "user", "rel_type": "participated_in", "object": _canon,
                          "fact_provenance": "user_stated"}
            if _es_iso:
                _crop_edge["event_date"] = _es_iso
                _crop_edge["event_date_granularity"] = _es_gran or "day"
            out.append(_crop_edge)
            if _plural and _plural != _canon:
                out.append({"subject": _canon, "rel_type": "also_known_as", "object": _plural,
                            "fact_provenance": "user_stated"})
        # NAMED-EVENT IDENTITY (the dog/Rex split — highest-leverage recall fix): when the eventive
        # noun phrase carries a TITLE (a quoted name "Data Analysis using Python" or a PROPN
        # appositive/PP "on Effective Time Management"), ALSO emit a naming edge binding the title to
        # the event TYPE via the existing ``also_known_as`` naming rel — exactly as _detect_naming_states
        # does for "a dog named Rex". THE HARD LINE: the type ("webinar") is the PLACE and stays the
        # occurrence object; the title is the NAME and rides ``also_known_as`` so recall can disambiguate
        # "which webinar". rel chosen by SEMANTICS (the canonical naming rel), NOT a hardcoded check.
        _title = (ev.title or "").strip()
        if _title and len(_title) >= 2 and _title.lower() != event:
            log.info("detect_event_states.captured", event_noun=event[:32], title=_title[:48])
            # subject_type="Event" marks the alias TARGET as a non-person event TYPE. Event titles are
            # legitimately multi-word ("Data Analysis using Python") — the ingest alias path's name-like
            # ≤2-word guard is a PERSON-NAME heuristic that must NOT reject a typed event title. The
            # guard reads this type to widen the word cap for non-person aliases (it stays strict for
            # Person/unknown name aliases). Structural type signal, NOT a hardcoded rel_type/word check.
            out.append({"subject": event, "rel_type": "also_known_as", "object": _title,
                        "subject_type": "Event", "fact_provenance": "user_stated"})
        else:
            log.info("detect_event_states.captured", event_noun=event[:32])
        # SUBJECT-MATTER (the with-PP specific entity): "I had an issue WITH my car's GPS system"
        # reifies the bland head "issue" while "gps system" sits in ``concerns``. Host it as a SEPARATE
        # linked REAL entity off the occurrence (here the bare type, which is the flat-shape occurrence
        # object) so recall walking the occurrence surfaces it. THE HARD LINE: never a date, never the
        # occurrence object. Rel is metadata-resolved (related_to). Fail-safe: no concerns → unchanged.
        _concerns = (ev.concerns or "").strip()
        if (_concerns and _concerns.lower() != event
                and _concerns.lower() != (_title or "").lower()):
            log.info("detect_event_states.subject_matter", event_noun=event[:32],
                     concerns=_concerns[:48])
            out.append({"subject": event, "rel_type": _subject_matter_rel(), "object": _concerns,
                        "fact_provenance": "user_stated"})
    return out


# Occurrence-residue capture: default ON, independent kill-switch. OFF → only the deterministic
# fast-path (_detect_event_states) fires; today's behavior is exactly preserved.
OCCURRENCE_RESIDUE_CAPTURE = os.getenv("OCCURRENCE_RESIDUE_CAPTURE", "1") not in ("0", "false", "False")

# Occurrence REIFICATION (keystone A): default ON, independent kill-switch. OFF → the seams emit
# the legacy flat shape (user, participated_in, <type>) + (<type>, also_known_as, <title>) where
# the title piles onto the SHARED type node. ON → each occurrence is reified as its OWN entity
# (the memory) filed at the bare type (the place), with title + date cohering on the occurrence.
OCCURRENCE_REIFY = os.getenv("OCCURRENCE_REIFY", "1") not in ("0", "false", "False")


def _subject_matter_rel() -> str:
    r"""METADATA-DRIVEN rel for hosting an occurrence's SUBJECT-MATTER (``EventAnalysis.concerns``).

    "I had an issue WITH my car's GPS system" reifies the bland eventive head ("issue") as the
    occurrence; the SPECIFIC entity ("gps system") rides a separate edge so recall walking the
    occurrence surfaces it. THE HARD LINE: ``concerns`` is a REAL linked entity (the memory), never
    a date and never swallowed into the occurrence object — the occurrence object stays the bare
    type, this edge links it to the specific subject-matter.

    Rel is chosen by SEMANTICS, not a hardcoded token: the canonical loose-association rel
    ``related_to`` (skos:related, ANY/ANY, is_hierarchy_rel=false — the engine's existing
    "X is about / concerns Y" link). Resolution mirrors the /learn orphan-binder
    (``_binding_rel`` ~line 31125): take ``related_to`` only when its metadata is ANY/ANY (so the
    WGM gate admits the Occurrence→subject-matter pair unconditionally). If the rel is absent from
    the per-tenant overlay (metadata empty) it is grown via the source="mcp"/user_stated ingest
    path like any novel rel — we still NAME it ``related_to`` so it converges by identity. Subject-
    agnostic, deterministic, no word-list."""
    _meta = _REL_TYPE_META.get("related_to", {})
    if (list(_meta.get("head_types", ["ANY"])) == ["ANY"]
            and list(_meta.get("tail_types", ["ANY"])) == ["ANY"]):
        return "related_to"
    # Metadata not (yet) ANY/ANY in this tenant's overlay (e.g. unseeded): still emit related_to —
    # the ingest grows/admits it via the user_stated path. Convergence-by-identity keeps it single.
    return "related_to"


# Bounded English-grammar function-word set used when folding an occurrence's (title, type) into its
# canonical identity key. A language primitive (determiners/articles/possessives/preps the two parses
# may add or drop), NOT a domain word-list — same role as ``_REATTACH_FN_WORDS`` below. Dropping these
# before the token-set fold lets the same real occurrence converge regardless of a stray "the"/"a".
_OCCURRENCE_FN_WORDS = frozenset({
    "the", "a", "an", "my", "our", "your", "his", "her", "its", "their",
    "of", "from", "to", "in", "on", "at", "for", "with", "and", "or",
})


def _occurrence_identity_tokens(event_type: str, title: str | None) -> list[str]:
    r"""Fold an occurrence's TYPE + optional TITLE into a stable, sorted content-token list.

    THE CONVERGENCE KEY. The same real occurrence is parsed INCONSISTENTLY across mentions — e.g.
    "Turbocharged Tuesdays" reads as ``event="turbocharged tuesdays", title=None`` in one turn and
    ``event="tuesdays", title="Turbocharged"`` in another (the proper-noun modifier splits off the
    type when a trailing date is present). Either parse contributes the SAME content tokens
    {turbocharged, tuesdays}, so a sorted-deduped token fold of (title ∪ type) is IDENTICAL across
    both — that is what makes ``uuid5`` converge the fragments by IDENTITY (no date, no parse-order,
    no prefix baked in). Function words are dropped so a stray determiner cannot fork the key.

    Deterministic, subject-agnostic, NO word-list of events/domains (only the grammar function-word
    primitive). Returns the sorted unique content tokens (possibly empty)."""
    toks: list[str] = []
    for _src in ((title or ""), (event_type or "")):
        for _t in _src.strip().lower().split():
            _t = _t.strip()
            if _t and _t not in _OCCURRENCE_FN_WORDS:
                toks.append(_t)
    return sorted(set(toks))


def _occurrence_handle(event_type: str, title: str | None, event_date_iso: str | None) -> str | None:
    r"""Deterministic SURFACE HANDLE for a reified per-occurrence entity (the MEMORY node).

    THE HARD LINE: the bare ``event_type`` ("webinar") is the L4 PLACE; THIS handle names the
    SPECIFIC OCCURRENCE filed at it (the memory). The entity registry mints a stable surrogate via
    ``uuid5(handle)``, so the handle's IDENTITY must be STABLE across every mention of the same real
    occurrence — otherwise the date scalar lands on one surrogate and the name on another and they
    divorce (the litmus fragmentation: "rack fest" → 3 nodes, the dated one not the one recall lands
    on). Therefore the handle is **DATE-INDEPENDENT and PREFIX-INDEPENDENT** — it derives ONLY from
    the stable TYPE(+TITLE) content, never from the date or an "event:"/"on <date>" surface:

      • TITLED or otherwise NAMED occurrence → ``"occurrence:" + <sorted content tokens of
        (title ∪ type)>``. The sorted token fold (``_occurrence_identity_tokens``) converges the
        inconsistent parses of the SAME occurrence ("turbocharged tuesdays" vs "tuesdays"+title
        "Turbocharged") onto ONE surrogate. The ``occurrence:`` prefix keeps the node DISTINCT from
        the bare L4 type PLACE node (which the occurrence ``instance_of``-files itself at), so the
        memory and the place never collapse. The DATE rides the participated_in edge as the
        ``event_date`` SCALAR; the human-facing NAME rides ``also_known_as`` — neither is in the
        identity. A later mention adding a title/date the earlier node lacked MERGES onto this same
        surrogate (convergence-by-identity), it does NOT mint a new node.

      • UNTITLED, only a DATE (no name beyond the bare type) → ``None``. A bare-type occurrence has
        no stable per-occurrence identity (two undated "I went to a webinar" mentions are not
        knowably the same occurrence, and baking the date back in is exactly the fragmentation we
        are removing) — so we keep the FLAT (user, participated_in, <type>) shape (today's behavior)
        and let the date ride that edge. We never invent a fake date-baked discriminator.

      • no type → ``None``.

    Subject-agnostic, deterministic, no event/domain word-list. The handle is an INTERNAL surrogate
    surface (sorted tokens are fine — it is never shown); the human-facing NAME rides
    ``also_known_as`` (the title, original surface) on the occurrence (see the caller).
    """
    et = (event_type or "").strip().lower()
    if not et:
        return None
    t = (title or "").strip().lower()
    _toks = _occurrence_identity_tokens(et, t if (t and t != et) else None)
    # An occurrence is REIFIED (gets its own stable node) when it is effectively NAMED — i.e. it
    # carries a title, OR its bare event phrase is a multi-token proper name ("rack fest",
    # "turbocharged tuesdays"). A single bare common type ("webinar", "meeting") with no title is
    # NOT a distinguishable per-occurrence identity → flat shape. This is a GRAMMAR signal
    # (named vs generic by token count + the presence of a title), NOT an event/domain word-list.
    # CRITICAL: the same real occurrence is parsed inconsistently — "turbocharged tuesdays"
    # (title=None) vs "tuesdays"+title="Turbocharged" — but BOTH fold to the SAME sorted token set,
    # so both reify onto the SAME ``occurrence: ...`` surrogate (convergence-by-identity). The date
    # is NEVER in this identity; it rides the participated_in edge as the event_date scalar.
    _named = bool(t and t != et) or len(_toks) >= 2
    if _named and _toks:
        return "occurrence: " + " ".join(_toks)
    # UNTITLED single-token bare type → no stable per-occurrence identity: keep the flat shape.
    # Baking the date into the handle is the fragmentation bug, so we never do it.
    return None


def _reify_occurrence_edges(event_type: str, title: str | None,
                            event_date_iso: str | None,
                            event_date_granularity: str | None,
                            concerns: str | None = None) -> list[dict] | None:
    r"""Build the COHERING per-occurrence edge set for ONE reified occurrence, or ``None``.

    KEYSTONE A — reify each occurrence as its OWN entity (the memory) filed at the bare type (the
    place), with ALL hinges cohering on the occurrence (commit e2b8a9c fracture fix). Returns the
    edge list, or ``None`` when there is no disambiguator (caller keeps the flat legacy shape).

    The cohering hinges (THE HARD LINE throughout — occurrence=memory, type=place, title=name on
    occurrence, date=scalar+granularity ON the occurrence):
      1. (user, participated_in, <occurrence>)            — participation; <occurrence> is the
         per-occurrence node, NOT the shared type. This edge HOSTS the date (temporal_class=event).
      2. (<occurrence>, instance_of, <event-type>)        — the occurrence is FILED AT the bare
         type ("webinar" stays the L4 place; the occurrence is its instance).
      3. (<occurrence>, also_known_as, <name>)            — the NAME of the occurrence (not the
         shared type node) → recall can disambiguate "which webinar". The name is the TITLE when one
         exists, else the readable event PHRASE (named-untitled case, e.g. "turbocharged tuesdays")
         since the handle itself is an internal sorted-token surrogate, never human-facing.

    The DATE + true GRANULARITY ride hinge (1) via the per-edge ``event_date``/
    ``event_date_granularity`` fields on the participated_in edge (the row-build site hosts them on
    the occurrence). The title NEVER leaks as a participated_in/educated_at OBJECT — the occurrence
    object is the surrogate handle, and the title is bound only via also_known_as on the occurrence.

    Fail-safe: returns ``None`` on no-handle so the caller falls back; never raises."""
    et = (event_type or "").strip().lower()
    handle = _occurrence_handle(et, title, event_date_iso)
    if not handle or not et:
        return None
    edges: list[dict] = [
        # (1) participation — the occurrence is the object; THIS edge hosts the occurrence's own date.
        {"subject": "user", "rel_type": "participated_in", "object": handle,
         "subject_type": "Person", "object_type": "Event",
         "event_date": event_date_iso, "event_date_granularity": event_date_granularity,
         "fact_provenance": "user_stated"},
        # (2) FILE the occurrence at the bare type (the place). instance_of is the rdf:type seed.
        {"subject": handle, "rel_type": "instance_of", "object": et,
         "subject_type": "Event", "object_type": "Event",
         "fact_provenance": "user_stated"},
    ]
    t = (title or "").strip()
    # (3) NAME the occurrence (not the shared type) via also_known_as. The handle is an internal
    # sorted-token surrogate that must never be the human-facing name, so we ALWAYS attach a readable
    # name: the TITLE when one exists, else the readable event PHRASE (the named-untitled case, e.g.
    # "turbocharged tuesdays"). Both rides anchor the SAME converged surrogate, so a later mention
    # that adds a title MERGES its name onto the existing node (no fan-out). subject_type="Event"
    # widens the alias word-cap guard for legitimately multi-word event names.
    _display = t if (t and t.lower() != et) else et
    if _display and _display.lower() != handle:
        edges.append({"subject": handle, "rel_type": "also_known_as", "object": _display,
                      "subject_type": "Event", "fact_provenance": "user_stated"})
    if t and t.lower() != et and t.lower() != _display.lower() and t.lower() != handle:
        # A distinct title alongside the readable phrase → also name the occurrence by it (extra
        # also_known_as ride on the same converged node).
        edges.append({"subject": handle, "rel_type": "also_known_as", "object": t,
                      "subject_type": "Event", "fact_provenance": "user_stated"})
    # (4) SUBJECT-MATTER — the occurrence is ABOUT the specific entity (``concerns``). THE HARD
    # LINE: the occurrence object stays the bare type ("issue"); the specific thing ("gps system")
    # is a SEPARATE linked REAL entity so recall walking the occurrence surfaces it. Never a date,
    # never the occurrence object. Rel is metadata-resolved (related_to), not a hardcoded token.
    c = (concerns or "").strip()
    if c and c.lower() != et and c.lower() != handle and c.lower() != t.lower():
        edges.append({"subject": handle, "rel_type": _subject_matter_rel(), "object": c,
                      "fact_provenance": "user_stated"})
    return edges


def _compute_ingest_reference_and_text(req_text: str | None):
    r"""Resolve the FROZEN ingest reference instant + the marker-stripped text for date extraction.

    Single source of truth for (a) the session reference date (parsed from a leading harness
    ``[Date: ...]`` marker, else wall-clock now) and (b) the text with that marker stripped (the
    marker is the REFERENCE only, never an event date). Extracted so BOTH the early per-clause
    occurrence reification AND the request-level temporal block resolve the SAME reference
    deterministically (no drift). Fail-safe: any error → (now_utc, req_text).

    SINGLE-DOOR (temporal module): the marker semantics now live in ``src.temporal.reference``
    (``derive_now``) — the single NOW-reference source of truth (fix #1b). This wrapper
    delegates to it and keeps the identical ``(reference, text)`` contract + fail-safe so every
    existing caller is byte-for-byte unchanged."""
    from datetime import datetime as _dt_ref, timezone as _tz_ref
    try:
        from src.temporal import derive_now as _derive_now
        return _derive_now(req_text)
    except Exception:  # noqa: BLE001 — fail-safe: module unavailable → wall-clock now + raw text
        return (_dt_ref.now(_tz_ref.utc), req_text or "")


def _peel_dates_at_entry(spans: list[str], reference, declarative_text: str | None = None):
    r"""HARVEST ENTRY-PEEL — peel EVERY date out ONCE, ABOVE the atomizer/lanes.

    THE COMPOSITIONAL CAPTURE PRINCIPLE, applied at the TOP of /harvest-spans instead of inside each
    lane. The per-lane peel was too LOW in the stack: /harvest-spans ATOMIZES the turn first, then
    runs MULTIPLE lanes (GLiNER2 relation scorer, verb-lift, event seam, merge, born_on/scalar) — and
    the scorer + verb-lift do NOT peel, so they re-encountered the raw date ("February 20th") on every
    atomized span and eventified / born_on'd / object-ified it. Peeling ONCE here means the date is
    simply GONE from every span (and the joined declarative text) every lane sees, so NO lane can mint
    a date-as-event / date-as-object / born_on-date edge. The peeled dates are reattached to their HOST
    edges afterwards by ``_reattach_clause_dates``.

    GRANULARITY SPLIT (the reattach-fix). Two jobs run here with DIFFERENT granularity:
      1. **date-free SPANS for the lanes** — peeled per atomized ``span`` (the single source the
         declarative text is joined from), so EVERY lane sees DATE-FREE input. A span with no date is
         kept verbatim; a date-ONLY span ("on February 20th") is DROPPED from the list.
      2. **``clause_dates`` for the reattach** — recorded per WHOLE GRAMMATICAL CLAUSE
         (``segment_clauses(declarative_text)``), NOT per fragmented atom. The atomizer fragments a
         clause, so a date ("February 20th") can land in a DIFFERENT atom than its host entity
         ("Samsung Galaxy S22"); a fragment residue ("from best buy") then fails the reattach's
         text-containment match against the edge's object. Recording the residue from the FULL clause
         ("i got a samsung galaxy s22 from best buy") guarantees the residue CONTAINS the edge's object
         surface → the reattach binds ``@2023-02-20`` to the ``get→samsung`` edge. When the full clause
         is unavailable (no ``declarative_text`` / layer down / parse miss) it falls back to the
         per-span residue (pre-fix behavior) so the peel never regresses.

    Returns ``(datefree_spans, clause_dates)``:
      • ``datefree_spans`` — each span with its first resolvable date span excised (the SAME
        ``extract_event_date_and_residue`` the lanes used, hoisted to the entry).
      • ``clause_dates`` — ordered list of ``{"residue", "residue_lc", "iso", "gran", "date_only"}``,
        one per dated WHOLE clause (full date-free residue), used to reattach the date to the edge(s)
        produced from that clause's content.

    DETERMINISTIC, fail-safe, NO ML/LLM. Any error / no reference → ``(spans, [])`` so the harvest
    behaves exactly as before this peel existed (every lane keeps its own per-clause peel as the
    backstop). ``reference`` is the marker-resolved session instant so relative dates anchor to the
    conversation, not wall-clock."""
    if not spans or reference is None:
        return (list(spans or []), [])
    try:
        from src.extraction.linguistics import extract_event_date_and_residue as _peel
    except Exception as e:  # noqa: BLE001 — layer unavailable → no entry-peel (lanes self-peel)
        log.debug("harvest.entry_peel_import_failed", error=str(e)[:120])
        return (list(spans), [])

    # ── Job 1: date-free SPANS for the downstream lanes (peeled per atomized span) ────────────────
    out_spans: list[str] = []
    any_span_dated = False
    for _span in spans:
        if not _span or not _span.strip():
            continue
        try:
            _iso, _gran, _residue = _peel(_span, reference)
        except Exception:  # noqa: BLE001 — peel miss → keep the span verbatim, no date
            _iso, _gran, _residue = (None, None, _span)
        if not _iso:
            out_spans.append(_span)  # no resolvable date — keep verbatim
            continue
        any_span_dated = True
        _residue_stripped = (_residue or "").strip()
        is_date_only = (not _residue_stripped) or (_residue_stripped == (_span or "").strip())
        if is_date_only:
            # Span was ESSENTIALLY just the date ("on February 20th"): DROP it so no lane eventifies
            # it. Its date is recovered by the WHOLE-CLAUSE pass below (Job 2).
            continue
        out_spans.append(_residue_stripped)

    # ── Job 2: clause_dates for the reattach (peeled per WHOLE GRAMMATICAL CLAUSE) ────────────────
    # The residue recorded here must CONTAIN the host edge's entity surface, so peel whole clauses,
    # not fragmented atoms. Source the clauses from the declarative text (the marker-stripped turn);
    # fall back to the spans only when the clause segmenter is unavailable.
    clause_units: list[str] = []
    if declarative_text and declarative_text.strip():
        try:
            from src.extraction.linguistics import segment_clauses as _segment
            clause_units = _segment(declarative_text) or []
        except Exception as e:  # noqa: BLE001 — segmenter unavailable → span-residue fallback
            log.debug("harvest.entry_peel_segment_failed", error=str(e)[:120])
            clause_units = []
    if not clause_units:
        # Fallback: no whole-clause source → record dates from the spans (pre-fix granularity).
        clause_units = [s for s in spans if s and s.strip()]

    clause_dates: list[dict] = []
    any_clause_dated = False
    for _clause in clause_units:
        if not _clause or not _clause.strip():
            continue
        try:
            _iso, _gran, _residue = _peel(_clause, reference)
        except Exception:  # noqa: BLE001 — peel miss → no date for this clause
            _iso, _gran, _residue = (None, None, _clause)
        if not _iso:
            continue
        any_clause_dated = True
        _gran = _gran or "day"
        _residue_stripped = (_residue or "").strip()
        is_date_only = (not _residue_stripped) or (_residue_stripped == (_clause or "").strip())
        # date_only: the clause was essentially just the date — the residue stays the FULL clause text
        # (date intact) so a sibling host edge whose object/subject overlaps it can still claim it.
        _res_for_match = _residue_stripped if not is_date_only else (_clause or "").strip()
        clause_dates.append({
            "residue": _res_for_match,
            "residue_lc": _res_for_match.lower(),
            "iso": _iso, "gran": _gran, "date_only": is_date_only,
        })

    if not any_span_dated and not any_clause_dated:
        # Nothing peeled anywhere → return the spans untouched (zero behavior change).
        return (list(spans), [])
    if not out_spans:
        # Excision emptied every span (the turn was only date(s)) → keep the originals so the lanes
        # still run their own per-clause peel as the backstop; dates still ride clause_dates.
        out_spans = list(spans)
    log.info("harvest.entry_peel",
             spans_in=len(spans), spans_out=len(out_spans), dated=len(clause_dates))
    return (out_spans, clause_dates)


def _reattach_clause_dates(edges: list[dict], clause_dates: list[dict]) -> list[dict]:
    r"""Reattach each entry-peeled date to the HOST edge(s) produced from that clause's residue.

    Companion to ``_peel_dates_at_entry``: the date was peeled ONCE at the harvest entry so no lane
    could eventify/object-ify/born_on it; here it is bound back to the edge(s) that came from the same
    date-free residue. Deterministic, fail-safe, content-preserving.

    Matching (no offsets survive atomization, so match by residue TEXT overlap — the residue is the
    date-free string the edge was built from, but the two parses can disagree on the exact surface):
      • An edge gets a clause's date iff the edge does NOT already carry an ``event_date`` AND the
        edge's OBJECT surface (or, failing that, its SUBJECT surface) OVERLAPS that clause's date-free
        residue. Overlap is ROBUST to surface drift between the two passes (the merge edge is parsed
        from the date-FREE text, the residue from the DATED, differently-segmented text — so the
        object head can differ, "galaxy s22" vs "samsung galaxy s22", or "best buy" can attach into
        the NP). Overlap holds when EITHER (a) the full lowercased surface is a substring of the
        residue (fast path), OR (b) ALL content tokens of the surface (whitespace-split, determiners/
        stopwords dropped) are present in the residue's token set (content-token-set containment), OR
        (c) the surface's HEAD token (last token, e.g. "s22") is a whole token of the residue. A
        ``date_only`` clause (the residue IS the original clause, date intact) matches the same way so
        a sibling host edge can claim the date. Content-token-set (not any-token) so an unrelated edge
        sharing only a stopword can NOT false-bind. Pure in-memory token compare — NO fuzzy/cosine,
        NO DB read.
      • A flat ``participated_in <event-type>`` edge that receives a date is UPGRADED in place to the
        reified handle shape (``_reify_occurrence_edges``) so the occurrence is dated + disambiguated
        ("concert" → "concert on 2023-02-24") — parity with the reified event seam, exactly the shape
        the /ingest door expects (the date is the SCALAR on the occurrence, never the event itself).

    Only the FIRST matching dated clause is applied per edge (a single host date). Edges that already
    carry an ``event_date`` (e.g. the merge/event lanes set one) are left untouched. Fail-safe: any
    error → the edges unchanged."""
    if not edges or not clause_dates:
        return edges
    # Bounded English-grammar function-word set — a language primitive (determiners/articles/
    # possessives/preps the two parses may add or drop), NOT a domain word-list. Dropped from the
    # surface BEFORE content-token containment so "from best buy" attaching into the residue, or a
    # leading "a/the/my" on the object, cannot block a legit bind — and so that a shared stopword
    # alone can NEVER carry a false-bind (content tokens only).
    _REATTACH_FN_WORDS = frozenset({
        "the", "a", "an", "my", "our", "your", "his", "her", "its", "their",
        "of", "from", "to", "in", "on", "at", "for", "with", "and", "or",
    })

    def _content_tokens(_surface: str) -> list[str]:
        # whitespace-split, drop function words → the meaning-bearing tokens of the surface.
        return [_t for _t in _surface.split() if _t and _t not in _REATTACH_FN_WORDS]

    def _surface_overlaps_residue(_surface: str, _residue: str, _res_tokens: set[str]) -> bool:
        if not _surface or not _residue:
            return False
        # (a) fast path — full surface is a literal substring of the residue.
        if _surface in _residue:
            return True
        _toks = _content_tokens(_surface)
        if not _toks:
            return False
        # (b) content-token-set containment — ALL content tokens present as whole tokens.
        if all(_t in _res_tokens for _t in _toks):
            return True
        # (c) head-token fallback — the surface's head noun (last token) is a whole residue token.
        if _toks[-1] in _res_tokens:
            return True
        return False

    try:
        out: list[dict] = []
        for _edge in edges:
            try:
                if not isinstance(_edge, dict):
                    out.append(_edge)
                    continue
                if _edge.get("event_date"):
                    out.append(_edge)
                    continue
                _obj = (_edge.get("object") or "").strip().lower()
                _subj = (_edge.get("subject") or "").strip().lower()
                _match = None
                for _cd in clause_dates:
                    _res = _cd.get("residue_lc") or ""
                    if not _res:
                        continue
                    _res_tokens = set(_res.split())
                    if (_obj and _surface_overlaps_residue(_obj, _res, _res_tokens)) or (
                        _subj and _subj != "user"
                        and _surface_overlaps_residue(_subj, _res, _res_tokens)
                    ):
                        _match = _cd
                        break
                if _match is None:
                    out.append(_edge)
                    continue
                _iso = _match["iso"]
                _gran = _match.get("gran") or "day"
                # Flat participated_in <type> → upgrade to the dated reified handle shape.
                _rel = (_edge.get("rel_type") or "").strip().lower()
                if _rel == "participated_in" and _obj and " on " not in _obj:
                    _reified = _reify_occurrence_edges(_obj, None, _iso, _gran) if OCCURRENCE_REIFY else None
                    if _reified:
                        out.extend(_reified)
                        continue
                _edge["event_date"] = _iso
                _edge["event_date_granularity"] = _gran
                out.append(_edge)
            except Exception:  # noqa: BLE001 — per-edge fail-safe
                out.append(_edge)
        return out
    except Exception as e:  # noqa: BLE001 — whole-pass fail-safe
        log.warning("harvest.reattach_dates_failed", error=str(e)[:120])
        return edges


# ════════════════════════════════════════════════════════════════════════════════════════════════
# STAGE 1 — GROUNDED per-candidate-edge confidence score (LOGGED + NON-COMMITTING).
# ════════════════════════════════════════════════════════════════════════════════════════════════
# Stage 0 (WGM_TYPE_MISMATCH_VETO) made the tail-type mismatch a BINARY veto at the gate. Stage 1
# builds the richer GRADED score that Stage 2's arbitration will consume — but COMMITS NOTHING. It
# only COMPUTES + LOGS a per-candidate breakdown so a human (and later Stage 2) can see WHY a
# candidate is strong/weak. Behind SPINE_CANDIDATE_SCORE (default ON). Every component is a
# PROVENANCE OF A REAL SIGNAL the parse or GLiNER2 actually saw — NO fabricated/opaque constant.
#
# The four grounded signals (assembled per candidate participation edge):
#   1. TYPE-FIT (heavy) — GLiNER2 object entity_type vs the rel's tail_types (metadata via the
#      per-tenant overlay, NO type literal). Reuses the SAME verdict logic as the Stage-0 veto
#      (_passed_type_is_genuine_mismatch semantics, re-expressed as a GRADE not a bool): exact
#      member → STRONG; hierarchy-reachable subtype → MODERATE; concrete-incompatible → CRATER;
#      unknown/unconstrained → NEUTRAL (fail-safe, never craters). Symmetric for head/subject.
#   2. CONSTRUCTION — which lane proposed it + how cleanly, read from the actual parse (the
#      EventAnalysis the deriver produced), NOT a word list. A bland LVC head whose specific entity
#      had to be PROMOTED out of a `with`-PP (concerns set → the head is semantically empty:
#      "had an issue WITH my car's GPS system") is a WEAK participation signal. A clean eventive
#      head (a titled/reified occurrence, no argument-promotion) is STRONG.
#   3. CUE/PREDICATE — a clear state/problem predicate UP-weights a state reading. Resolved from a
#      DB cue class (`problem_noun`/`state_predicate`). That class lands in STAGE 3 — until then we
#      DEGRADE GRACEFULLY: probe the DB for the class; if ABSENT, FLAG the dependency and use ONLY
#      the parse-available signal (the bland-head construction already evidences it). We do NOT
#      hardcode a noun list as a stopgap.
#   4. POSSESSIVE/PART — an object that is a COMPONENT of an owned device (a possessive chain in the
#      promoted argument, "my car's GPS system" → part_of) reinforces the OBJECT reading over the
#      event reading (down-weights participation). Structural (poss in the concerns NP), no list.
#
# The result is INSPECTABLE: each signal yields a named verdict + the assembled GRADE, logged as a
# structured breakdown. Fail-loud per component: if a component can't be grounded it logs that and
# DEFAULTS TO THE CONSERVATIVE GRADE — never invents a number.

# Grade ladder (ordinal — the score is a GRADE label, not an opaque float; Stage 2 maps it to an
# arbitration weight). Ordered weakest→strongest so a min() picks the most conservative.
_SPINE_GRADE_ORDER = ("crater", "weak", "moderate", "neutral", "strong")


def _spine_typefit_grade(passed_type: str | None, allowed_types, role: str) -> tuple[str, str]:
    """GRADED re-expression of the Stage-0 type-fit verdict (NOT a duplicate gate — same semantics,
    extended from bool→grade). Returns (grade, verdict_reason).

    Mirrors gate._passed_type_is_genuine_mismatch / _check_type_constraints type gate:
      • unconstrained role (no allowed types / 'any') → ('neutral', 'unconstrained')
      • no concrete passed type (None/'unknown')      → ('neutral', 'type_unknown')  (fail-safe)
      • exact member of allowed                       → ('strong', 'exact_member')
      • hierarchy-reachable subtype (Stage 2 wires    → ('moderate', 'hierarchy_reachable')
        the live _hierarchy_expand check; Stage 1 has
        no entity_id here, so a concrete non-member is
        a candidate for reachability — graded MODERATE
        only when the type plausibly subtypes, else)
      • concrete + constrained + not a member         → ('crater', 'concrete_incompatible')
    Metadata-only, subject-agnostic, NO type literal."""
    allowed = [str(t).strip().lower() for t in (allowed_types or []) if t and str(t).strip()]
    if not allowed or "any" in allowed:
        return ("neutral", f"{role}_unconstrained")
    pt = (passed_type or "").strip().lower()
    if not pt or pt == "unknown":
        return ("neutral", f"{role}_type_unknown")
    if pt in allowed:
        return ("strong", f"{role}_exact_member:{pt}")
    # Concrete, constrained, not a direct member. The Stage-0 veto craters this (after a hierarchy-
    # reachability check it cannot do here without the entity_id). Stage 1 is non-committing, so we
    # grade it CRATER to MIRROR the Stage-0 verdict that WILL fire — that is the whole point (the
    # logged grade must agree with the binary veto). Stage 2 will refine crater↔moderate using the
    # live _hierarchy_expand. Record the concrete incompatibility verbatim.
    return ("crater", f"{role}_concrete_incompatible:{pt}∉{{{','.join(allowed)}}}")


def _spine_problem_cue_present(dsn: str, schema_name: str | None) -> tuple[bool, bool]:
    """Probe whether the Stage-3 state/problem cue class EXISTS for this tenant.

    Returns (class_present, probe_ok). class_present=True iff `<schema>.linguistic_cues` has any
    active row in category 'problem_noun' or 'state_predicate'. probe_ok=False ⇒ the probe itself
    could not run (no schema / DB error) — caller degrades gracefully and FLAGS the dependency.

    We do NOT use linguistic_cue_overlay.resolve_cues here: that resolver FALLS BACK to the naming-
    verb bootstrap for an unknown category (never empty), which would falsely report the class as
    'present'. Stage 1 must detect genuine ABSENCE so it can degrade + flag honestly. Direct count,
    fail-safe."""
    if not dsn or not schema_name or schema_name.strip().lower() in ("", "public"):
        return (False, False)
    try:
        import psycopg2 as _pg
        with _pg.connect(dsn, connect_timeout=5) as _c:
            with _c.cursor() as _cur:
                _cur.execute(
                    f"SELECT 1 FROM {schema_name}.linguistic_cues "
                    f"WHERE category IN ('problem_noun','state_predicate') "
                    f"AND is_active = true LIMIT 1",
                    (),
                )
                return (_cur.fetchone() is not None, True)
    except Exception as _e:  # noqa: BLE001 — fail-safe: probe failed → degrade + flag
        log.debug("spine_candidate_score.cue_probe_failed", error=str(_e)[:120])
        return (False, False)


def _spine_candidate_score(
    candidate: dict,
    ev,
    *,
    promoted_arg: bool = False,
    lane: str = "reified",
) -> dict | None:
    """STAGE 1 — assemble + LOG a grounded, NON-COMMITTING confidence breakdown for ONE candidate
    participation edge. Returns the breakdown dict (also emitted to the log) or None when disabled /
    not a participation candidate. CHANGES NO COMMIT BEHAVIOR — pure compute + log.

    ``candidate`` — the about-to-be-emitted edge dict (subject/rel_type/object/object_type/...).
    ``ev``        — the EventAnalysis the deriver produced for this clause (construction signal
                    source: .concerns/.title), or None.
    ``promoted_arg`` — True when the OBJECT is an argument PROMOTED out of a bland head's with-PP
                    (the GPS case); the strongest WEAK-construction tell.
    ``lane``      — which emit lane proposed it ('reified' | 'flat' | 'flat_crop' | 'conjoined').
    """
    if not _flag_on("SPINE_CANDIDATE_SCORE", default="true"):
        return None
    try:
        rel = (candidate.get("rel_type") or "").strip().lower()
        if rel != "participated_in":
            return None  # Stage 1 scores the participation candidate (the Stage-0 veto target)
        obj = (candidate.get("object") or "").strip().lower()
        subj_type = (candidate.get("subject_type") or "").strip() or None

        # Read the parse-derived construction signals FIRST — they decide whether the lane's
        # self-asserted object_type is TRUSTWORTHY for the type-fit (see below).
        _concerns = None
        _title = None
        if ev is not None:
            try:
                _concerns = (getattr(ev, "concerns", None) or "").strip() or None
                _title = (getattr(ev, "title", None) or "").strip() or None
            except Exception:  # noqa: BLE001
                _concerns, _title = None, None

        # POSSESSIVE/PART structure of the promoted argument (SIGNAL 4, needed early): a possessive
        # chain in the with-PP argument ("my car's GPS system") is a component-of-owned-device — the
        # object is a concrete OBJECT, not an event. Structural (genitive 's / possessive det), no list.
        part_reinforced = False
        if _concerns:
            _cl = _concerns.lower()
            _first = _cl.split(" ")[0] if _cl else ""
            part_reinforced = ("'s " in _cl or _cl.startswith("my ") or "'s" in _first)

        # ── SIGNAL 1: TYPE-FIT (heavy). Metadata via the per-tenant overlay — NO type literal. ──
        # The lane stamps object_type='Event' on its OWN participation edge — but for an
        # ARGUMENT-PROMOTED bland head (the GPS case) that 'Event' is a lane CLAIM, not the object's
        # independent type (exactly the masking Stage-0's veto corrects via _indep_subj_type). The
        # promoted object lived inside a `with`-PP off a SEMANTICALLY-EMPTY head ("issue WITH my
        # car's GPS system") — it is the SUBJECT-MATTER the event is ABOUT, a concrete real-world
        # entity, NOT the event type the tail constraint admits. That with-PP-promotion is a REAL
        # PARSE signal (the deriver had to lift the entity out of the bland head), so the lane's
        # 'Event' self-cast is untrustworthy here. We feed a NON-EVENT independent type to the type-
        # fit so the grade MIRRORS the Stage-0 veto that fires on the same edge. A possessive chain
        # ("my car's GPS system" → component-of-owned-device) further EVIDENCES Object; without it the
        # promoted subject-matter is still a concrete non-event entity (Object). A clean reified
        # occurrence (no promotion) keeps its genuine 'Event'. NO type literal in the CONSTRAINT
        # (tail_types come from the overlay); the 'Object' here is the independent ENTITY type the
        # parse evidences, the same value Stage-0's sibling part_of/owns edge carries.
        _lane_obj_type = (candidate.get("object_type") or "").strip() or None
        if promoted_arg or _concerns:
            # with-PP-promoted subject-matter → independent concrete entity, NOT the lane's 'Event'.
            obj_type = "Object"
            _obj_type_src = ("independent_structural(possessive_part)" if part_reinforced
                             else "independent_structural(with_pp_promotion)")
        else:
            obj_type = _lane_obj_type
            _obj_type_src = "lane_asserted"
        try:
            _meta = _rel_meta(rel) or {}
            _tail = list(_meta.get("tail_types") or [])
            _head = list(_meta.get("head_types") or [])
        except Exception as _me:  # noqa: BLE001 — fail-loud per component, conservative default
            log.debug("spine_candidate_score.meta_resolve_failed", error=str(_me)[:120])
            _tail, _head = [], []
        tail_grade, tail_reason = _spine_typefit_grade(obj_type, _tail, "tail")
        head_grade, head_reason = _spine_typefit_grade(subj_type, _head, "head")
        # The worse of the two role grades governs type-fit (a crater on either role craters fit).
        if _SPINE_GRADE_ORDER.index(tail_grade) <= _SPINE_GRADE_ORDER.index(head_grade):
            typefit_grade, typefit_reason = tail_grade, tail_reason
        else:
            typefit_grade, typefit_reason = head_grade, head_reason

        # ── SIGNAL 2: CONSTRUCTION — read from the actual parse (EventAnalysis), no word list. ──
        # The discriminator is the LVC HEAD's nature, derived from the EventAnalysis the deriver
        # produced (the analyze_events / reified-event lane only fires for a genuine support-verb +
        # eventive-noun construction). NOT the emit shape (reified-handle vs flat fallback): "had
        # surgery" / "attended a webinar" may not mint a stable handle yet still be a CLEAN eventive
        # head. The WEAK tell is the bland head that had to PROMOTE its specific entity out of a
        # with-PP (concerns/promoted_arg set: "had an issue WITH …") — the head is semantically empty.
        _ev_event = None
        if ev is not None:
            try:
                _ev_event = (getattr(ev, "event", None) or "").strip() or None
            except Exception:  # noqa: BLE001
                _ev_event = None
        if promoted_arg or _concerns:
            # The specific entity had to be PROMOTED out of a bland head's with-PP — the head is
            # semantically empty ("issue"/"problem"/"trouble"). WEAK participation construction.
            construction = "weak_lvc_bland_head"
        elif _ev_event or _title or lane == "reified":
            # A genuine eventive head from the LVC/reified lane, no argument-promotion — a clean
            # occurrence ("attended a webinar", "had surgery"), titled or bare. STRONG.
            construction = "clean_eventive_head"
        else:
            # No EventAnalysis eventive head behind this candidate (a flat edge from a non-event
            # lane) — no construction evidence either way → neutral, never invented strong/weak.
            construction = "bare_eventive_head"

        # ── SIGNAL 3: CUE/PREDICATE — Stage-3 cue class; degrade gracefully + FLAG if absent. ──
        _dsn = os.environ.get("POSTGRES_DSN", "")
        _schema = rel_type_overlay.get_current_schema()
        _cue_present, _probe_ok = _spine_problem_cue_present(_dsn, _schema)
        if not _probe_ok:
            cue_verdict = "cue_probe_unavailable_degraded"  # flagged, parse-signal only
        elif not _cue_present:
            cue_verdict = "cue_class_absent_stage3_pending"  # flagged dependency, parse-signal only
        else:
            # Class exists — a bland-head construction IS the problem/state predicate evidence the
            # class would corroborate (Stage 3 wires the per-noun match). Up-weights state reading.
            cue_verdict = ("state_predicate_corroborated"
                           if construction == "weak_lvc_bland_head" else "no_state_cue")

        # SIGNAL 4 (POSSESSIVE/PART) was computed early (it gates the type-fit's independent-type
        # override above): part_reinforced is set. No recomputation here.

        # ── ASSEMBLE the GRADE (ordinal, conservative — min governs). Every input is a real signal. ──
        grades = [typefit_grade]
        if construction == "weak_lvc_bland_head":
            grades.append("weak")
        elif construction == "clean_eventive_head":
            grades.append("strong")
        else:
            grades.append("neutral")
        if part_reinforced:
            grades.append("weak")  # object-reading reinforced → down-weight participation
        # The assembled grade is the MOST CONSERVATIVE (weakest) component — a crater anywhere
        # craters the candidate (matches the Stage-0 veto), a clean event with good type-fit stays
        # strong. Deterministic, inspectable.
        grade = min(grades, key=lambda g: _SPINE_GRADE_ORDER.index(g))

        breakdown = {
            "subject": (candidate.get("subject") or "")[:32],
            "rel": rel,
            "object": obj[:48],
            "lane": lane,
            "type_fit": {"grade": typefit_grade, "reason": typefit_reason,
                         "tail": [tail_grade, tail_reason], "head": [head_grade, head_reason],
                         "object_type": obj_type, "object_type_src": _obj_type_src,
                         "lane_object_type": _lane_obj_type, "tail_types": _tail},
            "construction": construction,
            "cue": cue_verdict,
            "part_reinforced": part_reinforced,
            "grade": grade,
        }
        log.info("spine.candidate_score",
                 subject=breakdown["subject"], object=breakdown["object"], lane=lane,
                 grade=grade, type_fit=typefit_grade, type_fit_reason=typefit_reason,
                 construction=construction, cue=cue_verdict,
                 part_reinforced=part_reinforced,
                 object_type=obj_type, object_type_src=_obj_type_src,
                 tail_types=",".join(str(t) for t in _tail),
                 note="STAGE-1 NON-COMMITTING grounded score — logs WHY, commits nothing")
        return breakdown
    except Exception as _e:  # noqa: BLE001 — fail-loud, never break ingest; conservative default
        log.warning("spine.candidate_score_failed", error=str(_e)[:160])
        return None


def _detect_event_states_reified(text: str, reference) -> list[dict]:
    r"""PER-CLAUSE reified EVENT capture — the keystone-A wiring of ``_detect_event_states``.

    Closes the multi-event single-date-per-request collapse: a turn like "I attended a webinar on
    'Data Analysis' on Feb 10 and a conference last month" carries TWO occurrences, each with its
    OWN date in its OWN clause. The legacy whole-text seam minted one flat edge and the request-level
    date smeared onto it; here we DECOMPOSE the turn into clauses (the existing decompose seam — NOT
    a new splitter), run the deterministic ``analyze_event`` per clause, and parse EACH clause's OWN
    ``event_date`` (the SAME ``extract_event_date`` resolver, reference-anchored), then REIFY each
    occurrence as its own dated entity via ``_reify_occurrence_edges``.

    THE HARD LINE: each occurrence is the MEMORY filed at the bare TYPE (the place); the title NAMES
    the occurrence; the per-clause date + true granularity ride the occurrence's participated_in
    edge. Subject-agnostic, deterministic (spaCy + dateparser, NO LLM, NO word-list). Fail-safe: any
    error → ``[]`` (the caller's legacy seam still runs as the fallback). When reification yields no
    handle for an occurrence (no title, no date) the FLAT legacy shape is emitted for that clause so
    nothing is lost. Gated by OCCURRENCE_REIFY."""
    if not text or not text.strip():
        return []
    try:
        from src.extraction.linguistics import (
            analyze_events, extract_event_date_and_residue as _peel_date, linguistics_available,
        )
        if not linguistics_available():
            return []
        from src.extraction import decompose as _decompose
        clauses = _decompose.decompose(text) or [text]
    except Exception as e:  # noqa: BLE001 — fail-safe: never break ingest
        log.warning("detect_event_states_reified.setup_failed", error=str(e)[:120])
        return []

    out: list[dict] = []
    seen_handles: set[str] = set()
    for clause in clauses:
        # ── PEEL THE DATE FIRST → date-free residue (upstream of analyze_event) ──────────────────
        # THE HARD LINE: a date is an event_date SCALAR, NEVER the event. Resolve THIS clause's date
        # ONCE (reference-anchored) and DROP its span out of the clause BEFORE analyze_event runs, so
        # the eventive-noun detector can never grab "February 20th" as the occurrence (it is simply
        # GONE from the residue) and the date string can never become a participated_in object that a
        # downstream lane re-resolves (the 2026 duplicate). A clause with no date → residue == clause,
        # (None, None). The peeled date is attached to the occurrence's host edge below. Fail-safe:
        # any peel error → undated occurrence on the full clause (never fabricated, never crashes).
        c_iso, c_gran, _residue = (None, None, clause)
        if reference is not None:
            try:
                c_iso, c_gran, _residue = _peel_date(clause, reference)
            except Exception:  # noqa: BLE001 — peel miss → undated occurrence on the full clause
                c_iso, c_gran, _residue = (None, None, clause)
        # FIX #1 — DATE-ONLY SPAN → NO EVENT. When the peel resolved a date (c_iso) but the residue
        # came back UNCHANGED (== the original clause), the excision EMPTIED the clause and the peel's
        # fail-safe restored the original text (extract_event_date_and_residue: empty-residue branch).
        # That means the span was ESSENTIALLY JUST THE DATE ("on February 20th"): there is no event
        # here — the date belongs to a HOST edge elsewhere (the merge brain's get→samsung), never its
        # own occurrence. Do NOT fall back to analyze_event on the date text (that is the 2026
        # eventification bug). Skip the clause; the host edge carries the date.
        if c_iso and _residue is not None and _residue.strip() == (clause or "").strip():
            log.info("detect_event_states_reified.date_only_span_skipped",
                     date=c_iso, span=(clause or "")[:48])
            continue
        if not _residue or not _residue.strip():
            _residue = clause
        if c_iso and not c_gran:
            c_gran = "day"
        # ── Q4 ACQUISITION LANE (transfer-of-possession) — LIVE-PATH MIRROR ──────────────────────
        # The acquisition lane (user→owns→device + located_in + also_known_as, with the locative kept
        # as located_in and NOT promoted to a participated_in event) was only wired into the legacy
        # fast-path _detect_event_states; under OCCURRENCE_REIFY (default ON) THIS reified function is
        # the live harvest path, so without this mirror "I got a Samsung Galaxy S22 … at the mall on
        # Feb 20" still minted (user, participated_in, mall)/(…, buy store) instead of the inferred
        # ownership. Run the SAME shared lane PER-CLAUSE on the date-free residue (so the device NP,
        # not the date, is read) with THIS clause's peeled iso/gran. A non-None return = the clause was
        # an acquisition: emit its edges and SKIP the occurrence/reify lanes for THIS clause only (a
        # sibling occurrence clause in the same turn still reaches its lanes). None → not an acquisition
        # → proceed to the occurrence lanes unchanged. Subject-agnostic, deterministic, fail-safe.
        _acq_edges = _acquisition_lane_edges(_residue, c_iso, c_gran)
        if _acq_edges is not None:
            for _ae in _acq_edges:
                # Dedup the inferred owns handle across clauses (the device is the owns OBJECT) so a
                # turn restating the same acquisition does not double-emit. Other acquisition edges
                # (alias/located_in) are device-keyed and naturally single per device.
                if (_ae.get("rel_type") or "").strip().lower() == "owns":
                    _oh = (_ae.get("object") or "").strip().lower()
                    if _oh and _oh in seen_handles:
                        continue
                    if _oh:
                        seen_handles.add(_oh)
                out.append(_ae)
            log.info("detect_event_states_reified.acquisition", clause=(_residue or "")[:48],
                     date=c_iso, edges=len(_acq_edges))
            continue
        # MULTIPLE OCCURRENCES PER CLAUSE (Q2 PRIMARY): a clause can carry several eventive heads
        # ("…attending various workshops, like the workshop on 'Effective Time Management'" →
        # generic head + appositive titled occurrence; "a workshop on 'X', and a webinar on 'Y'" →
        # two titled occurrences). analyze_events enumerates EVERY eventive head; the old single-head
        # analyze_event dropped all but the first. Each occurrence carries the clause's peeled date.
        try:
            _evs = analyze_events(_residue)
            # INCHOATIVE FALLBACK (q7 gap): "started <item> on DATE" — the event meaning is on the
            # ingressive VERB, not an eventive noun, so the LVC lane misses it. Recognize the
            # ingressive-verb + concrete-direct-object shape per clause so the dated start reifies as
            # its own occurrence on the item. Only when the LVC lane produced nothing (no double-cap).
            if not _evs:
                from src.extraction.linguistics import analyze_inchoative as _analyze_inchoative
                _inch = _analyze_inchoative(_residue)
                _evs = [_inch] if _inch is not None else []
        except Exception:  # noqa: BLE001 — per-clause fail-safe
            _evs = []
        for ev in _evs:
            if ev is None or ev.negated:
                continue
            event = (ev.event or "").strip().lower()
            if not event or len(event) < 3:
                continue
            title = (ev.title or "").strip() or None
            if title and title.lower() == event:
                title = None
            # SUBJECT-MATTER (the with-PP specific entity) rides hinge (4) on the reified occurrence so
            # recall surfaces "gps system" off the bland "issue". Threaded alongside title; fail-safe
            # absent → unchanged. Not applied to the conjoined-list expansion (a coordinated UNTITLED
            # list is several bare occurrences; a per-occurrence with-PP does not co-occur there).
            concerns = (ev.concerns or "").strip() or None
            # Q8 CROP ANCHORS (reified lane — the live OCCURRENCE_REIFY path): a "started <crop> seeds" /
            # "starting seeds … tomatoes, peppers" start is intrinsically PER-CROP — emit one reified
            # dated occurrence per specific crop (+ its plural alias) so a comparison operand
            # ("tomatoes"/"marigolds") reaches the start, not just the generic head ("seeds"). HARD LINE:
            # crop = type/entity (occurrence object); date = scalar on the edge.
            _crop_anchors = getattr(ev, "anchors", ()) or ()
            if OCCURRENCE_REIFY and not title and _crop_anchors:
                _added_crop = False
                for _canon, _plural in _crop_anchors:
                    if not _canon or _canon == event:
                        continue
                    _rf = _reify_occurrence_edges(_canon, None, c_iso, c_gran)
                    if not _rf:
                        # NO STABLE OCCURRENCE IDENTITY for this crop (a single-token bare crop —
                        # "tomato", "marigold" — has no per-occurrence discriminator, so
                        # _occurrence_handle returns None, dated or not). The reified lane would
                        # otherwise DROP the crop entirely — the crop never becomes a typed entity,
                        # so the ±6 buildout has nothing to climb (tomato → … → plant never grows)
                        # and the crop is unreachable from its own operand. FALL BACK to the FLAT
                        # crop shape the legacy lane (_detect_event_states) already uses: emit
                        # (user, participated_in, <crop>) carrying THIS clause's date as the scalar.
                        # The crop is now a real relational OBJECT → the existing ingest grounding
                        # (_queue_concept_for_grounding / _attach_to_seeded_backbone) types it and
                        # the async climb deepens its is-a chain, exactly as for dog/hammer. HARD
                        # LINE: crop = type/entity (the object); date = event_date scalar on the edge.
                        if _canon in seen_handles:
                            continue
                        seen_handles.add(_canon)
                        _flat_crop = {"subject": "user", "rel_type": "participated_in",
                                      "object": _canon, "fact_provenance": "user_stated"}
                        if c_iso:
                            _flat_crop["event_date"] = c_iso
                            _flat_crop["event_date_granularity"] = c_gran or "day"
                        out.append(_flat_crop)
                        if _plural and _plural != _canon:
                            out.append({"subject": _canon, "rel_type": "also_known_as",
                                        "object": _plural, "fact_provenance": "user_stated"})
                        _added_crop = True
                        continue
                    _h = (_rf[0].get("object") or "").strip().lower()
                    if _h and _h in seen_handles:
                        continue
                    if _h:
                        seen_handles.add(_h)
                    out.extend(_rf)
                    if _plural and _plural != _canon:
                        out.append({"subject": _canon, "rel_type": "also_known_as", "object": _plural,
                                    "fact_provenance": "user_stated"})
                    _added_crop = True
                if _added_crop:
                    log.info("detect_event_states_reified.crop_anchored",
                             crops=len(_crop_anchors), date=c_iso, gran=c_gran)
                    continue
            # CONJOINED-LIST EXPANSION (Part B item 2): a coordinated event object ("I had a meeting,
            # a call, and a review on Jan 3") surfaces EACH conjunct as its own dated occurrence. Only
            # for an UNTITLED list (a titled occurrence is a single named thing). Deterministic conj walk.
            if OCCURRENCE_REIFY and not title:
                _conj = []
                try:
                    from src.extraction.linguistics import list_conjuncts as _list_conjuncts_ev
                    # Walk the conjuncts on the DATE-FREE residue (same string analyze_events saw) so a
                    # peeled date span can never surface as a conjoined "event".
                    _conj = _list_conjuncts_ev(_residue, event)
                except Exception:
                    _conj = []
                if len(_conj) >= 2:
                    _added_any = False
                    for _cj in _conj:
                        _rf = _reify_occurrence_edges(_cj, None, c_iso, c_gran)
                        if not _rf:
                            continue
                        _h = (_rf[0].get("object") or "").strip().lower()
                        if _h and _h in seen_handles:
                            continue
                        if _h:
                            seen_handles.add(_h)
                        out.extend(_rf)
                        _added_any = True
                    if _added_any:
                        log.info("detect_event_states_reified.conjoined",
                                 items=len(_conj), date=c_iso, gran=c_gran)
                        continue
            reified = (_reify_occurrence_edges(event, title, c_iso, c_gran, concerns=concerns)
                       if OCCURRENCE_REIFY else None)
            if reified:
                # Dedup occurrences by their handle (the participated_in object) across occurrences.
                _handle = (reified[0].get("object") or "").strip().lower()
                if _handle and _handle in seen_handles:
                    continue
                if _handle:
                    seen_handles.add(_handle)
                log.info("detect_event_states_reified.occurrence",
                         event_type=event[:24], title=(title or "")[:32], date=c_iso, gran=c_gran)
                # STAGE 1 (NON-COMMITTING): score the participation edge of this reified clean
                # occurrence ("attended a webinar", "had surgery") → logs a HIGH grade. The
                # participation edge is the participated_in hinge in the reified set (hinge 1).
                _part_edge = next(
                    (e for e in reified
                     if (e.get("rel_type") or "").strip().lower() == "participated_in"), None)
                if _part_edge is not None:
                    # The reified participation object is the occurrence HANDLE (a surrogate, not a
                    # GLiNER2-typed surface). The TYPE-FIT signal must read the occurrence's BARE
                    # TYPE (the instance_of object — the event place), which IS the Event/Concept the
                    # tail constraint admits. Pass object_type='Event' from the reified self-type so
                    # the type-fit reflects the occurrence's real nature (mirrors the lane's own cast).
                    _scored = dict(_part_edge)
                    _scored.setdefault("object_type", "Event")
                    _scored.setdefault("subject_type", "Person")
                    _spine_candidate_score(_scored, ev, promoted_arg=False, lane="reified")
                out.extend(reified)
            else:
                # No stable per-occurrence identity (a single bare common type → _occurrence_handle
                # returns None) → keep the flat legacy shape for this clause so the bare occurrence is
                # still captured. BUT a DATE was already peeled for THIS clause (c_iso) — host it on the
                # flat participated_in edge so an untitled-but-DATED occurrence ("started seeds since
                # February 20th" → the bare type "seeds") does not silently drop its date (the q7 gap:
                # the inchoative item is often a single bare noun). Dateless clause → unchanged (today's
                # behavior). THE HARD LINE: the date is a SCALAR on the participation edge, never the
                # occurrence object.
                #
                # FIX B — ARGUMENT PROMOTION over a bland result-noun head. A bland head that carries an
                # OBLIGATORY internal argument (a ``with``-PP / complement, surfaced as ``concerns`` —
                # "an issue WITH my car's GPS system" → concerns="gps system") is ABOUT its argument:
                # the meaning lives in the argument, not the empty head ("issue"/"problem"). Promote the
                # ARGUMENT ENTITY to be the participated_in OBJECT (the walkable anchor) and DEMOTE the
                # bland head from being a standalone participated_in object — so the deterministic walk
                # surfaces "gps system", not "issue". The discriminator is ARGUMENT STRUCTURE (the
                # PRESENCE of a ``concerns`` argument on an UNTITLED head), NEVER a noun/word-list: a
                # genuine titled/named occurrence (webinar/workshop/seeds) reifies above and never
                # reaches here, and a bland head with NO argument (no ``concerns``) keeps the flat
                # head shape unchanged. Subject-agnostic + deterministic. Fail-safe: no concerns →
                # the original flat-head edge (today's behavior).
                _c = (concerns or "").strip()
                _promote_arg = bool(
                    _c and _c.lower() != event and _c.lower() != (title or "").lower()
                )
                _flat_object = _c if _promote_arg else event
                _flat = {"subject": "user", "rel_type": "participated_in", "object": _flat_object,
                         "subject_type": "Person", "object_type": "Event",
                         "fact_provenance": "user_stated"}
                if c_iso:
                    _flat["event_date"] = c_iso
                    _flat["event_date_granularity"] = c_gran or "day"
                out.append(_flat)
                # STAGE 1 (NON-COMMITTING): score this flat participation candidate. The GPS case
                # lands HERE (argument-promoted bland head) → logs a LOW grade. Pure log, no commit.
                _flat_bd = _spine_candidate_score(_flat, ev, promoted_arg=_promote_arg, lane="flat")
                if _promote_arg:
                    log.info("detect_event_states_reified.flat_argument_promoted",
                             bland_head=event[:32], promoted=_c[:48], date=c_iso)
                # STAGE 3 — the COMPETING STATE candidate (the payoff). When the bland head is a
                # PROBLEM noun (DB-grown ``problem_noun`` cue class, set on EventAnalysis.problem_head)
                # AND a with-PP affected entity was promoted (``_promote_arg``: "I had an issue WITH my
                # car's GPS system"), the affected entity's PROBLEM is a typed reusable STATE — the
                # structural twin of ``feels``. Emit ``(<affected>, has_state, <problem-state>)``
                # ALONGSIDE the participated_in candidate (do NOT swap — let Stage-2 arbitration decide).
                # The state object is the bland head TYPE ("issue"/"problem") — a Concept the has_state
                # tail admits. We carry the Stage-1 GRADES so arbitration sees STRONG has_state vs the
                # CRATER participated_in (the GPS-as-Event tail-type veto) and picks has_state. The
                # affected entity keeps its part_of/owns grounding from the other chains (untouched here).
                # THE DISCRIMINATOR: problem_head (cue class ∧ with-PP) — a non-problem "have + with-PP"
                # ("had a meeting with Sarah") never sets problem_head, so this lane never fires there.
                # CARVE-OUT GROWTH: problem_noun is grown per-tenant. When the head is NOT (yet) a grown
                # problem head but the analysis flagged it as a candidate (a "had a <bland-head> with
                # <NON-person thing>" construction — person-gated in _build_event_analysis), queue the
                # head for freq-gated growth so a future cycle promotes it into the problem_noun class
                # (then problem_head fires and the has_state competitor lands). Best-effort; the affected
                # entity is already captured here (participated_in/Class-C) + walkable via its other
                # chains, so this is purely additive growth, never a drop.
                _pc = getattr(ev, "problem_candidate", None)
                if _pc and not getattr(ev, "problem_head", False):
                    try:
                        linguistic_cue_overlay.record_cue_candidate(_pc, "problem_noun")
                    except Exception:  # noqa: BLE001 — fail-safe: growth signal never breaks ingest
                        pass
                # FIRE the competing has_state candidate ONLY when the LVC device-issue gate holds in
                # FULL (tight — an LVC is broad; most LVCs are NOT device-issues, so every clause below
                # must hold or we FALL THROUGH to the normal reading, never forcing a has_state):
                #   (1) DOBJ ∈ problem-noun cue class  — ``problem_head`` (the eventive head is a
                #       SEMANTICALLY-EMPTY problem noun: issue/bug/glitch/…; grown per-tenant + the
                #       cold-tenant floor). Excludes "had a MEETING/LUNCH/CONVERSATION with X".
                #   (2) PP-COMPLEMENT pobj is a TYPED THING — ``problem_affected_thing`` (GLiNER2/NER
                #       typed it NON-social: Object/Concept/…, never Person/Org). Excludes "had a problem
                #       with my COWORKER Sam" (interpersonal) and a forced bind on an ABSTRACT/untyped
                #       pobj ("a problem with the traffic/the math" → untyped → no fire).
                #   (3) the ``with`` adposition (a closed grammatical primitive; ``_with_pp_subject_matter``
                #       already rejects a date/temporal pobj) — the affected-entity preposition, not a
                #       temporal/other PP.
                #   (4) light-verb head ∈ lvc_support cue + first-person/possessive grounding — already
                #       established upstream by this LVC ``analyze_event`` path that produced ``ev``.
                # LVC classification basis: light-verb head + problem-noun dobj + typeable-thing
                # PP-complement (dependency-tree LVC identification + noun-complement relation; cf. AAAI
                # "English LVC Identification Using Lexical Knowledge"). Fail-safe: any gate miss → the
                # flat participated_in reading stands (today's behavior); arbitration keeps BOTH on a tie.
                _problem_fire = (
                    getattr(ev, "problem_head", False)
                    and getattr(ev, "problem_affected_thing", False)
                )
                if _promote_arg and _problem_fire:
                    _state_obj = event  # the bland head TYPE ("issue"/"problem") = the reusable state
                    _state = {"subject": _flat_object, "rel_type": "has_state", "object": _state_obj,
                              "subject_type": "Object", "object_type": "Concept",
                              "fact_provenance": "user_stated",
                              # Stage-2 arbitration reads the attached grade verbatim (the STATE reading
                              # is the strong, type-fit-clean candidate — Object→has_state→Concept).
                              "_spine_grade": "strong", "_lane": "state"}
                    if c_iso:
                        _state["event_date"] = c_iso
                        _state["event_date_granularity"] = c_gran or "day"
                    out.append(_state)
                    # Tag the competing participated_in candidate with its Stage-1 grade (the crater
                    # the type-fit veto produces) so the arbitration grader reads it without recompute.
                    if isinstance(_flat_bd, dict):
                        _flat["_spine_grade"] = (_flat_bd.get("grade") or "crater")
                    else:
                        _flat["_spine_grade"] = "crater"
                    _flat["_promoted_arg"] = True
                    _flat["_lane"] = "flat"
                    log.info("detect_event_states_reified.has_state_competitor",
                             affected=_flat_object[:48], state=_state_obj[:32],
                             participated_grade=_flat.get("_spine_grade"), date=c_iso)
    # STAGE 2 — arbitrate the competing readings WITHIN this reified edge set (the participated_in vs
    # has_state pair for the same affected-entity span both live HERE, before the caller merges them
    # into edges_dict). The committed _arbitrate_spine_candidates picks the strong has_state over the
    # cratered participated_in (decisive gap) and DROPS the loser; a tie / close grade / ungroundable
    # candidate keeps BOTH (fail-safe, "we don't forget"). The internal _spine_* hint keys are stripped
    # below before the edges leave this function so they never reach the gate/commit.
    out = _arbitrate_spine_candidates(out, is_edgeinput=False)
    for _e in out:
        if isinstance(_e, dict):
            _e.pop("_spine_grade", None)
            _e.pop("_promoted_arg", None)
            _e.pop("_lane", None)
    return out


def _reified_event_manifest(reified_edges: list[dict]) -> dict:
    r"""Derive the SUPPRESSION MANIFEST for a set of reified occurrence edges (keystone A).

    When ``_detect_event_states_reified`` mints occurrences, the SAME event is ALSO seen by the
    competing flat lanes (the LLM/GLiNER2 relation extractor and the verb-lift), which emit:
      • flat verb edges  — (user, attended, webinar) / (user, go_to, conference)
      • a title-as-object — (user, participated_in, "data analysis using python")
      • the TITLE classified into L4 — ("data analysis using python") instance_of/subclass_of …

    All three are DUPLICATES (or, for the title-classify, a HARD-LINE VIOLATION: the title is a NAME
    on the occurrence, never an L4 place). This helper reads the reified edge set and returns the
    spans the flat lanes must NOT re-capture, so ``_suppress_flat_event_duplicates`` can purge them:

      • ``handles``     : the per-occurrence surrogate objects (the canonical event nodes) — kept.
      • ``titles``      : the also_known_as title spans (lowercased) — a NAME, NEVER an entity/place.
      • ``event_types`` : the bare event-type nodes (the instance_of objects, lowercased) — the L4
                          PLACE; the reified occurrence already files itself there, so a flat
                          (user, <verb/participated_in>, <type>) is a duplicate.
      • ``event_dates`` : the per-occurrence ``event_date`` values riding the reified participated_in
                          hinges (D1 spine-noise primary). The reified occurrence is the canonical
                          capture for that DATED clause, so any OTHER flat (user, participated_in,
                          <bare-noun>) sharing that exact date — discourse markers ("way"), day-words
                          ("sunday"), generic nouns ("issues"), session-date leakage — is the spine's
                          competing noise and is purged by date key (NOT by a noun list). A genuinely
                          distinct second event has a DIFFERENT date → not in this set → kept.

    Deterministic, no LLM, derived purely from the reified edges already built. Fail-safe → empty."""
    handles: set[str] = set()
    titles: set[str] = set()
    event_types: set[str] = set()
    event_dates: set[str] = set()
    # state_heads — the SEMANTICALLY-EMPTY problem-head OBJECTS the device-issue has_state lane bound
    # ("(gps system, has_state, ISSUE)"): the bland head is now a STATE of the affected thing, so its
    # DIVORCED mis-captures from the competing flat lanes — (user, owns, issue), (system, has_pet,
    # issue), (issue, subclass_of/instance_of, …) — are junk to purge (the affected thing keeps the
    # real binding). Collected here; the suppressor drops the divorced edges (never the has_state edge,
    # which lives in the reified set, not in edges_dict at suppression time).
    state_heads: set[str] = set()
    try:
        for _e in (reified_edges or []):
            _rel = (_e.get("rel_type") or "").strip().lower()
            _subj = (_e.get("subject") or "").strip().lower()
            _obj = (_e.get("object") or "").strip().lower()
            if _rel == "has_state":
                if _obj:
                    state_heads.add(_obj)
            if _rel == "instance_of":
                # (<occurrence-handle>) instance_of (<bare-type>): the handle is the canonical node,
                # the object is the bare L4 PLACE the flat lanes must not re-pile onto.
                if _subj:
                    handles.add(_subj)
                if _obj:
                    event_types.add(_obj)
            elif _rel == "also_known_as":
                # (<occurrence-handle>) also_known_as (<title>): the title is the NAME — it must
                # exist ONLY here, never as its own entity/subject/object in any other lane.
                if _subj:
                    handles.add(_subj)
                if _obj:
                    titles.add(_obj)
            elif _rel == "participated_in":
                if _obj:
                    handles.add(_obj)
                # D1: the canonical occurrence's OWN date (hinge 1 hosts event_date). Collect it so
                # the suppressor can drop any FLAT participated_in sharing this exact date — that is
                # the spine's competing dated noise for the SAME clause. Date-keyed, no noun list.
                _ed = (_e.get("event_date") or "").strip()
                if _ed:
                    event_dates.add(_ed)
    except Exception:  # noqa: BLE001 — fail-safe: no manifest → no suppression (legacy behavior)
        return {"handles": set(), "titles": set(), "event_types": set(), "event_dates": set(),
                "state_heads": set()}
    return {"handles": handles, "titles": titles, "event_types": event_types,
            "event_dates": event_dates, "state_heads": state_heads}


def _spine_bound_surfaces(edges, is_edgeinput: bool = False) -> set[str]:
    r"""The set of entity SURFACES the deterministic spine already bound with a CONTENTFUL relation.

    BRAIN-NOT-TRANSPORT / STRONG-DETERMINISTIC-INGEST: when the spine (the edges already in
    ``edges_dict`` from ``req.edges`` / the deterministic harvest) has bound an entity surface as a
    real participant of a contentful fact — ``(alvin, child_of, user)``, ``(sam, friend_of, user)``,
    ``(robin, age, 10)`` — that surface IS authoritative. A COMPETING parallel/inferred cast that
    re-files the SAME surface as something else (the reified-event seam casting "a son Alvin 19" as a
    ``participated_in`` occurrence whose NAME is "alvin") must NOT win. This returns the surfaces the
    spine owns so the reified-event lane can drop any occurrence that re-claims one of them.

    "Contentful" = any relation EXCEPT the reified event-occurrence relation itself. The occurrence
    rel is the ONE the competing lane mints; every other rel (kinship, friendship, scalar, typing,
    ownership, …) is a genuine binding that claims the surface. This is the SAME "a span the spine
    already bound is authoritative" structural pattern the suppressor uses for bare nouns — keyed on
    the structural fact that the spine bound the surface, NOT on any entity/domain/construction list.

    Subject-agnostic, deterministic (no LLM/cosine, no entity/rel allowlist — the only rel named is
    the canonical occurrence rel ``participated_in``, which is exactly the offending parallel cast and
    is metadata-justified as the occurrence backbone). Fail-safe: any error → empty set (no
    suppression → today's behavior)."""
    surfaces: set[str] = set()
    try:
        for e in (edges or []):
            _r = (getattr(e, "rel_type", None) if is_edgeinput else e.get("rel_type"))
            _r = (_r or "").strip().lower()
            # The occurrence rel is the parallel cast itself — a surface bound ONLY by it is NOT a
            # contentful spine binding (it would self-exempt the very cast we want to suppress).
            if _r == "participated_in":
                continue
            _s = (getattr(e, "subject", None) if is_edgeinput else e.get("subject"))
            _o = (getattr(e, "object", None) if is_edgeinput else e.get("object"))
            for _surf in (_s, _o):
                _surf = (_surf or "").strip().lower()
                # "user" is the universal speaking subject, not a captured entity surface — never let
                # it gate a real occurrence (e.g. (user, participated_in, <handle>)).
                if _surf and _surf != "user":
                    surfaces.add(_surf)
    except Exception:  # noqa: BLE001 — fail-safe: no surface set → no suppression (legacy behavior)
        return set()
    return surfaces


def _drop_reified_occurrences_for_bound_surfaces(reified_edges, bound_surfaces: set[str]):
    r"""Drop the reified-occurrence edges whose NAME/title/object surface the spine already bound
    with a contentful rel (``_spine_bound_surfaces``). STRONG-DETERMINISTIC-INGEST: the spine is
    authoritative, so a competing reified cast of the SAME surface is a mis-cast and is removed
    WHOLE — the ``participated_in`` hinge, the ``instance_of`` filing, and the ``also_known_as``
    naming for that occurrence — so its title never reaches the manifest and never purges the
    spine's correct ``child_of``/``friend_of``/scalar edges for that entity.

    The reified-event set groups edges by a per-occurrence ``occurrence: …`` handle. We first find
    the COLLIDING handles: a handle whose ``also_known_as`` title surface, OR whose ``participated_in``
    object surface (when the seam emitted the flat ``(user, participated_in, <name>)`` shape), is in
    ``bound_surfaces``. Then drop every edge belonging to a colliding handle. A legitimate event the
    spine did NOT bind (e.g. "I attended the Python webinar on May 3" — the spine never bound
    "webinar"/the webinar occurrence) has NO colliding handle → its occurrence is fully preserved.

    Deterministic, subject-agnostic, no LLM/cosine, no entity/rel allowlist. Fail-safe: any error →
    the input edges unchanged (never lose the legitimate event capture)."""
    if not reified_edges or not bound_surfaces:
        return reified_edges
    try:
        # Pass 1 — identify the handles whose occurrence re-claims a spine-bound surface.
        _colliding_handles: set[str] = set()
        _flat_collision = False  # a flat (user, participated_in, <bound-name>) with no handle
        for _e in reified_edges:
            _rel = (_e.get("rel_type") or "").strip().lower()
            _subj = (_e.get("subject") or "").strip().lower()
            _obj = (_e.get("object") or "").strip().lower()
            if _rel == "also_known_as" and _obj in bound_surfaces and _subj:
                # (<handle>) also_known_as (<bound-name>): the occurrence is NAMED for a spine entity.
                _colliding_handles.add(_subj)
            elif _rel == "participated_in" and _obj in bound_surfaces:
                # FLAT shape (user, participated_in, <bound-name>) — the object IS the spine entity
                # surface (no reified handle). Mark it for a direct drop.
                _flat_collision = True
        if not _colliding_handles and not _flat_collision:
            return reified_edges
        # Pass 2 — drop every edge belonging to a colliding occurrence.
        _kept = []
        for _e in reified_edges:
            _rel = (_e.get("rel_type") or "").strip().lower()
            _subj = (_e.get("subject") or "").strip().lower()
            _obj = (_e.get("object") or "").strip().lower()
            # The handle is the occurrence node: it is the SUBJECT of instance_of/also_known_as and
            # the OBJECT of the participated_in hinge. Drop the edge if EITHER endpoint is a colliding
            # handle, or it is the flat (user, participated_in, <bound-name>) cast itself.
            if _subj in _colliding_handles or _obj in _colliding_handles:
                log.info("ingest.reified_occurrence_dropped_spine_bound",
                         reason="spine_bound_surface", rel=_rel, subject=_subj[:48], object=_obj[:48])
                continue
            if _rel == "participated_in" and _obj in bound_surfaces:
                log.info("ingest.reified_occurrence_dropped_spine_bound",
                         reason="flat_bound_object", rel=_rel, subject=_subj[:48], object=_obj[:48])
                continue
            _kept.append(_e)
        return _kept
    except Exception:  # noqa: BLE001 — fail-safe: any error → unchanged (never drop legit events)
        return reified_edges


def _suppress_flat_event_duplicates(edges, manifest: dict, is_edgeinput: bool = False):
    r"""Drop the FLAT-lane duplicates of a reified event so the occurrence is the ONE canonical
    capture (keystone A — brain-not-transport: one event, one capture, not three competing).

    Given the reified manifest (``_reified_event_manifest``), purge from ``edges`` any edge that the
    reified occurrence already represents canonically:

      1. HARD-LINE VIOLATION (BUG 2) — the TITLE leaked into L4 as an entity. ANY edge whose subject
         OR object is a reified title span is dropped UNLESS it is the legitimate
         (<occurrence-handle>) also_known_as (<title>) hinge. This kills
         ("data analysis using python") instance_of webinar and ... subclass_of data_analysis, and
         (user, participated_in, "data analysis using python") (title-as-object leak).

      2. FLAT EVENT DUPLICATE (BUG 1) — a flat verb/participation edge whose object is a bare
         reified event TYPE and whose subject is NOT a reified occurrence handle: (user, attended,
         webinar), (user, go_to, conference), (user, participated_in, conference). The reified
         occurrence (user, participated_in, <handle>) already captures the participation; these are
         duplicates that pile onto the shared type node. The reified edges themselves are PRESERVED
         (their subject/object is a handle, exempt from this clause).

    Fail-safe: empty manifest → returns ``edges`` unchanged (reification didn't fire → legacy flat
    lane stays, today's behavior). Deterministic, GLiNER2-pure (operates on already-built edges).

    ``is_edgeinput`` selects attribute access (EdgeInput at /ingest) vs dict access (harvest lane)."""
    titles = manifest.get("titles") or set()
    event_types = manifest.get("event_types") or set()
    handles = manifest.get("handles") or set()
    event_dates = manifest.get("event_dates") or set()
    state_heads = manifest.get("state_heads") or set()
    if not titles and not event_types and not event_dates and not state_heads:
        return edges
    # STEP-4 gate signal: the spine minted ≥1 reified occurrence handle for this turn (an
    # instance_of/also_known_as/participated_in reified edge populates ``handles``). When True, the
    # spine is the authoritative participation capture and clause (3) below supersedes competing
    # flat participation edges. Fail-safe: no handle → False → clause (3) is a no-op.
    spine_reified = bool(handles)

    def _is_occurrence_handle(s: str) -> bool:
        # A reified occurrence handle is STRUCTURALLY identified by the canonical "occurrence:" prefix
        # (_occurrence_handle always mints "occurrence: <sorted tokens>"). The per-turn ``handles`` set
        # only carries handles the /ingest reified RUN produced; a reified occurrence minted UPSTREAM
        # (the harvest dash-specifier inchoative-crop lane → (user, participated_in, occurrence: seed
        # tomato)) is a genuine occurrence the suppressor must NEVER mistake for a flat dup. Keying on
        # the prefix exempts EVERY reified occurrence, not just the ones this manifest happened to see.
        return (s or "").strip().lower().startswith("occurrence:")

    def _field(e, name: str) -> str:
        v = getattr(e, name, None) if is_edgeinput else e.get(name)
        return (v or "").strip().lower()

    def _raw_field(e, name: str) -> str:
        # Case-preserving accessor (event_date is an ISO string — never lowercase/canonicalize it).
        v = getattr(e, name, None) if is_edgeinput else e.get(name)
        return (v or "").strip()

    # BUG 2 FIX: a flat lane (the LLM /extract/rewrite extractor, canonicalized e.g. attended→
    # participated_in) emits the bare TITLE as a participated_in OBJECT, but its surface form
    # varies from the manifest title (analyze_event quote-strips the title; the LLM often copies
    # the SURROUNDING quotes / a trailing period). An exact set-membership test then misses the
    # leak and the stray (user, participated_in, "data analysis using python") survives. Normalize
    # BOTH sides by stripping surrounding quote/punctuation so the title-leak match is surface-form
    # robust. Deterministic, subject-agnostic, no word-list (quote/punct is a language primitive).
    import re as _re_sup
    _SURROUND = r'^[\s"“”‘’\'.,:;!?()\[\]-]+|[\s"“”‘’\'.,:;!?()\[\]-]+$'

    # DATE-SUFFIX STRIP (T1 class): the reified manifest title is bare ("turbocharged tuesdays")
    # because the deterministic seam PEELED the clause date out upstream of analyze_event. The LLM
    # flat lane, by contrast, has NO date peel on /extract/rewrite, so it bakes the trailing
    # temporal adjunct into the object surface — (user, participated_in, "turbocharged tuesdays on
    # 2023-06-14"). An exact/punct-only normalize then misses the manifest title and the dated dupe
    # SURVIVES even when the spine fired perfectly. We peel the SAME date span off the flat surface
    # with the EXISTING deterministic detector (extract_event_date_and_residue — spaCy DATE NER ∪
    # numeric regex → dateparser → drops the winning span AND its dangling leading temporal prep),
    # NOT a new date regex and NOT a literal date/word list. A non-date surface peels to itself
    # (the detector returns the original text on a miss → fail-safe, no false strip). The harness
    # session reference anchors relatives identically to the reify side; on any failure we fall back
    # to the punct-only normalize so the suppressor never crashes / never over-strips.
    _peel_for_norm = None
    try:
        from src.extraction.linguistics import extract_event_date_and_residue as _peel_for_norm  # noqa: E501
    except Exception:  # noqa: BLE001 — fail-safe: no peeler → punct-only normalize (today's behavior)
        _peel_for_norm = None
    _norm_reference = None
    if _peel_for_norm is not None:
        try:
            _norm_reference, _ = _compute_ingest_reference_and_text("")
        except Exception:  # noqa: BLE001 — reference resolve failed → wall-clock-free, peeler no-ops
            _norm_reference = None

    def _strip_date_suffix(s: str) -> str:
        """Drop a trailing normalized DATE span (and its dangling temporal prep) from a flat-lane
        surface so it matches the bare manifest title. Reuses the existing deterministic date
        peeler — NO new regex, NO word list. Fail-safe: peeler unavailable / no date / error →
        the input unchanged."""
        if not s or _peel_for_norm is None or _norm_reference is None:
            return s or ""
        try:
            _iso, _gran, _residue = _peel_for_norm(s, _norm_reference)
            # Only accept the peel when a date actually resolved (_iso) AND the residue shrank —
            # a non-date surface returns the original text (residue == s) → no strip.
            if _iso and _residue and _residue.strip() and len(_residue.strip()) < len(s.strip()):
                return _residue.strip()
        except Exception:  # noqa: BLE001 — fail-safe: any peel error → unchanged surface
            return s
        return s

    def _norm_title(s: str) -> str:
        # Order: peel a trailing date FIRST (so "tuesdays on 2023-06-14" → "tuesdays"), then strip
        # surrounding quotes/punctuation (so '"data analysis"' → "data analysis"). Both sides of
        # the match run through this, so the manifest's bare title and the date-suffixed flat
        # surface converge to the same normalized form.
        return _re_sup.sub(_SURROUND, "", _strip_date_suffix(s or ""))

    titles_norm = {_norm_title(t) for t in titles if _norm_title(t)}

    kept = []
    for e in edges:
        _s = _field(e, "subject")
        _o = _field(e, "object")
        _r = _field(e, "rel_type")
        _sn = _norm_title(_s)
        _on = _norm_title(_o)
        _s_is_title = _s in titles or _sn in titles_norm
        _o_is_title = _o in titles or _on in titles_norm
        # (1) TITLE never lives outside the also_known_as hinge on the occurrence handle.
        _is_legit_title_hinge = (
            _r == "also_known_as" and _s in handles and _o_is_title
        )
        if (_s_is_title or _o_is_title) and not _is_legit_title_hinge:
            log.info("ingest.flat_event_dup_suppressed",
                     reason="title_leak", subject=_s[:32], rel=_r, object=_o[:32])
            continue
        # (2) flat event-type duplicate: a non-handle subject pointing at a bare reified type.
        if _o in event_types and _s not in handles:
            log.info("ingest.flat_event_dup_suppressed",
                     reason="flat_event_type", subject=_s[:32], rel=_r, object=_o[:32])
            continue
        # (3) STEP-4 DURABILITY GATE — the spine reified an occurrence FOR THIS TURN, so it is the
        # ONE authoritative participation capture. Drop any COMPETING flat participation edge the LLM
        # lane emitted whose surface DISAGREES with the spine's (T1 class: the spine reified
        # "racking event", the LLM emitted a garbled "turbocharged tuesdays on 2023-06-14" — same
        # event, two captures). The gate is keyed PURELY on the occurrence relation + handle-ness,
        # NOT on any domain/word list:
        #   • the spine produced ≥1 reified occurrence handle (``spine_reified`` — proof it fired),
        #   • this edge IS the occurrence rel (participated_in),
        #   • its subject is NOT a reified handle (a real reified edge's subject IS a handle → kept),
        #   • its object is NOT a reified handle (the canonical (user, participated_in, <handle>)
        #     edges the spine itself emitted are exempt — their object IS a handle).
        # BLAST RADIUS: this clause ONLY ever drops the OCCURRENCE rel (participated_in). A non-event
        # LLM edge (has_pet, spouse, works_for, a scalar, …) has a different rel_type and is NEVER
        # touched — so non-event extraction is unaffected. Fail-safe: no reified handle → no-op.
        if (spine_reified and _r == "participated_in"
                and _s not in handles and not _is_occurrence_handle(_s)
                and _o not in handles and not _is_occurrence_handle(_o)):
            log.info("ingest.flat_event_dup_suppressed",
                     reason="flat_participation_superseded", subject=_s[:32], rel=_r, object=_o[:32])
            continue
        # (4) DATE-KEYED EVENT-NOISE SUPPRESSION (D1 spine-primary) — the spine reified the canonical
        # dated occurrence for a clause (its date is in ``event_dates``), but ALSO emitted competing
        # FLAT (user, participated_in, <bare-noun>) edges for the SAME clause: discourse markers
        # ("way"), day-words ("sunday"), generic nouns ("issues"), session-date-leaked dates. Each
        # such flat edge carries the SAME ``event_date`` as the reified occurrence (they describe the
        # same dated clause). The reified occurrence is THE canonical capture for that date, so any
        # OTHER flat participated_in edge sharing that exact date is noise → drop it. The match is
        # PURELY the date key (structural), NOT a noun list — subject-agnostic. Guards keep it tight:
        #   • this edge IS the occurrence rel (participated_in) — a non-event rel is never touched,
        #   • its object is NOT a reified handle (the spine's OWN canonical (user, participated_in,
        #     <handle>) edges are exempt — their object IS a handle),
        #   • its event_date EQUALS a reified occurrence's date (only same-date noise is purged).
        # A genuinely distinct SECOND dated event has a DIFFERENT date → not in ``event_dates`` → KEPT.
        # Fail-safe: no reified date for the turn → ``event_dates`` empty → this clause is a no-op
        # (never over-suppresses an undated/distinct-dated event).
        if (event_dates and _r == "participated_in"
                and _o not in handles and not _is_occurrence_handle(_o)):
            _ed = _raw_field(e, "event_date")
            if _ed and _ed in event_dates:
                log.info("ingest.flat_event_dup_suppressed",
                         reason="date_keyed_event_noise", subject=_s[:32], rel=_r,
                         object=_o[:32], event_date=_ed)
                continue
        # (5) DEVICE-ISSUE STATE-HEAD PURGE — the has_state lane bound the bland problem head as a
        # STATE of the affected thing ("(gps system, has_state, ISSUE)"), so the competing flat lanes'
        # DIVORCED captures of that same head are junk: (user/X, owns, issue) + (X, has_pet, issue)
        # [the head wrongly possessed], and (issue, instance_of/subclass_of, …) [the bland head wrongly
        # filed into L4 — a HARD-LINE violation; a state is not an L4 place]. Drop them by the
        # head-surface key (structural, no noun list). The real (affected, has_state, head) edge lives
        # in the reified set, not here, so it is never at risk. Fail-safe: no state_heads → no-op.
        if state_heads:
            # The bland problem head as ANY edge's OBJECT is a DIVORCED mis-capture: the has_state lane
            # rebound it as a state of the affected thing, so (user, have/owns, issue) and
            # (system, has_pet, issue) are junk regardless of the (possibly not-yet-canonicalized) rel
            # surface ("have"→"owns" happens downstream). The REAL (affected, has_state, head) edge is
            # in the reified set, NOT in this edge set, so it is never at risk here. Per-turn + only when
            # has_state fired for this exact head → no legit object-"issue" edge is collateral.
            if _o in state_heads:
                log.info("ingest.flat_event_dup_suppressed",
                         reason="state_head_divorced_possession", subject=_s[:32], rel=_r, object=_o[:32])
                continue
            # The bland head must NEVER be filed into L4 (a state is not a place — THE HARD LINE).
            if _s in state_heads and _r in ("instance_of", "subclass_of", "also_known_as"):
                log.info("ingest.flat_event_dup_suppressed",
                         reason="state_head_l4_leak", subject=_s[:32], rel=_r, object=_o[:32])
                continue
        kept.append(e)
    return kept


# ════════════════════════════════════════════════════════════════════════════════════════════════
# STAGE 2 — SAME-SPAN CANDIDATE ARBITRATION (strongest grounded candidate wins; ambiguous keeps BOTH).
# ════════════════════════════════════════════════════════════════════════════════════════════════
# Stage 0 made the tail-type mismatch a binary veto; Stage 1 computed a GRADED grounded score per
# participation candidate (logged, non-committing). Stage 2 builds the ARBITRATION machinery that
# CONSUMES that grade: when ≥2 candidate edges target the SAME span / affected-entity (e.g. a
# `participated_in <X>` candidate vs a `has_state <X>` candidate for the same X), compare them by the
# Stage-1 grounded grade and COMMIT THE STRONGEST, SUPPRESS THE LOSER. This extends the existing
# event-suppression machinery (it runs at the SAME call sites, on the SAME edge list, as a sibling of
# `_suppress_flat_event_duplicates`) — it does NOT invent a new merge path. The winning rel flows
# into `assign_class_and_confidence` UNCHANGED (arbitration decides WHICH rel; the tier model decides
# durability).
#
# LOAD-BEARING FAIL-SAFE — we DON'T FORGET. The loser is dropped ONLY when there is a CLEAR grounded
# winner (a decisive grade gap). Tie / close / any candidate with NO groundable grade → KEEP BOTH and
# let downstream tiering handle them — NEVER a silent drop. A `crater`-grade candidate vs a `strong`
# candidate is a clear winner; two same-grade (or adjacent-grade) candidates is ambiguous → keep both.
#
# ⚠️ INERT ON LIVE INPUT TODAY. The real competitor (a `has_state` candidate for the bland-head
# with-PP construction) does NOT exist yet — it lands in Stage 3. So on TODAY's input every span has
# exactly ONE grounded candidate → arbitration has nothing to arbitrate and changes NOTHING (the live
# first-10 + the GPS/webinar rows are IDENTICAL to Stage 1). It fires ONLY when ≥2 grounded candidates
# genuinely compete for the same span — which is exercised here only by SYNTHETIC unit-test candidates.

# How decisive a grade gap must be to declare a CLEAR winner. The ordinal ladder is
# _SPINE_GRADE_ORDER = (crater, weak, moderate, neutral, strong). A gap of ≥2 rungs (e.g.
# strong↔weak, moderate↔crater, neutral↔crater) is decisive → suppress the loser. A gap of ≤1 rung
# (same grade, or adjacent: strong↔neutral, weak↔crater) is AMBIGUOUS → keep both (fail-safe). Env-
# overridable for tuning, never below 2 in spirit (1 would suppress on a single-rung wobble).
_SPINE_ARB_DECISIVE_GAP = 2


def _spine_grade_rank(grade: str | None) -> int | None:
    """Ordinal rank of a grade on _SPINE_GRADE_ORDER (0=crater … 4=strong). None when the grade is
    missing/unknown — the caller treats that as UNGROUNDABLE → keep-both (fail-safe, never a drop)."""
    g = (grade or "").strip().lower()
    if g in _SPINE_GRADE_ORDER:
        return _SPINE_GRADE_ORDER.index(g)
    return None


def _spine_candidate_grade(cand: dict, ev=None) -> str | None:
    """Resolve ONE candidate edge's Stage-1 grounded grade for arbitration.

    Precedence:
      1. An explicit ``_spine_grade`` already attached to the candidate (the producing lane scored it,
         or a unit test injected it) — used verbatim.
      2. Otherwise compute it via the Stage-1 scorer (`_spine_candidate_score`) — which today only
         grades the `participated_in` participation candidate and returns None for everything else.

    Returns the grade string (a member of _SPINE_GRADE_ORDER) or None when no grade could be grounded
    (e.g. a `has_state` candidate before Stage 3 wires its scorer) → the caller keeps both. Pure,
    fail-safe: any error → None (ungroundable → keep-both)."""
    try:
        _g = cand.get("_spine_grade")
        if isinstance(_g, str) and _g.strip().lower() in _SPINE_GRADE_ORDER:
            return _g.strip().lower()
        _bd = _spine_candidate_score(dict(cand), ev,
                                     promoted_arg=bool(cand.get("_promoted_arg")),
                                     lane=str(cand.get("_lane") or "reified"))
        if isinstance(_bd, dict):
            _bg = (_bd.get("grade") or "").strip().lower()
            return _bg if _bg in _SPINE_GRADE_ORDER else None
        return None
    except Exception as _e:  # noqa: BLE001 — fail-safe: ungroundable grade → keep-both
        log.debug("spine.arbitrate_grade_failed", error=str(_e)[:120])
        return None


def _arbitrate_spine_candidates(edges, ev_by_span: dict | None = None,
                                is_edgeinput: bool = False):
    r"""STAGE 2 — arbitrate competing candidate edges that target the SAME span / affected-entity.

    Sibling of `_suppress_flat_event_duplicates`: same call sites, same edge list, same suppression
    discipline (it DROPS a loser only on a CLEAR grounded win and otherwise KEEPS BOTH). It does NOT
    invent a new merge path — it is the arbitration arm of the existing event-suppression machinery.

    ALGORITHM (deterministic, subject-agnostic, no rel/type literal except the DB-grown predicates the
    deriver already emits):
      1. GROUP candidate edges by their affected-entity SPAN — the lowercased ``object`` surface (the
         thing both a `participated_in <X>` and a `has_state <X>` candidate are ABOUT). A span with a
         single candidate is left untouched (no competitor → nothing to arbitrate → inert).
      2. For each span with ≥2 candidates, GRADE each via `_spine_candidate_grade` (Stage-1 score or
         an attached `_spine_grade`). The STRONGEST grounded grade is the provisional winner.
      3. SUPPRESS losers ONLY on a CLEAR grounded win: the winner has a real rank AND every loser it
         drops is ≥ ``_SPINE_ARB_DECISIVE_GAP`` rungs weaker. Otherwise (tie, close/adjacent grades,
         or ANY candidate with no groundable grade) → KEEP ALL candidates for that span (fail-safe,
         "we don't forget", never a silent drop).
      4. The kept winner flows on UNCHANGED into `assign_class_and_confidence` (we touch the EDGE SET,
         never the tier/confidence assignment).

    ``ev_by_span`` — optional {span_lower: EventAnalysis} so the grader can read construction signals
    for a candidate that didn't carry a precomputed grade. None → grader uses attached grades / a
    bare score. ``is_edgeinput`` selects attribute vs dict field access (EdgeInput at /ingest).

    Flag SPINE_CANDIDATE_ARBITRATION (default ON). OFF → returns ``edges`` unchanged (legacy). Fail-
    safe everywhere: any error → ``edges`` unchanged."""
    if not _flag_on("SPINE_CANDIDATE_ARBITRATION", default="true"):
        return edges
    try:
        ev_by_span = ev_by_span or {}

        def _f(e, name: str) -> str:
            v = getattr(e, name, None) if is_edgeinput else e.get(name)
            return (v or "").strip().lower()

        # The two rels that genuinely COMPETE for an affected-entity span: the occurrence/participation
        # reading vs the state reading. Both are DB-grown predicates the deriver already emits — this
        # is a STRUCTURAL gate on competing readings, NOT a domain word list. Any other rel on the span
        # (a scalar, a kinship edge, an ownership edge) is NOT a competing reading of the same span and
        # is never arbitrated. Resolved from the deriver's emitted predicate name, kept generic.
        _COMPETING_RELS = {"participated_in", "has_state"}

        # The AFFECTED-ENTITY span is the axis both readings compete on — but it sits in a DIFFERENT
        # role per rel: the occurrence reading puts the affected entity in the OBJECT
        # (``user participated_in <X>``), while the state reading puts it in the SUBJECT
        # (``<X> has_state <problem>``). Group on the affected-entity surface REGARDLESS of role so the
        # two genuinely compete for the same span (otherwise they'd land in different groups and never
        # arbitrate). Structural, metadata-driven from the rel's argument structure — NO domain list.
        def _affected_span(e) -> str:
            return _f(e, "subject") if _f(e, "rel_type") == "has_state" else _f(e, "object")

        # GROUP by affected-entity span. Only edges whose rel is a competing reading enter a group;
        # everything else is passed straight through untouched.
        groups: dict[str, list[int]] = {}
        for _i, e in enumerate(edges):
            if _f(e, "rel_type") in _COMPETING_RELS:
                _span = _affected_span(e)
                if _span:
                    groups.setdefault(_span, []).append(_i)

        drop_idx: set[int] = set()
        for _span, idxs in groups.items():
            if len(idxs) < 2:
                continue  # single candidate → no competitor → INERT (today's live behavior)
            graded = []  # (idx, grade_str, rank)
            ungroundable = False
            for _i in idxs:
                _cand = edges[_i]
                _cand_dict = ({k: getattr(_cand, k, None) for k in
                               ("subject", "rel_type", "object", "object_type", "subject_type")}
                              if is_edgeinput else _cand)
                _grade = _spine_candidate_grade(_cand_dict, ev_by_span.get(_span))
                _rank = _spine_grade_rank(_grade)
                if _rank is None:
                    ungroundable = True  # a candidate we cannot grade → ambiguous → keep ALL
                graded.append((_i, _grade, _rank))
            if ungroundable:
                log.info("spine.arbitration_keep_both",
                         span=_span[:48], reason="ungroundable_candidate",
                         candidates=len(idxs))
                continue
            # All candidates have a real rank. Find the strongest; suppress a loser ONLY when it is
            # ≥ decisive-gap rungs weaker than the winner (a tie / adjacent grade → keep both).
            graded.sort(key=lambda t: t[2], reverse=True)
            _win_i, _win_grade, _win_rank = graded[0]
            # Tie at the top (two candidates share the strongest rank) → AMBIGUOUS → keep all.
            if len(graded) >= 2 and graded[1][2] == _win_rank:
                log.info("spine.arbitration_keep_both",
                         span=_span[:48], reason="tie_at_top", grade=_win_grade,
                         candidates=len(idxs))
                continue
            _span_drops = []
            for _i, _grade, _rank in graded[1:]:
                if (_win_rank - _rank) >= _SPINE_ARB_DECISIVE_GAP:
                    _span_drops.append((_i, _grade))
                else:
                    # This loser is within the ambiguity band of the winner → keep it (fail-safe).
                    log.info("spine.arbitration_keep_both",
                             span=_span[:48], reason="close_grade",
                             winner=_win_grade, loser=_grade)
            for _i, _grade in _span_drops:
                drop_idx.add(_i)
                log.info("spine.arbitration_suppressed_loser",
                         span=_span[:48], winner_grade=_win_grade, winner_rel=_f(edges[_win_i],
                         "rel_type"), loser_grade=_grade, loser_rel=_f(edges[_i], "rel_type"),
                         note="STAGE-2 clear grounded winner — loser suppressed")

        if not drop_idx:
            return edges  # inert: no clear winner anywhere (today's live path)
        return [e for _i, e in enumerate(edges) if _i not in drop_idx]
    except Exception as _e:  # noqa: BLE001 — fail-safe: never break ingest; keep ALL edges
        log.warning("spine.arbitration_failed", error=str(_e)[:160])
        return edges


async def _classify_occurrence_residue(text: str, user_id: str) -> list[dict]:
    r"""GROWTH-WIRED occurrence classifier — closes the tail the deterministic LVC seam misses.

    THE RESIDUE SIGNAL (deterministic, computed by the pipeline already): the span carries a
    parseable DATE/relative-time (``linguistics.has_date_residue`` — the SAME date detector
    ``extract_event_date`` uses) but the structured lanes produced NO host edge for it. That is the
    exact "I underwent surgery on March 3, 2021" / "I scheduled a meeting last Tuesday" gap: a real
    ``event_date`` parses but there is no edge to attach it to, because the verb is outside the
    bounded light-verb class (so ``_detect_event_states`` no-ops) and GLiNER2 surfaces no pair.

    THE TARGETED CLASSIFICATION (detect + classify, NOT the general triple extractor that already
    missed it, NOT rewording): ONE bounded LLM call asks "what OCCURRED in this sentence?" and
    returns the VERBATIM occurrence noun phrase (the eventive head, e.g. "surgery", "meeting") or
    "none". The LLM only DETECTS + hands back a verbatim span — it never invents a date, never
    rewords, never names the relation. Deterministic code then emits the backbone edge
    ``(user, participated_in, <verbatim span>)`` (migration 100's occurrence rel, ``temporal_class=
    'event'``); the object grounds into the ``event`` place via the EXISTING re_embedder "what is
    X" pushback (exactly as anxious→emotion) and the DATE rides the EXISTING per-edge
    ``event_date`` gate. A novel occurrence TYPE is just a novel object of ``participated_in`` → grows
    through the existing freq-gated ontology growth, not a hardcode.

    GUARD: only escalates when ``has_residue`` is True AND ``already_have_host`` is False (the
    caller passes whether the structured/deterministic lanes already produced ANY edge for this
    text — if so, the date already has a host, no LLM). VERBATIM CHECK: the returned span must be a
    substring of the source (case-insensitive) — the LLM may DETECT but never REWORD; a non-verbatim
    answer is rejected (fail-loud → drop, never fabricate). Returns
    ``[{subject:'user', rel_type:'participated_in', object:<span>, fact_provenance:'user_stated'}]`` or
    ``[]`` (no residue / 'none' / non-verbatim / failure). Fail-safe; bounded; thinking suppressed
    by the centralized stack. Gated by OCCURRENCE_RESIDUE_CAPTURE."""
    if not text or not text.strip() or not OCCURRENCE_RESIDUE_CAPTURE:
        return []
    # ── Deterministic residue gate: is there an unattached DATE in this span? ──
    try:
        from datetime import datetime as _dt, timezone as _tz
        from src.extraction.linguistics import has_date_residue
        if not has_date_residue(text, _dt.now(_tz.utc)):
            return []  # no dateful residue → nothing for the occurrence classifier to host
    except Exception as e:  # noqa: BLE001 — fail-safe: layer unavailable → no escalation
        log.warning("classify_occurrence_residue.residue_check_failed", error=str(e)[:120])
        return []

    # ── Targeted LLM detect+classify: "what occurred here?" → VERBATIM span only ──
    try:
        from .llm_calls import call_llm_with_retry_async
        messages = [
            {"role": "system", "content": (
                "A sentence is given that mentions a date or time. Decide whether it describes "
                "something the speaker DID or that HAPPENED to them on that date — EITHER:\n"
                "  (1) a named event/occurrence (an appointment, surgery, meeting, trip, ceremony, "
                "visit), OR\n"
                "  (2) an ACTION the speaker performed on or with a thing (washed my car, fixed the "
                "fence, repaired the router, painted the deck).\n"
                "If so, copy the VERBATIM noun phrase naming WHAT the occurrence is ABOUT — the "
                "event noun for (1) (e.g. \"surgery\", \"a meeting\", \"dentist visit\"), or the "
                "THING acted upon for (2) (e.g. \"my car\", \"the fence\", \"the router\"). Copy "
                "the words from the sentence EXACTLY; do NOT reword, summarize, or invent.\n"
                "If nothing happened (just a state, preference, opinion, or static fact), answer none.\n"
                'Respond with STRICT JSON only: {"occurrence":"<verbatim noun phrase from the sentence> | none"}.'
            )},
            {"role": "user", "content": text},
        ]
        res = await call_llm_with_retry_async(
            messages=messages,
            model=LLMModels.get("OCCURRENCE_CLASSIFY"),
            user_id=user_id,
            max_retries=1,                   # latency-bounded; fail open
            operation="OCCURRENCE_CLASSIFY",  # small focused classification (4s / 48 tok)
        )
    except Exception as e:  # noqa: BLE001 — fail-safe: never break ingest
        log.warning("classify_occurrence_residue.llm_failed", user_id=user_id[:8], error=str(e)[:120])
        return []
    if not isinstance(res, dict):
        return []
    span = (res.get("occurrence") or "").strip()
    low = span.lower()
    if not low or low == "none" or len(low) < 3:
        return []
    # VERBATIM GUARD (USER IS TRUTH / LLM never rewords): the occurrence phrase the model returned
    # must appear in the source text BEFORE we trim it. The LLM may DETECT the span but must not
    # REWORD/invent it — a non-verbatim answer is dropped (fail-loud, never fabricate an occurrence
    # the user did not state). Checked on the RAW span so the verbatim contract is enforced against
    # exactly what the model emitted (the determiner trim below is OUR deterministic normalization).
    if low not in text.lower():
        log.warning("classify_occurrence_residue.non_verbatim_dropped",
                    user_id=user_id[:8], span=low[:32])
        return []
    # Strip a leading DETERMINER the model may copy with the phrase — articles ("a meeting" →
    # "meeting") AND possessive determiners ("my Corolla" → "corolla", "the fence" → "fence"). The
    # occurrence OBJECT is the bare THING/event noun (the L4 place the re_embedder "what is X"
    # pushback grounds, e.g. corolla → car → vehicle); the determiner is not part of it (matches
    # _np_phrase). Bounded English-grammar determiner set — a language primitive, NOT a domain list.
    import re as _re_occ
    obj = _re_occ.sub(r"^(?:a|an|the|my|our|your|his|her|its|their)\s+", "", low).strip()
    if not obj or len(obj) < 3:
        return []
    # KEYSTONE A — REIFY the residue occurrence to PARITY with the deterministic seam: the residue
    # gate already PROVED a date is present (has_date_residue), so this occurrence is datable and
    # MUST be reified as its own dated entity filed at the bare type — not the flat (user,
    # participated_in, <type>) shape that piled occurrences onto a shared node. Parse the residue
    # span's OWN date (the SAME resolver, reference-anchored to the ingest/session instant) and
    # reify. THE HARD LINE: <obj> ("surgery") is the bare TYPE/place; the reified occurrence handle
    # ("surgery on 2021-03-03") is the memory filed at it; the date+granularity ride the
    # occurrence's participated_in edge. No title for a residue noun (bare occurrence) → the date
    # disambiguates the handle. Fail-safe: no date/no handle → flat shape (today's behavior).
    if OCCURRENCE_REIFY:
        try:
            from src.extraction.linguistics import extract_event_date as _extract_event_date_res
            # BUG 1 FIX: parse the RESIDUE CLAUSE's OWN date off the MARKER-STRIPPED text, never the
            # raw request. The leading harness [Date: YYYY/MM/DD] marker is the SESSION REFERENCE
            # only — it is an explicit-year absolute date, so if it stays in the text it OUT-RANKS the
            # clause's own bare month-day ("February 27th") in extract_event_date's preference sort and
            # the reference smears onto the occurrence (e.g. "corolla on 2023-03-01" instead of
            # 2023-02-27). _compute_ingest_reference_and_text returns BOTH the reference AND the text
            # with the marker stripped; feed the STRIPPED text to the resolver (parity with the
            # deterministic seam, which parses per-clause off decomposed/stripped text).
            _ref_res, _text_res = _compute_ingest_reference_and_text(text)
            _r_iso, _r_gran = _extract_event_date_res(_text_res, _ref_res)
            if _r_iso and not _r_gran:
                _r_gran = "day"
            # CONJOINED-LIST EXPANSION (Part B item 2): when the residue object is a coordinated list
            # head ("tomatoes, peppers, and cucumbers"), surface EACH conjunct as its OWN occurrence
            # so the shared date hosts on each — instead of collapsing the list to one generic node.
            # Deterministic spaCy `conj` walk (NO list/word enumeration), GLiNER2-pure (segmentation,
            # not labels). A non-coordinated object → [] → falls through to the single reify below.
            _conjuncts = []
            try:
                from src.extraction.linguistics import list_conjuncts as _list_conjuncts
                _conjuncts = _list_conjuncts(_text_res, obj)
            except Exception:
                _conjuncts = []
            if len(_conjuncts) >= 2:
                _multi: list[dict] = []
                _seen_h: set[str] = set()
                for _cj in _conjuncts:
                    _rf = _reify_occurrence_edges(_cj, None, _r_iso, _r_gran)
                    if not _rf:
                        continue
                    _h = (_rf[0].get("object") or "").strip().lower()
                    if _h and _h not in _seen_h:
                        _seen_h.add(_h)
                        _multi.extend(_rf)
                if _multi:
                    log.info("classify_occurrence_residue.reified_conjoined",
                             user_id=user_id[:8], items=len(_conjuncts), date=_r_iso, gran=_r_gran)
                    return _multi
            _reified = _reify_occurrence_edges(obj, None, _r_iso, _r_gran)
            if _reified:
                log.info("classify_occurrence_residue.reified",
                         user_id=user_id[:8], occurrence=obj[:32], date=_r_iso, gran=_r_gran)
                return _reified
        except Exception as _rre:  # noqa: BLE001 — fail-safe: fall back to the flat shape
            log.warning("classify_occurrence_residue.reify_failed",
                        user_id=user_id[:8], error=str(_rre)[:120])
    log.info("classify_occurrence_residue.captured", user_id=user_id[:8], occurrence=obj[:32])
    return [{"subject": "user", "rel_type": "participated_in", "object": obj,
             "subject_type": "Person", "object_type": "Event",
             "fact_provenance": "user_stated"}]


# Missing-slot residue capture: default ON, independent kill-switch. OFF → the harvest path
# behaves exactly as before (no atomic-value rescue in the harvest fallback).
MISSING_SLOT_CAPTURE = os.getenv("MISSING_SLOT_CAPTURE", "1") not in ("0", "false", "False")


async def _classify_value_subject_residue(text: str, edges: list[dict], user_id: str) -> list[dict]:
    r"""GROWTH-WIRED missing-SUBJECT classifier — closes the "value with no host edge" tail.

    THE RESIDUE SIGNAL (deterministic, computed by the EXISTING atomic detector — a legit
    format-grammar we HARNESS, never bypass): ``_detect_atomic_values`` finds a structured
    scalar (an IP / MAC / email / CIDR / FQDN / URL / phone / uuid) in the span, but NONE of the
    structured/deterministic lanes produced an edge whose OBJECT is that value. That is the exact
    "My server has ip 192.168.1.50" gap in the live ``/harvest-spans`` fallback: the value parses
    cleanly but no host edge carries it, so the scalar is dropped (live-confirmed ``no_ingest``).

    THE TARGETED CLASSIFICATION (detect + bind the MISSING slot, NOT rewording): the only empty
    slot is the SUBJECT (the value + its rel_type are already known from the format-grammar). ONE
    bounded LLM call (the existing ``_resolve_atomic_subjects_via_llm``, full-text context) binds
    each hostless value to the entity that owns it. The LLM only names the SUBJECT entity — it
    never invents the value, never rewords it, never names the relation (the rel_type comes from
    the atomic detector's format-grammar, e.g. ``has_ip``). A value the LLM cannot attribute is
    DROPPED (fail-loud, never fabricate an owner).

    THE GATE (the concession is safe because the GATE decides, not the LLM): each emitted edge
    carries ``object_datatype`` (ipv4/mac/email/...) and flows through the EXISTING source="mcp"
    /ingest path → WGM gate → migration-101 scalar-datatype validation (``_validate_scalar_datatype``).
    A malformed value is rejected there; a novel construction grows freq-gated. THE HARD LINE: the
    value is a SCALAR LEAF memory (never a place); this seam only emits the scalar edge.

    GUARD: only fires for values NOT already present as an object in ``edges`` (the structured
    lanes already hosted them → no LLM, no duplicate). Subject-agnostic, no word-list. Returns
    ``[{subject, rel_type, object, object_datatype, fact_provenance:'llm_inferred'}, ...]`` (the
    detector is an inference about ownership, not a user-stated identity) or ``[]``. Fail-safe;
    bounded; thinking suppressed by the centralized stack. Gated by MISSING_SLOT_CAPTURE."""
    if not text or not text.strip() or not MISSING_SLOT_CAPTURE:
        return []
    # ── Deterministic residue gate: find structured scalar values in the span ──
    _atomic_db = None
    try:
        _atomic_db = psycopg2.connect(os.environ.get("POSTGRES_DSN"))
    except Exception:
        _atomic_db = None
    try:
        try:
            _atomic = _detect_atomic_values(text, _atomic_db)
        except Exception as e:  # noqa: BLE001 — fail-safe: detector unavailable → no escalation
            log.warning("classify_value_subject_residue.detect_failed", error=str(e)[:120])
            return []
    finally:
        if _atomic_db is not None:
            try:
                _atomic_db.close()
            except Exception:
                pass
    if not _atomic:
        return []
    # Drop dates here: a hostless DATE is the OCCURRENCE seam's job (it asks "what occurred?"),
    # not a scalar leaf in search of a subject. THE HARD LINE: the date rides an event edge.
    _atomic = [_av for _av in _atomic if (_av.get("type") or "").lower() != "date"]
    if not _atomic:
        return []
    # GUARD: skip any value already hosted as an OBJECT by a structured/deterministic lane.
    _existing_objects = {
        (e.get("object") or "").strip().lower()
        for e in (edges or [])
        if e.get("object")
    }
    _unresolved = [
        _av for _av in _atomic
        if _av["value"].strip().lower() not in _existing_objects
    ]
    if not _unresolved:
        return []
    # ── Targeted MISSING-SUBJECT bind: the value + rel_type are known; only the owner is empty ──
    try:
        _resolved = _resolve_atomic_subjects_via_llm(text, _unresolved, user_id)
    except Exception as e:  # noqa: BLE001 — fail-safe: never break the harvest path
        log.warning("classify_value_subject_residue.resolve_failed", user_id=user_id[:8], error=str(e)[:120])
        return []
    out: list[dict] = []
    for _av in (_resolved or []):
        _val = (_av.get("value") or "").strip()
        _subj = (_av.get("subject") or "").strip().lower()
        _rel = (_av.get("rel_type") or "").strip().lower()
        if not (_val and _subj and _rel):
            continue
        out.append({
            "subject": _subj,
            "rel_type": _rel,
            "object": _val,
            # SCALAR-TYPE discipline (migration 101): carry the detector's typed label so the gate
            # validates + persists it as entity_attributes.datatype (ipv4/mac/email/...).
            "object_datatype": _datatype_for_detector_label(_av.get("type")),
            # The owner was INFERRED by the resolver, not user-stated identity → llm_inferred (the
            # gate computes confidence/class from this provenance, exactly as the /ingest atomic path).
            "fact_provenance": "llm_inferred",
        })
    if out:
        log.info("classify_value_subject_residue.captured", user_id=user_id[:8], bound=len(out))
    return out


async def _fill_missing_slots(text: str, edges: list[dict], user_id: str) -> list[dict]:
    r"""Generalized MISSING-SLOT residue gap-filler — the "what's the missing piece?" mechanism.

    We usually have all but one slot of a fact. The deterministic lanes detect WHICH slot is empty;
    ONE bounded, targeted LLM call fills EXACTLY that piece; the filled piece then flows through the
    EXISTING WGM/ontology/scalar gate (the gate decides — not the LLM — so the concession is safe).
    Each branch is verbatim-/format-guarded where the answer is a span and FAIL-LOUD on a miss (drop,
    never fabricate). The branches (one per empty slot):

      • DATE with no EVENT  → ``_classify_occurrence_residue`` (ask "what occurred?", verbatim span)
      • VALUE with no SUBJECT → ``_classify_value_subject_residue`` (ask "whose <value>?", bind owner)

    (subject+object with no RELATION, and thing with no TYPE / the ``what-is`` path, are the other
    natural branches of this same mechanism — wired here as they land.) ``edges`` is whatever the
    structured/deterministic lanes already produced for this span, so each branch can GUARD on what
    is already hosted (no duplicate, no LLM where a slot is already filled). Fail-safe per branch:
    any failure contributes nothing and never breaks the caller. Gated by the per-branch flags."""
    filled: list[dict] = []
    # Branch: DATE with no host event edge. Only escalate when no event edge already hosts the date.
    if not any((e.get("rel_type") or "").strip().lower() == "participated_in" for e in (edges or [])):
        try:
            filled.extend(await _classify_occurrence_residue(text, user_id))
        except Exception as e:  # noqa: BLE001 — fail-safe
            log.warning("fill_missing_slots.occurrence_branch_failed", error=str(e)[:120])
    # Branch: structured VALUE with no host edge (missing SUBJECT). Guards internally on `edges`.
    try:
        filled.extend(await _classify_value_subject_residue(text, edges, user_id))
    except Exception as e:  # noqa: BLE001 — fail-safe
        log.warning("fill_missing_slots.value_subject_branch_failed", error=str(e)[:120])
    return filled


# _SCALAR_REL_TYPES removed — replaced by classify_fact_type() which uses
# value-driven heuristics + DB-driven ontology hints (rel_types.tail_types).

# dprompt-152: Pattern metadata cache for intent classification
# Loaded at startup from negation_patterns table
# Used to enhance GLiNER2 prompt with real pattern examples from DB
_NEGATION_PATTERNS_CACHE: list = []
_PREFERENCE_PATTERNS_CACHE: list = []

# ── CORRECTION BYPASS GATE (pre-GLiNER2) ──────────────────────────────────────
# DESIGN (Alexander 2026-06-14): a correction is a BYPASS GATE, not a post-hoc
# supersede. GLiNER2 stays PURE and good at its strengths (QUERY vs STATEMENT, entity
# typing/matching) — it is NEVER asked to judge negation it is bad at. When confident the
# intent is a fix/omission — LLM-driven, hinged on the validated postgres cache — we SKIP
# *only the GLiNER2 intent classification* (classify_text) and route to the correction
# path. We are NOT skipping classification (the LLM classifies) nor the pipeline: the
# message still flows through EXTRACT / QUERY, where GLiNER2 does its real job — matching
# the target entity/attribute against postgres ("what are we fixing") — and the
# supersede/delete/update lands. The LLM decides THAT it is a fix; extract/query (with
# GLiNER2) determine and land WHAT. The confident call also GROWS the validated cache.
CORRECTION_BYPASS_GATE = os.getenv(
    "CORRECTION_BYPASS_GATE", os.getenv("DB_WEIGHTED_INTENT_SUPERSEDE", "1")
) not in ("0", "false", "False")
# Only a CONFIDENT LLM fix/omission call may bypass GLiNER2 intent classification. High bar.
try:
    INTENT_SUPERSEDE_MIN_CONF = float(os.getenv("INTENT_SUPERSEDE_MIN_CONF", "0.80"))
except (ValueError, TypeError):
    INTENT_SUPERSEDE_MIN_CONF = 0.80
# The correction/omission routing is the spaCy∧LLM dual-gate (_spacy_cue_route + LLM corroboration)
# — there is deliberately NO hardcoded negation keyword list in this module. A confident spaCy cue
# routes deterministically; an ambiguous cue escalates to the LLM; no cue → STATEMENT/ingest.

_UUID_PATTERN = re.compile(
    r'^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$',
    re.IGNORECASE
)
# Slug form: hyphens replaced with underscores (used as schema suffix and seeded
# as is_preferred=true at provisioning time — a known bad default, see schema_manager fix)
_UUID_SLUG_PATTERN = re.compile(
    r'^[0-9a-f]{8}_[0-9a-f]{4}_[0-9a-f]{4}_[0-9a-f]{4}_[0-9a-f]{12}$',
    re.IGNORECASE
)

# Fact class taxonomy replaced by metadata-driven queries (dprompt-73b).
# rel_types.fact_class column is authoritative — see _get_rel_type_metadata().
# ── dprompt-27: Graph + Hierarchy traversal systems (dprompt-122: DB-driven) ─────────────
# Two orthogonal traversal systems (dprompt-26 architecture):
#   GRAPH:     connectivity — who am I connected to? (is_hierarchy_rel=false)
#   HIERARCHY: composition + classification — what are they, what do they belong to? (is_hierarchy_rel=true)
# Both derived from _REL_TYPE_META at runtime — NO HARDCODED LISTS.

def _get_graph_rels() -> frozenset:
    """
    Return all graph relationship types (is_hierarchy_rel=false).
    Queries DB directly to include novel rel_types approved by re_embedder.
    Falls back to cache if DB unreachable.
    """
    dsn = os.environ.get("POSTGRES_DSN")
    if dsn:
        try:
            with psycopg2.connect(dsn) as conn:
                with conn.cursor() as cur:
                    cur.execute(
                        "SELECT rel_type FROM rel_types WHERE is_hierarchy_rel = false OR is_hierarchy_rel IS NULL"
                    )
                    return frozenset(row[0] for row in cur.fetchall())
        except Exception as e:
            log.warning("graph_rels.db_query_failed", error=str(e), using_fallback=True)
    # Fallback to startup cache if DB unavailable
    if _REL_TYPE_META:
        return frozenset(
            rt for rt, meta in _REL_TYPE_META.items()
            if not meta.get("is_hierarchy_rel", False)
        )
    return frozenset()

def _get_hierarchy_rels() -> frozenset:
    """
    Return all hierarchy relationship types (is_hierarchy_rel=true).
    Queries DB directly to include novel rel_types approved by re_embedder.
    Falls back to cache if DB unreachable.
    """
    dsn = os.environ.get("POSTGRES_DSN")
    if dsn:
        try:
            with psycopg2.connect(dsn) as conn:
                with conn.cursor() as cur:
                    cur.execute(
                        "SELECT rel_type FROM rel_types WHERE is_hierarchy_rel = true"
                    )
                    return frozenset(row[0] for row in cur.fetchall())
        except Exception as e:
            log.warning("hierarchy_rels.db_query_failed", error=str(e), using_fallback=True)
    # Fallback to startup cache if DB unavailable
    if _REL_TYPE_META:
        return frozenset(
            rt for rt, meta in _REL_TYPE_META.items()
            if meta.get("is_hierarchy_rel", False)
        )
    return frozenset()


# W3C/Wikidata classification PIDs: P31 (rdf:type / instance_of, is_a),
# P279 (rdfs:subClassOf / subclass_of). These are the rels that answer
# "what IS this entity" — as opposed to membership (member_of) or
# composition (part_of), which are hierarchy rels but NOT type-classification.
# Metadata-driven (read from rel_types.wikidata_pid), never hardcoded rel_type names.
_CLASSIFICATION_PIDS = ("P31", "P279")


def _get_classification_rels(db_conn=None) -> frozenset:
    """Return the TYPE-CLASSIFICATION hierarchy rels (Pillar 2).

    These walk an entity UP to its class to answer "what is this thing". They are
    the subset of hierarchy rels with a W3C/Wikidata classification PID
    (P31/P279) — instance_of, subclass_of, is_a — and EXCLUDE member_of (membership)
    and part_of (composition), which would otherwise mis-classify an entity by its
    group/whole (the exact failure that lets `fatty member_of you` make fatty a
    Person).

    Reads from the rel_types table under the caller's search_path when a connection
    is supplied (per-tenant), else opens its own (public). Falls back to the startup
    cache, then to the W3C-aligned default set, so this NEVER returns empty — an
    empty classification set would silently disable Pillar-2 type authority.
    """
    rels: set[str] = set()
    try:
        if db_conn is not None:
            with db_conn.cursor() as cur:
                cur.execute(
                    "SELECT rel_type FROM rel_types "
                    "WHERE is_hierarchy_rel = true AND wikidata_pid = ANY(%s)",
                    (list(_CLASSIFICATION_PIDS),),
                )
                rels.update(row[0].lower() for row in cur.fetchall())
        else:
            dsn = os.environ.get("POSTGRES_DSN")
            if dsn:
                with psycopg2.connect(dsn) as conn:
                    with conn.cursor() as cur:
                        cur.execute(
                            "SELECT rel_type FROM rel_types "
                            "WHERE is_hierarchy_rel = true AND wikidata_pid = ANY(%s)",
                            (list(_CLASSIFICATION_PIDS),),
                        )
                        rels.update(row[0].lower() for row in cur.fetchall())
    except Exception as e:
        log.warning("classification_rels.db_query_failed", error=str(e), using_fallback=True)

    if not rels and _REL_TYPE_META:
        rels.update(
            rt for rt, meta in _REL_TYPE_META.items()
            if meta.get("is_hierarchy_rel", False)
            and (meta.get("wikidata_pid") in _CLASSIFICATION_PIDS)
        )
    if not rels:
        # Last-resort W3C-aligned default — never disable type authority.
        rels = {"instance_of", "subclass_of", "is_a"}
    return frozenset(rels)


def _resolve_type_signals(db_conn, entity_id: str, max_depth: int = 4) -> tuple[set[str], bool]:
    """Pillar 2 — HIERARCHY is the type authority; the entity_type column is a hint.

    Walks the entity's CLASSIFICATION chain (instance_of/subclass_of, DB-driven)
    upward and returns ``(signals, hierarchy_authoritative)`` where ``signals`` is a
    lowercased set of every type label the entity could legitimately satisfy:
      • each ancestor class's ``entities.entity_type`` (when not 'unknown'), AND
      • each ancestor class's aliases (the class NAME itself, e.g. "homelab server")
        — because a class entity's own type column is frequently 'unknown' while its
        name carries the type (this is exactly fatty's case).

    ``hierarchy_authoritative`` is True iff at least one classification edge exists.
    When True, the caller MUST IGNORE the entity's denormalized ``entity_type``
    column (it is a stale cache that drifts — fatty's says Person while the
    hierarchy says homelab server; hierarchy wins). When False, no classification
    info exists and the caller may fall back to the column as a hint.

    Reads facts + staged_facts under the caller's search_path. Cycle-safe via a CTE
    depth bound.
    """
    signals: set[str] = set()
    class_rels = sorted(_get_classification_rels(db_conn))
    if not class_rels:
        return signals, False
    try:
        with db_conn.cursor() as cur:
            # Collect ancestor class UUIDs via the classification chain (facts ∪ staged).
            cur.execute(
                """
                WITH RECURSIVE chain AS (
                    SELECT object_id AS ancestor, 1 AS depth
                    FROM facts
                    WHERE subject_id = %s AND rel_type = ANY(%s)
                      AND superseded_at IS NULL
                      AND deleted_at IS NULL
                    UNION
                    SELECT object_id, 1
                    FROM staged_facts
                    WHERE subject_id = %s AND rel_type = ANY(%s)
                      AND promoted_at IS NULL
                      AND (expires_at IS NULL OR expires_at > now())
                      AND deleted_at IS NULL
                    UNION ALL
                    SELECT f.object_id, c.depth + 1
                    FROM facts f JOIN chain c ON f.subject_id = c.ancestor
                    WHERE f.rel_type = ANY(%s) AND f.superseded_at IS NULL
                      AND f.deleted_at IS NULL
                      AND c.depth < %s
                )
                SELECT DISTINCT ancestor FROM chain WHERE ancestor IS NOT NULL
                """,
                (entity_id, class_rels, entity_id, class_rels, class_rels, max_depth),
            )
            ancestors = [r[0] for r in cur.fetchall()]
            if not ancestors:
                return signals, False  # no classification edge → column is the hint

            # Each ancestor contributes its (non-unknown) entity_type AND its aliases.
            cur.execute(
                "SELECT entity_type FROM entities WHERE id = ANY(%s)"
                "  AND entity_type IS NOT NULL AND entity_type != 'unknown'",
                (ancestors,),
            )
            signals.update(r[0].lower() for r in cur.fetchall() if r[0])
            cur.execute(
                "SELECT alias FROM entity_aliases WHERE entity_id = ANY(%s)",
                (ancestors,),
            )
            signals.update(r[0].lower() for r in cur.fetchall() if r[0])
    except Exception as e:
        log.warning("resolve_type_signals.failed", entity_id=str(entity_id)[:16],
                    error=str(e)[:120])
        return signals, False
    return signals, True


def _get_structural_rels() -> frozenset:
    """
    D2: Structural rel_types that describe what an entity IS or what it's composed of.

    Metadata-driven, no hardcoded names:
      • every hierarchy rel_type (is_hierarchy_rel = true: instance_of, subclass_of,
        part_of, is_a, member_of, ...) — from the rel_types table, and
      • every rel_type whose NAME begins with ``has_`` (has_ip, has_mac, has_router, ...).
        ``has_*`` rels assert a structural/compositional property of the entity; a
        FALSE-learned one (e.g. "computer has_router") must surface in scope so the user
        can correct it (→ Class A override), per spec A2.

    These are ALWAYS included in a scoped fetch so structure is never filtered out for
    being "off-topic". Falls back to the startup cache if the DB is unreachable.
    """
    structural: set[str] = set(_get_hierarchy_rels())

    dsn = os.environ.get("POSTGRES_DSN")
    if dsn:
        try:
            with psycopg2.connect(dsn) as conn:
                with conn.cursor() as cur:
                    cur.execute("SELECT rel_type FROM rel_types WHERE rel_type LIKE 'has\\_%'")
                    structural.update(row[0] for row in cur.fetchall())
                    return frozenset(structural)
        except Exception as e:
            log.warning("structural_rels.db_query_failed", error=str(e), using_fallback=True)

    # Fallback to startup cache if DB unavailable
    if _REL_TYPE_META:
        structural.update(rt for rt in _REL_TYPE_META if rt.startswith("has_"))
    return frozenset(structural)


def _get_event_state_rels() -> frozenset:
    """Dated EVENT / STATE rel_types — the TEMPORAL retrieval tier.

    The deterministic, subject-agnostic analogue of ``_get_structural_rels`` for
    time-stamped occurrence/state assertions. In bi-temporal KG memory a time-stamped
    EVENT/STATE edge ("server is down", "leg is broken", "gps has_state break") forms
    its OWN retrieval tier keyed on a valid-time attribute (here the rel_type's
    ``temporal_class``/``category`` metadata), admitted INDEPENDENTLY of which
    domain-taxonomy grouping it happens to fall in — because a dated state predicate is
    not "about" the anchor's taxonomy, it's about WHAT HAPPENED to the anchor. (See
    Zep/Graphiti temporal-KG: edges carry validity intervals as core attributes and are
    retrieved on those, not on entity type.)

    Metadata-driven, NO hardcoded rel names:
      • ``temporal_class = 'event'``  — a dated occurrence/state (drives the temporal
        lifecycle; the distinguishing marker, since ``temporal_class`` defaults to
        'state' for ordinary rels), OR
      • ``category = 'state'``        — a state-change predicate (``feels``, ``has_state``).

    These are admitted into a concrete-anchor scope so an anchor's own "what happened"
    edges are never projected out for being off-taxonomy. Falls back to the startup
    cache if the DB is unreachable. NOTE: this admits the rel TYPES that qualify; the
    caller intersects with the rels actually present on the anchor, so an anchor with no
    event/state edges is unaffected (additive + safe).
    """
    event_state: set[str] = set()

    dsn = os.environ.get("POSTGRES_DSN")
    if dsn:
        try:
            with psycopg2.connect(dsn) as conn:
                with conn.cursor() as cur:
                    cur.execute(
                        "SELECT rel_type FROM rel_types "
                        "WHERE temporal_class = 'event' OR category = 'state'"
                    )
                    event_state.update(row[0] for row in cur.fetchall())
                    return frozenset(event_state)
        except Exception as e:
            log.warning("event_state_rels.db_query_failed", error=str(e), using_fallback=True)

    # Fallback to startup cache if DB unavailable
    if _REL_TYPE_META:
        event_state.update(
            rt for rt, meta in _REL_TYPE_META.items()
            if (meta.get("temporal_class") == "event") or (meta.get("category") == "state")
        )
    return frozenset(event_state)

# ── AXIS RESOLUTION (DESIGN-hierarchy-ladder §"Query model — axis-scoped walk") ──
# Minimal, deterministic intent cues for the CLASSIFICATION axis ("what IS X / what
# kind of …"). These are SURFACE cues only — they tilt axis selection toward
# classification; the authoritative signal is metadata (is_hierarchy_rel of the
# resolved defining rels). NOT a keyword zoo: a tiny fixed set of question forms,
# mirror of the existing intent-cue style already used for temporal intent.
_CLASSIFICATION_QUERY_CUES = (
    "what is", "what're", "what are", "what kind", "what type", "what sort",
    "what species", "what breed", "is a", "classify", "categor",
)


def _rel_is_classification(rel_type: str, classification_rels: frozenset) -> bool:
    """True iff rel_type is on the CLASSIFICATION axis (is_hierarchy_rel, P31/P279:
    instance_of / subclass_of / is_a). Metadata-driven — the set is resolved once by
    the caller via _get_classification_rels and passed in. Lowercased compare."""
    return (rel_type or "").lower() in classification_rels


def _member_fact_passes_axis(
    fact_rel: str,
    axis: Optional[str],
    classification_rels: frozenset,
) -> bool:
    """Axis filter for facts collected by the hierarchy member-walk (transitive fold +
    rung-4 trace-back). DESIGN-hierarchy-ladder §"Query model — axis-scoped walk":

      • MEMBERSHIP query: EXCLUDE a reached member's CLASSIFICATION chain
        ("Rex instance_of poodle / subclass_of dog") — that answers a DIFFERENT
        question. Membership edges + scalars pass.
      • CLASSIFICATION query: the classification axis is what's returned (keep it);
        membership edges of the same members still pass (they connect the walk).
      • None / axis off: pass everything (legacy behaviour).

    Scalars (no rel on the classification axis) always pass — they are the leaf data the
    walk exists to reach (a pet's name/age). Metadata-driven; no hardcoded rel names.
    """
    if not axis:
        return True
    if axis == "membership":
        # Drop the member's classification chain; keep membership edges + scalars.
        return not _rel_is_classification(fact_rel, classification_rels)
    # classification axis (or anything else): keep all (the classification chain is the
    # answer; membership edges merely connect the walk).
    return True


def _resolve_query_axis(path: "QueryPath", query_text: str, db) -> Optional[str]:
    """Deterministically classify the query's AXIS — membership vs classification.

    DESIGN-hierarchy-ladder §"Query model — axis-scoped deterministic walk": the two
    hierarchy axes meet at the entity but a question picks ONE.
      • CLASSIFICATION = the is_hierarchy_rel set (instance_of/subclass_of). Answers
        "what is X / what kind of …" and "my animals".
      • MEMBERSHIP/composition = everything else in scope (parent_of, has_pet,
        member_of, part_of, spouse, …). Answers "tell me about my family/pets/network".

    Resolution (metadata-driven, NO hardcoded rel/taxonomy name lists):
      1. If the scope's own defining rels are PREDOMINANTLY hierarchy rels
         (is_hierarchy_rel=true), the query is CLASSIFICATION.
      2. Else if a minimal "what is / what kind" surface cue fires, CLASSIFICATION.
      3. Else MEMBERSHIP (the common case — "tell me about my family").

    Returns "membership" | "classification" | None (None = no concrete scope; leave
    legacy behaviour). Fail-safe: any error returns None so the caller falls back.
    """
    try:
        if not path or not path.scope_active:
            return None
        scope_rels = {r.lower() for r in path.allowed_rels}
        # Also fold in the taxonomy's defining rels (allowed_rels is scalar+relationship,
        # which is taxonomy-expanded already, but read defining rels directly to be robust).
        try:
            hierarchy_rels = {r.lower() for r in _get_hierarchy_rels()}
        except Exception:
            hierarchy_rels = set()

        if scope_rels and hierarchy_rels:
            scoped_hier = scope_rels & hierarchy_rels
            scoped_non_hier = scope_rels - hierarchy_rels
            # Defining rels are predominantly classification → CLASSIFICATION axis.
            if scoped_hier and not scoped_non_hier:
                return "classification"

        # Surface cue for "what is / what kind" — tilts toward classification even when
        # the resolved scope is mixed/membership (e.g. "what kind of pet is Rex").
        q = (query_text or "").lower()
        if any(cue in q for cue in _CLASSIFICATION_QUERY_CUES):
            return "classification"

        # Default: membership/composition — "tell me about my family / pets / network".
        return "membership"
    except Exception as _ae:
        log.warning("resolve_query_axis.failed", error=str(_ae)[:120])
        return None


# dprompt-125: Rel-type alias cache (alias → canonical)
# Loaded at startup, queries DB at runtime for fresh aliases from re_embedder
_REL_TYPE_ALIASES: dict = {}

def _load_rel_type_aliases() -> dict:
    """
    Load rel_type_aliases from database (alias → canonical mapping).
    Called at startup and refreshed periodically by re_embedder.
    """
    dsn = os.environ.get("POSTGRES_DSN")
    if dsn:
        try:
            with psycopg2.connect(dsn) as conn:
                with conn.cursor() as cur:
                    cur.execute(
                        "SELECT alias, canonical_rel_type FROM rel_type_aliases WHERE canonical_rel_type IN (SELECT rel_type FROM rel_types)"
                    )
                    return {row[0].lower(): row[1].lower() for row in cur.fetchall()}
        except Exception as e:
            log.warning("rel_type_aliases.load_failed", error=str(e))
    return {}

def _get_canonical_rel_type(rel_type_alias: str) -> str:
    """
    Normalize LLM rel_type variations to canonical form via database aliases.
    Queries DB first (fresh), falls back to startup cache.
    Returns canonical rel_type or original if no alias found.
    dprompt-125: DB-driven, no hardcoded mappings.
    """
    if not rel_type_alias:
        return rel_type_alias

    alias_lower = rel_type_alias.lower().strip()

    # Try DB query first (includes newly-learned aliases from re_embedder)
    dsn = os.environ.get("POSTGRES_DSN")
    if dsn:
        try:
            with psycopg2.connect(dsn) as conn:
                with conn.cursor() as cur:
                    cur.execute(
                        "SELECT canonical_rel_type FROM rel_type_aliases WHERE alias = %s",
                        (alias_lower,)
                    )
                    row = cur.fetchone()
                    if row:
                        return row[0].lower()
        except Exception:
            pass  # Fall through to cache

    # Fall back to startup cache
    return _REL_TYPE_ALIASES.get(alias_lower, rel_type_alias)


def _get_canonical_rel_type_with_directionality(rel_type_alias: str) -> tuple[str, bool]:
    """
    Normalize LLM rel_type variations to canonical form and preserve directionality.

    dprompt-126: Phase 1 — Alias directionality preservation

    Returns:
        (canonical_rel_type, requires_inversion)
        - canonical_rel_type: canonical form from rel_types table
        - requires_inversion: True if subject/object need to be swapped to match canonical direction

    Examples:
        "son_of" → ("parent_of", True) — swap child/parent to parent/child
        "has_child" → ("parent_of", False) — already same direction
        "spouse_of" → ("spouse", False) — symmetric, direction doesn't matter
    """
    if not rel_type_alias:
        return rel_type_alias, False

    alias_lower = rel_type_alias.lower().strip()

    # Try DB query first (fresh data from re_embedder)
    dsn = os.environ.get("POSTGRES_DSN")
    if dsn:
        try:
            with psycopg2.connect(dsn) as conn:
                with conn.cursor() as cur:
                    cur.execute(
                        """SELECT canonical_rel_type, requires_inversion
                           FROM rel_type_aliases
                           WHERE alias = %s""",
                        (alias_lower,)
                    )
                    row = cur.fetchone()
                    if row:
                        return row[0].lower(), row[1] or False
        except Exception as e:
            log.warning("directionality.db_query_failed", alias=alias_lower, error=str(e))

    # Fall back: canonical from cache, no inversion (safe default)
    canonical = _REL_TYPE_ALIASES.get(alias_lower, rel_type_alias)
    return canonical, False


# ──────────────────────────────────────────────────────────────────────────────
# Phase 2: Schema-per-User Isolation Helpers
# ──────────────────────────────────────────────────────────────────────────────

# SECURITY (multi-tenant isolation, Phase 0 — fail-loud on absent identity).
# See DEV/SECURITY-multiuser-tenant-isolation.md §RP-2 / §RP-5.
# When NO identity can be resolved for a tenant-data operation, FaultLine must
# FAIL LOUD (log_crit + 4xx) rather than silently collapse to the shared
# "anonymous"/faultline_test pool (Finding 1b). The legacy shared-pool path is
# reachable ONLY via the explicit, audited opt-in below (default OFF), and even
# then every use is log_crit'd so it is never silent.
def _allow_anonymous_tenant() -> bool:
    return os.environ.get("ALLOW_ANONYMOUS_TENANT", "").strip().lower() in ("1", "true", "yes")


def _require_resolvable_user_id(user_id: str | None, endpoint: str) -> str:
    """
    Phase 0 fail-loud guard for tenant-data entry points.

    Returns the resolved user_id when identity is present. When user_id is empty
    or the literal "anonymous":
      - default (ALLOW_ANONYMOUS_TENANT unset): log_crit + raise HTTPException(400).
      - explicit opt-in (ALLOW_ANONYMOUS_TENANT=1): log_crit + return "anonymous"
        (legacy shared-pool, audited — dev/single-user only).

    This replaces the silent `user_id = req.user_id or "anonymous"` collapse.
    """
    if user_id and user_id != "anonymous":
        return user_id

    if _allow_anonymous_tenant():
        log_crit(
            log,
            "tenant.anonymous_shared_pool_used",
            endpoint=endpoint,
            note="ALLOW_ANONYMOUS_TENANT=1 — request routed to shared schema (dev/single-user only)",
        )
        return "anonymous"

    log_crit(
        log,
        "tenant.identity_absent_rejected",
        endpoint=endpoint,
        note="no resolvable user_id; refusing shared-pool fallback (set ALLOW_ANONYMOUS_TENANT=1 to opt in)",
    )
    raise HTTPException(
        status_code=400,
        detail="user_id required: no resolvable tenant identity for this request",
    )


def get_user_schema_context(user_id: str, db) -> dict:
    """
    Retrieve user's schema context from provisioning table.

    Called by every endpoint that queries DB. Sets search_path in connection.

    Args:
        user_id: UUID from request (comes from auth, not user input)
        db: psycopg2 connection

    Returns:
        {
            "user_id": user_id,
            "schema_name": "faultline_christopher",  # from users.slug
            "status": "ready"
        }

    Raises:
        ValueError: if user not provisioned or status != 'ready'
    """
    if not user_id or user_id == "anonymous":
        # SECURITY (Phase 0): do NOT silently route identity-absent reads to the
        # shared faultline_test pool. Reachable only via explicit audited opt-in.
        if not _allow_anonymous_tenant():
            log_crit(
                log,
                "tenant.identity_absent_rejected",
                endpoint="get_user_schema_context",
                note="no resolvable user_id; refusing shared-pool fallback",
            )
            raise ValueError("user_id required: no resolvable tenant identity")
        log_crit(
            log,
            "tenant.anonymous_shared_pool_used",
            endpoint="get_user_schema_context",
            note="ALLOW_ANONYMOUS_TENANT=1 — shared schema (dev/single-user only)",
        )
        return {
            "user_id": "anonymous",
            "schema_name": os.environ.get("QDRANT_COLLECTION", "faultline-test").replace("faultline-", "faultline_"),
            "status": "ready"
        }

    try:
        with db.cursor() as cur:
            cur.execute("""
                SELECT schema_name, status
                FROM public.user_provisioning
                WHERE user_id = %s
            """, (user_id,))
            row = cur.fetchone()
    except Exception as e:
        log.error("get_user_schema_context.query_failed", user_id=user_id, error=str(e))
        raise ValueError(f"Schema context lookup failed: {str(e)}")

    if not row:
        log.warning("get_user_schema_context.user_not_provisioned", user_id=user_id)
        raise ValueError(f"User {user_id} not provisioned")

    schema_name, status = row
    if status != "ready":
        log.warning("get_user_schema_context.user_not_ready",
                   user_id=user_id, status=status)
        raise ValueError(f"User {user_id} status: {status}")

    return {
        "user_id": user_id,
        "schema_name": schema_name,
        "status": status
    }

# REMOVED: Hardcoded categories. Query database for valid categories at runtime.
# See _get_valid_categories() for DB-driven implementation.
# Allows engine to learn and create new categories without code changes.

def _get_valid_categories() -> set[str]:
    """
    Query all DISTINCT categories from rel_types table.
    FAIL HARD if database unavailable or no categories found — engine must have learned them.
    Returns set of category strings.
    """
    dsn = os.environ.get("POSTGRES_DSN")
    if not dsn:
        msg = "CRITICAL: POSTGRES_DSN not set — cannot query categories from database"
        log.critical(msg, log_level="CRIT", component="database")
        raise RuntimeError(msg)

    try:
        with psycopg2.connect(dsn) as conn:
            with conn.cursor() as cur:
                cur.execute("SELECT DISTINCT(category) FROM rel_types WHERE category IS NOT NULL")
                rows = cur.fetchall()
                if not rows:
                    msg = (
                        "CRITICAL: No categories found in rel_types table. "
                        "Engine has not learned any relationship types yet. "
                        "Expected: family, location, work, identity, household, pets, temporal, physical, etc. "
                        "ACTION: Check if re_embedder is running and ontology_evaluations are being processed."
                    )
                    log.critical(msg, log_level="CRIT", component="ontology")
                    raise RuntimeError(msg)
                return set(cat[0] for cat in rows if cat[0])
    except RuntimeError:
        raise  # Re-raise intentional errors
    except Exception as e:
        msg = f"CRITICAL: Failed to query categories from database: {e}"
        log.critical(msg, log_level="CRIT", component="database", error=str(e))
        raise RuntimeError(msg)

# Temporal event routing replaced by metadata-driven queries (dprompt-73b).
# rel_types.storage_target column is authoritative — see _get_rel_type_metadata().
# _EVENT_RECURRENCE_DEFAULTS kept for calendar semantics of events table.

_EVENT_RECURRENCE_DEFAULTS = {
    "born_on": "yearly",
    "born_in": "once",
    "anniversary_on": "yearly",
    "met_on": "once",
    "married_on": "once",
    "appointment_on": "once",
}

# Fact classification replaced by metadata-driven queries (dprompt-73b).
# rel_types.fact_class column is authoritative — queried at ingest time.
# Correction/engine_generated/confidence < 0.6 logic preserved inline in ingest loop.

def _infer_category(rel_type: str) -> str | None:
    """
    Keyword-based category inference — offline fallback only.
    Used when LLM is unavailable or returns an invalid category.
    """
    rt = rel_type.lower()
    if any(k in rt for k in ("height","weight","gender","age","physical","body")):
        return "physical"
    if any(k in rt for k in ("born","birth","anniversary","met_on","married_on")):
        return "temporal"
    if any(k in rt for k in ("live","address","location","city","home","reside")):
        return "location"
    if any(k in rt for k in ("work","job","employ","occupation","career")):
        return "work"
    if any(k in rt for k in ("parent","child","spouse","sibling","family")):
        return "family"
    if any(k in rt for k in ("pet","animal","dog","cat","fish","bird")):
        return "pets"
    if any(k in rt for k in ("name","alias","known","called","pref")):
        return "identity"
    return None

def _get_rel_type_category(rel_type: str) -> str | None:
    """
    Get category for rel_type: DB → cache → keyword inference.
    Queries DB directly to include novel rel_types approved by re_embedder.
    """
    dsn = os.environ.get("POSTGRES_DSN")
    if dsn:
        try:
            with psycopg2.connect(dsn) as conn:
                with conn.cursor() as cur:
                    cur.execute(
                        "SELECT category FROM rel_types WHERE rel_type = %s",
                        (rel_type.lower(),)
                    )
                    row = cur.fetchone()
                    if row and row[0]:
                        return row[0]
        except Exception as e:
            log.warning("rel_type_category.db_query_failed", rel_type=rel_type, error=str(e))
    # Fallback to cache
    meta = _REL_TYPE_META.get(rel_type.lower(), {})
    if meta.get("category"):
        return meta["category"]
    # Final fallback: keyword inference
    return _infer_category(rel_type)

def _infer_symmetry_from_rel_type(rel_type: str) -> bool:
    """
    Metadata-driven infer of is_symmetric from rel_types table.
    Queries _REL_TYPE_META first, falls back to safe default (False).
    Logs warning for unknown rel_types (destined for re_embedder learning).
    """
    rt = rel_type.lower()

    # Layer 1: Metadata query (authoritative)
    rel_meta = _REL_TYPE_META.get(rt, {})
    if rel_meta:
        is_symmetric = rel_meta.get("is_symmetric", False)
        return is_symmetric

    # Layer 2: Pattern-based inference (fallback for novel rel_types)
    # Keyword patterns suggest symmetry — used only if metadata missing
    symmetric_patterns = ("spouse", "sibling", "friend", "knows", "met", "same_as")
    has_symmetric_pattern = any(pattern in rt for pattern in symmetric_patterns)

    if has_symmetric_pattern:
        log.info("infer_symmetry.pattern_fallback", rel_type=rel_type, inferred=True)
    else:
        log.info("infer_symmetry.pattern_fallback", rel_type=rel_type, inferred=False)

    return has_symmetric_pattern

def _infer_inverse_rel_type(rel_type: str) -> Optional[str]:
    """
    Metadata-driven inference of inverse_rel_type from rel_types table.
    Queries _REL_TYPE_META first (authoritative), falls back to safe default (None).
    Logs warning for unknown rel_types (destined for re_embedder learning).
    """
    rt = rel_type.lower()

    # Layer 1: Metadata query (authoritative)
    rel_meta = _REL_TYPE_META.get(rt, {})
    if rel_meta:
        inverse = rel_meta.get("inverse_rel_type")
        if inverse:
            return inverse.lower() if inverse else None
        # Metadata says no inverse (asymmetric or no bidirectional pair)
        return None

    # Layer 2: Pattern-based inference (fallback for novel rel_types)
    # These patterns are hints only — actual inverse determined by re_embedder + rel_types table

    # If rel_type ends with _of, try semantic reversal
    if rt.endswith("_of"):
        base = rt[:-3]  # Remove _of
        # Common pattern: "X_of" → "has_X" (e.g., child_of → has_child, creator_of → has_created)
        potential_inverse = f"has_{base}"
        log.info("infer_inverse.pattern_fallback", rel_type=rel_type,
                 inferred_inverse=potential_inverse, source="_of_pattern")
        return potential_inverse

    # If rel_type starts with has_, try reverse
    if rt.startswith("has_"):
        base = rt[4:]  # Remove has_
        # Common pattern: "has_X" → "X_of" (e.g., has_child → child_of, has_creator → creator_of)
        potential_inverse = f"{base}_of"
        log.info("infer_inverse.pattern_fallback", rel_type=rel_type,
                 inferred_inverse=potential_inverse, source="has_pattern")
        return potential_inverse

    # No inverse pattern detected — unknown/asymmetric rel_type
    # Log for re_embedder to learn
    log.info("infer_inverse.no_pattern_found", rel_type=rel_type, will_learn=True)
    return None


def _retraction_semantic_fallback(
    text: str,
    user_id: str,
    db,
    log,
) -> Optional[str]:
    """
    Semantic fallback for retraction lookup when all 6 pattern-match steps fail.

    Fires ONLY when: is_retraction=True AND old_fact_row is still None after the
    6-step pattern match. Never raises -- returns None on any error so the caller
    falls through to the existing "not found" path.

    Phases:
        SF-1: Embed retraction text -> search user's Qdrant collection (top_k=8, threshold=0.35)
        SF-2: Extract unique entity UUIDs from Qdrant results; resolve to display names
        SF-3: Shallow hierarchy walk (depth<=2) to surface entity type context
        SF-4: Build human-readable candidate summary string (max 5 facts)

    Returns:
        str  -- summary of candidate facts for clarification prompt, or
        None -- if Qdrant unavailable, embedding fails, or no results above threshold
    """
    try:
        qdrant_url = os.environ.get("QDRANT_URL", "http://qdrant:6333")
        collection = derive_collection(user_id)

        # SF-1: Embed the retraction text (QUERY side → nomic search_query prefix)
        embedding = embed_text(
            text,
            _LLM_URL,
            timeout=10.0,
            fallback=False,
            embedding_url=_EMBEDDING_API_URL,
            task="search_query",
        )
        if embedding is None:
            log.warning("retraction_semantic_fallback.embed_failed", user_id=user_id[:8])
            return None

        # SF-1: Search Qdrant
        try:
            qdrant_response = httpx.post(
                f"{qdrant_url}/collections/{collection}/points/query",
                json={
                    "query": {"nearest": embedding},
                    "score_threshold": 0.35,
                    "limit": 8,
                    "with_payload": True,
                    "with_vectors": False,
                },
                timeout=10.0,
            )
        except Exception as _qe:
            log.warning("retraction_semantic_fallback.qdrant_unreachable", error=str(_qe))
            return None

        if qdrant_response.status_code != 200:
            log.warning(
                "retraction_semantic_fallback.qdrant_search_failed",
                status=qdrant_response.status_code,
                collection=collection,
            )
            return None

        qdrant_results = qdrant_response.json().get("result", {}).get("points", [])
        if not qdrant_results:
            log.info("retraction_semantic_fallback.no_qdrant_results", user_id=user_id[:8])
            return None

        # SF-2: Collect unique entity UUIDs from subject + object fields in payloads
        entity_uuids = set()
        candidate_facts = []
        _uuid_re = re.compile(
            r"^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$",
            re.IGNORECASE,
        )
        for point in qdrant_results:
            payload = point.get("payload", {})
            score = point.get("score", 0.0)
            subj = payload.get("subject")
            obj = payload.get("object")
            rel_type_val = payload.get("rel_type", "")
            fact_class_val = payload.get("fact_class", "?")
            if subj:
                entity_uuids.add(subj)
            if obj:
                entity_uuids.add(obj)
            candidate_facts.append({
                "subject": subj,
                "rel_type": rel_type_val,
                "object": obj,
                "fact_class": fact_class_val,
                "score": score,
            })

        if not candidate_facts:
            return None

        # SF-2: Resolve UUIDs to display names (batch query)
        uuid_to_name = {}
        try:
            uuid_list = [u for u in entity_uuids if u and _uuid_re.match(str(u))]
            if uuid_list:
                with db.cursor() as cur:
                    cur.execute(
                        """
                        SELECT entity_id, alias
                        FROM entity_aliases
                        WHERE entity_id = ANY(%s)
                          AND is_preferred = true
                        """,
                        (uuid_list,),
                    )
                    for row in cur.fetchall():
                        uuid_to_name[row[0]] = row[1]
                # Fallback: any alias for UUIDs with no preferred alias
                missing = [u for u in uuid_list if u not in uuid_to_name]
                if missing:
                    with db.cursor() as cur:
                        cur.execute(
                            """
                            SELECT DISTINCT ON (entity_id) entity_id, alias
                            FROM entity_aliases
                            WHERE entity_id = ANY(%s)
                            ORDER BY entity_id, is_preferred DESC
                            """,
                            (missing,),
                        )
                        for row in cur.fetchall():
                            if row[0] not in uuid_to_name:
                                uuid_to_name[row[0]] = row[1]
        except Exception as _re_err:
            log.warning("retraction_semantic_fallback.alias_resolve_failed", error=str(_re_err))
            # Non-fatal: continue with raw UUIDs if name resolution fails

        # SF-3: Shallow hierarchy walk (depth<=2) for entity type context
        entity_type_hints = {}
        try:
            hierarchy_rels = ["instance_of", "subclass_of"]
            for eid in list(uuid_to_name.keys()):
                with db.cursor() as cur:
                    cur.execute(
                        """
                        SELECT f1.object_id, f2.object_id
                        FROM facts f1
                        LEFT JOIN facts f2
                          ON f2.subject_id = f1.object_id
                         AND f2.rel_type = ANY(%s)
                         AND f2.superseded_at IS NULL
                        WHERE f1.subject_id = %s
                          AND f1.rel_type = ANY(%s)
                          AND f1.superseded_at IS NULL
                        LIMIT 3
                        """,
                        (hierarchy_rels, eid, hierarchy_rels),
                    )
                    rows = cur.fetchall()
                type_ids = []
                for row in rows:
                    if row[0]:
                        type_ids.append(row[0])
                    if row[1]:
                        type_ids.append(row[1])
                if type_ids:
                    type_names = []
                    for tid in set(type_ids):
                        name = uuid_to_name.get(tid)
                        if not name:
                            try:
                                with db.cursor() as c2:
                                    c2.execute(
                                        "SELECT alias FROM entity_aliases WHERE entity_id = %s AND is_preferred = true LIMIT 1",
                                        (tid,),
                                    )
                                    r = c2.fetchone()
                                    if r:
                                        name = r[0]
                            except Exception:
                                pass
                        if name:
                            type_names.append(name)
                    if type_names:
                        entity_type_hints[eid] = type_names
        except Exception as _he:
            log.warning("retraction_semantic_fallback.hierarchy_walk_failed", error=str(_he))
            # Non-fatal: proceed without type context

        # SF-4: Build human-readable candidate summary (max 5 facts, sorted by score)
        def _display(entity_val):
            if not entity_val:
                return "?"
            # UUID -> display name with optional type hint
            if _uuid_re.match(str(entity_val)):
                name = uuid_to_name.get(entity_val, str(entity_val)[:8] + "...")
                hints = entity_type_hints.get(entity_val)
                if hints:
                    name = f"{name} ({hints[0]})"
                return name
            # Scalar string value: return as-is
            return str(entity_val)

        lines = []
        sorted_facts = sorted(candidate_facts, key=lambda f: f["score"], reverse=True)[:5]
        for fact in sorted_facts:
            subj_display = _display(fact["subject"])
            obj_display = _display(fact["object"])
            rt_display = fact["rel_type"] or "unknown_rel"
            fc_display = fact["fact_class"]
            lines.append(f"- {subj_display} {rt_display} {obj_display} (Class {fc_display})")

        if not lines:
            return None

        summary = "\n".join(lines)
        log.info(
            "retraction_semantic_fallback.candidates_found",
            user_id=user_id[:8],
            count=len(lines),
        )
        return summary

    except Exception as e:
        log.warning("retraction_semantic_fallback.unexpected_error", error=str(e))
        return None


def _grouping_candidate_rels(db) -> list[str]:
    """The rel_types that can DEFINE a grown grouping, read from per-tenant metadata.

    A grouping/containment edge ("X member_of/part_of/located_in <group>") names a
    collective the members belong to — exactly the edge that should mint a walkable
    grouping. We select these GENERICALLY from rel metadata, never by literal name:

      hierarchy rels (is_hierarchy_rel = true)   ← "belongs to a group/whole/place"
        MINUS the TYPE-CLASSIFICATION rels (wikidata_pid ∈ P31/P279 — instance_of,
        subclass_of, is_a), which answer "what IS this" and would intercept every
        typed entity (the exact danger the defining-group eligibility trigger guards).

    This mirrors `_get_classification_rels`' P31/P279 distinction (membership/composition
    are hierarchy rels but NOT classification). Subject-agnostic, zero domain literals.
    Returns [] on any error (fail-safe: no mint, never crash ingest).
    """
    try:
        with db.cursor() as cur:
            cur.execute(
                "SELECT rel_type FROM rel_types "
                "WHERE is_hierarchy_rel = true "
                "  AND (wikidata_pid IS NULL OR wikidata_pid <> ALL(%s))",
                (list(_CLASSIFICATION_PIDS),),
            )
            return [r[0].lower() for r in cur.fetchall() if r[0]]
    except Exception as _e:
        log.warning("grouping_mint.candidate_rels_failed", error=str(_e)[:120])
        return []


def _mint_groupings_from_membership(db, user_id: str, min_members: int = None) -> int:
    """ENGINE GROWTH: auto-mint a grouping taxonomy from OBSERVED membership at ingest.

    The system grows an entity's FACTS for any novel subject, but the GROUPING node the
    scoped query walk needs (entity_taxonomies) was 100% hand-seeded — so a novel
    collective ("my band", "my book club") captured `member_of <group>` edges perfectly
    yet had no taxonomy to scope, leaking to fetch-all. This producer closes that gap:
    it forms/extends the grouping node from the membership edges ingest already commits.

    DETERMINISTIC + FREQ-GATED + SUBJECT-AGNOSTIC + ZERO domain literals:
      • Defining rel  : any `_grouping_candidate_rels` (membership/containment, metadata).
      • Grouping head : the SHARED group OBJECT of those edges (co-membership) — its own
                        preferred alias becomes the `taxonomy_name`. NOT a name map.
      • Members       : the distinct SUBJECTS pointing at that group via the rel; their
                        resolved GLiNER2 entity types become `member_entity_types`.
      • Freq gate     : a grouping is minted only once ≥ `min_members` DISTINCT members
                        share the same group object (a single membership is just a fact).
      • Convergence   : ON CONFLICT extends member_types/defining rels by IDENTITY (array
                        union) — no cosine/embedding/fuzzy.
      • Per-tenant    : writes UNQUALIFIED under the request's tenant search_path; refuses
                        to run if the search_path fell through to `public` (fail-loud).
      • Source        : 'engine_grown_ingest' (NEVER 'seeded'); seeded rows are protected
                        from grown mutation by the ON CONFLICT … WHERE source <> 'seeded'.

    The defining-group eligibility TRIGGER still polices the write (it strips a true
    type-classification rel / a cross-type rel) — we feed it eligible membership rels and
    let it arbitrate. A mint failure is swallowed (the underlying facts are already
    committed); the grouping simply isn't grown this pass. Returns the number of
    groupings minted/extended.
    """
    floor = min_members if min_members is not None else max(
        2, int(os.getenv("GROUPING_MINT_MIN_MEMBERS", "2"))
    )
    minted = 0
    try:
        # Fail-loud per-tenant guard: never grow into the public template.
        with db.cursor() as cur:
            cur.execute("SHOW search_path")
            _sp = (cur.fetchone() or [""])[0] or ""
        _first = _sp.split(",")[0].strip().strip('"')
        if not _first.startswith("faultline_"):
            log_crit(log, "grouping_mint.refused_non_tenant_search_path",
                     search_path=_sp[:120], user_id=str(user_id)[:8])
            return 0

        cand = _grouping_candidate_rels(db)
        if not cand:
            return 0

        # Co-membership: distinct members sharing one group OBJECT via a candidate rel.
        with db.cursor() as cur:
            cur.execute(
                """
                SELECT object_id, rel_type,
                       COUNT(DISTINCT subject_id) AS n,
                       ARRAY_AGG(DISTINCT subject_id) AS members
                  FROM (
                        SELECT subject_id, object_id, rel_type FROM facts
                         WHERE rel_type = ANY(%s) AND superseded_at IS NULL
                           AND archived_at IS NULL AND deleted_at IS NULL
                        UNION
                        SELECT subject_id, object_id, rel_type FROM staged_facts
                         WHERE rel_type = ANY(%s) AND promoted_at IS NULL
                  ) m
                 WHERE object_id <> %s
                 GROUP BY object_id, rel_type
                HAVING COUNT(DISTINCT subject_id) >= %s
                """,
                (cand, cand, user_id, floor),
            )
            rows = cur.fetchall()

        for object_id, rel_type, n, members in rows:
            # Grouping name = the group object's preferred alias (its surface), never a map.
            with db.cursor() as cur:
                cur.execute(
                    "SELECT alias FROM entity_aliases WHERE entity_id = %s "
                    "ORDER BY is_preferred DESC, alias ASC LIMIT 1",
                    (object_id,),
                )
                _r = cur.fetchone()
            group_name = (_r[0] if _r else None)
            if not group_name:
                continue
            group_name = group_name.strip().lower()
            if len(group_name) < 2:
                continue

            # member_entity_types = resolved GLiNER2 types of the members (drop unknown).
            with db.cursor() as cur:
                cur.execute(
                    "SELECT DISTINCT entity_type FROM entities "
                    "WHERE id = ANY(%s) AND entity_type IS NOT NULL "
                    "  AND entity_type <> 'unknown'",
                    (list(members),),
                )
                mtypes = sorted({t[0] for t in cur.fetchall() if t[0]})

            try:
                with db.cursor() as cur:
                    cur.execute(
                        """
                        INSERT INTO entity_taxonomies
                            (taxonomy_name, description, member_entity_types,
                             rel_types_defining_group, has_transitivity,
                             transitive_rel_types, is_hierarchical, parent_rel_type, source)
                        VALUES (%s, %s, %s::text[], %s::text[], false,
                                '{}'::text[], false, NULL, 'engine_grown_ingest')
                        ON CONFLICT (taxonomy_name) DO UPDATE SET
                            member_entity_types = (
                                SELECT ARRAY_AGG(DISTINCT e)
                                  FROM unnest(COALESCE(entity_taxonomies.member_entity_types, '{}')
                                              || EXCLUDED.member_entity_types) e),
                            rel_types_defining_group = (
                                SELECT ARRAY_AGG(DISTINCT x)
                                  FROM unnest(COALESCE(entity_taxonomies.rel_types_defining_group, '{}')
                                              || EXCLUDED.rel_types_defining_group) x)
                        WHERE entity_taxonomies.source <> 'seeded'
                        """,
                        (group_name,
                         f"auto-grown grouping from observed {rel_type} membership",
                         mtypes, [rel_type]),
                    )
                db.commit()
                minted += 1
                log.info("ingest.grouping_minted",
                         taxonomy=group_name, defining_rel=rel_type,
                         member_types=mtypes, members=int(n),
                         source="engine_grown_ingest")
            except Exception as _ie:
                log.warning("ingest.grouping_mint_insert_failed",
                            taxonomy=group_name, error=str(_ie)[:140])
                try:
                    db.rollback()
                except Exception:
                    pass
        return minted
    except Exception as _e:
        log.warning("ingest.grouping_mint_failed", error=str(_e)[:160])
        try:
            db.rollback()
        except Exception:
            pass
        return 0


def _safe_taxonomy_rel_types(rel_types: list[str]) -> list[str]:
    """Strip hierarchy rel_types from a rel_types_defining_group candidate list.

    Hierarchy rel_types (is_hierarchy_rel=True) classify entities into types — they
    are NOT behavioral rel_types and must never appear in rel_types_defining_group.
    A taxonomy that matches on instance_of will intercept nearly every typed-entity
    query and the exclusive gate will silently drop non-matching entity types.

    Metadata-driven: checks _REL_TYPE_META first (authoritative), falls back to
    pattern inference for novel rel_types not yet in the DB.
    """
    safe = []
    for rt in (rel_types or []):
        if not rt:
            continue
        rt_lower = rt.lower()
        meta = _REL_TYPE_META.get(rt_lower, {})
        if meta:
            # Authoritative: DB says is_hierarchy_rel — skip it
            if meta.get("is_hierarchy_rel", False):
                continue
        else:
            # Pattern fallback for novel rel_types not yet in rel_types table
            if _infer_hierarchy_from_rel_type(rt_lower):
                continue
        safe.append(rt_lower)
    return safe


def _infer_hierarchy_from_rel_type(rel_type: str) -> bool:
    """
    Metadata-driven inference of is_hierarchy_rel from rel_types table.
    Queries _REL_TYPE_META first (authoritative), falls back to pattern inference.
    Logs warning for unknown rel_types (destined for re_embedder learning).
    """
    rt = rel_type.lower()

    # Layer 1: Metadata query (authoritative)
    rel_meta = _REL_TYPE_META.get(rt, {})
    if rel_meta:
        is_hierarchy = rel_meta.get("is_hierarchy_rel", False)
        return is_hierarchy

    # Layer 2: Pattern-based inference (fallback for novel rel_types)
    # Keywords suggest hierarchy semantics — used only if metadata missing
    hierarchy_patterns = ("instance_of", "subclass_of", "part_of", "member_of", "is_a", "taxonomy", "category")
    has_hierarchy_pattern = any(pattern in rt for pattern in hierarchy_patterns)

    if has_hierarchy_pattern:
        log.info("infer_hierarchy.pattern_fallback", rel_type=rel_type, inferred=True)
    else:
        log.info("infer_hierarchy.pattern_fallback", rel_type=rel_type, inferred=False, will_learn=True)

    return has_hierarchy_pattern

# Sentinel returned when a novel rel cannot be placed into any taxonomy layer.
# Callers route a PENDING rel to ontology_evaluations (the growth-engine quarantine)
# instead of silently bucketing it to "general" (a permanent orphan). The marker is
# written to rel_types.category so the row is a TRACKED candidate, never a silent
# dead-end — the re_embedder freq>=3 / cosine-map / LLM placement loop owns it from there.
_CATEGORY_PENDING = "pending_placement"

# Flag-gate the taxonomy-driven category resolution (default ON). Setting
# TAXONOMY_DRIVEN_CATEGORY=false reverts to the legacy keyword fallback for both call
# sites — a one-env-var rollback. See DEV/DESIGN-hierarchy-ladder-and-growth.md (rung 4,
# "no permanent orphans") and AUDIT-ingest-protocol-compliance.md Item 6a.
def _taxonomy_driven_category_on() -> bool:
    return os.getenv("TAXONOMY_DRIVEN_CATEGORY", "true").strip().lower() not in ("0", "false", "no", "off")


def _resolve_category_via_taxonomy(rel_type: str,
                                   head_types=None,
                                   tail_types=None) -> str | None:
    """Resolve a novel rel's LAYER (category) against the per-tenant entity_taxonomies
    overlay — subject-agnostic + hierarchy-aware. NO entity names, NO hardcoded word lists.

    Placement is decided by metadata only, against the current request's tenant schema
    (seed ∪ tenant rows, via taxonomy_overlay which resolves the bound search_path —
    never `public` directly, never another tenant):

      1. DEFINING MATCH (strongest): a taxonomy whose `rel_types_defining_group` already
         names this rel → it defines that group → that taxonomy IS its layer.
      2. TYPE MATCH (hierarchy-aware): a taxonomy whose `member_entity_types` cover the
         rel's head/tail entity types → the rel relates members of that group's layer.
         Wildcards (ANY/SCALAR) are not domain types and never match (avoids dumping every
         ANY rel into the first taxonomy).

    Returns the matched taxonomy_name (the category/layer), or None when no taxonomy
    covers the rel (genuinely novel — caller quarantines). Fail-safe: any overlay/DB
    error returns None (→ quarantine), never crashes ingest.
    """
    rt = (rel_type or "").strip().lower()
    if not rt:
        return None

    def _lc_set(vals):
        out = set()
        for v in (vals or []):
            s = str(v).strip().lower()
            if s and s not in ("any", "scalar"):  # wildcards are not domain types
                out.add(s)
        return out

    rel_types_present = _lc_set(head_types) | _lc_set(tail_types)

    try:
        dsn = os.environ.get("POSTGRES_DSN", "")
        if not dsn:
            return None
        # Resolve against the ContextVar-bound tenant schema (seed ∪ tenant). This is the
        # SAME binding the rel_type/taxonomy overlays use for the live request — no public
        # fallthrough for tenant tables, no cross-tenant leak (overlay degrades to seed-only
        # if the tenant schema is unreadable).
        taxonomies = taxonomy_overlay.resolve_current(dsn)
    except Exception as e:
        log.warning("ingest.category_taxonomy_resolve_failed", rel_type=rt, error=str(e)[:160])
        return None

    if not taxonomies:
        return None

    # Pass 1: defining-rel match (a taxonomy already names this rel as one of its group rels).
    for name, meta in taxonomies.items():
        defining = {str(d).strip().lower() for d in (meta.get("rel_types_defining_group") or []) if d}
        if rt in defining:
            log.info("ingest.category_resolved_by_defining_rel", rel_type=rt, taxonomy=name)
            return name

    # Pass 2: type match (the rel's head/tail types fall inside a taxonomy's member types).
    if rel_types_present:
        for name, meta in taxonomies.items():
            members = {str(m).strip().lower() for m in (meta.get("member_entity_types") or []) if m}
            if members & rel_types_present:
                log.info("ingest.category_resolved_by_member_types", rel_type=rt,
                         taxonomy=name, matched_types=sorted(members & rel_types_present))
                return name

    # No taxonomy covers it — genuinely novel; caller quarantines to ontology_evaluations.
    return None


def _infer_category_from_rel_type(rel_type: str) -> str:
    """LAST-RESORT keyword fallback ONLY (used when TAXONOMY_DRIVEN_CATEGORY is off).

    ⚠️ This is a hardcoded English keyword zoo encoding WORLD/ONTOLOGY facts (which words
    mean "pets"/"family"/…). It crosses the language-primitive line and is the documented
    rollback path, NOT the primary placement mechanism — `_resolve_category_via_taxonomy`
    (taxonomy-driven, subject-agnostic) is. See AUDIT-ingest-protocol-compliance.md Item 6a.
    Kept only so TAXONOMY_DRIVEN_CATEGORY=false fully restores prior behavior.

    Returns a category string; falls back to "general" if no keyword matches.
    """
    rt = rel_type.lower()

    # Keyword-based category inference
    if any(k in rt for k in ("height", "weight", "gender", "age", "physical", "body")):
        return "physical"
    if any(k in rt for k in ("born", "birth", "anniversary", "met_on", "married_on")):
        return "temporal"
    if any(k in rt for k in ("live", "address", "location", "city", "home", "reside")):
        return "location"
    if any(k in rt for k in ("work", "job", "employ", "occupation", "career")):
        return "work"
    if any(k in rt for k in ("parent", "child", "spouse", "sibling", "family")):
        return "family"
    if any(k in rt for k in ("pet", "animal", "dog", "cat", "fish", "bird")):
        return "pets"
    if any(k in rt for k in ("name", "alias", "known", "called", "pref")):
        return "identity"

    # Default category
    return "general"


def _resolve_or_quarantine_category(rel_type: str,
                                    head_types=None,
                                    tail_types=None) -> tuple[str, bool]:
    """Resolve a novel rel's category/layer; the SINGLE entry point both novel-mint
    call sites use. Returns ``(category, is_pending)``:

      • Taxonomy-driven match  → (taxonomy_name, False)  — placed in a real layer.
      • No taxonomy match (ON) → (_CATEGORY_PENDING, True) — quarantine to the growth
        engine via ontology_evaluations; NEVER a silent permanent "general".
      • Flag off               → (legacy keyword category, False) — documented rollback.

    Subject-agnostic + hierarchy-aware: placement keys on entity TYPES + taxonomy
    membership, never entity names or hardcoded word lists. Fail-safe: an overlay/DB
    error inside the resolver surfaces as "no match" → pending (tracked), never a crash.
    """
    if not _taxonomy_driven_category_on():
        return (_infer_category_from_rel_type((rel_type or "").lower()), False)

    matched = _resolve_category_via_taxonomy(rel_type, head_types, tail_types)
    if matched:
        return (matched, False)

    log.info("ingest.category_pending_placement", rel_type=(rel_type or "").lower(),
             note="no taxonomy covers this novel rel — quarantined for engine placement")
    return (_CATEGORY_PENDING, True)


def _quarantine_pending_rel(db, rel_type: str, head_types, tail_types,
                            confidence: float, natural_language: str | None = None) -> None:
    """Record a layer-UNPLACED novel rel into ontology_evaluations so the re_embedder
    growth engine (freq>=3 approve / cosine-map / LLM placement) PLACES it — the rel is a
    TRACKED candidate, never a silent orphan ("no permanent orphans",
    DESIGN-hierarchy-ladder-and-growth.md rung 4).

    Mirrors the existing in-flow ontology_evaluations audit write: schema-qualified to the
    bound tenant (growth tables live in faultline_<slug>, NEVER public — public's row has
    user_id NOT NULL and would fail), savepoint-guarded, and fully fail-safe (any error is
    logged and swallowed so it can NEVER crash ingest). Idempotent on the
    (candidate_rel_type, sample_subject_id, sample_object) unique key — re-occurrence just
    bumps occurrence_count, which is what the freq>=3 gate counts.
    """
    schema_name = None
    try:
        schema_name = rel_type_overlay.get_current_schema()
    except Exception:
        schema_name = None
    if not schema_name:
        # No bound tenant schema → writing to public.ontology_evaluations would hit the
        # NOT-NULL user_id template and fail. Fail loud, do not crash ingest.
        log.error("ingest.pending_rel_quarantine_skipped", rel_type=rel_type,
                  error="schema_name unset — refusing public fallthrough")
        return

    def _t(v):
        for x in (v or []):
            s = str(x).strip()
            if s and s.upper() not in ("ANY", "SCALAR"):
                return s
        return None

    try:
        with db.cursor() as _oc:
            _oc.execute("SAVEPOINT sp_pending_rel")
            try:
                # Schema-qualify directly: a prior rollback resets search_path to default,
                # so a bare table name would resolve to public.ontology_evaluations.
                _oc.execute(
                    f"INSERT INTO {schema_name}.ontology_evaluations"
                    " (candidate_rel_type, candidate_subject_type, candidate_object_type,"
                    "  first_text_snippet, extraction_confidence, extraction_method,"
                    "  sample_subject_id, sample_object, occurrence_count, last_seen_at,"
                    "  decision_reason, llm_natural_language, llm_category)"
                    " VALUES (%s, %s, %s, %s, %s, 'category_pending', %s, %s, 1, now(), %s, %s, %s)"
                    " ON CONFLICT (candidate_rel_type, sample_subject_id, sample_object)"
                    " DO UPDATE SET"
                    "   occurrence_count = ontology_evaluations.occurrence_count + 1,"
                    "   last_seen_at = now()",
                    (rel_type, _t(head_types), _t(tail_types),
                     None, confidence, None, None,
                     "novel rel — no taxonomy layer matched; awaiting engine placement",
                     natural_language, _CATEGORY_PENDING),
                )
                _oc.execute("RELEASE SAVEPOINT sp_pending_rel")
                log.info("ingest.pending_rel_quarantined", rel_type=rel_type, schema=schema_name)
            except Exception as _qe:
                _oc.execute("ROLLBACK TO SAVEPOINT sp_pending_rel")
                log.error("ingest.pending_rel_quarantine_failed",
                          rel_type=rel_type, error=str(_qe)[:160])
    except Exception as _qe2:
        log.error("ingest.pending_rel_quarantine_failed",
                  rel_type=rel_type, error=str(_qe2)[:160])

# Canonical closed set of GLiNER2 general entity-type labels (Pitfall 11). Any
# head_types/tail_types or member_entity_types eventually fed to GLiNER2 as labels MUST
# be drawn from this set (plus the ANY/SCALAR type-constraint wildcards). An unconstrained
# LLM returns domain/architecture nouns (KnowledgeGraph, MemoryManager, …) that collapse
# GLiNER2 detection — see RC-expand-taxonomy-pollution.
_CANONICAL_ENTITY_TYPES = ("Person", "Animal", "Organization", "Location", "Object", "Concept")
_CANONICAL_ENTITY_TYPES_LC = {t.lower(): t for t in _CANONICAL_ENTITY_TYPES}

# READ-TIME GLiNER2 LABEL SAFETY (directive B). When `/extract` reads
# entity_taxonomies.member_entity_types to build GLiNER2 entity-discovery labels, re-apply
# the canonical closed-set filter and cap the label count as defense-in-depth against the
# write-side filter being bypassed by any other writer (Pitfall 11 / RC-expand-taxonomy-
# pollution). This is a PURE SAFETY NARROWING (drops/caps only), so it defaults ON; set
# GLINER2_READ_LABEL_FILTER=0/false/off to restore the verbatim read. The cap mirrors the
# documented Pitfall-11 ceiling (the 6 canonical general types).
_GLINER2_READ_LABEL_FILTER = os.environ.get(
    "GLINER2_READ_LABEL_FILTER", "true").strip().lower() in ("1", "true", "yes", "on")
_GLINER2_MAX_LABELS = int(os.environ.get("GLINER2_MAX_LABELS", str(len(_CANONICAL_ENTITY_TYPES))))

# GLiNER2 INPUT-WINDOW SAFETY (the over-token half of the capture wall).
# GLiNER (deberta backbone) TRUNCATES at its trained ~384-word window REGARDLESS of `max_len`
# — so a long turn silently loses its tail and `max_len=2048` is a RED HERRING (it does not
# extend the trained context, it only raises the truncation ceiling that the model never reaches
# usefully). The fix the literature converges on is SEGMENT→union: type each in-window segment
# with a FRESH call and dict-merge the results (benchmarked ~35→77 entities, 2.2x, on a long
# turn) — N short in-window CPU calls are net-CHEAPER than one degrading long call (deberta
# attention is O(n²)). This is a SIZE+ISOLATION measure only; GLiNER2 LABELS are NEVER touched
# here (Pitfall 11 N/A). Conservative default ~384 WORDS; env-overridable. We treat the limit in
# WORDS (a token proxy of words×_GLINER2_TOKEN_PER_WORD ≈ tokens is used for the deterministic
# catch so a word-dense segment still gets split before the model sees it).
_GLINER2_MAX_INPUT_TOKENS = int(os.environ.get("GLINER2_MAX_INPUT_TOKENS", "384"))
# Subword-per-word proxy: a conservative deberta tokenizer expansion factor. Used to convert the
# WORD window into a token budget for the deterministic hard-window catch (words × this ≈ tokens).
# (_env_float is defined further below; parse inline to avoid the forward-reference.)
try:
    _GLINER2_TOKEN_PER_WORD = float(os.environ.get("GLINER2_TOKEN_PER_WORD", "1.3"))
except (TypeError, ValueError):
    _GLINER2_TOKEN_PER_WORD = 1.3


def _filter_to_canonical_types(types, allow_wildcards: bool = True):
    """Filter LLM-returned type names to the canonical general-type set (Pitfall 11).

    Title-cases survivors; keeps ANY/SCALAR (upper) when ``allow_wildcards``. Drops
    everything else and logs loudly. Returns a deduped, order-preserving list or None
    when nothing survives — callers treat None as "no constraint" / fail loud upstream.
    """
    if not types:
        return None
    out: list[str] = []
    seen: set[str] = set()
    for t in types:
        tl = str(t).strip().lower()
        if not tl:
            continue
        if allow_wildcards and tl in ("any", "scalar"):
            canon = tl.upper()
        elif tl in _CANONICAL_ENTITY_TYPES_LC:
            canon = _CANONICAL_ENTITY_TYPES_LC[tl]
        else:
            log.warning("rel_meta.entity_type_rejected", rejected=str(t)[:60])
            continue
        if canon not in seen:
            seen.add(canon)
            out.append(canon)
    return out or None


def _normalize_novel_rel_metadata(meta: dict, rel_type: str) -> dict | None:
    """
    Normalize the LLM-returned metadata for a novel rel_type into a clean dict.

    Phase 2 (B.2): the miss-handling LLM call returns COMPLETE metadata for any rel_type
    it emits that is not already known. This coerces the raw LLM dict into the canonical
    shape used to create the rel_type in-flow. Returns None if nothing usable is present.

    Expected keys (any subset): head_types, tail_types, category, is_symmetric,
    inverse_rel_type, natural_language.
    """
    if not isinstance(meta, dict):
        return None

    def _as_type_list(v):
        # Accept list, comma-string, or single string; normalize to non-empty list or None.
        if v is None:
            return None
        if isinstance(v, str):
            parts = [p.strip() for p in v.split(",") if p.strip()]
            return parts or None
        if isinstance(v, (list, tuple)):
            parts = [str(p).strip() for p in v if str(p).strip()]
            return parts or None
        return None

    # FIX (RC-expand-taxonomy-pollution §2): constrain head/tail to the canonical closed
    # set BEFORE they propagate into rel_types.head_types/tail_types AND into
    # entity_taxonomies.member_entity_types (both become GLiNER2 labels). The LLM is asked
    # to use general types but won't self-police on meta/recursive topics — filter, don't trust.
    head_types = _filter_to_canonical_types(_as_type_list(meta.get("head_types")))
    tail_types = _filter_to_canonical_types(_as_type_list(meta.get("tail_types")))

    category = meta.get("category")
    if isinstance(category, str):
        category = category.strip() or None
    else:
        category = None

    is_symmetric = meta.get("is_symmetric")
    is_symmetric = bool(is_symmetric) if is_symmetric is not None else None

    inverse_rel_type = meta.get("inverse_rel_type")
    if isinstance(inverse_rel_type, str):
        inverse_rel_type = inverse_rel_type.strip().lower() or None
        # LLM may return "null"/"none" as a string — treat as no inverse.
        if inverse_rel_type in ("null", "none"):
            inverse_rel_type = None
    else:
        inverse_rel_type = None

    natural_language = meta.get("natural_language")
    if isinstance(natural_language, str):
        natural_language = natural_language.strip() or None
    else:
        natural_language = None

    # Second-person template (subject baked as "you", Y kept). Validate: must keep Y,
    # must not reintroduce X — _create_rel_type_in_flow re-validates as a backstop.
    natural_language_2p = meta.get("natural_language_2p")
    if isinstance(natural_language_2p, str):
        natural_language_2p = natural_language_2p.strip() or None
        if natural_language_2p and ("Y" not in natural_language_2p or "X" in natural_language_2p):
            natural_language_2p = None
    else:
        natural_language_2p = None

    normalized = {
        "head_types": head_types,
        "tail_types": tail_types,
        "category": category,
        "is_symmetric": is_symmetric,
        "inverse_rel_type": inverse_rel_type,
        "natural_language": natural_language,
        "natural_language_2p": natural_language_2p,
    }
    # Require at least one concrete field to consider this usable.
    if not any(v is not None for v in normalized.values()):
        return None
    return normalized


# ── Phase 4: GLiNER2 candidate-set helpers (Severance #1+E) ──────────────────
# The GLiNER2 GLiREL relation extractor was trained with a 25-label-per-instance
# cap (arxiv:2501.03172). Passing more than 25 relation_types operates outside the
# training distribution and degrades confidence. These helpers (a) compute the
# per-type confidence threshold from rel_type metadata (no hardcoding) and (b)
# select WHICH relational rel_types are domain-relevant to the entities GLiNER2's
# NER pass actually found in THIS text — so grown RELATIONAL types get their
# "second shot" without polluting the seed (Pitfall 11) or exceeding the cap.
_GLINER2_RELATION_LABEL_CAP = 25  # legacy — kept for backward compat; new split caps below
_GLINER2_SCALAR_LABEL_CAP = int(os.environ.get("GLINER2_SCALAR_LABEL_CAP", "15"))
_GLINER2_RELATIONAL_LABEL_CAP = int(os.environ.get("GLINER2_RELATIONAL_LABEL_CAP", "20"))

# GLiNER2 closed-set RELATION scorer confidence floor (extract_relations threshold).
# The closed-set scorer will FORCE an existing label onto a weak entity pair when the floor is
# low (the live "resides_in | east side" noise). Raising the floor drops those low-confidence
# forced pairs — a miss beats a junk rel. This dials ONLY the confidence threshold on GLiNER2's
# OUTPUT; the model / labels are UNTOUCHED (Pitfall 11). Env-tunable, fail-safe parse → default.
def _env_float(name: str, default: float) -> float:
    try:
        return float(os.environ.get(name, str(default)))
    except (TypeError, ValueError):
        return default

GLINER2_RELATION_THRESHOLD = _env_float("GLINER2_RELATION_THRESHOLD", 0.5)


def _gliner2_threshold_for(head_types, category) -> float:
    """Per-type GLiNER2 confidence threshold, metadata-driven (no hardcoded rel_types).

    Mirrors the existing scalar build logic so relational candidates inherit the
    SAME per-type discipline:
      - Human types (Person in head_types, or identity/physical/temporal/work
        category): 0.5
      - Network/bootstrap (empty head_types + network category): 0.85 — blocks
        false positives
      - Default: 0.6
    """
    head_list = head_types if head_types else []
    is_human = ("Person" in head_list or
                category in ("identity", "physical", "temporal", "work"))
    is_network = (not head_list and category == "network")
    if is_human:
        return 0.5
    if is_network:
        return 0.85
    return 0.6


def _select_domain_relational_rel_types(dsn: str, detected_entity_types: set) -> dict:
    """Phase 4: select RELATIONAL rel_types domain-relevant to the entities present
    in THIS text, so a grown relational type (e.g. ``runs``, ``manages``) gets handed
    back to GLiNER2 on the next encounter (closes Severance #1+E / Link E).

    Selection is fully metadata-driven, read from the DB at runtime — NO hardcoded
    domain lists or rel_type names:

      1. Map the GLiNER2-detected NER entity types → ``entity_taxonomies`` whose
         ``member_entity_types`` intersect them; collect their
         ``rel_types_defining_group``.
      2. Additionally include any ``rel_types`` whose ``head_types`` or ``tail_types``
         intersect the detected entity types.

    Only RELATIONAL types are returned (``is_hierarchy_rel = false`` and NOT scalar)
    — scalars are already built separately. Returns
    ``{rel_type: {"description": natural_language, "threshold": float}}`` so the
    caller can merge them straight into the GLiNER2 ``relation_types`` dict with
    per-type thresholds preserved. Labels stay CLEAN (name + short natural_language
    only — Pitfall 11). Returns ``{}`` on any failure (logged loud) so GLiNER2 still
    gets the scalar seed (graceful degradation).
    """
    if not dsn or not detected_entity_types:
        return {}

    # Normalize detected types for case-insensitive matching against title-cased
    # member_entity_types/head_types in the DB (NER cache uppercases, e.g. "OBJECT").
    detected_lower = {t.strip().lower() for t in detected_entity_types if t and t.strip()}
    if not detected_lower:
        return {}

    selected: dict = {}
    try:
        with psycopg2.connect(dsn) as _conn:
            with _conn.cursor() as _cur:
                # Component 1: taxonomy rel_types_defining_group for taxonomies whose
                # member_entity_types intersect the detected entity types.
                defining_rel_types: set = set()
                _cur.execute(
                    "SELECT member_entity_types, rel_types_defining_group"
                    " FROM entity_taxonomies"
                )
                for _members, _defining in _cur.fetchall():
                    members_lower = {m.strip().lower() for m in (_members or []) if m}
                    if members_lower & detected_lower:
                        for rt in (_defining or []):
                            if rt:
                                defining_rel_types.add(rt.strip().lower())

                # Component 2: relational rel_types whose head_types/tail_types
                # intersect the detected entity types — plus any taxonomy-defining
                # rel_types from Component 1. Only RELATIONAL (non-hierarchy, non-scalar).
                _cur.execute(
                    "SELECT rel_type, natural_language, head_types, tail_types, category,"
                    "       is_hierarchy_rel"
                    " FROM rel_types"
                    " WHERE tail_types IS NOT NULL"
                    "   AND NOT (tail_types @> ARRAY['SCALAR']::TEXT[])"
                    "   AND COALESCE(is_hierarchy_rel, false) = false"
                )
                for rt, desc, head_types, tail_types, category, _is_hier in _cur.fetchall():
                    rt_lower = (rt or "").strip().lower()
                    if not rt_lower:
                        continue
                    head_lower = {h.strip().lower() for h in (head_types or []) if h}
                    tail_lower = {t.strip().lower() for t in (tail_types or []) if t}
                    # "ANY" head/tail = unconstrained → treat as domain-relevant only
                    # when the taxonomy already named it (avoids dumping all ANY rels).
                    type_match = bool((head_lower & detected_lower) or
                                      (tail_lower & detected_lower))
                    taxonomy_match = rt_lower in defining_rel_types
                    if not (type_match or taxonomy_match):
                        continue
                    selected[rt_lower] = {
                        "description": desc or "",
                        "threshold": _gliner2_threshold_for(head_types, category),
                        # carried for cap prioritization (dropped before GLiNER2 call)
                        "_type_match": type_match,
                        "_category": category,
                    }
        log.debug("ingest.gliner2_domain_relational_selected",
                  detected_types=sorted(detected_lower),
                  defining_rel_types=sorted(defining_rel_types),
                  selected_count=len(selected))
    except Exception as _sel_err:
        log.warning("ingest.gliner2_domain_relational_select_failed",
                    error=str(_sel_err),
                    detected_types=sorted(detected_lower),
                    note="GLiNER2 falls back to scalar-only seed (graceful degradation)")
        return {}
    return selected


def _create_rel_type_in_flow(db, rel_type: str, metadata: dict, confidence: float,
                             source: str = "engine") -> bool:
    """
    Create a novel rel_type in-flow WITH the COMPLETE metadata inferred by the miss-handling
    LLM call (Phase 2 / B.2). Unlike _insert_novel_rel_type (heuristic, ANY/ANY defaults),
    this persists the LLM-inferred head_types/tail_types/category/symmetry/inverse/
    natural_language so WGM type validation is NOT a silent no-op for the new type.

    Refreshes _REL_TYPE_META in-process so the SAME request can use the new type (Phase 3).
    Returns True on success, False on failure (logs loudly — fail loud, never silent).
    """
    try:
        rt_lower = (rel_type or "").lower().strip()
        if not rt_lower:
            log.warning("ingest.create_rel_type_in_flow.empty_rel_type")
            return False

        norm = metadata or {}
        head_types = norm.get("head_types") or ["ANY"]
        tail_types = norm.get("tail_types") or ["ANY"]
        # Layer placement: metadata-first (an LLM-/curated-supplied category wins, unchanged),
        # else resolve against the per-tenant entity_taxonomies overlay (subject-agnostic,
        # hierarchy-aware). No taxonomy match → PENDING (quarantine below), never silent
        # "general". `category_pending` gates BOTH the rel_types.category write AND the
        # taxonomy-append (a pending rel joins no group until the engine places it).
        category = norm.get("category")
        category_pending = False
        if not category:
            category, category_pending = _resolve_or_quarantine_category(
                rt_lower, head_types, tail_types)
        is_symmetric = norm.get("is_symmetric")
        if is_symmetric is None:
            is_symmetric = _infer_symmetry_from_rel_type(rt_lower)
        inverse_rel_type = norm.get("inverse_rel_type")  # None acceptable
        natural_language = norm.get("natural_language")
        # Second-person template (subject baked as "you", Y kept). Validate: must keep
        # Y, must not reintroduce X — else drop (render falls back to 3p + fixup).
        natural_language_2p = norm.get("natural_language_2p") or None
        if natural_language_2p and ("Y" not in natural_language_2p or "X" in natural_language_2p):
            log.warning("ingest.natural_language_2p_invalid",
                        rel_type=rt_lower, value=natural_language_2p,
                        reason="missing_Y_or_has_X — dropping 2p form")
            natural_language_2p = None
        # is_hierarchy_rel is structural — infer from the rel_type name (metadata-driven heuristic).
        is_hierarchy = _infer_hierarchy_from_rel_type(rt_lower)
        label = rt_lower.replace("_", " ").title()

        with db.cursor() as cur:
            cur.execute(
                """
                INSERT INTO rel_types (
                    rel_type, label, natural_language, natural_language_2p, confidence, source, category,
                    is_symmetric, inverse_rel_type, is_hierarchy_rel,
                    tail_types, head_types, fact_class,
                    correction_behavior, engine_generated, created_at
                )
                VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, true, now())
                ON CONFLICT (rel_type) DO UPDATE SET
                    natural_language = COALESCE(EXCLUDED.natural_language, rel_types.natural_language),
                    natural_language_2p = COALESCE(EXCLUDED.natural_language_2p, rel_types.natural_language_2p),
                    category = COALESCE(EXCLUDED.category, rel_types.category),
                    is_symmetric = EXCLUDED.is_symmetric,
                    inverse_rel_type = COALESCE(EXCLUDED.inverse_rel_type, rel_types.inverse_rel_type),
                    head_types = CASE WHEN rel_types.head_types IS NULL
                                        OR rel_types.head_types = ARRAY[]::TEXT[]
                                      THEN EXCLUDED.head_types ELSE rel_types.head_types END,
                    tail_types = CASE WHEN rel_types.tail_types IS NULL
                                        OR rel_types.tail_types = ARRAY[]::TEXT[]
                                      THEN EXCLUDED.tail_types ELSE rel_types.tail_types END,
                    confidence = GREATEST(rel_types.confidence, EXCLUDED.confidence)
                """,
                (
                    rt_lower, label, natural_language, natural_language_2p, confidence, source, category,
                    is_symmetric, inverse_rel_type, is_hierarchy,
                    tail_types, head_types, "B",
                    "supersede",
                ),
            )
        db.commit()

        log.info("ingest.rel_type_created_in_flow",
                 rel_type=rt_lower, source=source, confidence=confidence,
                 category=category, is_symmetric=is_symmetric,
                 inverse_rel_type=inverse_rel_type,
                 head_types=head_types, tail_types=tail_types,
                 is_hierarchy=is_hierarchy)

        # Fix B (dprompt-156): propagate new rel_type to entity_taxonomies so
        # determine_path() routes queries through it on the very same request.
        # Category → taxonomy_name mapping is DB-driven: try exact match first,
        # then ILIKE fallback. No hardcoded category→taxonomy mappings.
        # Guard: hierarchy rel_types must never appear in rel_types_defining_group —
        # they classify entity types and cause taxonomy over-interception if added.
        # PENDING rels join NO group (category is the quarantine marker, not a taxonomy)
        # — they are routed to ontology_evaluations below for engine placement instead.
        if category_pending:
            _quarantine_pending_rel(db, rt_lower, head_types, tail_types,
                                    confidence, natural_language)
        elif category:
            if not _safe_taxonomy_rel_types([rt_lower]):
                log.debug("ingest.taxonomy_append_skipped_hierarchy", rel_type=rt_lower)
            else:
                try:
                    with db.cursor() as _tax_cur:
                        _tax_cur.execute(
                            """
                            UPDATE entity_taxonomies
                            SET rel_types_defining_group = array_append(rel_types_defining_group, %s)
                            WHERE taxonomy_name = %s
                              AND NOT (rel_types_defining_group @> ARRAY[%s]::TEXT[])
                            """,
                            (rt_lower, category, rt_lower),
                        )
                        if _tax_cur.rowcount > 0:
                            log.info("ingest.taxonomy_rel_type_appended",
                                     rel_type=rt_lower, taxonomy=category)
                        else:
                            # Exact match found no row — try ILIKE fallback
                            _tax_cur.execute(
                                """
                                UPDATE entity_taxonomies
                                SET rel_types_defining_group = array_append(rel_types_defining_group, %s)
                                WHERE taxonomy_name ILIKE %s
                                  AND NOT (rel_types_defining_group @> ARRAY[%s]::TEXT[])
                                """,
                                (rt_lower, category, rt_lower),
                            )
                            if _tax_cur.rowcount > 0:
                                log.info("ingest.taxonomy_rel_type_appended_ilike",
                                         rel_type=rt_lower, taxonomy_pattern=category)
                            else:
                                log.debug("ingest.taxonomy_no_match_for_category",
                                          rel_type=rt_lower, category=category)
                    db.commit()
                except Exception as _tax_err:
                    log.warning("ingest.taxonomy_append_failed",
                                rel_type=rt_lower, error=str(_tax_err)[:100])
                    try:
                        db.rollback()
                    except Exception:
                        pass

        # Phase 3: refresh in-process _REL_TYPE_META so the SAME request/session sees it.
        # Also refresh _TAXONOMY_CACHE so determine_path() sees the new rel_type immediately.
        try:
            global _REL_TYPE_META
            _REL_TYPE_META = _build_rel_type_meta(os.environ.get("POSTGRES_DSN", ""))
            # Per-tenant overlay: this rel_type was written to the CURRENT request's
            # tenant schema (db has the tenant search_path). Invalidate that tenant's
            # overlay so _rel_meta()/classify_fact_3d see it within THIS request.
            try:
                _cur_schema = rel_type_overlay.get_current_schema()
                if _cur_schema:
                    rel_type_overlay.invalidate(_cur_schema)
            except Exception:
                pass
            # Keep the routing/validation cache (_REL_TYPE_CACHE) consistent too.
            _refresh_rel_type_cache()
        except Exception as _refresh_err:
            log.warning("ingest.rel_type_in_flow_cache_refresh_failed",
                        rel_type=rt_lower, error=str(_refresh_err))

        try:
            _dsn = os.environ.get("POSTGRES_DSN", "")
            if _dsn:
                _tax_conn = psycopg2.connect(_dsn)
                try:
                    _load_taxonomy_cache(_tax_conn)
                    log.info("ingest.taxonomy_cache_refreshed_in_flow", rel_type=rt_lower)
                finally:
                    _tax_conn.close()
        except Exception as _tax_refresh_err:
            log.warning("ingest.taxonomy_cache_refresh_in_flow_failed",
                        rel_type=rt_lower, error=str(_tax_refresh_err)[:100])

        return True

    except Exception as e:
        log.error("ingest.create_rel_type_in_flow_failed",
                  rel_type=rel_type, source=source, error=str(e))
        try:
            db.rollback()
        except Exception:
            pass
        return False


def _insert_novel_rel_type(db, rel_type: str, confidence: float,
                            source: str = "engine",
                            text_snippet: str = "") -> bool:
    """
    Insert a novel rel_type discovered by GLiNER2 or LLM.
    Metadata populated from heuristics; re_embedder refines over time.

    Returns True if inserted/updated, False on failure (logs error).
    """
    try:
        rt_lower = rel_type.lower().strip()
        if not rt_lower:
            log.warning("insert_novel_rel_type: empty rel_type provided")
            return False

        # Layer placement: taxonomy-driven (subject-agnostic, hierarchy-aware), not the
        # keyword zoo. This call site mints with no typed entity pair (head/tail default to
        # ANY), so a brand-new rel typically resolves to PENDING → quarantined to
        # ontology_evaluations for the growth engine to place (freq>=3 / cosine-map / LLM),
        # never a silent permanent "general". Other metadata stays heuristic-bootstrap.
        category, category_pending = _resolve_or_quarantine_category(rt_lower, ["ANY"], ["ANY"])
        is_symmetric = _infer_symmetry_from_rel_type(rt_lower)
        inverse = _infer_inverse_rel_type(rt_lower)
        is_hierarchy = _infer_hierarchy_from_rel_type(rt_lower)

        # Humanize label from rel_type name
        label = rt_lower.replace("_", " ").title()

        with db.cursor() as cur:
            cur.execute("""
                INSERT INTO rel_types (
                    rel_type, label, confidence, source, category,
                    is_symmetric, inverse_rel_type, is_hierarchy_rel,
                    tail_types, head_types, fact_class,
                    correction_behavior, engine_generated, created_at
                )
                VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, now())
                ON CONFLICT (rel_type) DO UPDATE SET
                    confidence = GREATEST(rel_types.confidence, %s)
            """, (
                rt_lower,                  # rel_type
                label,                     # label
                confidence,                # confidence
                source,                    # source (gliner2_discovery|llm_inference)
                category,                  # category
                is_symmetric,              # is_symmetric
                inverse,                   # inverse_rel_type
                is_hierarchy,              # is_hierarchy_rel
                ["ANY"],                   # tail_types (default)
                ["ANY"],                   # head_types (default)
                "B",                       # fact_class (LLM-inferred following ontology)
                "supersede",               # correction_behavior
                False,                     # engine_generated
                confidence                 # confidence (for ON CONFLICT)
            ))
        db.commit()

        log.info("ingest.rel_type_auto_created",
                 rel_type=rt_lower, source=source, confidence=confidence,
                 category=category, is_symmetric=is_symmetric,
                 is_hierarchy=is_hierarchy)

        # Unplaced novel rel → quarantine for engine placement (no permanent orphan).
        if category_pending:
            _quarantine_pending_rel(db, rt_lower, ["ANY"], ["ANY"], confidence, None)

        # Invalidate cache so next query uses updated metadata
        global _REL_TYPE_META
        _REL_TYPE_META = _build_rel_type_meta(os.environ.get("POSTGRES_DSN", ""))

        return True

    except Exception as e:
        log.warning("ingest.rel_type_creation_failed",
                    rel_type=rel_type, source=source, error=str(e))
        db.rollback()
        return False

def _coerce_scalar(value: str) -> tuple:
    """
    Coerce a scalar value string to (value_text, value_int, value_float, value_date).
    Returns appropriate typed value AND value_text copy for all paths (dprompt-132).
    """
    # Try integer - populate both value_text and value_int
    try:
        int_val = int(value)
        return (str(int_val), int_val, None, None)
    except ValueError:
        pass
    # Try float - populate both value_text and value_float
    try:
        float_val = float(value)
        return (str(float_val), None, float_val, None)
    except ValueError:
        pass
    # Try date (basic YYYY-MM-DD) - populate value_date and value_text
    if re.match(r'^\d{4}-\d{2}-\d{2}$', value):
        return (value, None, None, value)
    # Fall back to text
    return (value, None, None, None)

def _detect_preference_signal(text: str) -> bool:
    text_lower = text.lower()
    return any(signal in text_lower for signal in _PREFERENCE_SIGNALS)

def _extract_identity(text: str) -> str | None:
    """Return the user's stated name if a self-identification pattern is found.

    LOOSE ON INPUT (CLAUDE.md "dumb registry / smart query"): registration accepts
    the captured candidate RAW. We do NOT gate on capitalization here — a legitimate
    lowercase "my name is alex" must register, and a loose candidate like "worried"
    is allowed to land as just-another alias (hundreds of also_known_as cost nothing;
    they all hang off the one user). Discernment about whether a stored alias is junk
    happens ONLY at READ time, when the user's name is surfaced (see the owner-identity
    lookup in /query). The capture group is (\\w+) so source casing survives into
    storage if useful downstream, but we never gate on it at ingest. Fail-safe: no
    match → None (today's no-op behavior).
    """
    for pattern in _IDENTITY_PATTERNS:
        m = pattern.search(text)
        if m:
            return m.group(1).lower().strip()
    return None


# Patterns for extracting explicitly preferred names from preference signals.
# Captured group is (\w+) so source casing survives into storage if useful, but the
# ingest path does NOT gate on it — registration is LOOSE ON INPUT (see
# _extract_preferred_name). Read-time discernment is _is_surfaceable_user_name.
_PREFERRED_NAME_PATTERNS = [
    # Must NOT be preceded by "who" — those are third-person.
    re.compile(r"(?<!who )(?<!she )(?<!he )(?<!it )(?<!they )\bprefers?\s+to\s+be\s+called\s+(\w+)", re.IGNORECASE),
    re.compile(r"(?<!who )(?<!she )(?<!he )(?<!it )(?<!they )\bprefers?\s+you\s+call\s+(?:me|them|her|him)\s+(\w+)", re.IGNORECASE),
    re.compile(r"(?<!who )(?<!she )(?<!he )(?<!it )(?<!they )\bgoes\s+by\s+(\w+)", re.IGNORECASE),
    re.compile(r"\bgo\s+by\s+(\w+)", re.IGNORECASE),
    re.compile(r"(?<!who )(?<!she )(?<!he )(?<!it )(?<!they )\bpreferred\s+name\s+is\s+(\w+)", re.IGNORECASE),
    re.compile(r"\bplease\s+call\s+me\s+(\w+)", re.IGNORECASE),
    re.compile(r"(?<!who )(?<!she )(?<!he )(?<!it )(?<!they )\bknown\s+as\s+(\w+)", re.IGNORECASE),
    re.compile(r"(?<!who )(?<!she )(?<!he )(?<!it )(?<!they )\blike\s+to\s+(?:be|go)\s+(?:by|called)\s+(\w+)", re.IGNORECASE),
]


def _extract_preferred_name(text: str) -> str | None:
    """Return the preferred name if a preference signal is found with an explicit name.

    LOOSE ON INPUT, same as _extract_identity: registration accepts the captured
    candidate RAW (no capitalization gate), so a lowercase explicit "I prefer to be
    called alex" registers, and a loose candidate like "worried" is allowed to land
    as a preferred alias. The smart filtering — refusing to SURFACE a junk preferred
    name as the user's display name — happens at READ time in /query. The only ingest
    guard kept is the single-character length floor (a bare initial is not a name).
    Fail-safe: no match → None.
    """
    for pattern in _PREFERRED_NAME_PATTERNS:
        m = pattern.search(text)
        if m:
            name = m.group(1).lower().strip()
            if len(name) > 1:
                return name
    return None

def _resolve_user_anchor(entity_id: str, user_id: str) -> str:
    """Return the canonical user UUID if entity_id matches, else return entity_id."""
    return user_id if entity_id == user_id else entity_id


def _convert_gliner_relations_to_edges(gliner_relations_dict: dict,
                                       gliner_cache: dict | None = None) -> list[dict] | None:
    """
    Convert GLiNER2.extract_relations() output to EdgeInput format.

    GLiNER2 returns: {
        "relation_extraction": {
            "spouse": [("jordan", "user")],
            "instance_of": [("theo", "person")],
        }
    }

    Convert to: [
        {"subject": "jordan", "object": "user", "rel_type": "spouse", "confidence": 0.85, "fact_provenance": "gliner2"},
        {"subject": "theo", "object": "person", "rel_type": "instance_of", "confidence": 0.85, "fact_provenance": "gliner2"},
    ]

    Severance #4 (Phase 1): carry subject_type/object_type on each edge, sourced from the
    GLiNER2 NER cache ({entity_name_lower: ENTITY_TYPE}) when available. Without this,
    GLiNER2-path edges feed ontology_evaluations with NULL types, starving head_types/
    tail_types inference. Types are looked up by lowercased name; absent → None (not blank).
    """
    # FIXED: Check for "relation_extraction" (correct GLiNER2 output format)
    if not gliner_relations_dict or "relation_extraction" not in gliner_relations_dict:
        return None

    cache = gliner_cache or {}

    edges = []
    relation_data = gliner_relations_dict.get("relation_extraction", {})

    # relation_data is dict of {rel_type: [(subject, object), ...], ...}
    for rel_type, entity_pairs in relation_data.items():
        if not entity_pairs:
            continue

        for subject, obj in entity_pairs:
            # Convert GLiNER2 tuple format (subject, object) to EdgeInput dict format
            subject = (subject or "").lower().strip()
            object_val = (obj or "").lower().strip()
            rel_type_clean = (rel_type or "").lower().strip()

            if subject and object_val and rel_type_clean:
                # SELF-LOOP GUARD (RC-locative-drop FIX 3): drop degenerate self-referential
                # pairs (subject == object) for NON-identity rels — e.g. a GLiNER2 mis-map of
                # "live in Ottawa" → owns(ottawa, ottawa). Mirrors the /ingest guard
                # (main.py ~12881): identity rels where subject == object IS the norm
                # (the entity IS its own name), so pref_name/also_known_as are exempt.
                # Deterministic, subject-agnostic; stops the self-loop at emission rather
                # than relying on the downstream /ingest backstop.
                if subject == object_val and rel_type_clean not in ("pref_name", "also_known_as"):
                    continue
                # Source types from the NER cache (metadata-driven; None when unknown).
                subject_type = cache.get(subject) or None
                object_type = cache.get(object_val) or None
                edges.append({
                    "subject": subject,
                    "object": object_val,
                    "rel_type": rel_type_clean,
                    "confidence": 0.85,  # Default GLiNER2 confidence
                    "fact_provenance": "gliner2",
                    "subject_type": subject_type,
                    "object_type": object_type,
                })

    return edges if edges else None


def _build_relational_candidate_labels(rel_meta: dict, cap: int = _GLINER2_RELATIONAL_LABEL_CAP) -> dict:
    """Build the GLiNER2 relation candidate label set for the trigger-span pass.

    Input: the per-tenant merged rel_type metadata dict ({rel_type: meta}) as returned
    by ``_rel_meta()`` (public seed ∪ tenant overlay). Output: the ``relation_types``
    argument GLiNER2's ``extract_relations`` expects —
    ``{rel_type: {"description": <short>, "threshold": <float>}}``.

    PITFALL 11 (GLiNER2 PURITY): the label is the concise rel_type NAME, and the
    description is the rel_type's short ``natural_language`` (or empty string) — NEVER a
    string_agg blob, taxonomy prose, or pattern. Multi-clause/blob descriptions are
    dropped to the empty string so a bad seed cannot pollute GLiNER2's scoring. The set
    is deterministically CAPPED at ``cap`` (relational budget) — GLiNER2's GLiREL trainer
    used a ~25-label-per-instance cap (arxiv:2501.03172); overshooting craters confidence.

    Both relational and scalar rel_types are included (the trigger spans are focused, so
    a small scalar+relational candidate set is the point — capture KNOWN relations AND
    scalars on the span). Hierarchy rels are included as relational (they are object-UUID
    facts, same as graph rels). Per-type thresholds reuse ``_gliner2_threshold_for`` so
    candidates inherit the same metadata-driven discipline as the /ingest candidate path.

    Returns {} on empty/garbage input — caller then skips the GLiNER2 pass cleanly.
    """
    if not rel_meta or not isinstance(rel_meta, dict):
        return {}

    def _concise_desc(nl) -> str:
        # Keep only short, single-clause natural_language; drop blobs (Pitfall 11).
        if not nl or not isinstance(nl, str):
            return ""
        nl = nl.strip()
        # Reject obvious blobs: too long, or aggregated/multi-entry prose.
        if len(nl) > 80 or "\n" in nl or ";" in nl:
            return ""
        return nl

    # SEEDED BACKBONE RESERVATION (RC-locative-drop): the canonical relation backbone
    # (rel_types whose source IN ('wikidata','builtin')) is the always-present language
    # scaffold and must NOT be evicted from the candidate set by tenant-grown rels. We
    # carry a seeded-flag as the PRIMARY sort key so seeded rels are reserved their slots
    # within the cap first; grown rels fill only the REMAINING slots. The cap is UNCHANGED
    # (Pitfall 11 — overshooting craters GLiNER2 confidence). Deterministic.
    _SEEDED_SOURCES = ("wikidata", "builtin")

    ranked: list[tuple[int, int, str, dict]] = []
    for rel_type, meta in rel_meta.items():
        if not rel_type or not isinstance(meta, dict):
            continue
        rt = str(rel_type).strip().lower()
        if not rt:
            continue
        head_types = meta.get("head_types") or []
        category = meta.get("category")
        entry = {
            "description": _concise_desc(meta.get("natural_language")),
            "threshold": _gliner2_threshold_for(head_types, category),
        }
        # Seeded backbone first (0), tenant-grown after (1) — reserve seeded slots.
        source = str(meta.get("source") or "").strip().lower()
        seeded_rank = 0 if source in _SEEDED_SOURCES else 1
        # Within each tier, deterministic priority so the cap keeps the most useful labels:
        # human/identity categories first, network/bootstrap last.
        is_network = (not head_types and category == "network")
        prio = 2 if is_network else (0 if category in ("identity", "physical", "temporal", "work", "family") else 1)
        ranked.append((seeded_rank, prio, rt, entry))

    # Stable, deterministic ordering: seeded-first, then priority asc, then rel_type name asc.
    ranked.sort(key=lambda x: (x[0], x[1], x[2]))

    candidates: dict = {}
    for _seeded, _prio, rt, entry in ranked:
        if len(candidates) >= cap:
            break
        candidates[rt] = entry
    return candidates


# ── THE MERGE BRAIN — one assembly line, both doors ────────────────────────────────────────────
# THE DIAGNOSED WALL (capture 1/10): GLiNER2 (entities), spaCy (grammar/temporal/self-ref), and the
# LLM (long-tail relations) are three GOOD components that run SEPARATELY and never MERGE into a
# fact. GLiNER2 cleanly types "Samsung Galaxy S22"; spaCy cleanly parses "I got … on Feb 20 2023";
# but the verb-lift needs a GLiNER2 entity PAIR (and the Samsung turn has ONE entity + the self-ref
# "I"), so the clean components are thrown away → junk rels / dropped facts. This is the assembly
# line that COMPOSES each component's STRENGTH into one grounded edge:
#   • spaCy → SUBJECT (self-ref "I"/"we" → user, or a nominal entity), PREDICATE (the user's own
#     verb lemma + load-bearing particle), OBJECT-attachment (which span the verb targets), DATE
#     (event_date via the existing temporal lane, bound to THIS edge only).
#   • GLiNER2 → the typed ENTITY that becomes the edge OBJECT (positionally overlapping the spaCy
#     object span) — so the object IS the GLiNER2 entity, never a verb-lift-invented noun.
#   • LLM → the GATED relation PROPOSAL (long-tail only): fired ONLY when grammar produced no
#     content predicate; verbatim-anchored, no rewording; disposed by the WGM gate + Class C.
# Each component contributes its slice; the merge composes; the /ingest WGM gate disposes (A/B/C).
# Flag-gated (MERGE_CAPTURE, default ON), fail-safe to today's lanes on any miss/disable.
MERGE_CAPTURE = os.getenv("MERGE_CAPTURE", "true").lower() not in ("0", "false", "no")
# Sub-flag: allow the GATED LLM relation proposal when grammar leaves the predicate slot empty.
# OFF → the merge is purely deterministic (spaCy verb + GLiNER2 entity); a no-verb construction is
# left to the other deterministic seams. The grammar-named predicate path is UNAFFECTED by this flag.
MERGE_LLM_RELATION = os.getenv("MERGE_LLM_RELATION", "true").lower() not in ("0", "false", "no")


def _merge_object_for_span(
    span: str,
    obj_start: int,
    obj_end: int,
    obj_fallback: str,
    entities_by_type: dict,
) -> tuple[str, str | None]:
    """Pick the EDGE OBJECT for an SVO clause: PREFER a GLiNER2-typed entity overlapping the spaCy
    object span; fall back to the spaCy object-head phrase when GLiNER2 surfaced nothing there.

    Returns ``(object_surface, object_type_or_None)``. The GLiNER2 entity wins so the object carries
    its TYPE (Samsung Galaxy S22 / Object) and is the model's clean span, not a parser fragment.
    Overlap is positional (char ranges), not a fragile string compare. Deterministic, fail-safe."""
    try:
        span_lower = (span or "").lower()
        best = None  # (overlap_len, name, TYPE)
        for etype, names in (entities_by_type or {}).items():
            if not names or not isinstance(names, list):
                continue
            for nm in names:
                nm = (nm or "").strip()
                if not nm:
                    continue
                # locate every occurrence of this entity in the span; keep the one overlapping the
                # spaCy object range most.
                start = 0
                low = nm.lower()
                while True:
                    idx = span_lower.find(low, start)
                    if idx < 0:
                        break
                    e_lo, e_hi = idx, idx + len(low)
                    overlap = min(e_hi, obj_end) - max(e_lo, obj_start)
                    if overlap > 0 and (best is None or overlap > best[0]):
                        best = (overlap, nm, (etype or "").upper() or None)
                    start = idx + 1
        if best is not None:
            return (best[1].strip().lower(), best[2])
    except Exception as e:  # noqa: BLE001 — fail-safe: fall back to the grammar object
        log.debug("merge.object_pick_failed", error=str(e)[:120])
    return ((obj_fallback or "").strip().lower(), None)


async def _merge_capture_edges(
    text: str,
    user_id: str,
    gmodel,
    schema_name: str | None,
    reference=None,
    seen: set | None = None,
) -> list[dict]:
    r"""THE MERGE BRAIN (one assembly line, used by BOTH /harvest-spans and /extract/rewrite).

    Compose a grounded edge from each component's STRENGTH for every SVO clause spaCy can parse:
      1. spaCy ``analyze_svo_relations`` → (subject, predicate, object-span, negated) for each clause.
      2. SUBJECT: a 1st-person self-ref ("I"/"we") → the canonical ``user`` subject; otherwise the
         nominal subject surface (the /ingest resolver grounds it — strong ingest, lean query).
      3. OBJECT: PREFER a GLiNER2-typed entity overlapping the spaCy object span (``_merge_object_for_
         span``) so the object IS the GLiNER2 entity (carries its type); else the spaCy object head.
      4. PREDICATE: the user's OWN verb (deterministically normalized via ``canonical.resolve_canonical``
         → known synonym collapses to the canonical PK; novel verb grows via the source="mcp" path).
         "USER IS TRUTH": grammar names the relation. The GATED LLM proposal fires ONLY when grammar
         produced NO content predicate (ambiguous construction) — it proposes a relation token
         (verbatim-anchored, no rewording) that the WGM gate then disposes.
      5. DATE: this clause's OWN ``event_date`` (the existing ``extract_event_date`` resolver, incl.
         the vague-month gate) bound to THIS edge only — never smeared across clauses.
      6. MERGE: assemble (subject, rel_type, object, [event_date]) → one edge → returned for /ingest
         (WGM gate → A/B/C). Each filled edge carries fact_provenance="user_stated".

    Subject-agnostic, metadata-driven, GLiNER2-pure (entities only). Negated clauses are SKIPPED
    (absence modeling deferred). Dedups against the shared ``seen`` set so a stronger lane wins.
    Fail-safe: flag off / layer unavailable / any error → ``[]`` (the caller keeps today's lanes)."""
    if not MERGE_CAPTURE or not text or not text.strip():
        return []
    if seen is None:
        seen = set()
    try:
        from src.extraction.linguistics import (
            analyze_svo_relations, linguistics_available,
            segment_clauses, extract_event_date_and_residue,
        )
        if not linguistics_available():
            return []
    except Exception as e:  # noqa: BLE001 — fail-safe: never break ingest
        log.debug("merge.import_failed", error=str(e)[:120])
        return []

    # ── CLAUSE DECOMPOSITION (peel-and-drop-out is PER CLAUSE) ──────────────────────────────────
    # Different clauses carry different dates ("I got X on Feb 20. I sold Y last week"), so the date
    # peel must be per-clause, not whole-text. Segment first; fall back to the whole text as a single
    # clause when the segmenter is unavailable (preserves single-sentence behavior exactly).
    try:
        _clauses = segment_clauses(text) or [text]
    except Exception:  # noqa: BLE001 — fail-safe
        _clauses = [text]
    if not _clauses:
        _clauses = [text]

    _dsn = os.environ.get("POSTGRES_DSN")
    _labels = _gliner2_entity_labels(source="user") if gmodel is not None else None
    out: list[dict] = []

    for _clause in _clauses:
        if not _clause or not _clause.strip():
            continue
        # ── 1. PEEL THE DATE FIRST → date-free residue ─────────────────────────────────────────
        # Extract THIS clause's event_date and DROP the date span out of the clause text, so the
        # circumstantial date PP ("on February 20th") is GONE before the SVO build and CANNOT fold
        # into the predicate (no spurious ``get_on`` / date-as-object). A clause with no date → the
        # residue IS the clause unchanged (clause_iso None). Fail-safe inside the helper.
        clause_iso = clause_gran = None
        residue = _clause
        if reference is not None:
            try:
                clause_iso, clause_gran, residue = extract_event_date_and_residue(_clause, reference)
            except Exception:  # noqa: BLE001 — peel miss → undated edge on the full clause
                clause_iso, clause_gran, residue = None, None, _clause
        if not residue or not residue.strip():
            residue = _clause

        # ── 2. BUILD THE RELATION ON THE RESIDUE ──────────────────────────────────────────────
        # SVO + GLiNER2 both run on the date-stripped residue so the object char-offsets line up
        # with the entity-name positions in the SAME string (overlap match stays consistent).
        try:
            svos = analyze_svo_relations(residue) or []
        except Exception as e:  # noqa: BLE001
            log.warning("merge.svo_failed", user_id=user_id[:8], error=str(e)[:120])
            continue
        if not svos:
            continue

        # GLiNER2 entity typing on the RESIDUE (concise zero-shot personal-memory labels — Pitfall 11,
        # GLiNER2 stays an entity TYPER, never names the rel). Overlap-matched by char range.
        _ent_map: dict = {}
        if gmodel is not None and _labels is not None:
            try:
                _ner = gmodel.extract_entities(residue, _labels, max_len=2048)
                _ent_map = (_ner or {}).get("entities") or {}
            except Exception as _ee:  # noqa: BLE001 — typing miss → grammar object fallback
                log.debug("merge.entities_failed", error=str(_ee)[:120])
                _ent_map = {}

        for svo in svos:
            try:
                if svo.negated:
                    continue
                subject = "user" if svo.subject_is_self else (svo.subject_text or "").strip().lower()
                if not subject:
                    continue
                # OBJECT — prefer the GLiNER2 entity overlapping the spaCy object span (carries type).
                obj_surface, obj_type = _merge_object_for_span(
                    residue, svo.object_char_start, svo.object_char_end, svo.object_text, _ent_map)
                if not obj_surface or len(obj_surface) < 2:
                    continue
                # PREDICATE — the user's own BARE verb (the date is peeled, so no ``get_on``), resolved
                # against the tenant ontology (known synonym → canonical PK; novel → grow via the
                # source="mcp"/user_stated /ingest path). Grammar names the relation ("USER IS TRUTH").
                rel = (svo.predicate or "").strip().lower()
                if rel and schema_name:
                    try:
                        from src.ontology import canonical as _canon
                        _res = _canon.resolve_canonical(rel, dsn=_dsn, schema=schema_name)
                        if _res.get("canonical"):
                            rel = _res["canonical"]
                    except Exception as _ce:  # noqa: BLE001 — novel → mint via growth path
                        log.debug("merge.resolve_failed", error=str(_ce)[:120])
                # GATED LLM RELATION PROPOSAL — long-tail only: fired ONLY when grammar produced NO
                # content predicate (svo.predicate empty/None). Verbatim-anchored against the residue
                # (no rewording); the WGM gate disposes. (Residue, not the raw clause: the date is not
                # a relation and must not be offered as a connecting phrase.)
                if not rel and MERGE_LLM_RELATION and gmodel is not None:
                    try:
                        rel = await _merge_llm_relation_proposal(
                            residue, subject, obj_surface, user_id)
                    except Exception as _le:  # noqa: BLE001 — fail-safe: drop the edge, never guess
                        log.debug("merge.llm_relation_failed", error=str(_le)[:120])
                        rel = ""
                if not rel:
                    continue
                key = (subject, rel, obj_surface)
                if key in seen:
                    continue
                seen.add(key)
                edge = {
                    "subject": subject,
                    "rel_type": rel,
                    "object": obj_surface,
                    "fact_provenance": "user_stated",
                    "confidence": 0.8,
                }
                if svo.subject_is_self:
                    edge["subject_type"] = "Person"
                if obj_type:
                    edge["object_type"] = obj_type
                # ── 3. ATTACH the peeled date (event_date SCALAR) to THIS edge only ─────────────
                if clause_iso:
                    edge["event_date"] = clause_iso
                    edge["event_date_granularity"] = clause_gran or "day"
                out.append(edge)
            except Exception as _me:  # noqa: BLE001 — per-clause fail-safe
                log.debug("merge.clause_failed", error=str(_me)[:120])
                continue
    if out:
        log.info("merge.edges_built", user_id=user_id[:8],
                 schema=(schema_name or "")[:24], clauses=len(_clauses), edges=len(out))
    return out


async def _merge_llm_relation_proposal(
    text: str, subject: str, object_surface: str, user_id: str,
) -> str:
    """GATED LLM relation PROPOSAL — the long-tail slot-filler for the merge brain.

    Fired ONLY when the grammar produced NO content predicate for a clause that DOES have a clean
    (subject, object) pair (GLiNER2 entity + spaCy subject). The LLM proposes the SINGLE relation
    token connecting them, USING THE USER'S OWN WORDS — it must be a verb/phrase verbatim present in
    ``text`` (the verbatim guard drops anything else, fail-loud), it NEVER rewords or invents. The
    proposed token is snake_cased via ``normalize_rel`` and returned for the WGM gate to dispose
    (Class C if novel/unknown). Returns "" on any miss/failure (caller drops the edge, never guesses).

    This is NOT a free triple emitter: the subject and object are already fixed by spaCy + GLiNER2;
    the LLM only names the relation the grammar could not, and the gate still validates it."""
    if not text or not subject or not object_surface:
        return ""
    try:
        from .llm_calls import call_llm_with_retry_async
        messages = [
            {"role": "system", "content": (
                "You are given one sentence and two things in it: a SUBJECT and an OBJECT. Return the "
                "SINGLE verb (or short verb phrase) FROM THE SENTENCE that connects the subject to "
                "the object.\n"
                "RULES:\n"
                "- Return the COMPLETE verb, including any prefix or particle that is part of it "
                '("pre-ordered" -> "pre-ordered", NEVER "pre"; "picked up" -> "picked up", NEVER '
                '"up").\n'
                "- It MUST be an action/relationship word that links the subject to the object. NEVER "
                'return a time word ("week", "ago", "yesterday"), a number, a stray noun, or a '
                "fragment.\n"
                "- COPY THE WORD(S) EXACTLY as they appear; do NOT reword, paraphrase, or invent.\n"
                "- If there is no single connecting verb, return an empty string.\n"
                'Respond with STRICT JSON only: {"relation":"<verbatim verb phrase or empty>"}.'
            )},
            {"role": "user", "content": (
                f"Sentence: {text}\nSubject: {subject}\nObject: {object_surface}"
            )},
        ]
        res = await call_llm_with_retry_async(
            messages=messages,
            model=LLMModels.get("INTENT_PRECLASSIFY"),
            user_id=user_id,
            max_retries=1,                   # latency-bounded; fail open to dropping the edge
            operation="INTENT_PRECLASSIFY",  # small focused proposal (4s / 32 tok)
        )
    except Exception as e:  # noqa: BLE001 — fail-safe
        log.debug("merge.llm_proposal_call_failed", user_id=user_id[:8], error=str(e)[:120])
        return ""
    if not isinstance(res, dict):
        return ""
    proposed = (res.get("relation") or "").strip()
    if not proposed or len(proposed) < 2:
        return ""
    # VERBATIM GUARD (HARD CONSTRAINT — the LLM never rewords): the proposed phrase must appear
    # VERBATIM (case-insensitive) in the source. A reworded/invented relation is DROPPED (fail-loud).
    if proposed.lower() not in text.lower():
        log.warning("merge.llm_proposal_non_verbatim", user_id=user_id[:8], proposed=proposed[:32])
        return ""
    # Normalize the user's own verb to a rel token (RUNG-1 morphology); the WGM gate disposes it.
    try:
        from src.ontology.canonical import normalize_rel
        token = normalize_rel(proposed) or proposed.strip().lower().replace(" ", "_")
    except Exception:  # noqa: BLE001
        token = proposed.strip().lower().replace(" ", "_")
    return token or ""


def _verb_lift_edges_for_spans(
    spans: list[str],
    gmodel,
    schema_name: str | None,
    seen: set | None = None,
) -> list[dict]:
    """Shared deterministic verb-lift growth helper (RC-route-growth-ingest Phase 0).

    For each fact-bearing span: run GLiNER2 ``extract_entities`` (concise zero-shot labels —
    Pitfall 11, GLiNER2 stays an entity-pair FINDER + TYPER, never named the relation), lift the
    user's connecting verb between each entity pair (``predicate_span.lift_predicate``), then
    resolve the lifted token deterministically against the tenant ontology
    (``canonical.resolve_canonical(schema=<tenant>)``). The edge's rel_type is:
      • the canonical PK when the user's verb resolves to a KNOWN rel (RUNG 2/3 hit), OR
      • the RUNG-1 normalized USER VERB when it is novel (canonical=None) → this is the
        net-new predicate that GROWS via the existing source="mcp"/user_stated /ingest path.

    The predicate is ALWAYS the user's own verb (deterministically normalized only) — no LLM,
    no GLiNER2 label, names the relation ("USER IS TRUTH"). Returns growth-ready edges carrying
    fact_provenance="user_stated".

    DEDUP / NON-REGRESSION: skips any (subject, rel_type, object) already in ``seen`` (so the
    closed-set ``extract_relations`` edges win for a pair they already named — RUNG 2 canonical
    wins; the verb-lift only ADDS net-new predicates). Mutates ``seen`` with the keys it adds.

    NO PUBLIC FALLTHROUGH: if ``schema_name`` is unset, canonical resolution is skipped (the
    lifted token is used as-is and the existing /ingest growth guards refuse public writes).

    Fail-safe: any failure on a span/pair is logged and skipped; never raises.
    """
    if not gmodel:
        return []
    try:
        from src.extraction import predicate_span
        from src.ontology import canonical
    except Exception as e:  # import problem → fall back to scorer-only
        log.debug("verb_lift.import_failed", error=str(e)[:120])
        return []

    if seen is None:
        seen = set()
    _dsn = os.environ.get("POSTGRES_DSN")
    # Concise personal-memory zero-shot labels (Pitfall 11). GLiNER2 typing only.
    _labels = _gliner2_entity_labels(source="user")
    out: list[dict] = []
    for _span in spans:
        try:
            _ner = gmodel.extract_entities(_span, _labels, max_len=2048)
        except Exception as _ee:
            log.debug("verb_lift.entities_error", error=str(_ee)[:120])
            continue
        if not _ner:
            continue
        _ents = _ner.get("entities") or {}
        try:
            _cand = predicate_span.lift_edges_from_entities(_span, _ents)
        except Exception as _le:
            log.debug("verb_lift.lift_error", error=str(_le)[:120])
            continue
        for _ed in _cand:
            _s = (_ed.get("subject") or "").strip().lower()
            _o = (_ed.get("object") or "").strip().lower()
            _lifted = (_ed.get("rel_type") or "").strip().lower()
            if not (_s and _o and _lifted):
                continue
            # Resolve the user's verb against the tenant ontology (known synonym → canonical).
            _rel = _lifted
            if schema_name:
                try:
                    _res = canonical.resolve_canonical(_lifted, dsn=_dsn, schema=schema_name)
                    if _res.get("canonical"):
                        _rel = _res["canonical"]
                except Exception as _ce:
                    log.debug("verb_lift.resolve_error", error=str(_ce)[:120])
                    _rel = _lifted  # novel → mint via growth path
            _ed["rel_type"] = _rel
            _key = (_s, _rel, _o)
            if _key in seen:
                continue  # a known rel already named this pair — don't override (RUNG 2 wins)
            seen.add(_key)
            out.append(_ed)
    if out:
        log.info("verb_lift.edges_added",
                 schema=(schema_name or "")[:24], spans=len(spans), edges=len(out))
    return out


def _build_rel_type_meta(dsn: str, schema_name: str | None = None) -> dict:
    """Load rel_types metadata as public seed ∪ (optional) tenant schema overlay.

    Delegates to rel_type_overlay.resolve_meta so the per-tenant overlay (public seed
    ∪ <tenant>.rel_types, tenant overriding) is the SINGLE source of truth for known
    rel_types. With schema_name=None this returns the public seed only — that is the
    process-wide _REL_TYPE_META baseline loaded at startup / on refresh. Per-request
    readers resolve the tenant overlay via the ContextVar (see _rel_meta()).
    """
    try:
        return rel_type_overlay.resolve_meta(dsn, schema_name)
    except Exception as e:
        log.warning("startup.rel_type_meta_builder_failed", error=str(e))
        return {}


def _rel_meta(rel_type: str | None = None):
    """Resolve rel_type metadata for the CURRENT request's tenant (public seed ∪
    tenant overlay), honoring the schema bound in rel_type_overlay's ContextVar.

    • _rel_meta()            → full merged {rel_type: meta} dict for this tenant.
    • _rel_meta("spouse")    → meta dict for one rel_type (already lowercased by caller
                               convention), {} if unknown.

    Cache-hit path is DB-free. When no tenant schema is bound (startup, internal
    callers, non-request context) this falls back to the module-level _REL_TYPE_META
    seed so behaviour is unchanged outside request scope.
    """
    schema = rel_type_overlay.get_current_schema()
    if not schema:
        merged = _REL_TYPE_META
    else:
        merged = rel_type_overlay.resolve_meta(
            os.environ.get("POSTGRES_DSN", ""), schema
        ) or _REL_TYPE_META
    if rel_type is None:
        return merged
    return merged.get(rel_type, {})

def classify_fact_3d(
    rel_type: str,
    object_value: str,
    registry,
    user_id: str,
) -> dict:
    """
    Classify fact along three dimensions: STORAGE × CLASS × DIRECTION

    All determinations use rel_types metadata (deterministic on create).
    Heuristics only for unknown rel_types (rare, engine-generated).

    Returns:
        {
            "storage": "scalar" | "relational" | "hierarchical",
            "direction": "asymmetric" | "symmetric" | "hierarchical" | None,
            "is_symmetric": bool,
            "inverse_rel_type": str | None,
            "is_hierarchy_rel": bool,
            "reason": str,
        }
    """
    rt_lower = rel_type.lower()
    stripped = object_value.strip()

    if not stripped:
        return {
            "storage": None,
            "direction": None,
            "reason": "empty value",
        }

    # L0: ONTOLOGY CONSTRAINT (METADATA-FIRST)
    # Per-tenant overlay: resolve known rel_types as public seed ∪ this request's
    # tenant schema (grown/curated). _rel_meta() honors the ContextVar-bound schema;
    # falls back to the seed _REL_TYPE_META outside request scope. Cache-hit = DB-free.
    rel_meta = _rel_meta(rt_lower) or None

    if rel_meta:  # Known rel_type
        tail_types = rel_meta.get("tail_types", [])
        is_hierarchy = rel_meta.get("is_hierarchy_rel", False)
        is_symmetric = rel_meta.get("is_symmetric", False)
        inverse_rel = rel_meta.get("inverse_rel_type")

        # Determine storage path
        if "SCALAR" in tail_types:
            storage = "scalar"
            direction = None
        elif is_hierarchy:
            storage = "hierarchical"
            direction = "hierarchical"
        else:
            storage = "relational"
            direction = "symmetric" if is_symmetric else "asymmetric"

        return {
            "storage": storage,
            "direction": direction,
            "is_symmetric": is_symmetric,
            "inverse_rel_type": inverse_rel,
            "is_hierarchy_rel": is_hierarchy,
            "reason": f"ontology: {rt_lower} in rel_types (deterministic)",
        }

    # L1–L5: VALUE HEURISTICS (FALLBACK FOR UNKNOWN REL_TYPES)
    import re
    stripped_lower = stripped.lower()

    # L1: Numeric patterns
    if re.match(r'^-?\d+$', stripped):
        return {
            "storage": "scalar",
            "direction": None,
            "reason": "heuristic: integer pattern (unknown rel_type)",
        }

    # L2: Date patterns
    if re.match(r'^\d{4}-\d{2}-\d{2}$', stripped):
        return {
            "storage": "scalar",
            "direction": None,
            "reason": "heuristic: date pattern (unknown rel_type)",
        }

    # L3: UUID pattern (use existing _UUID_PATTERN if available)
    try:
        if _UUID_PATTERN.match(stripped):
            return {
                "storage": "relational",
                "direction": "asymmetric",
                "reason": "heuristic: UUID pattern (unknown rel_type)",
            }
    except NameError:
        pass

    # L4: Entity alias lookup. Tenant isolation is via the per-tenant search_path;
    # the tenant entity_aliases table is keyed by (alias) and has NO user_id column
    # (only the public SEED template does). Filtering by user_id here raised
    # UndefinedColumn under the tenant search_path and — swallowed below without a
    # rollback — left registry.db_conn ABORTED for the rest of the request (every
    # novel rel_type hit this, poisoning the in-flow rel_type mint). Query by alias
    # only (as the registry itself does), and SAVEPOINT-guard the probe so any
    # future failure rolls back the probe instead of poisoning the whole txn.
    try:
        with registry.db_conn.cursor() as cur:
            cur.execute("SAVEPOINT l4_alias_probe")
            try:
                cur.execute(
                    "SELECT entity_id FROM entity_aliases WHERE alias = %s LIMIT 1",
                    (stripped_lower,)
                )
                _l4_row = cur.fetchone()
                cur.execute("RELEASE SAVEPOINT l4_alias_probe")
            except Exception as _l4_err:
                # Fail loud, never silent — and roll back ONLY the probe.
                cur.execute("ROLLBACK TO SAVEPOINT l4_alias_probe")
                log.error("classify_fact_3d.l4_alias_probe_failed",
                          error=str(_l4_err)[:200], alias=stripped_lower)
                _l4_row = None
            if _l4_row:
                return {
                    "storage": "relational",
                    "direction": "asymmetric",
                    "reason": "heuristic: entity alias lookup (unknown rel_type)",
                }
    except Exception:
        pass

    # L5: Email/URL/phone
    if re.match(r'^[a-zA-Z0-9._%+-]+@', stripped):
        return {
            "storage": "scalar",
            "direction": None,
            "reason": "heuristic: email pattern (unknown rel_type)",
        }

    # FALLBACK
    return {
        "storage": None,
        "direction": None,
        "reason": "no pattern match, unknown rel_type",
    }


def assign_class_and_confidence(
    classification_3d: dict,
    fact_provenance: str = "llm_inferred",
    is_correction: bool = False,
    ontology_created: bool = False,
    hierarchy_created: bool = False,
    rel_type: str = None,
    confidence: float = None,
) -> tuple:
    """
    Assign Class (A | B | C) and confidence based on provenance + rel_type metadata.

    Three provenances:
      user_stated  — user directly said it → per rel_type's fact_class, high confidence
      llm_inferred — LLM extracted from conversation → per rel_type's fact_class, lower confidence
      llm_learned  — /expand self-growth engine → always B or C, never A

    Corrections (is_correction=True) always override to Class A, confidence 1.0.

    Returns: (class_letter, confidence_score)
    """
    if rel_type:
        rel_type_lower = rel_type.lower()
        metadata = _REL_TYPE_CACHE.get(rel_type_lower) or _REL_TYPE_META.get(rel_type_lower, {})
        defined_class = metadata.get("fact_class", "C")
    else:
        defined_class = "C"

    # Corrections are always Class A — user authority overrides everything
    if is_correction:
        return ("A", 1.0)

    if fact_provenance == "user_stated":
        if defined_class == "A":
            return ("A", 1.0)
        return ("B", 0.8)

    if fact_provenance == "llm_learned":
        if defined_class == "A":
            return ("B", 0.6)
        return (defined_class, min(confidence or 0.6, 0.6))

    # llm_inferred: follow rel_type's defined class with extraction confidence
    current_confidence = confidence if confidence is not None else 0.4

    if current_confidence < 0.9:
        if ontology_created:
            current_confidence -= 0.2
        if hierarchy_created:
            current_confidence -= 0.2

    current_confidence = max(0.0, min(1.0, current_confidence))
    return (defined_class, current_confidence)


# ── STRONG-INGEST ENTITY GROUNDING (DESIGN-hierarchy-ladder-and-growth.md) ───────
# A TYPING problem, not a dropping problem. When the LLM slots a classification
# ("X is a poodle", "I have a poodle named Rex") into a Person-only SCALAR rel
# (nationality, occupation, …) the INFORMATION is right ("poodle") but the SLOT is
# wrong. The decision is PURELY METADATA-DRIVEN — no source-text inspection:
# subject type inconsistent with the rel's constrained head_types AND the object
# resolves to a known class (canonical-typed entity or existing hierarchy node).
# We RE-TYPE the edge to the correct classification rel (instance_of) keeping the
# object; if the object isn't a known class we QUARANTINE to Class C — we NEVER
# hard-drop the information.
#
# Three feature flags (default ON, reversible). Setting any to a false-y value
# (0/false/no/off) restores the pre-change behaviour for that lever exactly.
def _flag_on(name: str, default: str = "true") -> bool:
    return os.getenv(name, default).strip().lower() not in ("0", "false", "no", "off")


# The canonical classification rel a re-typed edge re-routes to. Resolved
# against the per-tenant ontology at call time (must be a known hierarchy rel);
# never invented. instance_of is the W3C rdf:type seed and is always present.
_CLASSIFICATION_RETYPE_REL = "instance_of"

# NOTE: the intransitive STATE predicate (`has_state`, migration 110) is named only in the
# linguistic deriver (src/extraction/linguistics._STATE_REL) which EMITS it. The ingest /
# harvest side needs no literal reference: it routes the state by the predicate's SCALAR
# tail_types via _is_scalar_rel_type (entity_attributes, no UUID resolve, no L4 grounding,
# skipped by backbone-attach) — the same generic scalar discipline every scalar rel rides.


def _retype_mistyped_edge(
    edge,
    subject_gliner_type: str | None,
    object_is_known_class: bool,
    rel_meta_resolver,
    rel_is_scalar: bool = False,
) -> dict | None:
    """RE-ROUTE a type-inconsistent classificatory edge — keep the info, fix the slot.

    Returns a directive dict the ingest loop acts on, or None to leave the edge as-is:
      {"action": "retype",     "rel_type": "instance_of"}  → re-slot, keep object
      {"action": "quarantine", "reason": "..."}            → Class C, route to ontology_evaluations
      {"action": "miss_pushback", "reason": "...", "object": "..."}
            → MISS on a head-CONSTRAINED SCALAR rel that we cannot confirm:
              the subject type is unknown (GLiNER2 miss) OR type-inconsistent, AND the
              object does NOT resolve to a known class — so we can neither trust the
              scalar slot NOR re-type it. Route to C-raw (returnable) and queue the
              unknown object for the background "what is X?" classification, instead of
              storing a FALSE-CONFIDENT B scalar (occupation=poodle) or dropping it.
              (DESIGN-hierarchy-ladder-and-growth §"On a MISS: push back to the LLM".)

    NEVER returns a "drop" — information is never deleted (user hard rule).

    PURELY METADATA-DRIVEN — there is NO inspection of the source sentence. The
    decision comes from the ontology + the resolved entity types alone:

      1. TYPE-INCONSISTENT: the rel is a KNOWN rel whose head_types is constrained
         and does NOT include the GLiNER2-typed subject (e.g.
         occupation.head_types=[Person], subject=Animal). 'unknown'/ANY/empty →
         not a violation, fail-safe leave-as-is.
      2. OBJECT IS A KNOWN CLASS: the object value resolves to an existing
         entity/alias whose entity_type is a canonical class (Animal/Object/…) OR
         is itself a hierarchy node — i.e. the edge is really a CLASSIFICATION
         ("X <is/has-a> poodle"), regardless of how the sentence was phrased. The
         caller resolves this against the DB/ontology and passes the boolean here.
      3. RE-TYPE TARGET KNOWN: instance_of is a KNOWN hierarchy rel in this tenant.

    When (1) holds but (2) does NOT — type-inconsistent yet the object is not a
    known class, so the correct rel can't be determined — QUARANTINE (Class C +
    ontology_evaluations); never hard-drop.

    Metadata-driven: head_types/is_hierarchy_rel are read from the resolved ontology
    and the object's class signal is resolved by the caller from the entity registry
    / hierarchy; no rel_type name is hardcoded except the canonical classification
    seed (instance_of), pinned by the design as the rung-4 closed set. No surface
    text, no keyword heuristics, subject-agnostic.
    """
    rt = (getattr(edge, "rel_type", "") or "").lower().strip()
    if not rt:
        return None
    rel_meta = rel_meta_resolver(rt) or {}
    head_types = rel_meta.get("head_types") or []
    # Only a CONSTRAINED head_type can be violated. ANY/empty → nothing to re-route.
    head_constrained = [h for h in head_types if h and h.upper() not in ("ANY",)]
    # NAMING identity rels (also_known_as / pref_name) carry a NAME string, never a classifiable
    # concept. Re-typing one into instance_of would file a NAME as an L4 PLACE — the founding
    # hard-line violation. Leave it as-is; the name binds via the naming rel only.
    #
    # MIS-SLOT FIX (subject-agnostic, metadata-driven — NOT a rel-name check): the discriminator
    # between a NAMING identity rel and a VALUE-bearing identity scalar is the head constraint, not
    # the bare category. Naming rels are head-UNCONSTRAINED (anything can be named, so their
    # head_types span the canonical set) → genuinely "carry a name", skip them. A head-CONSTRAINED
    # identity scalar (nationality.head_types={Person}) carries a VALUE that CAN be a misclassified
    # concept ("a beagle" mis-slotted into nationality on an Animal subject), so it MUST flow to the
    # normal head-type-violation check below — exactly the breed-as-nationality / poodle-as-occupation
    # case. Skipping all of identity (the old guard) silently let those mis-slots survive as scalars.
    if (rel_meta.get("category") or "").strip().lower() == "identity" and not head_constrained:
        return None
    if not head_constrained:
        return None

    st = (subject_gliner_type or "").strip()
    if not st or st.lower() == "unknown":
        # GLiNER2-MISS on the subject of a head-CONSTRAINED rel. We cannot CONFIRM
        # type-consistency. For a SCALAR rel this is the false-confident-B risk
        # (occupation=poodle stored as a hard scalar). MISS-PUSHBACK only when the
        # object is ALSO not a confirmed class — i.e. we can neither trust the slot
        # NOR re-type it. Route to C-raw + queue "what is <object>?" classification.
        # (Non-scalar / object-is-class cases stay fail-safe: relational edges are
        # not false-B scalars, and a known-class object will re-type on re-ingest
        # once signals A/B fire — so leave them as-is here.)
        if rel_is_scalar and not object_is_known_class:
            return {
                "action": "miss_pushback",
                "reason": f"gliner_miss_subject_unconfirmable_scalar:{rt}",
                "object": (getattr(edge, "object", "") or "").strip(),
            }
        return None  # No authoritative subject type → do NOT re-route (fail-safe).

    head_lc = {h.lower() for h in head_constrained}
    if st.lower() in head_lc:
        return None  # Subject is type-consistent — the edge is fine as-is.

    # Type-INCONSISTENT. Does the OBJECT resolve to a known class? (metadata only)
    if not object_is_known_class:
        # Inconsistent but the object is not a known class → we cannot determine the
        # correct rel. For a SCALAR rel, this would otherwise store a false-confident
        # B (occupation=poodle); for any rel the info must be preserved. Route to the
        # MISS-PUSHBACK path: stage C-raw (returnable) AND queue "what is <object>?"
        # so the unknown concept gets TYPED + GROUNDED and the structure can resolve
        # on a later cycle. (Plain quarantine — same C-raw store — for the rare case
        # we want NO classification queued; here we always queue, since the object IS
        # the unknown concept the user named.)
        return {
            "action": "miss_pushback",
            "reason": f"head_type_inconsistent:{rt}:subject={st}:object_not_a_class",
            "object": (getattr(edge, "object", "") or "").strip(),
        }

    # Confirm the re-type target is a real hierarchy rel in this tenant's ontology.
    retype_meta = rel_meta_resolver(_CLASSIFICATION_RETYPE_REL) or {}
    if not retype_meta.get("is_hierarchy_rel"):
        # Canonical classification rel unexpectedly missing/non-hierarchy → quarantine,
        # never drop.
        return {
            "action": "quarantine",
            "reason": f"retype_target_unavailable:{_CLASSIFICATION_RETYPE_REL}",
        }

    return {"action": "retype", "rel_type": _CLASSIFICATION_RETYPE_REL}


def _object_resolves_to_known_class(
    db_conn,
    object_value: str,
    schema_name: str | None,
    gliner_type: str | None = None,
    batch_class_objects: set | None = None,
) -> bool:
    """Does the object value resolve to a KNOWN CLASS — metadata/DB only, no text?

    FOUR deterministic signals, any ONE suffices (subject-agnostic, per-tenant):
      A. The value matches an existing entity/alias whose entity_type is a canonical
         class (Animal/Object/Organization/Location/Concept/Person, NOT 'unknown').
      B. The value is itself a hierarchy NODE — it already appears as the OBJECT or
         SUBJECT of a hierarchy fact (instance_of / subclass_of) in facts or
         staged_facts — i.e. the backbone already treats it as a category.
      C. GLiNER2 typed the value to a canonical class IN THIS BATCH (the in-memory
         `_gliner_cache`). This is the same authoritative typing the subject uses, and
         it fires BEFORE the object lands in `entities` — without it, the very first
         "I have a poodle named Rex" can never re-type because `poodle` isn't yet
         a DB row (it was the STRING object of a scalar rel, never persisted). Signal C
         is the metadata that closes the re-type baseline; A/B then hold on re-ingest.
      D. The value is the OBJECT of a CLASSIFICATION edge in the SAME ingest batch —
         i.e. the same request also asserts "<x> is_a/instance_of/subclass_of <value>",
         which PROVES <value> is a class in this request. This is ORDERING-ROBUST: it
         does not matter whether the scalar garbage edge (occupation=poodle) or the
         classification edge (Rex is_a poodle) is processed first, because the
         class-object set is computed once over the WHOLE batch before the loop. GLiNER2
         types `rex` (the named instance), NOT the breed word `poodle`, so signal C
         is empty for `poodle` on this batch — D is what closes the leak. The set is
         supplied ONLY by the ingest call site (default None → non-breaking for pure
         callers/tests). Computed via `is_hierarchy_rel` metadata, not hardcoded.

    Signals C and D are checked first (cheap, in-memory, no DB round-trip). Signals A/B
    are a pure DB lookup against the bound tenant schema (NO public). Fail-safe: any
    error returns False so the edge is quarantined, never mis-slotted. Never raises.
    """
    val = (object_value or "").strip().lower()
    if not val:
        return False
    # Signal C: GLiNER2's in-batch type for this value is a canonical class. The
    # 6-type closed set (_CANONICAL_ENTITY_TYPES_LC) is the same Pitfall-11 vocabulary
    # the subject typing uses; 'unknown'/empty/non-canonical → not a class signal.
    gt = (gliner_type or "").strip().lower()
    if gt and gt != "unknown" and gt in _CANONICAL_ENTITY_TYPES_LC:
        return True
    # Signal D: the value is asserted as a CLASS by a sibling classification edge in
    # THIS batch (set pre-computed once over all edges, ordering-robust). In-memory,
    # no DB. The set is already lowercased by the caller.
    if batch_class_objects and val in batch_class_objects:
        return True
    try:
        with db_conn.cursor() as cur:
            cur.execute("SAVEPOINT sp_obj_class_probe")
            try:
                # Signal A: existing entity (via alias) with a canonical, known type.
                cur.execute(
                    "SELECT e.entity_type"
                    "  FROM entity_aliases a"
                    "  JOIN entities e ON e.id = a.entity_id"
                    " WHERE a.alias = %s"
                    " LIMIT 5",
                    (val,),
                )
                for (etype,) in cur.fetchall():
                    if etype and str(etype).strip().lower() in _CANONICAL_ENTITY_TYPES_LC:
                        cur.execute("RELEASE SAVEPOINT sp_obj_class_probe")
                        return True
                # Signal B: the value is already a hierarchy node (a category) — it
                # participates in a classification edge as object or subject.
                cur.execute(
                    "SELECT 1 FROM ("
                    "  SELECT object_id AS nid, rel_type FROM facts"
                    "  UNION ALL SELECT subject_id AS nid, rel_type FROM facts"
                    "  UNION ALL SELECT object_id AS nid, rel_type FROM staged_facts"
                    "  UNION ALL SELECT subject_id AS nid, rel_type FROM staged_facts"
                    ") h"
                    " JOIN entity_aliases a2 ON a2.entity_id = h.nid"
                    " WHERE a2.alias = %s"
                    "   AND h.rel_type IN ('instance_of', 'subclass_of')"
                    " LIMIT 1",
                    (val,),
                )
                hit = cur.fetchone() is not None
                cur.execute("RELEASE SAVEPOINT sp_obj_class_probe")
                return hit
            except Exception as _probe_e:
                cur.execute("ROLLBACK TO SAVEPOINT sp_obj_class_probe")
                log.warning("ingest.object_class_probe_failed",
                            object=val[:40], error=str(_probe_e)[:160])
                return False
    except Exception as _e:
        log.warning("ingest.object_class_probe_failed_outer",
                    object=val[:40], error=str(_e)[:160])
        # Best-effort re-apply of the tenant search_path so a failed probe never
        # leaves the shared connection scoped wrong.
        if schema_name:
            try:
                with db_conn.cursor() as _sp:
                    _sp.execute(f"SET search_path TO {schema_name}")
            except Exception:
                pass
        return False


# Canonical classification (hierarchy) rel seeds — the closed set named in
# DESIGN-hierarchy-ladder-and-growth.md §"deterministic resolution ladder" rung 4.
# These are the ONLY rels whose OBJECT names a class in a classification assertion.
# Membership/composition hierarchy rels (member_of/part_of) group instances, they do
# NOT name a class for the object, so they are deliberately EXCLUDED here.
_BATCH_CLASS_OBJECT_RELS = frozenset({"instance_of", "is_a", "subclass_of"})


def _compute_batch_class_objects(edges, rel_meta_resolver) -> set:
    """Signal-D source: the set of OBJECT values asserted as a CLASS in THIS batch.

    Scans every edge ONCE before the ingest loop and collects the `.object` value of
    any edge whose rel_type is a CLASSIFICATION rel — i.e. one of the canonical
    closed-set seeds (instance_of / is_a / subclass_of) AND confirmed `is_hierarchy_rel`
    in this tenant's metadata. This makes the re-type ORDERING-ROBUST: when a request
    contains both "occupation=poodle" (scalar garbage) and "Rex is_a poodle"
    (classification), `poodle` is known to be a class regardless of which edge the loop
    processes first, because this set is built over the whole batch up front.

    Metadata-driven, with a canonical-seed fallback (mirroring the established hierarchy
    helpers, e.g. _retract_conflicting_staged_types): a rel must FIRST be one of the
    closed-set seeds, then its metadata is consulted — if a metadata row exists it MUST
    flag `is_hierarchy_rel` (so a tenant cannot re-map a seed name onto a non-hierarchy
    rel and have it count as a class source); if metadata is ABSENT (e.g. `is_a` is
    carried as an ALIAS, not a first-class rel_type row, or a startup cache miss) the
    canonical seed membership alone qualifies it. No hardcoding beyond the documented
    rung-4 seed set. Values are lowercased to match the caller's lookup. Fail-safe: any
    error returns an empty set (signal D simply does not fire → falls back to A/B/C →
    quarantine, never a mis-slot). Never raises.
    """
    out: set = set()
    try:
        for e in edges or []:
            rt = (getattr(e, "rel_type", "") or "").strip().lower()
            if rt not in _BATCH_CLASS_OBJECT_RELS:
                continue
            meta = rel_meta_resolver(rt)
            # Metadata present → must confirm is_hierarchy_rel. Metadata absent (alias /
            # cache miss) → the canonical seed membership above already qualifies it.
            if meta and not meta.get("is_hierarchy_rel"):
                continue
            obj = (getattr(e, "object", "") or "").strip().lower()
            if obj:
                out.add(obj)
    except Exception as _e:
        log.warning("ingest.batch_class_objects_failed", error=str(_e)[:160],
                    note="signal D disabled for this batch (fail-safe)")
        return set()
    return out


# Bounded ±X classification climb (rung 6). From a confirmed classification
# (Rex instance_of poodle), propose the SHALLOW canonical chain
# poodle → dog → … toward generality. LLM = CLASSIFIER (proposes), deterministic
# rules VALIDATE, re_embedder grows in-chain (freq/convergence). Born Class C.
# Bounded: connect-to-known, depth cap, salience-gated (caller decides salience),
# MAP slots (subclass_of between category nodes) — never instances.
_CLASSIFICATION_CLIMB_DEPTH = int(os.getenv("INGEST_CLASSIFICATION_GROWTH_DEPTH", "2") or "2")


def _propose_classification_climb(
    leaf_type_name: str,
    subject_gliner_type: str | None,
    rel_meta_resolver,
) -> list[dict]:
    """Propose a bounded subclass_of climb for a freshly-classified leaf type.

    Input: the OBJECT of an instance_of edge (e.g. "poodle") and the GLiNER2 root
    type of the entity (e.g. "Animal"). Output: a SMALL ordered list of proposed
    subclass_of edges (poodle subclass_of <?> … subclass_of animal) for the caller
    to stage Class C. The LLM proposes the chain; this function returns the
    deterministic SCAFFOLD + a flag telling the caller whether an LLM classifier
    call is warranted.

    BUILT vs FLAGGED: the LLM-driven mid-chain proposal (poodle→dog→canine→mammal)
    is a FLAGGED STUB here — we emit the deterministic connect-to-known endpoint
    (leaf subclass_of <gliner_root>, e.g. poodle subclass_of animal) which is always
    safe (the GLiNER2 root is a canonical type, depth 1, connect-to-known). The
    multi-rung LLM climb is gated behind INGEST_CLASSIFICATION_GROWTH and described
    in the report as design-target so it is not silently half-wired.

    Returns [] when growth is disabled or inputs are insufficient (fail-safe).
    Never raises — growth is best-effort and must not break ingest.
    """
    if not _flag_on("INGEST_CLASSIFICATION_GROWTH"):
        return []
    leaf = (leaf_type_name or "").strip().lower()
    root = (subject_gliner_type or "").strip()
    if not leaf or not root or root.lower() == "unknown":
        return []
    # subclass_of must be a known hierarchy rel; never invent it.
    sc_meta = rel_meta_resolver("subclass_of") or {}
    if not sc_meta.get("is_hierarchy_rel"):
        return []
    # Canonical root of the climb — the GLiNER2 detection type, lowercased to act as
    # a backbone category node ("animal"). connect-to-KNOWN: stop at this node, do
    # NOT extend to a universal root (Bounded growth §2).
    root_node = root.lower()
    if leaf == root_node:
        return []  # already at the root; nothing to climb.
    # Deterministic, always-safe rung: leaf → gliner_root (depth 1). This is the
    # connect-to-known endpoint that guarantees an UP-walk reaches a backbone node.
    proposals = [{
        "subject": leaf,
        "rel_type": "subclass_of",
        "object": root_node,
        "depth": 1,
    }]
    # FLAGGED STUB (design-target): the bounded mid-chain (poodle→dog→canine→mammal)
    # is an LLM-CLASSIFIER proposal validated per-rung, depth-capped at
    # _CLASSIFICATION_CLIMB_DEPTH, grown by the re_embedder via convergence/freq. It
    # is intentionally NOT minted here to keep ingest fast and the change low-risk;
    # the endpoint rung above already populates the rank so an UP-walk has data.
    return proposals[:max(1, _CLASSIFICATION_CLIMB_DEPTH)]


def _attach_to_seeded_backbone(
    db_conn,
    schema_name: str | None,
    concept_object_id: str,
    concept_display: str,
    object_type: str | None,
    registry,
    user_id: str,
) -> bool:
    """L4 Phase 1 — SYNCHRONOUS, DETERMINISTIC classification-axis attach.

    THE GAP THIS CLOSES: a novel concept-object that arrives as the OBJECT of a
    NON-classification rel (the common case — "I have a dog" -> (user, owns, dog))
    gets a fact + an entity but ZERO is-a rung at ingest. The async re_embedder
    "what is X?" classifier eventually builds one rung, but until then the concept
    is an ISLAND: "what is a dog?" can find nothing to walk. The existing
    rung-6 climb (_propose_classification_climb) only fires for the re-typed-leaf
    `instance_of` path, never for a relational object — so dog stays un-laddered.

    THE FIX (connect-to-known endpoint, generalized): if the object's GLiNER2 type
    maps to a SEEDED HIERARCHICAL taxonomy whose member_entity_types contains that
    type, deterministically stage `<concept> <hier_rel> <taxonomy_anchor>` BORN
    CLASS C — connecting the concept to the SEEDED CANONICAL BACKBONE in-flow. This
    is the same always-safe depth-1 endpoint _propose_classification_climb emits
    (leaf subclass_of <gliner_root>), but driven by the per-tenant taxonomy overlay
    instead of a re-type event, so it fires for ANY relational object.

    SUBJECT-AGNOSTIC by construction: the attach target is whatever seeded
    hierarchical taxonomy claims the object's type (animal claims Animal,
    computer_system claims Object/Concept, location claims Location, ...). NO entity
    name is hardcoded, NO rel_type is hardcoded — the hierarchy rel is read from the
    taxonomy's transitive_rel_types (the classification rels it declares). A new
    domain needs ONLY a seeded hierarchical taxonomy row + the matching GLiNER2 type.

    DETERMINISTIC, NOT FUZZY: pure type-string membership against seeded metadata.
    NO LLM, NO cosine, NO similarity. The mid-chain rungs (dog -> canine -> animal)
    are STILL the async re_embedder's job (LLM-proposed, gated) — this only
    guarantees the connect-to-backbone endpoint exists synchronously so the walker
    is never empty. The intermediate rungs converge the chain over time.

    INV-2 (anti-pollution): this does NOT mint a novel rel or a novel taxonomy — it
    reuses an EXISTING seeded hierarchy rel against an EXISTING seeded taxonomy. The
    NOVEL-concept side (typing/placing the concept node itself, finer-grained
    parents) stays QUARANTINED to the async engine via _queue_concept_for_grounding.

    INV-4 (UUID-keyed walkability): both ends resolved to entity UUID surrogates
    (EntityRegistry UUID v5, idempotent) before the staged write — the rung lands in
    the SAME UUID keyspace the walker (_resolve_type_signals) traverses; never a
    string-keyed island. Unresolvable -> skip (the async path retries).

    Skips: object already laddered (has a walkable is-a edge — preserve the
    deliberate skip), no usable type, no matching seeded hierarchical taxonomy,
    self-attach (concept == its own backbone group). Flag-gated
    (INGEST_BACKBONE_ATTACH, default ON; kill-switch). Per-tenant search_path
    (refuse public fallthrough). Fail-safe: never raises, never blocks the commit.
    Returns True iff a backbone rung was staged.
    """
    if not _flag_on("INGEST_BACKBONE_ATTACH", default="true"):
        return False
    # Growth writes MUST land in the per-tenant schema; refuse public fallthrough.
    if not schema_name:
        return False
    concept = (concept_display or "").strip().lower()
    otype = (object_type or "").strip()
    if not concept or not concept_object_id or not otype or otype.lower() == "unknown":
        return False
    if concept_object_id in (user_id, "user"):
        return False
    try:
        with db_conn.cursor() as _cur:
            _cur.execute("SAVEPOINT sp_backbone_attach")
            try:
                # 1. ALREADY-LADDERED gate (preserve the deliberate skip): if the
                #    concept already has a walkable is-a edge (facts ∪ staged), the
                #    backbone is reachable — do not duplicate. Mirrors the
                #    _queue_concept_for_grounding gate exactly.
                _cur.execute(
                    "SELECT 1 FROM facts"
                    " WHERE subject_id = %s"
                    "   AND rel_type IN ('instance_of', 'subclass_of')"
                    "   AND superseded_at IS NULL AND archived_at IS NULL"
                    " UNION ALL"
                    " SELECT 1 FROM staged_facts"
                    " WHERE subject_id = %s"
                    "   AND rel_type IN ('instance_of', 'subclass_of')"
                    "   AND promoted_at IS NULL AND deleted_at IS NULL"
                    " LIMIT 1",
                    (concept_object_id, concept_object_id),
                )
                if _cur.fetchone():
                    _cur.execute("RELEASE SAVEPOINT sp_backbone_attach")
                    return False
                # THE HARD LINE — never attach a NAMED INSTANCE to the L4 backbone. If the object is
                # the SUBJECT of a naming edge (also_known_as / pref_name — e.g. `rex
                # also_known_as Rex`), it is a proper name (a memory), not a type: a name never
                # becomes an L4 place. Without this, a relational object that is a named instance
                # (`user has_pet rex`, rex typed Animal) would mint `rex subclass_of
                # animal` — the founding category error. The named instance climbs via its TYPE
                # (poodle) through its own instance_of edge, never via the name. Ordering-independent
                # structural signal (canonical SKOS naming rels; no proper-noun word list).
                _cur.execute(
                    "SELECT 1 FROM facts"
                    " WHERE subject_id = %s"
                    "   AND rel_type IN ('also_known_as', 'pref_name')"
                    "   AND superseded_at IS NULL AND archived_at IS NULL"
                    " UNION ALL"
                    " SELECT 1 FROM staged_facts"
                    " WHERE subject_id = %s"
                    "   AND rel_type IN ('also_known_as', 'pref_name')"
                    "   AND promoted_at IS NULL AND deleted_at IS NULL"
                    " LIMIT 1",
                    (concept_object_id, concept_object_id),
                )
                if _cur.fetchone():
                    _cur.execute("RELEASE SAVEPOINT sp_backbone_attach")
                    return False
                _cur.execute("RELEASE SAVEPOINT sp_backbone_attach")
            except Exception:
                _cur.execute("ROLLBACK TO SAVEPOINT sp_backbone_attach")
                return False
    except Exception:
        try:
            db_conn.rollback()
            with db_conn.cursor() as _r:
                _r.execute(f"SET search_path TO {schema_name}")
        except Exception:
            pass
        return False

    # 2. Resolve the object's type to a SEEDED HIERARCHICAL taxonomy via the
    #    per-tenant overlay (seed ∪ tenant, ContextVar-bound — no public
    #    fallthrough, no cross-tenant leak). DETERMINISTIC type-string membership.
    try:
        dsn = os.environ.get("POSTGRES_DSN", "")
        if not dsn:
            return False
        taxonomies = taxonomy_overlay.resolve_current(dsn)
    except Exception as e:
        log.warning("ingest.backbone_attach_taxonomy_resolve_failed",
                    concept=concept, error=str(e)[:120])
        return False
    if not taxonomies:
        return False

    otype_lc = otype.lower()
    backbone_group = None
    hier_rel = None
    for _name, _meta in taxonomies.items():
        if not _meta.get("is_hierarchical"):
            continue
        _members = {str(m).strip().lower() for m in (_meta.get("member_entity_types") or []) if m}
        if otype_lc not in _members:
            continue
        # Never self-attach (the concept IS the backbone group, e.g. "animal").
        if (_name or "").strip().lower() == concept:
            continue
        # Pick the classification hierarchy rel this taxonomy declares — metadata
        # driven, never hardcoded. Prefer a transitive_rel_type that is a known
        # classification rel; fall back to subclass_of (the canonical default).
        _class_rels = _get_classification_rels(db_conn)
        _declared = [str(r).strip().lower()
                     for r in (_meta.get("transitive_rel_types") or []) if r]
        for _r in _declared:
            if _r in _class_rels:
                hier_rel = _r
                break
        # ONLY attach to a taxonomy that genuinely declares a CLASSIFICATION rel
        # (e.g. animal -> {subclass_of, instance_of}). Do NOT fall back to subclass_of
        # for MEMBERSHIP/relational taxonomies (family -> {has_pet, age, ...}, pets ->
        # {has_pet}) — that would mis-attach a (often mis-typed) entity as a subclass of a
        # membership group (e.g. a server typed Person -> "apollo subclass_of family").
        # A taxonomy that declares no classification rel is not a classification target.
        if hier_rel is None:
            continue
        backbone_group = (_name or "").strip().lower()
        break

    if not backbone_group or not hier_rel:
        return False

    # 3. UUID-key BOTH ends (idempotent UUID v5) and stage the rung Class C.
    try:
        _subj = registry.resolve(user_id, concept)            # the concept node
        _obj = registry.resolve(user_id, backbone_group)      # the seeded backbone node
    except Exception as _re:
        try:
            db_conn.rollback()
            with db_conn.cursor() as _r:
                _r.execute(f"SET search_path TO {schema_name}")
        except Exception:
            pass
        log.debug("ingest.backbone_attach_resolve_failed",
                  concept=concept, group=backbone_group, error=str(_re)[:120])
        return False
    if not _subj or not _obj or _subj == _obj:
        return False

    # The concept UUID MUST be the object UUID the original relational edge points at
    # (resolve() is idempotent UUID v5 from the normalized name) so the rung lands in
    # the SAME keyspace the walker traverses — never a string-keyed island (INV-4).
    if str(_subj) != str(concept_object_id):
        # Defensive: if the names disagree, prefer the edge's UUID for the subject so
        # the rung attaches to the very entity the user's fact references.
        _subj = concept_object_id

    try:
        _commit_staged(db_conn, [(
            user_id, _subj, _obj, hier_rel,
            "ingest_backbone_attach",
            "",            # definition
            "hierarchical",  # storage_type
            True,          # is_hierarchy_rel
            [backbone_group],  # taxonomies
            "llm_inferred",
        )], "C", confidence=0.4)
        return True
    except Exception as _ce:
        try:
            db_conn.rollback()
            with db_conn.cursor() as _r:
                _r.execute(f"SET search_path TO {schema_name}")
        except Exception:
            pass
        log.debug("ingest.backbone_attach_stage_failed",
                  concept=concept, group=backbone_group, error=str(_ce)[:120])
        return False


def _queue_concept_for_grounding(
    db_conn,
    schema_name: str | None,
    concept_object_id: str,
    concept_display: str,
    rel_type: str,
    subject_id: str,
    first_text_snippet: str | None = None,
    subject_display: str | None = None,
) -> bool:
    """Queue a NOVEL CONCEPT-OBJECT for the background 'what is X?' is-a grounding.

    Understanding-hierarchy arc, piece 1b. A relational edge whose object is a
    valid novel concept (e.g. "i feel jealous" -> (user, feels, jealous)) is NOT a
    mis-slot, so the existing miss-pushback directive never fires for it -> the
    concept gets a fact + an entity but ZERO is-a rung -> an "understanding island".
    This helper writes the SAME `ingest_miss_pushback` row the mis-slot path writes
    (so the re_embedder `classify_unknown_concepts` consumer picks it up: it reads
    `extraction_method='ingest_miss_pushback' AND re_embedder_decision IS NULL AND
    sample_object IS NOT NULL`) — building the ladder for clean novel concepts too.

    SUBJECT-AGNOSTIC by construction: the QUEUE condition is "the object is
    UN-LADDERED" — it has NO walkable instance_of/subclass_of is-a edge as subject
    (checked across BOTH `facts` and `staged_facts`, since a freshly-grounded is-a
    edge is born Class C in `staged_facts`) — NOT a rel-name / word-list check, and
    NOT the denormalized `entities.entity_type` column (which is not a walkable edge).
    ANY relational rel whose object is un-laddered qualifies — `feels` is never named
    here. A typed-but-unladdered object (e.g. Toronto: entity_type='Location', zero
    is-a edges) is CAUGHT here, because it is still an island the walker can't reach.

    Skips (NOT a concept to ladder): scalars (excluded by the caller — never reaches
    here), identity-alias rels (also_known_as/pref_name — name strings, excluded by
    the caller), the user/anchor or the subject itself, and GENUINELY-LADDERED
    entities (those that already carry a walkable is-a edge).

    CONTEXT-CARRY (additive, fail-safe): ``first_text_snippet`` (the full turn that
    surfaced the concept) and ``subject_display`` (the THING the state befell, e.g.
    "gps") are persisted into ``ontology_evaluations.first_text_snippet`` so the async
    re_embedder grounder classifies the concept AGAINST its sentence ("what broke? ->
    the GPS, a device"), never a stripped bare word ("broke" -> bankrupt -> finance).
    Both default to None → exactly today's behavior (NULL snippet = graceful
    degradation). The snippet is bounded ([:500], the established cap) and the ON
    CONFLICT branch COALESCEs so the FIRST sighting's sentence is preserved (a later,
    possibly less-informative sighting never overwrites it).

    Flag-gated (`INGEST_QUEUE_CONCEPT_GROUNDING`, default ON; kill-switch).
    Idempotent (ON CONFLICT reuses the existing miss-pushback row shape;
    candidate_rel_type is NOT NULL so the real rel_type is carried). Fail-safe:
    wrapped, never raises, never blocks the commit. Per-tenant search_path — the
    INSERT is schema-qualified so it never lands in public.ontology_evaluations
    (a NOT-NULL-user_id template). Returns True iff a row was written/bumped.
    """
    if not _flag_on("INGEST_QUEUE_CONCEPT_GROUNDING", default="true"):
        return False
    # Growth writes MUST land in the per-tenant schema; refuse public fallthrough.
    if not schema_name:
        return False
    concept = (concept_display or "").strip()
    if not concept or not concept_object_id:
        return False
    # The object must NOT be the user/anchor or the subject itself.
    if concept_object_id in (subject_id, "user"):
        return False
    try:
        with db_conn.cursor() as _cur:
            _cur.execute("SAVEPOINT sp_queue_concept_ground")
            try:
                # UN-LADDERED gate (subject-agnostic): gate on "NO WALKABLE is-a EDGE",
                # NOT on the denormalized `entities.entity_type` column. entity_type is
                # NOT a walkable edge — a typed-but-unladdered object (e.g. Toronto:
                # entity_type='Location', ZERO instance_of/subclass_of rows) is an island
                # the hierarchy walker (joins by UUID via is-a edges) cannot reach, so it
                # MUST still be queued. The deliberate skip is for GENUINELY-laddered
                # objects (those that already have a walkable is-a edge), not merely typed
                # ones. So: queue iff the object has no live is-a edge as subject —
                # regardless of entity_type. A 'feels'-object like "jealous" (un-typed,
                # un-laddered) qualifies; Toronto (typed, un-laddered) now ALSO qualifies;
                # a concept already carrying an is-a edge is still skipped.
                #
                # A freshly-grounded `<concept> subclass_of <parent>` edge is born Class C
                # and lives in STAGED_FACTS (not `facts`) until promotion, so the laddered
                # check MUST consider is-a edges in BOTH tables — otherwise a just-grounded
                # object reads un-laddered every cycle and re-queues forever. Live rows
                # only: facts `superseded_at IS NULL AND archived_at IS NULL`; staged
                # `promoted_at IS NULL AND deleted_at IS NULL` (matching how the walker /
                # the is-a existence check at the instance_of-linking site read staged).
                _cur.execute(
                    "SELECT 1 FROM facts"
                    " WHERE subject_id = %s"
                    "   AND rel_type IN ('instance_of', 'subclass_of')"
                    "   AND superseded_at IS NULL AND archived_at IS NULL"
                    " UNION ALL"
                    " SELECT 1 FROM staged_facts"
                    " WHERE subject_id = %s"
                    "   AND rel_type IN ('instance_of', 'subclass_of')"
                    "   AND promoted_at IS NULL AND deleted_at IS NULL"
                    " LIMIT 1",
                    (concept_object_id, concept_object_id),
                )
                if _cur.fetchone():
                    _cur.execute("RELEASE SAVEPOINT sp_queue_concept_ground")
                    return False
                # THE HARD LINE — never queue a NAMED INSTANCE for is-a grounding. If the object is
                # the SUBJECT of a naming edge (also_known_as / pref_name — e.g. `rex
                # also_known_as Rex`), it is a proper name (a memory), NOT a type/concept: a name
                # never becomes an L4 place. The instance_of guard above catches it only once the
                # `<name> instance_of <type>` edge has committed, but a named instance can be queued
                # via a sibling edge (`user has_pet rex`) earlier in the SAME ingest batch, before
                # that instance_of lands. The naming-edge presence is the ordering-independent
                # structural signal (canonical SKOS naming rels, no proper-noun word list). The async
                # consumer (`classify_unknown_concepts`) carries the same guard as the authoritative
                # stop; this prevents the row from ever being written.
                _cur.execute(
                    "SELECT 1 FROM facts"
                    " WHERE subject_id = %s"
                    "   AND rel_type IN ('also_known_as', 'pref_name')"
                    "   AND superseded_at IS NULL AND archived_at IS NULL"
                    " UNION ALL"
                    " SELECT 1 FROM staged_facts"
                    " WHERE subject_id = %s"
                    "   AND rel_type IN ('also_known_as', 'pref_name')"
                    "   AND promoted_at IS NULL AND deleted_at IS NULL"
                    " LIMIT 1",
                    (concept_object_id, concept_object_id),
                )
                if _cur.fetchone():
                    _cur.execute("RELEASE SAVEPOINT sp_queue_concept_ground")
                    return False
                # Idempotent INSERT — same row shape/ON CONFLICT key as the mis-slot
                # miss-pushback INSERT (~13783). candidate_rel_type is NOT NULL: carry
                # the real (subject-agnostic) rel that surfaced the concept. The concept
                # to type sits in sample_object (the consumer's read key).
                # CONTEXT-CARRY: bound the full turn ([:500], the established snippet cap)
                # so the grounder reads the sentence, not a stripped word. None → NULL
                # (today's bare-word behavior). On conflict COALESCE preserves the FIRST
                # (most-informative) sighting's sentence rather than a later partial one.
                _snippet = (first_text_snippet or "").strip()[:500] or None
                _cur.execute(
                    f"INSERT INTO {schema_name}.ontology_evaluations"
                    " (candidate_rel_type, candidate_subject_type,"
                    "  candidate_object_type,"
                    "  sample_subject_id, sample_object, extraction_method,"
                    "  first_text_snippet,"
                    "  decision_reason, occurrence_count, last_seen_at)"
                    " VALUES (%s, %s, %s, %s, %s, %s, %s, %s, 1, now())"
                    " ON CONFLICT (candidate_rel_type, sample_subject_id, sample_object)"
                    " DO UPDATE SET occurrence_count = ontology_evaluations.occurrence_count + 1,"
                    "   last_seen_at = now(),"
                    "   extraction_method = EXCLUDED.extraction_method,"
                    "   first_text_snippet = COALESCE("
                    "       ontology_evaluations.first_text_snippet, EXCLUDED.first_text_snippet)",
                    (
                        (rel_type or "").lower(),
                        "unknown",
                        # un-typed concept -> classifier knows to type it
                        "unknown",
                        str(subject_id),
                        concept.lower(),
                        "ingest_miss_pushback",
                        _snippet,
                        "novel concept-object — queued for background 'what is X?' "
                        "classify so the is-a ladder builds (understanding-island fix)",
                    ),
                )
                _cur.execute("RELEASE SAVEPOINT sp_queue_concept_ground")
                return True
            except Exception:
                _cur.execute("ROLLBACK TO SAVEPOINT sp_queue_concept_ground")
                return False
    except Exception:
        # Best-effort: recover the connection + tenant search_path; never raise.
        try:
            db_conn.rollback()
            if schema_name:
                with db_conn.cursor() as _r:
                    _r.execute(f"SET search_path TO {schema_name}")
        except Exception:
            pass
        return False


def _flush_cue_candidates(user_id: str) -> int:
    """Drain the request-scoped CARVED-CLASS growth candidates (social_role / problem_noun) recorded by
    the deriver/consumer and write them to the per-tenant ``ontology_evaluations`` growth queue (the
    SAME queue the rel_type / concept paths reuse), marked extraction_method='linguistic_cue_candidate'
    so the rel-type evaluator's firewall skips them. The re_embedder freq-gates (≥3) and grows them into
    ``<tenant>.linguistic_cues`` (``grow_linguistic_cue_candidates``).

    PER-TENANT: opens a short-lived connection and binds ``SET search_path TO <tenant>`` (NO public) —
    the INSERT is schema-qualified so growth NEVER lands in public.ontology_evaluations. Idempotent
    (ON CONFLICT bumps occurrence_count). Best-effort + fail-safe: any error is swallowed and NEVER
    breaks ingest (the construction already degraded to a generic walkable rel; growth is best-effort).
    Skips the connection entirely when nothing was recorded. Returns the number of rows written/bumped.
    """
    try:
        cands = linguistic_cue_overlay.drain_cue_candidates()
    except Exception:  # noqa: BLE001 — fail-safe
        return 0
    if not cands:
        return 0
    try:
        from src.provisioning.schema_manager import derive_user_slug_from_uuid
        schema = f"faultline_{derive_user_slug_from_uuid(user_id)}"
    except Exception:  # noqa: BLE001 — fail-safe
        return 0
    dsn = os.environ.get("POSTGRES_DSN", "")
    if not dsn or not schema:
        return 0
    written = 0
    _conn = None
    try:
        _conn = psycopg2.connect(dsn, connect_timeout=5)
        with _conn as conn:
            with conn.cursor() as cur:
                cur.execute(f"SET search_path TO {schema}")
                for (cue, category) in cands:
                    _cue = (cue or "").strip().lower()
                    _cat = (category or "").strip().lower()
                    if not _cue or not _cat:
                        continue
                    try:
                        cur.execute("SAVEPOINT sp_cue_cand")
                        # candidate_rel_type=category, sample_subject_id='__cue__', sample_object=cue →
                        # the UNIQUE (candidate_rel_type, sample_subject_id, sample_object) gives one
                        # freq-counted row per (category, cue). candidate_object_type also carries the
                        # category so the re_embedder grow sweep reads it back.
                        cur.execute(
                            f"INSERT INTO {schema}.ontology_evaluations"
                            " (candidate_rel_type, candidate_subject_type, candidate_object_type,"
                            "  sample_subject_id, sample_object, extraction_method,"
                            "  decision_reason, occurrence_count, last_seen_at)"
                            " VALUES (%s, %s, %s, %s, %s, %s, %s, 1, now())"
                            " ON CONFLICT (candidate_rel_type, sample_subject_id, sample_object)"
                            " DO UPDATE SET"
                            "   occurrence_count = ontology_evaluations.occurrence_count + 1,"
                            "   last_seen_at = now(),"
                            "   extraction_method = EXCLUDED.extraction_method",
                            (_cat, "unknown", _cat, "__cue__", _cue,
                             "linguistic_cue_candidate",
                             "carved cue-class candidate — freq-gated per-tenant growth"),
                        )
                        cur.execute("RELEASE SAVEPOINT sp_cue_cand")
                        written += 1
                    except Exception:  # noqa: BLE001 — one bad candidate never aborts the batch
                        try:
                            cur.execute("ROLLBACK TO SAVEPOINT sp_cue_cand")
                        except Exception:  # noqa: BLE001
                            pass
            conn.commit()
    except Exception as _ce:  # noqa: BLE001 — fail-safe: growth queue write never breaks ingest
        log.debug("flush_cue_candidates_failed", error=str(_ce)[:140])
        return written
    finally:
        # psycopg2's context manager commits/rolls back but does NOT close — close explicitly so the
        # per-turn growth write never leaks a connection.
        try:
            if _conn is not None:
                _conn.close()
        except Exception:  # noqa: BLE001
            pass
    if written:
        log.info("flush_cue_candidates.queued", schema=schema, count=written)
    return written


def enforce_directionality(
    subject: str,
    object: str,
    rel_type: str,
    is_symmetric: bool,
    inverse_rel_type: str = None,
    user_entity_id: str = None,
) -> tuple:
    """
    Enforce rel_type directionality rules. Correct asymmetric rels to canonical direction.

    Examples:
    - User says "alice is parent of me" → invert to "I am parent of alice" (parent_of canonical)
    - User says "Jordan is spouse of me" → swap to (user, spouse, jordan) (canonical anchor-first)

    Returns: (corrected_subject, corrected_object, corrected_rel_type)
    """
    if is_symmetric:
        # Canonical direction: anchor (user UUID) is always subject for user-anchored symmetric rels.
        # Prevents both (user, spouse, jordan) and (jordan, spouse, user) from accumulating as
        # separate DB rows — the unique constraint treats them as different facts.
        # Compare against resolved user_entity_id UUID, not the literal string "user"
        # (entity resolution has already replaced "user" with the UUID by call time).
        if user_entity_id and object == user_entity_id and subject != user_entity_id:
            return (object, subject, rel_type)
        return (subject, object, rel_type)

    # Asymmetric rels: accept as-is and let conflict detection handle duplicates
    # (Canonical direction rules per rel_type would go here)

    return (subject, object, rel_type)


def _commit_staged(
    db_conn,
    rows: list[tuple],
    fact_class: str,
    confidence: float,
) -> int:
    """
    Stage Class B facts (behavioral/contextual) for later promotion to facts table.

    Per-User Schema Context:
    ────────────────────────
    Called from /ingest endpoint in per-user schema context. The per-user schema's
    staged_facts table does NOT have a user_id column (schema isolation). The user_id in
    the row tuple is extracted but NOT used in INSERT (it's implicitly scoped by SET search_path).

    Input rows: list of (user_id, subject_id, object_id, rel_type, provenance, [definition],
                        [storage_type], [is_hierarchy_rel], [taxonomies], [fact_provenance])

    CRITICAL: Confirmation Tracking via PostgreSQL ON CONFLICT UPSERT
    ─────────────────────────────────────────────────────────────────
    FaultLine uses PostgreSQL's INSERT ... ON CONFLICT semantics to automatically track
    how many times a fact appears across separate ingest calls. This is the **confirmation
    mechanism** that enables automatic promotion from staged facts to authoritative facts.

    When the same fact (subject_id, object_id, rel_type) appears multiple times:

    Call 1: INSERT staged_facts (..., confirmed_count DEFAULT 0, ...)
            → First appearance, new row created with confirmed_count = 0

    Call 2: INSERT staged_facts (...) ON CONFLICT (subject_id, object_id, rel_type)
                DO UPDATE SET confirmed_count = staged_facts.confirmed_count + 1, ...
            → Conflict detected (same triple), confirmed_count incremented: 0 → 1

    Call 3: Same INSERT with ON CONFLICT
            → confirmed_count incremented again: 1 → 2

    Call 4: Same INSERT with ON CONFLICT
            → confirmed_count incremented again: 2 → 3 ✅ PROMOTION THRESHOLD MET

    Promotion Mechanism (Automatic):
    • Re-embedder polls every 60 seconds via promote_staged_facts()
    • Queries: SELECT ... FROM staged_facts WHERE confirmed_count >= 3
    • Facts meeting threshold are promoted to facts table (Class A confidence 1.0)
    • Old staged row marked with promoted_at timestamp (non-destructive soft delete)
    • Staged Qdrant point deleted (data consolidation)

    This mechanism is **automatic and atomic** — no separate UPDATE statements required.
    It relies entirely on PostgreSQL's UPSERT semantics and prevents race conditions
    between concurrent ingest calls and re-embedder polling.

    Return Value:
        Count of rows attempted (not necessarily successful due to conflicts, but
        the ON CONFLICT clause guarantees atomicity of the confirmation increment).

    Grounding Documents:
    • Self_Growth.md Section "Phase 2: Confirmation Tracking" (Mechanism #9, lines 1060-1100)
    • src/re_embedder/embedder.py promote_staged_facts() (line 480, promotion execution)
    • CLAUDE.md "Ingest Pipeline: Three-Stage Intent-Aware Pipeline" (stages 1-3)
    • CLAUDE.md "Fact Classification, Storage & Retrieval" (Class A/B/C lifecycle)
    """
    count = 0
    try:
        with db_conn.cursor() as cur:
            for row in rows:
                user_id, subject, obj, rel_type, prov = row[0], row[1], row[2], row[3], row[4]
                definition = row[5] if len(row) > 5 else ''
                storage_type = row[6] if len(row) > 6 else None
                is_hierarchy_rel = row[7] if len(row) > 7 else False
                taxonomies = row[8] if len(row) > 8 else []
                fact_prov = row[9] if len(row) > 9 else 'llm_inferred'
                # TEMPORAL MODEL (DESIGN-hierarchy-ladder §"Temporal model"): the Class C
                # mirror carries temporal_status (verb tense) + event_date alongside the fact.
                temporal_status = row[10] if len(row) > 10 else 'now'
                event_date = row[11] if len(row) > 11 else None
                event_date_granularity = row[12] if len(row) > 12 else None
                # ASSERTION POLARITY (Q1): 'affirmed' (default) | 'negated'. Carried like temporal.
                # Shorter caller tuples (no polarity) default to 'affirmed' (today's behavior).
                polarity = row[13] if len(row) > 13 else 'affirmed'
                if polarity not in ('affirmed', 'negated'):
                    polarity = 'affirmed'
                if temporal_status not in ('now', 'past', 'future'):
                    temporal_status = 'now'
                # Validate fact_provenance is canonical; fall back to llm_inferred
                if fact_prov not in ('user_stated', 'llm_inferred', 'llm_learned'):
                    fact_prov = 'llm_inferred'

                # Per-user schema isolation: no user_id column in per-user staged_facts
                # The search_path already scopes this to the correct user's schema
                cur.execute(
                    "INSERT INTO staged_facts"
                    " (subject_id, object_id, rel_type, fact_class,"
                    "  provenance, fact_provenance, confidence, expires_at, rel_type_definition, storage_type, is_hierarchy_rel, taxonomies, temporal_status, event_date, event_date_granularity, polarity)"
                    " VALUES (%s, %s, %s, %s, %s, %s, %s, now() + interval '30 days', %s, %s, %s, %s, %s, %s, %s, %s)"
                    " ON CONFLICT (subject_id, object_id, rel_type)"
                    " DO UPDATE SET"
                    "   confirmed_count = staged_facts.confirmed_count + 1,"
                    "   last_seen_at    = now(),"
                    "   expires_at      = now() + interval '30 days',"
                    "   confidence      = GREATEST(staged_facts.confidence, EXCLUDED.confidence),"
                    "   qdrant_synced   = false,"
                    "   fact_provenance = EXCLUDED.fact_provenance,"
                    "   rel_type_definition = EXCLUDED.rel_type_definition,"
                    "   storage_type = COALESCE(EXCLUDED.storage_type, staged_facts.storage_type),"
                    "   taxonomies = COALESCE(EXCLUDED.taxonomies, staged_facts.taxonomies),"
                    "   temporal_status = EXCLUDED.temporal_status,"
                    "   event_date = COALESCE(EXCLUDED.event_date, staged_facts.event_date),"
                    "   event_date_granularity = COALESCE(EXCLUDED.event_date_granularity, staged_facts.event_date_granularity),"
                    # ASSERTION POLARITY (Q1): a re-asserted negated state must keep its negated
                    # polarity; a later affirmed re-ingest of the SAME triple flips it back to
                    # 'affirmed' (the latest assertion wins, mirroring temporal_status). EXCLUDED
                    # carries this ingest's polarity verbatim.
                    "   polarity = EXCLUDED.polarity"
                    # FREEZE TOMBSTONE (Phase 4): a tombstoned row must NOT be resurrected /
                    # have its expiry+counters reset by a re-ingest hit. Skip the UPDATE for it.
                    "   WHERE staged_facts.deleted_at IS NULL",
                    (subject, obj, rel_type, fact_class, prov, fact_prov, confidence, definition, storage_type, is_hierarchy_rel, taxonomies, temporal_status, event_date, event_date_granularity, polarity),
                )

                # Log confirmation tracking via ON CONFLICT UPSERT
                log.debug(
                    "ingest.staged_fact_confirmation_tracked",
                    subject_id=subject[:8] if subject else "?",
                    rel_type=rel_type,
                    object_id=obj[:8] if obj else "?",
                    fact_class=fact_class,
                    mechanism="PostgreSQL ON CONFLICT — confirmed_count incremented, promotes when >= 3"
                )
                count += 1
        db_conn.commit()
        # ── SYNC RELIABILITY: immediately vector-sync freshly-staged Class C ──────
        # Class C is the ONLY vector-indexed tier. The re_embedder poll picks up
        # unsynced C rows, but the benchmark/prod REEMBED_INTERVAL is kept HIGH (so
        # the deterministic A/B gating isn't perturbed by background churn) — that
        # would otherwise leave an engine-minted C fact UN-retrievable in the same
        # session. The /ingest class_c_rows branch has its own immediate-sync block,
        # but SEVERAL other engine paths mint C via _commit_staged WITHOUT it, so do
        # it HERE, once, for every C-minting caller. A/B never reach this (the guard
        # is fact_class == "C"). Fail-safe: any sync error is swallowed — Postgres
        # staged_facts is authoritative and the re_embedder remains the backstop.
        if fact_class == "C" and count > 0:
            # user_id rides in row[0] (collection naming needs the full UUID, which is
            # NOT recoverable from the per-user schema slug — so take it from the row).
            _c_user_id = rows[0][0] if rows and rows[0] else "anonymous"
            try:
                _immediate_sync_class_c_staged(db_conn, _c_user_id, limit=count)
            except Exception as _cse:  # noqa: BLE001 — never break the commit
                log.warning("ingest.commit_staged_c_sync_failed non-blocking",
                            error=str(_cse)[:160])
        return count
    except Exception as e:
        db_conn.rollback()
        log.error("ingest.staged_commit_failed",
                  err=str(e),
                  row_count=len(rows),
                  fact_class=fact_class,
                  first_row=str(rows[0]) if rows else "empty")
        return 0


def _immediate_sync_class_c_staged(db_conn, user_id: str, limit: int = 50) -> int:
    """Immediately embed + upsert freshly-staged Class C rows to Qdrant.

    SYNC RELIABILITY (sync-reliability fix): every Class-C minting path (not just the
    /ingest class_c_rows branch) routes through _commit_staged, so syncing here makes
    a legit engine-minted C fact retrievable in the SAME session without lowering
    REEMBED_INTERVAL. Class C is the only vector-indexed tier — A/B are PostgreSQL-only
    and never reach this. Idempotent: only rows with qdrant_synced=false are touched,
    so the re_embedder simply finds nothing left to do.

    Per-user schema is already bound on db_conn's search_path; collection is derived
    from the in-scope user. Returns the count upserted. Fail-safe: returns 0 on any
    error (Postgres remains authoritative; the re_embedder is the backstop).
    """
    qdrant_url = os.environ.get("QDRANT_URL", "http://qdrant:6333")
    upserted = 0
    try:
        with db_conn.cursor() as cur:
            cur.execute(
                "SELECT id, subject_id, object_id, rel_type, provenance, confidence, fact_class"
                " FROM staged_facts"
                " WHERE qdrant_synced = false AND promoted_at IS NULL AND expires_at > now()"
                "   AND fact_class = 'C' AND deleted_at IS NULL"
                " ORDER BY id DESC LIMIT %s",
                (max(1, int(limit)),),
            )
            fresh = cur.fetchall()
        if not fresh:
            return 0
        collection = derive_collection(user_id)
        ensure_collection(collection, qdrant_url)
        for sf_id, sf_subj, sf_obj, sf_rel, sf_prov, sf_conf, sf_class in fresh:
            text = f"{sf_subj} {sf_rel} {sf_obj}"
            vector = embed_text(text, _LLM_URL, timeout=10.0, fallback=True, embedding_url=_EMBEDDING_API_URL)
            if vector is None:
                continue
            s_row = {
                "id": sf_id,
                "user_id": user_id,
                "subject_id": sf_subj,
                "subject_display": sf_subj,
                "object_id": sf_obj,
                "object_display": sf_obj,
                "rel_type": sf_rel,
                "provenance": sf_prov,
                "confidence": float(sf_conf) if sf_conf else 0.4,
                "confirmed_count": 0,
                "last_seen_at": None,
                "contradicted_by": None,
                # Class C only (the SELECT enforces it); pass it through.
                "fact_class": sf_class or "C",
            }
            if upsert_to_qdrant(s_row, vector, collection, qdrant_url, source_table="staged_facts"):
                with db_conn.cursor() as _mark:
                    _mark.execute(
                        "UPDATE staged_facts SET qdrant_synced = true WHERE id = %s",
                        (sf_id,),
                    )
                upserted += 1
        if upserted > 0:
            db_conn.commit()
            log.info("ingest.commit_staged_c_synced", synced=upserted, fact_class="C")
    except Exception as e:  # noqa: BLE001 — graceful degradation
        try:
            db_conn.rollback()
        except Exception:
            pass
        log.warning("ingest.immediate_sync_class_c_failed non-blocking", error=str(e)[:160])
        return 0
    return upserted


def get_gliner_model():
    return _gliner2_model


# ── Staged-facts hierarchy conflict cleanup (ingest path) ────────────────────
# Mirrors the logic in WGMValidationGate._delete_conflicting_staged_hierarchy_facts()
# but lives here so it fires unconditionally after every hierarchy fact commit —
# including the MCP path (fact_provenance="mcp") which bypasses the WGM gate.
#
# Called from the ingest endpoint after class_a_rows and class_b_rows are committed
# whenever any row in that batch has is_hierarchy_rel=True.
#
# The gate's own call is preserved as belt-and-suspenders for the non-MCP path.

# Generic ontology-token entity names — subjects that appear in inverted rows
# (e.g. "person instance_of alexander").  These should never be subjects of
# hierarchy facts; rows where they ARE the subject are deleted.
# Mirrors WGMValidationGate._SYSTEM_ENTITY_NAMES.
_SYSTEM_ENTITY_NAMES: frozenset = frozenset({
    "faultline",
    "knowledgegraph", "knowledge graph", "knowledge_graph",
    "node", "edge", "entitynode", "entity node",
    "relationshipedge", "relationship edge",
    "object", "concept", "thing", "entity",
    "organization", "person", "location", "group", "place",
})


def _purge_conflicting_staged_hierarchy_facts(
    db_conn,
    subject_id: str,
    rel_type: str,
    object_id: str,
    user_id: str | None = None,
) -> int:
    """Delete staged_facts rows that contradict a just-committed hierarchy fact.

    Two classes of rows are removed:

    1. Conflicting type rows — same subject + rel_type, different object_id, not yet
       promoted (e.g. "university instance_of person" when "university instance_of
       organization" was just committed).  staged_facts has no superseded_at column;
       hard-delete is correct.

    2. Inverted rows — subject_id is a generic ontology token (matches
       _SYSTEM_ENTITY_NAMES) and rel_type is a hierarchy rel.  These are mis-extracted
       facts with subject/object swapped.

    Only fires when rel_type is a hierarchy rel (is_hierarchy_rel=True in _REL_TYPE_META).
    Falls back to the hardcoded set if the metadata cache is empty (startup edge case).

    Qdrant cleanup is best-effort: failure never blocks the commit.

    Returns total number of staged_facts rows deleted.
    """
    rt_lower = rel_type.lower().strip()

    # Metadata-driven: check _REL_TYPE_META (loaded at startup), never hardcoded strings.
    rel_meta = _REL_TYPE_META.get(rt_lower)
    if rel_meta is not None:
        if not rel_meta.get("is_hierarchy_rel", False):
            return 0
    else:
        # Cache miss (startup race or novel rel_type) — use well-known fallback set.
        _FALLBACK_HIER = frozenset({"instance_of", "subclass_of", "part_of", "is_a", "member_of"})
        if rt_lower not in _FALLBACK_HIER:
            return 0

    deleted_ids: list[int] = []

    try:
        with db_conn.cursor() as cur:
            # Pass 1: conflicting type rows (same subject + rel_type, different object)
            cur.execute(
                """
                SELECT id FROM staged_facts
                WHERE subject_id = %s
                  AND rel_type   = %s
                  AND object_id != %s
                  AND promoted_at IS NULL
                """,
                (subject_id, rt_lower, object_id),
            )
            conflict_rows = [r[0] for r in cur.fetchall()]

            # Pass 2: inverted rows
            subj_lower = str(subject_id).lower().strip()
            if subj_lower in _SYSTEM_ENTITY_NAMES:
                # The incoming fact is itself inverted — also purge pre-existing inverted rows.
                cur.execute(
                    """
                    SELECT id FROM staged_facts
                    WHERE subject_id = %s
                      AND rel_type   = %s
                      AND promoted_at IS NULL
                    """,
                    (subject_id, rt_lower),
                )
                inverted_rows = [r[0] for r in cur.fetchall()]
            else:
                # Purge previously-written inverted rows (subject is a system token).
                cur.execute(
                    """
                    SELECT sf.id FROM staged_facts sf
                    WHERE sf.rel_type = %s
                      AND sf.promoted_at IS NULL
                      AND lower(sf.subject_id) = ANY(%s)
                    """,
                    (rt_lower, list(_SYSTEM_ENTITY_NAMES)),
                )
                inverted_rows = [r[0] for r in cur.fetchall()]

            all_to_delete = list(set(conflict_rows + inverted_rows))
            if not all_to_delete:
                return 0

            cur.execute(
                "DELETE FROM staged_facts WHERE id = ANY(%s)",
                (all_to_delete,),
            )
            deleted_count = cur.rowcount

        db_conn.commit()
        deleted_ids = all_to_delete

        log.info(
            "ingest.staged_hierarchy_conflicts_purged",
            subject_id=str(subject_id)[:16],
            rel_type=rt_lower,
            incoming_object=str(object_id)[:16],
            conflict_rows=len(conflict_rows),
            inverted_rows=len(inverted_rows),
            deleted_count=deleted_count,
        )

    except Exception as e:
        log.error(
            "ingest.staged_hierarchy_conflict_purge_failed",
            subject_id=str(subject_id)[:16],
            rel_type=rt_lower,
            error=str(e),
        )
        try:
            db_conn.rollback()
        except Exception:
            pass
        return 0

    # Best-effort Qdrant cleanup — never affects ingest outcome.
    if deleted_ids and user_id:
        try:
            _qdrant_url = os.environ.get("QDRANT_URL", "http://qdrant:6333")
            collection = derive_collection(user_id)
            # Filtered delete (new points with source_table payload field)
            for _did in deleted_ids:
                _http_client_sync.post(
                    f"{_qdrant_url}/collections/{collection}/points/delete",
                    json={
                        "filter": {
                            "must": [
                                {"key": "source_table", "match": {"value": "staged_facts"}},
                                {"key": "fact_id",     "match": {"value": _did}},
                            ]
                        }
                    },
                    timeout=5.0,
                )
            # Fallback by derived point ID (new (source_table, fact_id) scheme). Legacy
            # bare-int points are cleaned by re_embedder reconcile / collection re-sync.
            # Qdrant points-delete is a POST with a points-selector body; httpx .delete()
            # takes no body kwarg (json/content), so the call must POST to /points/delete.
            _http_client_sync.post(
                f"{_qdrant_url}/collections/{collection}/points/delete",
                json={"points": [derive_qdrant_point_id("staged_facts", _did) for _did in deleted_ids]},
                timeout=5.0,
            )
            log.info(
                "ingest.staged_hierarchy_qdrant_purged",
                collection=collection,
                deleted_count=len(deleted_ids),
            )
        except Exception as qe:
            log.warning(
                "ingest.staged_hierarchy_qdrant_purge_failed",
                error=str(qe),
            )

    return deleted_count

# ── end staged-facts hierarchy conflict cleanup (ingest path) ─────────────────


def _cleanup_entity_aliases_startup(dsn: str) -> None:
    """
    Clean up corrupted entity_aliases entries where entity_id is a string (not UUID).
    Entity IDs must always be UUID v5 surrogates or 'user'.
    This is idempotent and safe to run repeatedly.
    """
    try:
        with psycopg2.connect(dsn) as conn:
            with conn.cursor() as cur:
                # Find entity_aliases with string entity_ids (not UUID, not 'user')
                cur.execute("""
                    SELECT COUNT(*) FROM entity_aliases
                    WHERE entity_id NOT LIKE '%-%-%-%-%' AND entity_id != 'user'
                """)
                bad_count = cur.fetchone()[0]

                if bad_count == 0:
                    log.info("startup.entity_aliases_cleanup", status="ok")
                    return

                log.warning("startup.entity_aliases_corrupted_found",
                           corrupted_count=bad_count)

                # Delete corrupted entries (string entity_ids)
                # When the system re-ingests the correct edges, it will re-register
                # with proper UUID entity_ids via registry.register_alias()
                cur.execute("""
                    DELETE FROM entity_aliases
                    WHERE entity_id NOT LIKE '%-%-%-%-%' AND entity_id != 'user'
                """)
                deleted = cur.rowcount
                conn.commit()

                log.info("startup.entity_aliases_cleanup_deleted",
                        deleted_count=deleted)
    except Exception as e:
        log.error("startup.entity_aliases_cleanup_failed", error=str(e))


def _normalize_entity_ids_startup(dsn: str) -> None:
    """
    Normalize string entity_ids to UUID v5 surrogates at startup.
    This is idempotent and safe to run repeatedly.

    Scans facts/staged_facts for non-UUID entity_ids and converts them
    using EntityRegistry._make_surrogate() logic.
    """
    try:
        from src.entity_registry.registry import _make_surrogate

        with psycopg2.connect(dsn) as conn:
            with conn.cursor() as cur:
                # Find all string entity_ids
                # CRITICAL: Exclude scalar rel_types (also_known_as, pref_name) from object_id
                # normalization — their objects are display names, not entity references.
                cur.execute("""
                    SELECT DISTINCT user_id, subject_id FROM facts
                    WHERE subject_id NOT LIKE '%-%-%-%-%'
                    UNION
                    SELECT DISTINCT user_id, object_id FROM facts
                    WHERE object_id NOT LIKE '%-%-%-%-%'
                      AND rel_type NOT IN ('also_known_as', 'pref_name')
                    UNION
                    SELECT DISTINCT user_id, subject_id FROM staged_facts
                    WHERE subject_id NOT LIKE '%-%-%-%-%'
                    UNION
                    SELECT DISTINCT user_id, object_id FROM staged_facts
                    WHERE object_id NOT LIKE '%-%-%-%-%'
                      AND rel_type NOT IN ('also_known_as', 'pref_name')
                """)
                string_ids = cur.fetchall()

                if not string_ids:
                    log.info("startup.entity_id_normalization_check", status="ok")
                    return

                log.info("startup.entity_id_normalization_starting",
                         string_id_count=len(string_ids))

                # Build mapping from (user_id, string_id) -> surrogate UUID
                entity_map = {}
                for user_id, string_id in string_ids:
                    if not _UUID_PATTERN.match(string_id):
                        surrogate = _make_surrogate(user_id, string_id)
                        entity_map[(user_id, string_id)] = surrogate

                # Update facts table
                updated_count = 0
                for (user_id, string_id), surrogate in entity_map.items():
                    cur.execute(
                        "UPDATE facts SET subject_id = %s WHERE user_id = %s AND subject_id = %s",
                        (surrogate, user_id, string_id)
                    )
                    updated_count += cur.rowcount

                    cur.execute(
                        "UPDATE facts SET object_id = %s WHERE user_id = %s AND object_id = %s",
                        (surrogate, user_id, string_id)
                    )
                    updated_count += cur.rowcount

                # Update staged_facts table
                for (user_id, string_id), surrogate in entity_map.items():
                    cur.execute(
                        "UPDATE staged_facts SET subject_id = %s WHERE user_id = %s AND subject_id = %s",
                        (surrogate, user_id, string_id)
                    )
                    updated_count += cur.rowcount

                    cur.execute(
                        "UPDATE staged_facts SET object_id = %s WHERE user_id = %s AND object_id = %s",
                        (surrogate, user_id, string_id)
                    )
                    updated_count += cur.rowcount

                # Ensure entities are registered
                for (user_id, string_id), surrogate in entity_map.items():
                    cur.execute(
                        "INSERT INTO entities (id, entity_type) VALUES (%s, 'unknown') "
                        "ON CONFLICT (id, user_id) DO NOTHING",
                        (surrogate, user_id)
                    )

                # Sync aliases (is_preferred only for user identity anchors, not for other entities)
                for (user_id, string_id), surrogate in entity_map.items():
                    # Only mark as preferred if it's a user identity anchor (user, user_id, etc.)
                    # Other entities (family, pets) default to is_preferred=false
                    is_pref = string_id.lower() in ("user", "me", "myself")
                    cur.execute(
                        "INSERT INTO entity_aliases (entity_id, alias, is_preferred) "
                        "VALUES (%s, %s, %s) ON CONFLICT (entity_id, alias) DO UPDATE SET is_preferred = EXCLUDED.is_preferred",
                        (surrogate, string_id.lower(), is_pref)
                    )

                conn.commit()
                log.info("startup.entity_id_normalization_complete",
                         string_ids_processed=len(entity_map),
                         rows_updated=updated_count)
    except Exception as e:
        log.error("startup.entity_id_normalization_failed", error=str(e))


def _validate_schema_columns(dsn: str) -> dict:
    """
    Proactive schema validation: compare expected columns against actual DB schema.
    Fails fast with clear error message if any mismatch found.

    Returns dict mapping table_name -> set of expected columns.
    Raises RuntimeError if actual schema doesn't match expected.
    """
    # Define expected columns for critical tables
    # These must match the INSERT statements in FactStoreManager.commit()
    EXPECTED_SCHEMA = {
        "facts": {
            "id", "user_id", "subject_id", "object_id", "rel_type",
            "provenance", "confidence", "unified_confidence",
            "is_preferred_label", "rel_type_definition",
            "storage_type", "is_hierarchy_rel", "taxonomies",
            "created_at", "qdrant_synced", "confirmed_count",
            "last_seen_at", "updated_at", "fact_provenance", "fact_class",
            "archived_at", "source_weight"  # legacy column, may be dropped
        },
        "staged_facts": {
            "id", "user_id", "subject_id", "object_id", "rel_type",
            "fact_class", "provenance", "confidence", "unified_confidence",
            "confirmed_count", "first_seen_at", "last_seen_at",
            "expires_at", "promoted_at", "qdrant_synced",
            "rel_type_definition", "storage_type", "is_hierarchy_rel",
            "taxonomies", "created_at", "updated_at"
        },
        "rel_types": {
            "rel_type", "label", "wikidata_pid", "engine_generated",
            "confidence", "source", "correction_behavior", "category",
            "head_types", "tail_types", "is_symmetric", "inverse_rel_type",
            "is_leaf_only", "is_hierarchy_rel", "allows_leaf_rels",
            "created_at", "updated_at"
        },
        "entities": {
            "id", "user_id", "entity_type", "created_at", "updated_at"
        },
        "entity_aliases": {
            "entity_id", "user_id", "alias", "is_preferred",
            "created_at", "updated_at"
        },
    }

    try:
        with psycopg2.connect(dsn) as conn:
            with conn.cursor() as cur:
                for table_name, expected_cols in EXPECTED_SCHEMA.items():
                    # Query actual columns from information_schema
                    cur.execute(
                        "SELECT column_name FROM information_schema.columns "
                        "WHERE table_schema = 'public' AND table_name = %s",
                        (table_name,)
                    )
                    actual_cols = {row[0] for row in cur.fetchall()}

                    if not actual_cols:
                        raise RuntimeError(
                            f"Schema validation failed: table '{table_name}' not found in database. "
                            "Has the database been initialized with migrations?"
                        )

                    # Check for critical columns (must exist)
                    # Core columns that FactStoreManager depends on
                    critical_for_facts = {
                        "subject_id", "object_id", "rel_type", "provenance",
                        "confidence", "unified_confidence", "is_preferred_label",
                        "rel_type_definition", "storage_type", "is_hierarchy_rel",
                        "taxonomies"
                    }

                    if table_name == "facts":
                        missing = critical_for_facts - actual_cols
                        if missing:
                            raise RuntimeError(
                                f"Schema validation failed for '{table_name}': "
                                f"missing critical columns: {', '.join(sorted(missing))}. "
                                f"Run migrations before starting the service."
                            )

                    # Log unexpected columns (but don't fail on them)
                    unexpected = actual_cols - expected_cols
                    if unexpected and len(unexpected) > 2:  # noise threshold
                        log.warning(
                            "schema_validation_extra_columns",
                            table=table_name,
                            extra_count=len(unexpected),
                            samples=list(unexpected)[:3]
                        )

        log.info("startup.schema_columns_validation_passed",
                 tables_checked=len(EXPECTED_SCHEMA),
                 critical_columns_verified=True)
        return EXPECTED_SCHEMA

    except RuntimeError:
        raise
    except Exception as e:
        raise RuntimeError(
            f"Schema validation error: {str(e)}. "
            f"Check POSTGRES_DSN and database connectivity."
        )


def _ensure_schema(dsn: str) -> None:
    """
    Apply any pending schema migrations at startup.
    This is the idempotent equivalent of running migration SQL files —
    column renames, type changes, seed data. Each statement uses IF EXISTS
    or information_schema checks so it's safe to run on any DB state.
    """
    try:
        with psycopg2.connect(dsn) as conn:
            with conn.cursor() as cur:
                # Rename allowed_head → head_types if the old column exists
                cur.execute(
                    "SELECT column_name FROM information_schema.columns "
                    "WHERE table_name = 'rel_types' AND column_name = 'allowed_head'"
                )
                if cur.fetchone():
                    cur.execute("ALTER TABLE rel_types RENAME COLUMN allowed_head TO head_types")
                    log.info("startup.schema_rename", old="allowed_head", new="head_types")

                # Rename allowed_tail → tail_types if the old column exists
                cur.execute(
                    "SELECT column_name FROM information_schema.columns "
                    "WHERE table_name = 'rel_types' AND column_name = 'allowed_tail'"
                )
                if cur.fetchone():
                    cur.execute("ALTER TABLE rel_types RENAME COLUMN allowed_tail TO tail_types")
                    log.info("startup.schema_rename", old="allowed_tail", new="tail_types")

                # Alter staged_facts.user_id from UUID to TEXT (conditional)
                cur.execute(
                    "SELECT data_type FROM information_schema.columns "
                    "WHERE table_name = 'staged_facts' AND column_name = 'user_id'"
                )
                row = cur.fetchone()
                if row and row[0].upper() == 'UUID':
                    cur.execute("ALTER TABLE staged_facts ALTER COLUMN user_id TYPE TEXT")
                    cur.execute("ALTER TABLE staged_facts ALTER COLUMN subject_id TYPE TEXT")
                    cur.execute("ALTER TABLE staged_facts ALTER COLUMN object_id TYPE TEXT")
                    log.info("startup.schema_staged_facts_uuid_to_text")

                # Seed missing rel_types that are referenced in code but might
                # not exist in the DB (safe — ON CONFLICT DO NOTHING)
                _MISSING_TYPES = [
                    ("lives_at", "Lives At", "location", "supersede"),
                    ("located_at", "Located At", "location", "supersede"),
                    ("has_pet", "Has Pet", "pets", "supersede"),
                    ("height", "Height", "physical", "supersede"),
                    ("weight", "Weight", "physical", "supersede"),
                    ("has_ip", "Has IP Address", "system", "supersede"),
                    ("has_os", "Has Operating System", "system", "supersede"),
                    ("has_hostname", "Has Hostname", "system", "supersede"),
                    ("hostname", "Hostname", "system", "supersede"),
                    ("fqdn", "Fully Qualified Domain Name", "system", "supersede"),
                    ("ip_address", "IP Address", "system", "supersede"),
                    ("member_of", "Member Of", "identity", "supersede"),
                ]
                for rel_type, label, category, correction_behavior in _MISSING_TYPES:
                    cur.execute(
                        "INSERT INTO rel_types (rel_type, label, category, correction_behavior, source) "
                        "VALUES (%s, %s, %s, %s, 'builtin') "
                        "ON CONFLICT (rel_type) DO NOTHING",
                        (rel_type, label, category, correction_behavior),
                    )

                # ── Migration 019: entity_taxonomies (data-driven grouping system) ──
                cur.execute("""
                    CREATE TABLE IF NOT EXISTS entity_taxonomies (
                        id BIGSERIAL PRIMARY KEY,
                        taxonomy_name VARCHAR(64) NOT NULL UNIQUE,
                        description TEXT,
                        member_entity_types TEXT[] NOT NULL DEFAULT '{}',
                        rel_types_defining_group TEXT[] NOT NULL DEFAULT '{}',
                        has_transitivity BOOLEAN DEFAULT false,
                        transitive_rel_types TEXT[] DEFAULT '{}',
                        is_hierarchical BOOLEAN DEFAULT false,
                        parent_rel_type VARCHAR(64),
                        source VARCHAR(32) DEFAULT 'seeded',
                        created_at TIMESTAMP DEFAULT now()
                    )
                """)

                # Taxonomy seeding removed (dprompt-86).
                # Rationale: Hardcoded seeding creates brittleness (stale references like 'body_parts'
                # that don't exist, breaking extraction). Taxonomies should emerge from data via
                # self-building ontology. Graph traversal + LLM are authoritative for entity relationships.
                # Taxonomies table remains for future data-driven population and query-time filtering.

                # ── Migration 022: rel_types metadata (dprompt-65) ──
                # Add validation columns to rel_types + pre-populate metadata.
                # Idempotent: uses IF NOT EXISTS for columns, UPDATE for data.
                cur.execute("""
                    DO $$
                    BEGIN
                        IF NOT EXISTS (SELECT 1 FROM information_schema.columns
                                       WHERE table_name='rel_types' AND column_name='is_symmetric')
                        THEN ALTER TABLE rel_types ADD COLUMN is_symmetric BOOLEAN DEFAULT FALSE; END IF;
                        IF NOT EXISTS (SELECT 1 FROM information_schema.columns
                                       WHERE table_name='rel_types' AND column_name='inverse_rel_type')
                        THEN ALTER TABLE rel_types ADD COLUMN inverse_rel_type VARCHAR(100) DEFAULT NULL; END IF;
                        IF NOT EXISTS (SELECT 1 FROM information_schema.columns
                                       WHERE table_name='rel_types' AND column_name='is_leaf_only')
                        THEN ALTER TABLE rel_types ADD COLUMN is_leaf_only BOOLEAN DEFAULT FALSE; END IF;
                        IF NOT EXISTS (SELECT 1 FROM information_schema.columns
                                       WHERE table_name='rel_types' AND column_name='is_hierarchy_rel')
                        THEN ALTER TABLE rel_types ADD COLUMN is_hierarchy_rel BOOLEAN DEFAULT FALSE; END IF;
                        IF NOT EXISTS (SELECT 1 FROM information_schema.columns
                                       WHERE table_name='rel_types' AND column_name='allows_leaf_rels')
                        THEN ALTER TABLE rel_types ADD COLUMN allows_leaf_rels TEXT[] DEFAULT NULL; END IF;
                    END $$;
                """)
                cur.execute("UPDATE rel_types SET is_symmetric=TRUE WHERE rel_type IN ('spouse','sibling_of','knows','friend_of','met','same_as')")
                cur.execute("UPDATE rel_types SET inverse_rel_type='child_of' WHERE rel_type='parent_of'")
                cur.execute("UPDATE rel_types SET inverse_rel_type='parent_of' WHERE rel_type='child_of'")
                # is_leaf_only constraint removed (dprompt-86). Rationale: Too restrictive — prevents
                # legitimate facts like (user, lives_at, address) where address has instance_of type info.
                # Semantic conflict detection should not block leaf relationships on typed entities.
                cur.execute("UPDATE rel_types SET is_hierarchy_rel=TRUE WHERE rel_type IN ('instance_of','subclass_of','member_of','part_of','is_a')")

                # ── Migration 028: rel_type_definition column (dprompt-85) ──
                cur.execute("""
                    DO $$
                    BEGIN
                        IF NOT EXISTS (SELECT 1 FROM information_schema.columns
                                       WHERE table_name='facts' AND column_name='rel_type_definition')
                        THEN ALTER TABLE facts ADD COLUMN rel_type_definition TEXT DEFAULT ''; END IF;
                        IF NOT EXISTS (SELECT 1 FROM information_schema.columns
                                       WHERE table_name='staged_facts' AND column_name='rel_type_definition')
                        THEN ALTER TABLE staged_facts ADD COLUMN rel_type_definition TEXT DEFAULT ''; END IF;
                    END $$;
                """)

                # ── Migration 053: intent_classes (dprompt-152) ──
                # Metadata-driven intent class definitions for GLiNER2 semantic enrichment
                cur.execute("""
                    CREATE TABLE IF NOT EXISTS intent_classes (
                        id SERIAL PRIMARY KEY,
                        intent_name VARCHAR(50) NOT NULL UNIQUE,
                        description TEXT NOT NULL,
                        priority INT DEFAULT 100,
                        version INT DEFAULT 1,
                        refined_at TIMESTAMP DEFAULT now(),
                        is_active BOOLEAN DEFAULT true,
                        created_at TIMESTAMP DEFAULT now(),
                        updated_at TIMESTAMP DEFAULT now(),
                        refined_by VARCHAR(255) DEFAULT 'bootstrap'
                    )
                """)

                # Create indexes for fast lookup
                cur.execute("""
                    CREATE INDEX IF NOT EXISTS idx_intent_classes_name
                    ON intent_classes (intent_name)
                """)
                cur.execute("""
                    CREATE INDEX IF NOT EXISTS idx_intent_classes_active
                    ON intent_classes (is_active) WHERE is_active = true
                """)
                cur.execute("""
                    CREATE INDEX IF NOT EXISTS idx_intent_classes_priority
                    ON intent_classes (priority DESC) WHERE is_active = true
                """)

                # Populate intent classes with concise zero-shot descriptions for GLiNER2
                # (Pitfall 11 — keep zero-shot labels concise, single-concept, no examples).
                # D1_HYBRID label set: benchmarked on fastino/gliner2-base-v1 (39 cases) at
                # 87.2% accuracy / 0-of-10 false-CORRECTION / 20-of-20 STATEMENT, vs the prior
                # verbose labels at 48.7% / 8-of-10 editor-usage statements mis-scored as
                # CORRECTION. MUST stay byte-identical to _build_intent_descriptions_for_gliner2().
                _INTENT_CLASSES = [
                    ('QUERY',      'asking a question', 100),
                    ('STATEMENT',  'stating a fact, preference, or habit', 100),
                    ('RETRACTION', 'deleting or forgetting information', 100),
                    ('CORRECTION', 'replacing a previously stated value with a different one', 100),
                ]

                for intent_name, description, priority in _INTENT_CLASSES:
                    cur.execute("""
                        INSERT INTO intent_classes (intent_name, description, priority, refined_by)
                        VALUES (%s, %s, %s, 'bootstrap')
                        ON CONFLICT (intent_name) DO NOTHING
                    """, (intent_name, description, priority))

                log.info("startup.intent_classes_seeded", inserted=cur.rowcount)
                conn.commit()
                log.info("startup.schema_check_complete")
    except Exception as e:
        log.warning("startup.schema_check_failed", error=str(e))


# ── Entity Taxonomies (dprompt-20) ───────────────────────────────────────────
# Data-driven grouping system — replaces brittle hardcoded extraction patterns.

_TAXONOMY_CACHE: dict = {}


def _apply_taxonomy_rules(
    rows: list[tuple],
    user_id: str,
    db_conn,
) -> list[tuple]:
    """
    Given ingest rows, check each fact against registered taxonomies.
    CHAIN: determine → search → create/link

    For each unique rel_type:
      1. Search existing taxonomies (via _TAXONOMY_CACHE)
      2. If NO match → discover via LLM
      3. If discovered → INSERT into entity_taxonomies (immediate commit)
      4. Reload cache so subsequent facts see new taxonomy
      5. Annotate rows with taxonomy context

    Returns rows with taxonomy annotations (same rows, enhanced with taxonomy metadata).
    Does NOT change fact_class or storage path.
    """
    global _TAXONOMY_CACHE

    if not rows:
        return rows

    # Step 1: Collect unique rel_types from this ingest batch
    unique_rel_types = set()
    for row in rows:
        rel_type = row[3] if len(row) > 3 else None
        if rel_type:
            unique_rel_types.add(rel_type.lower().strip())

    # Step 2: For each rel_type, check existing taxonomies and discover if needed
    for rt_lower in unique_rel_types:
        # Check 1: Does this rel_type already match an existing taxonomy?
        found_in_existing = False
        for tax_name, tax_meta in _TAXONOMY_CACHE.items():
            def_rels = [r.lower() for r in tax_meta.get("rel_types_defining_group", []) if r]
            if rt_lower in def_rels:
                log.info("ingest.taxonomy_match_existing",
                        rel_type=rt_lower, taxonomy=tax_name)
                found_in_existing = True
                break

        if found_in_existing:
            continue

        # Check 2: Not in existing taxonomy — attempt LLM discovery
        try:
            # Fetch natural language definition from rel_types table for LLM context
            # LLMs reason better with semantic definitions than raw rel_type strings
            natural_lang = None
            try:
                with db_conn.cursor() as cur:
                    cur.execute(
                        "SELECT natural_language, label, examples FROM rel_types WHERE rel_type = %s",
                        (rt_lower,)
                    )
                    rt_row = cur.fetchone()
                    if rt_row:
                        natural_lang = rt_row[0]  # natural_language definition
            except Exception as _nl_err:
                log.debug("ingest.natural_language_lookup_failed",
                         rel_type=rt_lower, error=str(_nl_err))

            # Collect facts with this rel_type + semantic definition for LLM context
            discovery_facts = [{"rel_type": rt_lower, "natural_language": natural_lang}]

            # dprompt-142: Removed qwen_url parameter — now uses centralized resolver
            discovered = _llm_discover_taxonomy_from_facts(db_conn, user_id, discovery_facts)

            if not discovered:
                log.info("ingest.taxonomy_discovery_declined",
                        rel_type=rt_lower, reason="llm_no_natural_grouping")
                continue

            # Check 3: Create taxonomy in DB with immediate commit
            taxonomy_name = discovered.get("taxonomy_name")
            if not taxonomy_name:
                log.info("ingest.taxonomy_discovery_no_name",
                        rel_type=rt_lower)
                continue

            # Insert with proper DB context and commit
            try:
                with db_conn.cursor() as cur:
                    cur.execute(
                        "INSERT INTO entity_taxonomies "
                        "(taxonomy_name, description, member_entity_types, rel_types_defining_group, "
                        "has_transitivity, transitive_rel_types, is_hierarchical, parent_rel_type, source) "
                        "VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s) "
                        "ON CONFLICT (taxonomy_name) DO NOTHING",
                        (
                            taxonomy_name,
                            discovered.get("description", ""),
                            discovered.get("member_entity_types", "{}"),
                            discovered.get("rel_types_defining_group", []),
                            discovered.get("has_transitivity", False),
                            discovered.get("transitive_rel_types", "{}"),
                            discovered.get("is_hierarchical", False),
                            discovered.get("parent_rel_type"),
                            "engine_learned_ingest",
                        ),
                    )
                db_conn.commit()

                # Step 4: Reload taxonomy cache immediately
                _load_taxonomy_cache(db_conn)

                log.info("ingest.taxonomy_created_and_cached",
                        taxonomy_name=taxonomy_name,
                        rel_types=discovered.get("rel_types_defining_group", []),
                        source="engine_learned_ingest")

            except Exception as _db_err:
                log.warning("ingest.taxonomy_insert_failed",
                           taxonomy_name=taxonomy_name,
                           error=str(_db_err))
                db_conn.rollback()
                # Continue — don't fail ingest if taxonomy creation fails

        except Exception as _discovery_err:
            log.warning("ingest.taxonomy_discovery_failed",
                       rel_type=rt_lower,
                       error=str(_discovery_err))
            # Continue — don't fail ingest if discovery fails

    # Step 5: Annotate rows with taxonomy context (for query expansion later)
    for i, row in enumerate(rows):
        rt_lower = (row[3] or "").lower().strip() if len(row) > 3 else ""

        # Find which taxonomy(ies) this rel_type defines
        taxonomies_for_rel = []
        for tax_name, tax_meta in _TAXONOMY_CACHE.items():
            def_rels = [r.lower() for r in tax_meta.get("rel_types_defining_group", []) if r]
            if rt_lower in def_rels:
                taxonomies_for_rel.append(tax_name)

        # If row has taxonomy context slot, update it
        if len(row) > 12:  # taxonomies at index 12
            rows[i] = row[:12] + (taxonomies_for_rel,) + row[13:]
        elif len(row) == 12:  # Add taxonomy slot if missing
            rows[i] = row + (taxonomies_for_rel,)

        if taxonomies_for_rel:
            log.info("ingest.row_annotated_with_taxonomy",
                    rel_type=rt_lower, taxonomies=taxonomies_for_rel)

    return rows


def _llm_discover_taxonomy_from_facts(
    db_conn,
    user_id: str,
    facts: list[dict],
) -> dict | None:
    """
    Analyze fetched facts to discover what taxonomy they might define.
    Uses centralized endpoint resolver.
    Returns dict for INSERT into entity_taxonomies, or None if discovery fails.

    Sends to LLM:
    1. Examples of existing taxonomies (structure + rel_types)
    2. The facts that were fetched (rel_types, count)
    3. Request: "What taxonomy group do these rel_types define?"

    LLM returns: {taxonomy_name, description, rel_types_defining_group, ...}
    """
    if not facts:
        return None

    try:
        # Fetch existing taxonomies as dynamic examples (LIMITED to prevent context bloat)
        # dBug-051 fix: Unbounded taxonomy fetch was causing 5-15KB context. Now LIMIT 20.
        with db_conn.cursor() as cur:
            cur.execute(
                "SELECT taxonomy_name, description, rel_types_defining_group "
                "FROM entity_taxonomies ORDER BY created_at DESC LIMIT 20"
            )
            examples = cur.fetchall()

        if not examples:
            log.info("taxonomy.discover_skipped", reason="no_existing_taxonomies_to_use_as_context")
            return None

        # dBug-051 fix: Limit facts iteration to 50 max to prevent unbounded context growth
        facts_to_analyze = facts[:50]

        # Analyze facts: collect rel_types with natural language definitions
        rel_types_in_facts = [f.get("rel_type") for f in facts_to_analyze if f.get("rel_type")]
        rel_type_counts = {}
        rel_type_definitions = {}  # rel_type → natural_language
        for fact in facts_to_analyze:
            rt = fact.get("rel_type")
            if rt:
                rt_lower = rt.lower()
                rel_type_counts[rt_lower] = rel_type_counts.get(rt_lower, 0) + 1
                # Use provided natural_language if available (from rel_types table)
                if "natural_language" in fact and fact["natural_language"]:
                    rel_type_definitions[rt_lower] = fact["natural_language"]

        # Build dynamic examples from actual entity_taxonomies (growing as system learns)
        # Fetch semantic definitions for rel_types in each taxonomy
        examples_with_semantics = []
        for tax_name, tax_desc, tax_rels in examples:
            # Fetch natural_language definitions for rel_types in this taxonomy
            rel_defs = []
            if tax_rels:
                try:
                    placeholders = ",".join(["%s"] * len(tax_rels))
                    with db_conn.cursor() as cur:
                        cur.execute(
                            f"SELECT rel_type, natural_language FROM rel_types WHERE rel_type IN ({placeholders})",
                            tax_rels
                        )
                        for rel_type, natural_lang in cur.fetchall():
                            rel_defs.append(f"{rel_type} ({natural_lang or 'no definition'})")
                except Exception as _e:
                    # Fallback: use raw rel_types if lookup fails
                    rel_defs = tax_rels

            rel_defs_str = ", ".join(rel_defs) if rel_defs else "(no rel_types)"
            examples_with_semantics.append(
                f"- {tax_name}: {tax_desc or '(no description)'}\n  Defines members via: {rel_defs_str}"
            )

        examples_text = "\n".join(examples_with_semantics)

        # Build rel_types text with semantic definitions for stronger reasoning
        rel_types_with_defs = []
        for rt, cnt in sorted(rel_type_counts.items(), key=lambda x: -x[1]):
            if rt in rel_type_definitions:
                # Include semantic definition: much stronger for LLM reasoning
                rel_types_with_defs.append(f"- {rt}: {rel_type_definitions[rt]}")
            else:
                # Fallback to raw rel_type
                rel_types_with_defs.append(f"- {rt}")
        rel_types_text = "\n".join(rel_types_with_defs)

        prompt = f"""Analyze the following rel_types and their semantic meanings. Suggest if they define a new taxonomy group.

EXISTING TAXONOMIES (learned examples—use these as reference for patterns):
{examples_text}

REL_TYPES BEING ANALYZED (with semantic definitions):
{rel_types_text}

TASK: Do these rel_types define a natural grouping (taxonomy)?
Look at the semantic meanings. Similar to existing taxonomies:
- Taxonomies group rel_types that share a common semantic domain
- Each rel_type in the group contributes to defining membership in that domain
- E.g., family groups kinship rel_types; work groups employment rel_types

CRITICAL: rel_types_defining_group must NOT include instance_of, subclass_of, part_of, member_of, is_a, or any hierarchy/classification rel_type. Only include behavioral rel_types that describe what entities DO (works_for, owns, lives_at, etc.), not what they ARE.

If these rel_types form a natural semantic grouping, respond with JSON:
{{"taxonomy_name": "name", "description": "brief description explaining the grouping", "rel_types_defining_group": ["rel1", "rel2"]}}

If they do NOT form a natural grouping, respond with:
{{"taxonomy_name": null}}

Respond ONLY with valid JSON, no markdown or explanation."""

        messages = [{"role": "user", "content": prompt}]
        payload = build_llm_payload(
            messages=messages,
            model=LLMModels.get("TAXONOMY_DISCOVERY"),
            user_id=user_id,
            system="You are an ontology expert.",
            temperature=0.0,
            max_tokens=256,
            # NOTE: thinking parameter removed — Qwen doesn't support extended thinking
        )

        from src.api.llm_calls import (
            _llm_http_client,
            _llm_circuit_breaker,
            _get_endpoint_list,
            _parse_llm_response_robust,
        )

        if _llm_circuit_breaker.is_open():
            log.warning("taxonomy.discover_circuit_breaker_open",
                        rel_types=list(rel_type_counts.keys()))
            return None

        endpoints = _get_endpoint_list()
        if not endpoints:
            log.warning("taxonomy.discover_no_endpoints")
            return None

        endpoint = endpoints[0]  # Best-effort: primary endpoint only, no retry

        resp = _llm_http_client.post(
            endpoint,
            json=payload,
            headers=get_llm_headers(),
            timeout=LLMTimeouts.get("TAXONOMY_DISCOVERY"),
        )
        resp.raise_for_status()

        result = _parse_llm_response_robust(resp)
        if not result:
            return None

        content = result.get("choices", [{}])[0].get("message", {}).get("content", "").strip()
        if not content:
            return None

        import json
        parsed = json.loads(content)
        if not parsed.get("taxonomy_name"):
            log.info("taxonomy.discover_llm_declined", rel_types=list(rel_type_counts.keys()))
            return None

        # Validate taxonomy_name
        tax_name = parsed.get("taxonomy_name", "").lower().strip()
        if not tax_name or len(tax_name) > 64 or not all(c.isalnum() or c == '_' for c in tax_name):
            log.warning("taxonomy.discover_invalid_name", name=tax_name)
            return None

        taxonomy_def = {
            "taxonomy_name": tax_name,
            "description": parsed.get("description", ""),
            "member_entity_types": "{}",  # Will be populated as facts are classified
            "rel_types_defining_group": parsed.get("rel_types_defining_group", []),
            "has_transitivity": False,
            "transitive_rel_types": "{}",
            "is_hierarchical": False,
            "parent_rel_type": None,
            "source": "llm_learned",
        }

        log.info("taxonomy.discovered_by_llm", taxonomy_name=tax_name,
                 defining_rels=taxonomy_def["rel_types_defining_group"])
        return taxonomy_def

    except Exception as e:
        log.warning("taxonomy.discover_failed", error=str(e))
        return None


def _fetch_transitive_members(
    db_conn,
    user_id: str,
    taxonomy_name: str,
) -> set[str]:
    """
    Given a taxonomy name (e.g., 'family'), return all entity UUIDs that are
    transitive members — direct relations PLUS entities reachable via
    transitive_rel_types from direct members.
    """
    tax = _TAXONOMY_CACHE.get(taxonomy_name)
    if not tax or not tax.get("has_transitivity"):
        return set()

    try:
        with db_conn.cursor() as cur:
            # Direct members: entities related to user via defining rel_types
            # NOTE: Per-user schema context — user_id filter removed, schema isolation handles scoping
            cur.execute(
                "SELECT DISTINCT object_id FROM facts"
                " WHERE subject_id = %s"
                " AND rel_type = ANY(%s)"
                " AND superseded_at IS NULL",
                (user_id, tax["rel_types_defining_group"]),
            )
            direct = {row[0] for row in cur.fetchall()}

            # Also include from staged_facts
            # NOTE: Per-user schema context — user_id filter removed, schema isolation handles scoping
            cur.execute(
                "SELECT DISTINCT object_id FROM staged_facts"
                " WHERE subject_id = %s"
                " AND rel_type = ANY(%s)",
                (user_id, tax["rel_types_defining_group"]),
            )
            direct.update(row[0] for row in cur.fetchall())

            if not direct:
                return set()

            # Transitive members: for each direct member, find entities via transitive_rel_types
            transitive = set()
            trans_rels = tax.get("transitive_rel_types", [])
            if trans_rels:
                # Use a batch query approach for efficiency
                member_list = list(direct)
                # NOTE: Per-user schema context — user_id filter removed, schema isolation handles scoping
                cur.execute(
                    "SELECT DISTINCT object_id FROM facts"
                    " WHERE subject_id = ANY(%s)"
                    " AND rel_type = ANY(%s)"
                    " AND superseded_at IS NULL",
                    (member_list, trans_rels),
                )
                transitive.update(row[0] for row in cur.fetchall())

                # NOTE: Per-user schema context — user_id filter removed, schema isolation handles scoping
                cur.execute(
                    "SELECT DISTINCT object_id FROM staged_facts"
                    " WHERE subject_id = ANY(%s)"
                    " AND rel_type = ANY(%s)",
                    (member_list, trans_rels),
                )
                transitive.update(row[0] for row in cur.fetchall())

            all_members = direct | transitive
            log.info(
                "taxonomy.transitive_members",
                taxonomy=taxonomy_name,
                direct_count=len(direct),
                transitive_count=len(transitive),
                total=len(all_members),
            )
            return all_members
    except Exception as e:
        log.warning("taxonomy.transitive_members_failed", error=str(e), taxonomy=taxonomy_name)
        return set()


def _collect_member_taxonomy_entities(
    db_conn,
    anchor_uuid: str,
    taxonomy_name: str,
    depth_cap: int = 3,
    _seen_taxonomies: set[str] | None = None,
) -> set[str]:
    """SUBJECT-AGNOSTIC hierarchy trace-back (rung 4) — collect the member entities
    of a taxonomy anchored to `anchor_uuid`, recursing through NESTED sub-groups
    (entity_taxonomies.member_taxonomies) and walking DOWN transitive hierarchy
    rels (has_transitivity) to reach leaf entities.

    DESIGN-hierarchy-ladder-and-growth.md §"Hierarchy (rung 4)":
      - membership = member_entity_types (entities) ∪ member_taxonomies (sub-group refs)
      - "tell me about my family" → people (defining rels) ∪ recurse member_taxonomies
        (pets → animal) → returns the pet.
      - "my animals" → transitive subclass_of → the pet.

    SUBJECT-AGNOSTIC: the anchor is whatever `resolve_anchor` produced (user OR any
    entity UUID — my / Jordan's / the datacenter's). NEVER `if subject == user`. The
    nesting recursion stays anchored to the SAME subject, so "Jordan's family" folds
    Jordan's pets, not the user's.

    Metadata-driven: reads rel_types_defining_group, member_taxonomies,
    has_transitivity, transitive_rel_types from the bound tenant schema (NO
    hardcoded rel/taxonomy names). Bounded by depth_cap. Fail-safe: any error
    returns the partial set so the baseline taxonomy fetch never breaks.

    Returns a set of member entity UUIDs (excludes the anchor itself).
    """
    if _seen_taxonomies is None:
        _seen_taxonomies = set()
    members: set[str] = set()
    if not taxonomy_name or depth_cap <= 0:
        return members
    _tax_key = taxonomy_name.lower()
    if _tax_key in _seen_taxonomies:
        return members  # cycle guard for nested member_taxonomies
    _seen_taxonomies.add(_tax_key)

    try:
        with db_conn.cursor() as cur:
            # Read the taxonomy row from the bound tenant schema (search_path scoped).
            cur.execute(
                "SELECT rel_types_defining_group, member_taxonomies,"
                "       has_transitivity, transitive_rel_types"
                "  FROM entity_taxonomies WHERE taxonomy_name = %s",
                (_tax_key,),
            )
            row = cur.fetchone()
            if not row:
                return members
            defining_rels = list(row[0]) if row[0] else []
            member_taxonomies = list(row[1]) if row[1] else []
            has_transitivity = bool(row[2])
            transitive_rels = list(row[3]) if row[3] else []

            # ── Direct members: objects of defining rels anchored to the subject ──
            if defining_rels:
                cur.execute(
                    "SELECT DISTINCT object_id FROM facts"
                    " WHERE subject_id = %s AND rel_type = ANY(%s)"
                    "   AND superseded_at IS NULL",
                    (anchor_uuid, defining_rels),
                )
                members.update(r[0] for r in cur.fetchall())
                cur.execute(
                    "SELECT DISTINCT object_id FROM staged_facts"
                    " WHERE subject_id = %s AND rel_type = ANY(%s)"
                    "   AND promoted_at IS NULL",
                    (anchor_uuid, defining_rels),
                )
                members.update(r[0] for r in cur.fetchall())

            # ── Transitive DOWN walk over the direct members (rung-4 trace-back) ──
            # e.g. member subclass_of/part_of/member_of → leaf entities (Rex).
            if has_transitivity and transitive_rels and members:
                frontier = list(members)
                _d = depth_cap
                while frontier and _d > 0:
                    cur.execute(
                        "WITH RECURSIVE chain AS ("
                        "  SELECT subject_id, object_id, 1 AS depth FROM facts"
                        "   WHERE object_id = ANY(%s) AND rel_type = ANY(%s)"
                        "     AND superseded_at IS NULL"
                        "  UNION ALL"
                        "  SELECT f.subject_id, f.object_id, c.depth + 1 FROM facts f"
                        "   JOIN chain c ON f.object_id = c.subject_id"
                        "   WHERE f.rel_type = ANY(%s) AND f.superseded_at IS NULL"
                        "     AND c.depth < %s"
                        ") SELECT DISTINCT subject_id FROM chain",
                        (frontier, transitive_rels, transitive_rels, depth_cap),
                    )
                    new_down = {r[0] for r in cur.fetchall()} - members
                    members.update(new_down)
                    frontier = list(new_down)
                    _d -= 1
    except Exception as e:
        log.warning("collect_member_taxonomy_entities.failed",
                    taxonomy=_tax_key, error=str(e))
        # fall through to recurse what we can; partial set is safe

    # ── NESTED sub-groups: recurse member_taxonomies, SAME anchor, depth-bounded ──
    try:
        for sub_tax in member_taxonomies:
            members |= _collect_member_taxonomy_entities(
                db_conn, anchor_uuid, sub_tax,
                depth_cap=depth_cap - 1,
                _seen_taxonomies=_seen_taxonomies,
            )
    except Exception as e:
        log.warning("collect_member_taxonomy_entities.nested_failed",
                    taxonomy=_tax_key, error=str(e))

    members.discard(anchor_uuid)
    return members


def _collect_descendant_layered_facts(
    cur,
    anchor_uuid: str,
    descent_rels: list[str],
    classification_rels: frozenset,
    query_axis: Optional[str],
    depth_cap: int,
    scope_rels: Optional[set] = None,
    seed_entities: Optional[set] = None,
) -> list[dict]:
    """DESCEND to the LAYERED FACT (subject-agnostic completion of the hierarchy walk).

    THE GAP this closes: the walk descends ONE composition/membership hop and surfaces the
    *link* ("gps system is part of car") but then stops — it never collects the descended
    entity's OWN grounded facts ("(gps, has_state, issue)@date", a scalar firmware version,
    a nested pet's age). This helper completes the descent: from ``anchor_uuid`` it walks
    DOWN every DESCENT hierarchy rel (``descent_rels`` — the composition/membership
    hierarchy rels, i.e. ``_get_hierarchy_rels()`` MINUS the classification rels, so
    ``part_of``/``member_of`` descend but ``instance_of``/``subclass_of`` do NOT — descending
    a TYPE node would dump every instance of the class), and for EACH reached descendant
    collects that descendant's OWN facts + scalars. The descended fact is the grounded leaf
    the walk existed to find — returned, not abandoned at the link.

    This is the DETERMINISTIC walk reaching the fact — NOT new query intelligence: it climbs
    only REAL edges (no cosine / ILIKE / LLM), is subject-agnostic (anchor = whatever
    resolve_anchor produced — a car, a datacenter, "my family"), metadata-driven (descent
    rels read from the rel_types table, never literals), and bounded by ``depth_cap`` (=
    QUERY_MULTIHOP_CLIMB_DEPTH) with a visited-set cycle guard so it never maps the world.

    Scope honored: a descendant's OWN fact is admitted only when it passes the same
    membership-axis filter the rung-4 trace-back uses (drop the descendant's classification
    chain on a membership query) AND, when a concrete concept scope is active (``scope_rels``
    non-None), the descended relationship rel is in scope OR is itself a state/composition
    edge of the reached descendant (the very thing the descent went to find — admitted like
    a rung-4 member fact, exempt from the concept projection but STILL axis-filtered).
    Scalars always pass (the leaf data). Each returned fact carries ``_hierarchy_admitted``
    so the downstream axis/taxonomy projection treats it as a proven deterministic-walk member.

    Returns a list of fact dicts (db + attributes). Fail-safe: any error returns the partial
    set so the baseline fetch never breaks.
    """
    out: list[dict] = []
    if not anchor_uuid or not descent_rels or depth_cap <= 0:
        return out
    _descent = sorted({r.lower() for r in descent_rels})
    if not _descent:
        return out
    _scope = {r.lower() for r in scope_rels} if scope_rels is not None else None
    # Resolve the dated EVENT/STATE rel set ONCE (metadata-driven: temporal_class='event'
    # OR category='state' → has_state/feels). These are the "what happened to the descended
    # entity" edges admitted on their own temporal tier even under a concept scope.
    try:
        _state_rels = {r.lower() for r in _get_event_state_rels()}
    except Exception:
        _state_rels = set()
    # FRONTIER SEED: the anchor PLUS any entities the anchor reaches via its OWN in-scope
    # outbound relationship edges (e.g. user→owns→car). This makes the composition subtree
    # reachable when the resolved anchor is the OWNER, not the composed whole — so the SAME
    # grounded leaf ("(gps, has_state, issue)") surfaces whether the question anchors on the
    # car ("tell me about my car") OR on the user ("what issues have I had with my car?").
    # Deterministic: the seeds come from real owns/relationship edges the caller resolved,
    # never fuzzy. Bounded: only the directly-related entities seed; the depth cap still
    # governs how far the part_of/member_of descent runs from each seed.
    _seeds = {anchor_uuid}
    if seed_entities:
        _seeds |= {s for s in seed_entities if s}
    _visited: set[str] = set(_seeds)
    frontier: list[str] = list(_seeds)
    _depth = max(1, int(depth_cap))
    try:
        while frontier and _depth > 0:
            # Direct descendants of the frontier: (descendant, descent_rel, parent) — the
            # descendant points UP at the parent, so we read the INVERSE direction
            # (object_id = parent). Real edges only, from BOTH the committed facts table
            # AND staged_facts (Class B/C live there until promotion — the GPS/part_of edge
            # is staged-B at ingest, so a facts-only walk would never descend).
            cur.execute(
                "SELECT DISTINCT subject_id FROM facts"
                " WHERE object_id = ANY(%s) AND rel_type = ANY(%s)"
                "   AND superseded_at IS NULL"
                "   AND archived_at IS NULL AND deleted_at IS NULL"
                " UNION"
                " SELECT DISTINCT subject_id FROM staged_facts"
                " WHERE object_id = ANY(%s) AND rel_type = ANY(%s)"
                "   AND promoted_at IS NULL AND deleted_at IS NULL",
                (frontier, _descent, frontier, _descent),
            )
            _next = {r[0] for r in cur.fetchall()} - _visited
            if not _next:
                break
            for _did in _next:
                _visited.add(_did)
                # ── the descended entity's OWN outbound facts (its states / relationships) ──
                # Both tables: the descended has_state edge is staged-B until promotion.
                cur.execute(
                    "SELECT subject_id, object_id, rel_type, confidence, fact_class, event_date"
                    "  FROM facts"
                    " WHERE subject_id = %s"
                    "   AND superseded_at IS NULL"
                    "   AND archived_at IS NULL AND deleted_at IS NULL"
                    " UNION ALL"
                    " SELECT subject_id, object_id, rel_type, confidence, fact_class, event_date"
                    "  FROM staged_facts"
                    " WHERE subject_id = %s"
                    "   AND promoted_at IS NULL AND deleted_at IS NULL",
                    (_did, _did),
                )
                for row in cur.fetchall():
                    _rel = (row[2] or "").lower()
                    # MEMBERSHIP axis: drop the descendant's classification chain
                    # ("gps instance_of device") — a different question than its state.
                    if not _member_fact_passes_axis(_rel, query_axis, classification_rels):
                        continue
                    # Concept-scope projection: when a concrete scope is active, admit the
                    # descended fact iff its rel is in scope OR it is the descent edge itself
                    # (already walked) OR it is a dated EVENT/STATE edge of the reached
                    # descendant (``has_state``/``feels`` — the grounded "what happened"
                    # layer the walk descended to find, admitted on its own temporal tier,
                    # NOT by taxonomy; see _get_event_state_rels). A descended relationship
                    # that is off-scope AND not a descent/state edge is dropped (no scope
                    # bleed). Scalars are handled below (always pass — the leaf data).
                    if _scope is not None:
                        _admit = (
                            _rel in _scope
                            or _rel in _descent
                            or _rel in _state_rels
                        )
                        if not _admit:
                            continue
                    out.append({
                        "subject": row[0],
                        "object": row[1],
                        "rel_type": _rel,
                        "confidence": float(row[3]) if row[3] else 0.8,
                        "fact_class": row[4] or "B",
                        "source": "db",
                        "category": _get_rel_type_category(_rel),
                        "event_date": row[5].isoformat() if row[5] else None,
                        # Proven via the deterministic composition/membership descent —
                        # exempt from the membership/taxonomy projection (axis still applied
                        # above). Confidence gating still applies downstream.
                        "_hierarchy_admitted": True,
                    })
                # ── the descended entity's scalars (firmware version, age, ip, …) ──
                cur.execute(
                    "SELECT entity_id, attribute, value_text, value_int, value_float, value_date"
                    "  FROM entity_attributes WHERE entity_id = %s",
                    (_did,),
                )
                for row in cur.fetchall():
                    _val = row[2]
                    if _val is None and row[3] is not None:
                        _val = str(row[3])
                    if _val is None and row[4] is not None:
                        _val = str(row[4])
                    if _val is None and row[5] is not None:
                        _val = str(row[5])
                    if _val is not None:
                        out.append({
                            "subject": row[0],
                            "rel_type": row[1],
                            "object": _val,
                            "confidence": 1.0,
                            "fact_class": "A",
                            "source": "attributes",
                            "category": _get_rel_type_category(row[1]),
                            "valid_from": None,
                            "valid_until": None,
                            "_hierarchy_admitted": True,
                        })
            frontier = list(_next)
            _depth -= 1
    except Exception as e:
        log.warning("collect_descendant_layered_facts.failed",
                    anchor=anchor_uuid[:8] if anchor_uuid else "unknown",
                    error=str(e))
    return out


def _graph_traverse(
    db_conn,
    user_id: str,
    entity_id: str,
    max_hops: int = 1,
    graph_rel_types: frozenset = None,
) -> set[str]:
    """
    Single-hop graph traversal — find all entities directly connected to entity_id
    via rel_types in graph_rel_types. Searches both facts and staged_facts.

    Returns set of connected entity UUIDs (does NOT include the starting entity).
    """
    if graph_rel_types is None:
        graph_rel_types = _get_graph_rels()
    connected: set[str] = set()
    graph_rels = list(graph_rel_types)
    try:
        with db_conn.cursor() as cur:
            # Find entities where entity_id is the subject
            # NOTE: Per-user schema context — user_id filter removed, schema isolation handles scoping
            cur.execute(
                "SELECT DISTINCT object_id FROM facts"
                " WHERE subject_id = %s"
                " AND rel_type = ANY(%s)"
                " AND superseded_at IS NULL",
                (entity_id, graph_rels),
            )
            connected.update(row[0] for row in cur.fetchall())

            # Find entities where entity_id is the object
            # NOTE: Per-user schema context — user_id filter removed, schema isolation handles scoping
            cur.execute(
                "SELECT DISTINCT subject_id FROM facts"
                " WHERE object_id = %s"
                " AND rel_type = ANY(%s)"
                " AND superseded_at IS NULL",
                (entity_id, graph_rels),
            )
            connected.update(row[0] for row in cur.fetchall())

            # Also search staged_facts
            # NOTE: Per-user schema context — user_id filter removed, schema isolation handles scoping
            cur.execute(
                "SELECT DISTINCT object_id FROM staged_facts"
                " WHERE subject_id = %s"
                " AND rel_type = ANY(%s)",
                (entity_id, graph_rels),
            )
            connected.update(row[0] for row in cur.fetchall())

            # NOTE: Per-user schema context — user_id filter removed, schema isolation handles scoping
            cur.execute(
                "SELECT DISTINCT subject_id FROM staged_facts"
                " WHERE object_id = %s"
                " AND rel_type = ANY(%s)",
                (entity_id, graph_rels),
            )
            connected.update(row[0] for row in cur.fetchall())

        connected.discard(entity_id)  # Don't include self
        return connected
    except Exception as e:
        log.warning("graph_traverse.failed", error=str(e), entity_id=entity_id)
        return set()


def _hierarchy_expand(
    db_conn,
    user_id: str,
    entity_id: str,
    direction: str = "up",
    max_depth: int = 3,
) -> set[str]:
    """
    Traverse hierarchy chains from entity_id via _REL_TYPE_HIERARCHY rel_types.
    Uses SQL CTE (WITH RECURSIVE) with cycle protection via depth tracking.

    direction="up":  entity → instance_of/subclass_of → parent class (classification chain)
    direction="down": class → instance_of/subclass_of → members (class membership)

    Returns set of entity UUIDs in the chain (includes the starting entity).
    """
    hier_rels = list(_get_hierarchy_rels())
    chain: set[str] = {entity_id}

    try:
        with db_conn.cursor() as cur:
            if direction == "up":
                # NOTE: Per-user schema context — user_id filters removed, schema isolation handles scoping
                cur.execute("""
                    WITH RECURSIVE hierarchy_chain AS (
                        SELECT subject_id, object_id, rel_type, 1 AS depth
                        FROM facts
                        WHERE subject_id = %s
                          AND rel_type = ANY(%s)
                          AND superseded_at IS NULL
                          -- TOMBSTONE (Phase 4 / eacd209 parity): the staged side of this
                          -- walk already filters deleted_at; mirror it on facts so a
                          -- forgotten is-a edge does not re-admit an entity whose facts
                          -- then surface downstream.
                          AND archived_at IS NULL AND deleted_at IS NULL

                        UNION ALL

                        SELECT f.subject_id, f.object_id, f.rel_type, hc.depth + 1
                        FROM facts f
                        JOIN hierarchy_chain hc ON f.subject_id = hc.object_id
                        WHERE f.rel_type = ANY(%s)
                          AND f.superseded_at IS NULL
                          AND f.archived_at IS NULL AND f.deleted_at IS NULL
                          AND hc.depth < %s
                    )
                    SELECT DISTINCT object_id FROM hierarchy_chain
                """, (entity_id, hier_rels, hier_rels, max_depth))
                chain.update(row[0] for row in cur.fetchall())

                # Also search staged_facts
                # NOTE: Per-user schema context — user_id filters removed, schema isolation handles scoping
                cur.execute("""
                    WITH RECURSIVE hierarchy_chain AS (
                        SELECT subject_id, object_id, rel_type, 1 AS depth
                        FROM staged_facts
                        WHERE subject_id = %s
                          AND rel_type = ANY(%s)
                          AND deleted_at IS NULL

                        UNION ALL

                        SELECT f.subject_id, f.object_id, f.rel_type, hc.depth + 1
                        FROM staged_facts f
                        JOIN hierarchy_chain hc ON f.subject_id = hc.object_id
                        WHERE f.rel_type = ANY(%s)
                          AND f.deleted_at IS NULL
                          AND hc.depth < %s
                    )
                    SELECT DISTINCT object_id FROM hierarchy_chain
                """, (entity_id, hier_rels, hier_rels, max_depth))
                chain.update(row[0] for row in cur.fetchall())

            elif direction == "down":
                # NOTE: Per-user schema context — user_id filters removed, schema isolation handles scoping
                cur.execute("""
                    WITH RECURSIVE hierarchy_chain AS (
                        SELECT subject_id, object_id, rel_type, 1 AS depth
                        FROM facts
                        WHERE object_id = %s
                          AND rel_type = ANY(%s)
                          AND superseded_at IS NULL
                          -- TOMBSTONE (Phase 4 / eacd209 parity): mirror the staged side —
                          -- a forgotten is-a edge must not re-admit a descendant whose
                          -- facts then surface downstream.
                          AND archived_at IS NULL AND deleted_at IS NULL

                        UNION ALL

                        SELECT f.subject_id, f.object_id, f.rel_type, hc.depth + 1
                        FROM facts f
                        JOIN hierarchy_chain hc ON f.object_id = hc.subject_id
                        WHERE f.rel_type = ANY(%s)
                          AND f.superseded_at IS NULL
                          AND f.archived_at IS NULL AND f.deleted_at IS NULL
                          AND hc.depth < %s
                    )
                    SELECT DISTINCT subject_id FROM hierarchy_chain
                """, (entity_id, hier_rels, hier_rels, max_depth))
                chain.update(row[0] for row in cur.fetchall())

                # NOTE: Per-user schema context — user_id filters removed, schema isolation handles scoping
                cur.execute("""
                    WITH RECURSIVE hierarchy_chain AS (
                        SELECT subject_id, object_id, rel_type, 1 AS depth
                        FROM staged_facts
                        WHERE object_id = %s
                          AND rel_type = ANY(%s)
                          AND deleted_at IS NULL

                        UNION ALL

                        SELECT f.subject_id, f.object_id, f.rel_type, hc.depth + 1
                        FROM staged_facts f
                        JOIN hierarchy_chain hc ON f.object_id = hc.subject_id
                        WHERE f.rel_type = ANY(%s)
                          AND f.deleted_at IS NULL
                          AND hc.depth < %s
                    )
                    SELECT DISTINCT subject_id FROM hierarchy_chain
                """, (entity_id, hier_rels, hier_rels, max_depth))
                chain.update(row[0] for row in cur.fetchall())

        return chain
    except Exception as e:
        log.warning("hierarchy_expand.failed", error=str(e), entity_id=entity_id, direction=direction)
        return {entity_id}


# ── dprompt-59: Semantic Conflict Detection ──────────────────────────────────
# Detects when new facts contradict existing graph structure and auto-resolves.
# The graph IS the source of truth — hierarchy/type relationships define what
# entities ARE, and independent relationships (owns, has_pet, etc.) must respect
# those semantics.

# ── dprompt-65: Metadata-driven — queries rel_types table instead of hardcoded ─
# Module-level metadata cache, populated lazily and refreshed on cache miss.
# ── dprompt-73b: Unified metadata cache (replaces per-query lookup) ──────────
# Single cache for all rel_types (known + novel). Loaded at startup via
# _refresh_rel_type_cache(), refreshed when re-embedder approves novel types.
# Eliminates hardcoded frozensets — routing and classification are metadata-driven.

_REL_TYPE_CACHE: dict[str, dict] = {}

# Metadata-driven scalar rel_types cache (replaces hardcoded _SCALAR_OBJECT_RELS)
# Populated from rel_types table where tail_types contains 'SCALAR'
# Refreshed whenever novel rel_types are approved
_SCALAR_REL_TYPES_CACHE: set[str] = set()

# System / ontology entity names that must never be written as personal facts into
# a user schema.  These appear as subjects/objects of LLM-generated hierarchy edges
# (e.g. /expand FaultLine) and, if allowed through, surface as garbled query results
# ("alex is a subclass of theo").  frozenset gives O(1) membership tests.
# Primary guard — entity_type ('Concept'/'Object') is the metadata-driven secondary guard
# applied in learn_topic() alongside this name list.
_SYSTEM_ENTITY_NAMES: frozenset[str] = frozenset({
    # Product / system proper-nouns that are ontology roots, not personal facts
    "faultline",
    # Abstract knowledge-graph primitives
    "knowledgegraph", "knowledge graph", "knowledge_graph",
    "node", "edge", "entitynode", "entity node",
    "relationshipedge", "relationship edge",
    # Broad upper-ontology classes (Wikidata / OWL style)
    "object", "concept", "thing", "entity",
    # Generic social/org categories
    "organization", "person", "location", "group", "place",
})



def _refresh_rel_type_cache():
    """Load ALL rel_types from database into unified cache.
    Called at startup and when re-embedder approves novel rel_types.
    Uses psycopg2 directly (not SQLAlchemy) — consistent with the rest of main.py.
    """
    global _REL_TYPE_CACHE
    dsn = os.environ.get("POSTGRES_DSN")
    if not dsn:
        log.warning("rel_type_cache.no_dsn")
        return
    try:
        with psycopg2.connect(dsn) as conn:
            with conn.cursor() as cur:
                cur.execute(
                    "SELECT rel_type, storage_target, fact_class, "
                    "is_symmetric, inverse_rel_type, is_leaf_only, is_hierarchy_rel, "
                    "correction_behavior, "
                    "COALESCE(mutually_exclusive_with, '{}') "
                    "FROM rel_types"
                )
                _REL_TYPE_CACHE.clear()
                for row in cur.fetchall():
                    _REL_TYPE_CACHE[row[0].lower()] = {
                        "storage_target": row[1] if row[1] else "facts",
                        "fact_class": row[2] if row[2] else "C",
                        "is_symmetric": row[3] if row[3] else False,
                        "inverse_rel_type": row[4],
                        "is_leaf_only": row[5] if row[5] else False,
                        "is_hierarchy_rel": row[6] if row[6] else False,
                        "correction_behavior": row[7] if row[7] else "supersede",
                        "mutually_exclusive_with": row[8] if row[8] else [],
                    }
        log.info("rel_type_cache.refreshed", count=len(_REL_TYPE_CACHE))
    except Exception as e:
        log.warning("rel_type_cache.refresh_failed", error=str(e))


def _refresh_scalar_rel_types_cache():
    """Load rel_types with SCALAR tail_types from database into cache.
    Called at startup and when novel rel_types are approved.
    Metadata-driven: queries rel_types table, no hardcoding.
    """
    global _SCALAR_REL_TYPES_CACHE
    dsn = os.environ.get("POSTGRES_DSN")
    if not dsn:
        log.warning("scalar_rel_types_cache.no_dsn")
        return
    try:
        with psycopg2.connect(dsn) as conn:
            with conn.cursor() as cur:
                cur.execute(
                    "SELECT rel_type FROM rel_types WHERE tail_types @> '{SCALAR}'::TEXT[]"
                )
                _SCALAR_REL_TYPES_CACHE.clear()
                for row in cur.fetchall():
                    _SCALAR_REL_TYPES_CACHE.add(row[0].lower())
        log.info("scalar_rel_types_cache.refreshed", count=len(_SCALAR_REL_TYPES_CACHE))
    except Exception as e:
        log.warning("scalar_rel_types_cache.refresh_failed", error=str(e))


def _is_scalar_rel_type(rel_type: str) -> bool:
    """Check if rel_type has SCALAR tail_types.
    Queries cache first, then DB directly for novel types.
    Falls back to fallback set if DB unavailable.
    """
    rt = rel_type.lower().strip() if rel_type else ""
    if not rt:
        return False

    # Check cache first (faster)
    if _SCALAR_REL_TYPES_CACHE and rt in _SCALAR_REL_TYPES_CACHE:
        return True

    # Query DB directly for novel types approved by re_embedder
    dsn = os.environ.get("POSTGRES_DSN")
    if dsn:
        try:
            with psycopg2.connect(dsn) as conn:
                with conn.cursor() as cur:
                    cur.execute(
                        "SELECT 1 FROM rel_types WHERE rel_type = %s AND tail_types @> '{SCALAR}'::TEXT[]",
                        (rt,),
                    )
                    if cur.fetchone():
                        _SCALAR_REL_TYPES_CACHE.add(rt)  # Cache for next time
                        return True
        except Exception as e:
            log.debug("scalar_rel_type_query_failed", rel_type=rt, error=str(e))

    # Fallback: check hardcoded bootstrap set (pref_name, age, etc. always scalar)
    fallback_scalars = {
        'pref_name', 'also_known_as', 'age', 'height', 'weight', 'born_on',
        'occupation', 'nationality', 'has_gender'
    }
    return rt in fallback_scalars


def _edge_is_scalar(edge) -> bool:
    """Is THIS edge's object a SCALAR value (kept as a string, never resolved to a UUID)?

    Two deterministic signals, OR'd:
      1. the rel_type is SCALAR-tailed in the ontology (``_is_scalar_rel_type``), OR
      2. the edge CARRIES an ``object_datatype`` — the per-edge scalar signal set by the
         deterministic detectors (the atomic-value detector for ip/mac/email/…, and the spine
         deriver's possessive-attribute capture for a VERBATIM literal value like an address).

    Signal 2 is load-bearing for a NOVEL per-tenant attribute scalar (e.g. "address"): the
    ontology-only ``_is_scalar_rel_type`` resolves rel_types from the PUBLIC seed and cannot see a
    tenant-grown scalar rel, so without the per-edge datatype the value would be wrongly resolved to
    a phantom UUID entity. An edge with NO object_datatype is unchanged (today's behavior); the
    atomic-detector edges already carry one AND ride seeded SCALAR rels, so this is a no-op for them.
    Fail-safe: any error → fall back to the rel-type-only check."""
    try:
        if getattr(edge, "object_datatype", None):
            return True
    except Exception:  # noqa: BLE001
        pass
    return _is_scalar_rel_type(getattr(edge, "rel_type", "") or "")


def _get_rel_type_metadata(rel_type: str) -> dict:
    """Return validation + routing metadata for a rel_type.
    Queries DB directly to include novel rel_types approved by re_embedder.
    Falls back to cache, then hardcoded defaults.

    Returns dict with: storage_target, fact_class, is_symmetric,
    inverse_rel_type, is_leaf_only, is_hierarchy_rel.
    """
    rt = rel_type.lower().strip() if rel_type else ""
    if not rt:
        return {}

    # Check cache first (faster)
    if _REL_TYPE_CACHE and rt in _REL_TYPE_CACHE:
        return _REL_TYPE_CACHE[rt]

    # Query DB directly — includes novel rel_types approved by re_embedder
    dsn = os.environ.get("POSTGRES_DSN")
    if dsn:
        try:
            with psycopg2.connect(dsn) as conn:
                with conn.cursor() as cur:
                    cur.execute(
                        "SELECT storage_target, fact_class, is_symmetric, inverse_rel_type, "
                        "is_leaf_only, is_hierarchy_rel, correction_behavior, "
                        "COALESCE(mutually_exclusive_with, '{}') FROM rel_types WHERE rel_type = %s",
                        (rt,)
                    )
                    row = cur.fetchone()
                    if row:
                        metadata = {
                            "storage_target": row[0],
                            "fact_class": row[1],
                            "is_symmetric": row[2] or False,
                            "inverse_rel_type": row[3],
                            "is_leaf_only": row[4] or False,
                            "is_hierarchy_rel": row[5] or False,
                            "correction_behavior": row[6] or "supersede",
                            "mutually_exclusive_with": row[7] if row[7] else [],
                        }
                        # Cache it for next time
                        _REL_TYPE_CACHE[rt] = metadata
                        return metadata
        except Exception as e:
            log.warning("rel_type_metadata.db_query_failed", rel_type=rt, error=str(e))

    # Novel/unregistered rel_type or DB unavailable — safe defaults
    return {
        "storage_target": "facts",
        "fact_class": "C",
        "is_symmetric": False,
        "inverse_rel_type": None,
        "is_leaf_only": False,
        "is_hierarchy_rel": False,
        "correction_behavior": "supersede",
        "mutually_exclusive_with": [],
    }


def _infer_entity_type_from_rel_type(rel_type: str, position: str = 'object') -> str:
    """
    Infer entity_type from rel_type metadata constraints.

    Layer 2 type inference: if GLiNER2 returns 'unknown', try to infer
    entity type from rel_type constraints (head_types/tail_types).

    Args:
        rel_type: The relationship type (e.g., "works_for")
        position: 'head' (subject) or 'tail' (object) position

    Returns:
        entity_type string, or 'unknown' if no constraint found
    """
    try:
        # Query rel_types table for type constraints
        dsn = os.environ.get("POSTGRES_DSN")
        if not dsn:
            return 'unknown'

        with psycopg2.connect(dsn) as conn:
            with conn.cursor() as cur:
                cur.execute(
                    "SELECT head_types, tail_types FROM rel_types WHERE rel_type = %s",
                    (rel_type.lower().strip(),)
                )
                row = cur.fetchone()
                if not row:
                    return 'unknown'

                head_types = row[0] or []
                tail_types = row[1] or []

                if position == 'head' and head_types:
                    # If single type constraint (not 'ANY'), return it
                    if len(head_types) == 1 and head_types[0] != 'ANY':
                        return head_types[0]
                elif position == 'tail' and tail_types:
                    # If single type constraint (not 'ANY'), return it
                    if len(tail_types) == 1 and tail_types[0] != 'ANY':
                        return tail_types[0]

                return 'unknown'
    except Exception as err:
        log.warning("rel_type_inference_failed", rel_type=rel_type, error=str(err))
        return 'unknown'


def _detect_semantic_conflicts(
    db_conn,
    user_id: str,
    subject: str,
    rel_type: str,
    obj: str,
) -> tuple[str, str | None]:
    """
    Check if a new fact contradicts existing graph structure.

    Returns (decision, reason):
      - ("keep", None): No conflict — proceed with ingest.
      - ("supersede_new", reason): New fact semantically invalid — skip it.
      - ("supersede_existing_ids", reason): Existing fact(s) contradicted — supersede them.

    Principle: If X instance_of Y, Y is a TYPE, not a separate entity.
    Do not allow owns/has_pet/works_for on type entities.
    """
    rt_lower = rel_type.lower().strip() if rel_type else ""
    obj_id = str(obj).lower().strip() if obj else ""

    meta = _get_rel_type_metadata(rt_lower)

    # Only check leaf-only relationship types against hierarchy objects
    if not meta.get("is_leaf_only"):
        return ("keep", None)

    if not db_conn or not obj_id:
        return ("keep", None)

    try:
        _hierarchy_defining = ["instance_of","subclass_of","is_a","member_of","part_of"]
        with db_conn.cursor() as cur:
            # Check: is the object entity the object of any hierarchy relationship?
            # Note: search_path already scopes to per-user schema, so no user_id filter needed
            cur.execute(
                "SELECT id, subject_id, rel_type FROM facts "
                "WHERE object_id = %s "
                "AND rel_type = ANY(%s) "
                "AND superseded_at IS NULL "
                "LIMIT 1",
                (obj_id, _hierarchy_defining),
            )
            hierarchy_fact = cur.fetchone()

            if not hierarchy_fact:
                # Also check staged_facts
                cur.execute(
                    "SELECT id, subject_id, rel_type FROM staged_facts "
                    "WHERE object_id = %s "
                    "AND rel_type = ANY(%s) "
                    "LIMIT 1",
                    (obj_id, _hierarchy_defining),
                )
                hierarchy_fact = cur.fetchone()

            if hierarchy_fact:
                fact_id, hierarchy_subject, hierarchy_rel = hierarchy_fact
                reason = (
                    f"type_conflict: {obj_id} is object of {hierarchy_rel} "
                    f"(defined by {hierarchy_subject}) — cannot also be {rt_lower} target"
                )
                log.info(
                    "ingest.semantic_conflict_detected",
                    obj=obj_id,
                    new_rel=rt_lower,
                    existing_hierarchy=f"{hierarchy_subject} {hierarchy_rel} {obj_id}",
                    decision="supersede_new",
                )
                return ("supersede_new", reason)

    except Exception as e:
        log.warning("ingest.semantic_conflict_check_failed", error=str(e),
                    subject=subject, rel_type=rt_lower, obj=obj_id)

    return ("keep", None)


# ── dprompt-62: Bidirectional Relationship Validation ─────────────────────────
# Prevents impossible bidirectional relationships like child_of + parent_of
# coexisting for the same entity pair. Inverse relationships should NOT both
# exist — the semantics make them contradictory.


def _validate_bidirectional_relationships(
    db_conn,
    user_id: str,
    subject: str,
    rel_type: str,
    obj: str,
    confidence: float,
) -> str:
    """
    Check if a new fact would create an impossible bidirectional relationship.

    If both child_of AND parent_of exist for the same subject-object pair,
    keep the higher-confidence version and supersede the lower.

    Returns:
      - "keep": no inverse rel_type — proceed normally
      - "no_conflict": no conflicting inverse found — proceed normally
      - "supersede_new": existing inverse has higher confidence — skip new fact
    """
    rt_lower = rel_type.lower().strip() if rel_type else ""
    if not db_conn:
        return "keep"

    meta = _get_rel_type_metadata(rt_lower)
    inverse = meta.get("inverse_rel_type") if meta else None

    # ── BUG-B1: Mutual exclusion check (metadata-driven, migration 069) ──────────
    # Query mutually_exclusive_with from rel_types — no hardcoded rel_type names.
    # Checks both A→B and B→A directions since symmetric rels (spouse) exist in one row.
    # Returns "supersede_new" to BLOCK the incoming fact — existing fact is preserved.
    # Corrections (is_correction=True) bypass this via the Class A override path upstream.
    exclusive_with = meta.get("mutually_exclusive_with") if meta else []
    if exclusive_with:
        try:
            with db_conn.cursor() as cur:
                cur.execute(
                    "SELECT id, rel_type FROM facts "
                    "WHERE rel_type = ANY(%s) AND superseded_at IS NULL "
                    "AND ("
                    "  (subject_id = %s AND object_id = %s)"
                    "  OR (subject_id = %s AND object_id = %s)"
                    ") LIMIT 10",
                    (exclusive_with, subject, obj, obj, subject),
                )
                conflicting_rows = cur.fetchall()
                if conflicting_rows:
                    for _cid, conflict_rel_type in conflicting_rows:
                        log.info(
                            "gate.mutual_exclusion_blocked",
                            incoming_rel_type=rt_lower,
                            existing_rel_type=conflict_rel_type,
                            subject=subject,
                            object=obj,
                        )
                    return "supersede_new"  # Block incoming; existing fact untouched
        except Exception as e:
            log.warning("ingest.mutual_exclusion_check_failed", error=str(e),
                        rel_type=rt_lower, subject=subject, obj=obj)
    # ── end BUG-B1 ───────────────────────────────────────────────────────────────

    if not inverse:
        return "keep"

    try:
        with db_conn.cursor() as cur:
            # Note: search_path already scopes to per-user schema, so no user_id filter needed
            cur.execute(
                "SELECT id, confidence, 'facts' as source FROM facts "
                "WHERE subject_id = %s AND object_id = %s "
                "AND rel_type = %s AND superseded_at IS NULL "
                "LIMIT 1",
                (obj, subject, inverse),
            )
            inverse_fact = cur.fetchone()

            if not inverse_fact:
                cur.execute(
                    "SELECT id, confidence, 'staged' as source FROM staged_facts "
                    "WHERE subject_id = %s AND object_id = %s "
                    "AND rel_type = %s "
                    "LIMIT 1",
                    (obj, subject, inverse),
                )
                inverse_fact = cur.fetchone()

            if inverse_fact:
                inverse_id, inverse_conf, inverse_source = inverse_fact
                if confidence > inverse_conf:
                    if inverse_source == 'staged':
                        cur.execute(
                            "DELETE FROM staged_facts WHERE id = %s",
                            (inverse_id,),
                        )
                    else:
                        cur.execute(
                            "UPDATE facts SET superseded_at = now(), qdrant_synced = false "
                            "WHERE id = %s", (inverse_id,))
                    log.info(
                        "ingest.bidirectional_conflict_resolved",
                        kept=f"{subject} {rt_lower} {obj} (conf={confidence})",
                        superseded=f"{subject} {inverse} {obj} (conf={inverse_conf})",
                        reason="new_higher_confidence",
                    )
                    return "keep"  # allow new fact through
                else:
                    # Existing inverse has higher or equal confidence — skip new
                    log.info(
                        "ingest.bidirectional_conflict_resolved",
                        kept=f"{subject} {inverse} {obj} (conf={inverse_conf})",
                        superseded=f"{subject} {rt_lower} {obj} (conf={confidence})",
                        reason="existing_higher_confidence",
                    )
                    return "supersede_new"

    except Exception as e:
        log.warning("ingest.bidirectional_validation_failed", error=str(e),
                    subject=subject, rel_type=rt_lower, obj=obj)
        return "keep"  # DB error — skip auto-create for safety

    # Inverse rel_type exists but no inverse fact found — signal auto-creation
    log.info(
        "ingest.bidirectional_no_conflict",
        fact=f"{subject} {rt_lower} {obj}",
        inverse_rel=inverse,
    )
    return "no_conflict"


# ── DESIGN-memory-temporal-lifecycle §4: Supersede-vs-Coexist policy matrix ──
# Phase 3. ONE decided function: given an incoming edge that conflicts with an
# existing same-slot fact, decide SUPERSEDE-existing vs COEXIST, driven by
# temporal_class (overlay metadata) × provenance authority. Strong-ingest:
# decided at ingest. Soft only — application archives via superseded_at, never
# hard-deletes (Phase 4/5 owns deletion). Fail-safe: on missing metadata or any
# error the caller falls back to today's behavior (COEXIST = leave both).

# Provenance authority ladder (§4): user_stated > llm_learned > llm_inferred.
# Higher rank may supersede lower/equal; lower may NEVER override higher (user
# truth wins). Value-driven, no rel_type name checks. Unknown provenance →
# lowest rank (safe: cannot override anything).
_PROVENANCE_AUTHORITY: dict = {
    "user_stated": 3,
    "llm_learned": 2,
    "llm_inferred": 1,
}


def _provenance_rank(provenance: str | None) -> int:
    """Authority rank for a fact_provenance value; unknown → 0 (lowest, safe)."""
    return _PROVENANCE_AUTHORITY.get((provenance or "").lower().strip(), 0)


def _decide_supersede_or_coexist(
    new_edge: dict,
    existing_fact: dict,
    rel_meta: dict | None,
) -> str:
    """Decide the outcome of an incoming edge against an EXISTING conflicting
    same-slot fact. Pure (no DB write). Returns one of:

      - "supersede_existing": archive the old fact (soft); new becomes current.
      - "coexist":            leave both live (default / fail-safe).
      - "drop_incoming":      incoming loses to a higher-authority existing fact.

    Inputs (all metadata/value-driven, no rel_type name checks):
      new_edge:      {"fact_provenance": str, "is_correction": bool}
      existing_fact: {"fact_provenance": str}
      rel_meta:      overlay rel metadata; temporal_class read via
                     rel_meta.get("temporal_class","state").

    Matrix (§4):
      is_correction (user)            → supersede_existing (user authority)
      temporal_class == "immutable"   → authority decides: ≥ supersede_existing, < drop_incoming
                                        (ONE true value; a new value REPLACES the old)
      temporal_class == "state"       → coexist (a state CHANGE keeps both live: the old
                                        value is history, recency/Phase-2 resolves "current".
                                        NEVER-MODIFY-MEMORY — a legitimate prior value must
                                        not be hidden. Authority is moot here.)
      temporal_class == "event"       → coexist (distinct occurrences; exact restatement
                                        dedups upstream via ON CONFLICT, never reaches here)
      missing/unknown class           → "state" safe default (non-destructive-leaning)
    """
    # Corrections are user authority and already routed through the gate's
    # correction-semantics; honor the same outcome here for completeness.
    if new_edge.get("is_correction"):
        return "supersede_existing"

    temporal_class = (rel_meta or {}).get("temporal_class", "state")
    if temporal_class not in ("immutable", "state", "event"):
        temporal_class = "state"  # coerce unknowns to the safe, non-destructive class

    # state + event: a conflicting new value COEXISTS with the old.
    #   - state: a state CHANGE (e.g. moved cities) is NOT a replacement — the
    #     old value is live history ("where did I used to live"), recency/Phase-2
    #     present-state collapse resolves "current". Hiding the old value would
    #     violate NEVER-MODIFY-MEMORY. Explicit corrections are handled UPSTREAM
    #     (gate _apply_correction_semantics + Class-A override) BEFORE the decider,
    #     which only ever sees is_correction=False — so this is correct for the
    #     non-correction conflicts that reach here.
    #   - event: distinct datable occurrences. Exact restatement is handled by
    #     the ON CONFLICT dedup upstream and never produces a conflict here.
    if temporal_class in ("state", "event"):
        return "coexist"

    # immutable: ONE true value — a conflicting new value is a REPLACEMENT, so it
    # resolves by provenance authority (corrected birthplace/name, etc).
    new_rank = _provenance_rank(new_edge.get("fact_provenance"))
    old_rank = _provenance_rank(existing_fact.get("fact_provenance"))

    if new_rank >= old_rank:
        # incoming is at least as authoritative → it becomes current; old is
        # soft-superseded (archived as a correction). Same-turn tie (equal rank)
        # → later-ingested wins deterministically: the caller iterates rows in
        # ingest order, so the later row sees the earlier as existing and
        # supersedes it. No fuzzy scoring.
        return "supersede_existing"
    # incoming is lower authority than the existing fact → user/higher truth wins.
    return "drop_incoming"


def _soft_supersede_conflicting_fact(
    db_conn,
    subject_id: str,
    rel_type: str,
    object_id: str,
) -> int:
    """Soft-supersede (archive) existing live `facts` rows on the same slot
    (subject_id + rel_type) whose object differs from `object_id`. Reuses the
    established archive-at-write mechanism (superseded_at = now(); qdrant_synced
    = false so the re_embedder reconciles the Qdrant point). NEVER hard-deletes —
    rows remain queryable via include_archived and recoverable. Returns count.

    search_path already scopes to the per-user schema (no user_id filter).
    """
    if not db_conn:
        return 0
    try:
        with db_conn.cursor() as cur:
            cur.execute(
                "UPDATE facts SET superseded_at = now(), qdrant_synced = false "
                "WHERE subject_id = %s AND rel_type = %s "
                "AND object_id <> %s AND superseded_at IS NULL",
                (subject_id, rel_type, object_id),
            )
            return cur.rowcount or 0
    except Exception as e:
        log.warning("ingest.temporal_supersede_failed", error=str(e),
                    subject=subject_id, rel_type=rel_type, obj=object_id)
        return 0


def _find_conflicting_same_slot_fact(
    db_conn,
    subject_id: str,
    rel_type: str,
    object_id: str,
) -> dict | None:
    """Return the existing live `facts` row on the same slot (subject_id +
    rel_type) whose object DIFFERS from the incoming object_id, if any.
    Deterministic: exact equality on UUID/value columns — no ILIKE/substring/
    fuzzy. Returns {"id","object_id","fact_provenance","confidence"} or None.

    search_path already scopes to the per-user schema.
    """
    if not db_conn or not subject_id or not rel_type:
        return None
    try:
        with db_conn.cursor() as cur:
            cur.execute(
                "SELECT id, object_id, fact_provenance, confidence FROM facts "
                "WHERE subject_id = %s AND rel_type = %s "
                "AND object_id <> %s AND superseded_at IS NULL "
                "ORDER BY created_at DESC LIMIT 1",
                (subject_id, rel_type, object_id),
            )
            row = cur.fetchone()
            if not row:
                return None
            return {
                "id": row[0],
                "object_id": row[1],
                "fact_provenance": row[2],
                "confidence": row[3],
            }
    except Exception as e:
        log.warning("ingest.temporal_conflict_lookup_failed", error=str(e),
                    subject=subject_id, rel_type=rel_type, obj=object_id)
        return None


# ── dprompt-41: Production Readiness ─────────────────────────────────────────

def _get_llm_url() -> str:
    """Get LLM endpoint URL and cache the embedding URL.

    Delegates to llm_client canonical helpers. Return type (str) and
    _EMBEDDING_API_URL side effect are unchanged — all callers unaffected.
    """
    from src.api.llm_client import get_llm_chat_url, get_embedding_url

    endpoint = get_llm_chat_url()

    # Side effect preserved: _EMBEDDING_API_URL must still be set here
    # so all callers in this module that read _EMBEDDING_API_URL continue
    # to get the correct value.
    global _EMBEDDING_API_URL
    _EMBEDDING_API_URL = get_embedding_url(endpoint)

    return endpoint


# DEAD CODE REMOVED: _get_llm_url_fallbacks(), _LLM_URL, _resolve_llm_endpoint()
# All LLM endpoint logic consolidated in src/api/llm_calls._get_endpoint_list()


def _resolve_llm_endpoint(with_fallback: bool = True) -> Union[str, list[str]]:
    """Centralized LLM endpoint resolver used by ALL LLM calls.

    Consolidates endpoint resolution from _get_llm_url() and _get_llm_url_fallbacks().
    Single source of truth for endpoint selection across codebase.

    Args:
        with_fallback: If True, return list of endpoints for retry loop.
                      If False, return single cached endpoint (default behavior).

    Returns:
        Single endpoint string if with_fallback=False
        List of endpoints if with_fallback=True (ordered by priority for retry)

    Priority Chain (Docker-aware):
        1. ${OPENWEBUI_INTERNAL_URL} (container-internal endpoint, port 8080)
        2. ${OPENWEBUI_URL} (user-configured external endpoint)
        3. ${QWEN_API_URL} (direct LLM backend)
        4. Hardcoded fallbacks (development/testing only)

    CRITICAL: When running inside Docker Compose, use port 8080 (internal service port),
    NOT port 3000 (external host mapping). Container DNS name open-webui:8080 reaches
    the actual OpenWebUI service port within the openweb_ui_default network.
    """
    global _LLM_URL

    # Cache primary endpoint for fast access
    if _LLM_URL is None:
        _LLM_URL = _get_llm_url()

    # If only single endpoint needed, return cached version
    if not with_fallback:
        return _LLM_URL

    # Build fallback chain: try multiple endpoints if primary fails
    # All endpoints must be container-reachable (no external IPs)
    urls = []

    # PRIMARY (highest priority): OPENWEBUI_INTERNAL_URL for container-internal calls
    # When running inside Docker, internal service port is 8080, not 3000 (host mapping)
    openwebui_internal = os.environ.get("OPENWEBUI_INTERNAL_URL", "").strip()
    if openwebui_internal:
        if not openwebui_internal.startswith("http"):
            openwebui_internal = f"http://{openwebui_internal}"
        urls.append(f"{openwebui_internal}/api/chat/completions")
    else:
        # Fallback: use port 8080 for container DNS name (safe default)
        urls.append("http://open-webui:8080/api/chat/completions")

    # SECONDARY: configured OPENWEBUI_URL (external endpoint)
    openwebui_base = os.environ.get("OPENWEBUI_URL", "").strip()
    if openwebui_base and openwebui_base != openwebui_internal:
        if not openwebui_base.startswith("http"):
            openwebui_base = f"https://{openwebui_base}"
        urls.append(f"{openwebui_base}/api/chat/completions")

    # TERTIARY: QWEN_API_URL if configured
    qwen_url = os.environ.get("QWEN_API_URL")
    if qwen_url:
        urls.append(qwen_url)

    # Remove duplicates while preserving order
    seen = set()
    unique_urls = []
    for url in urls:
        if url not in seen:
            seen.add(url)
            unique_urls.append(url)

    log.info("llm_endpoint.fallback_chain_built",
            urls_count=len(unique_urls),
            primary=unique_urls[0] if unique_urls else None,
            all_urls=unique_urls)
    return unique_urls


def _validate_startup_config() -> dict:
    """Validate required environment variables at startup. Raises RuntimeError on failure."""
    llm_url = _get_llm_url()

    required = {
        "POSTGRES_DSN": os.environ.get("POSTGRES_DSN"),
        "QDRANT_URL": os.environ.get("QDRANT_URL", "http://qdrant:6333"),
        "LLM_URL": llm_url,
    }
    missing = [k for k, v in required.items() if not v]
    if missing:
        log.warning("startup.missing_env_vars", missing=missing,
                    detail="Set these variables for full functionality. App will start but may be degraded.")

    config = {
        "postgres_dsn": "***",  # sanitized
        "qdrant_url": required["QDRANT_URL"],
        "llm_url": required["LLM_URL"],
        "httpx_timeout": int(os.environ.get("HTTPX_TIMEOUT", "10")),
        "db_timeout": int(os.environ.get("DB_TIMEOUT", "30")),
        "qdrant_timeout": int(os.environ.get("QDRANT_TIMEOUT", "10")),
        "db_pool_size": int(os.environ.get("DB_POOL_SIZE", "10")),
        "rate_limit_per_min": int(os.environ.get("RATE_LIMIT_PER_MIN", "100")),
    }
    log.info("startup.config_validated", **{k: v for k, v in config.items() if k != "postgres_dsn"})
    return config


# In-memory health cache
_health_cache: dict = {}
_health_cache_ts: float = 0.0
_embedder_stats: dict = {
    "last_run": None, "facts_synced": 0, "facts_promoted": 0,
    "facts_expired": 0, "error_count": 0, "last_error": None,
}
# LLM endpoint URL (set at startup via _get_llm_url())
_LLM_URL: str = None


def _check_db_health(dsn: str) -> bool:
    try:
        with psycopg2.connect(dsn) as conn:
            with conn.cursor() as cur:
                cur.execute("SELECT 1")
        return True
    except Exception:
        return False


def _check_qdrant_health(url: str) -> bool:
    try:
        resp = httpx.get(f"{url}/collections", timeout=2.0)
        return resp.status_code == 200
    except Exception:
        return False


def _check_llm_health(url: str) -> bool:
    from src.api.llm_client import get_health_check_url
    try:
        resp = httpx.get(
            get_health_check_url(url),
            headers=get_llm_headers(),
            timeout=2.0,
        )
        return resp.status_code in (200, 401, 404)
    except Exception:
        return False


# Rate limiter: per-user_id tracking
_RATE_TRACKER: dict[str, list[float]] = {}
_RATE_LIMIT = int(os.environ.get("RATE_LIMIT_PER_MIN", "100"))


def _check_rate_limit(user_id: str) -> bool:
    now = __import__("time").time()
    window = now - 60
    _RATE_TRACKER.setdefault(user_id, [])
    _RATE_TRACKER[user_id] = [t for t in _RATE_TRACKER[user_id] if t > window]
    if len(_RATE_TRACKER[user_id]) >= _RATE_LIMIT:
        return False
    _RATE_TRACKER[user_id].append(now)
    return True


# Timeout helpers
_HTTPX_TIMEOUT = int(os.environ.get("HTTPX_TIMEOUT", "10"))
_DB_TIMEOUT = int(os.environ.get("DB_TIMEOUT", "30"))
_QDRANT_TIMEOUT = int(os.environ.get("QDRANT_TIMEOUT", "10"))

# Query confidence gating — controls Qdrant ranking and Class C lifecycle hits.
# D3: the gate RANKS A > B > C but NEVER EXCLUDES Class C — Qdrant rough memory is always
# part of full scope. QUERY_SKIP_QDRANT_GATE no longer skips Phase 4; when the DB already has
# a high-confidence answer it only RANKS DOWN the associative Qdrant/Class C results so the
# authoritative facts lead and rough memory still surfaces (for return + correction loop).
# QUERY_SKIP_QDRANT_GATE: DB max-confidence at/above this → rank Qdrant results down (not drop).
# QUERY_MIN_CONFIDENCE: rank-down floor for Qdrant noise — low-relevance C is demoted, not removed.
QUERY_SKIP_QDRANT_GATE = float(os.environ.get("QUERY_SKIP_QDRANT_GATE", "0.75"))
QUERY_MIN_CONFIDENCE = float(os.environ.get("QUERY_MIN_CONFIDENCE", "0.35"))

# TIER REALIGNMENT (DESIGN-hierarchy-ladder-and-growth.md §"Strong ingest / brain-dead
# query — and the hierarchy IS the index"). The class tier maps onto retrieval lane:
#   • A/B = HARD in POSTGRES → served ONLY by the deterministic structured walk. A/B are
#     NEVER served from / superseded-by / deduped-against the vector.
#   • C   = the rough catch-all → the VECTOR (Qdrant) ONLY; cosine inside C is the TALLY
#     (recall-hit → hit_count → promote-at-3 / decay), never an A/B retrieval path.
# When ON (default), the Qdrant lane's contribution is filtered to Class C ONLY: a Qdrant
# result whose AUTHORITATIVE DB class is A or B is dropped from the Qdrant lane (it's
# already covered by the postgres walk). A Class C result that ANSWERS the question is
# STILL returned (gated on the existing confidence floor) — the goal is to ANSWER, not
# tier-purity, so C answers are never suppressed. Set false (0/no) → legacy behaviour
# (Qdrant lane contributes all classes). Fail-safe: any error → legacy behaviour, recall
# never breaks.
VECTOR_CLASS_C_ONLY = os.environ.get("VECTOR_CLASS_C_ONLY", "true").strip().lower() not in ("false", "0", "no")

# When the deterministic typed multi-hop walk DEFERS (no authoritative A/B answer for a
# decomposable chain), fall through to the legacy scope path so the Class-C / Qdrant
# short-term backstop still runs, instead of returning empty immediately. A/B authority
# is unchanged — the walk's *answer* path still short-circuits and wins; this only adds
# the "less certain" short-term lane on a genuine miss.
#
# DEFAULT OFF — this branch changes the /query DECISION PATH (a previously-empty defer
# now runs the legacy scope + C lane), so it is gated OFF to keep the deterministic A/B
# benchmark byte-identical to baseline. Turn ON (1/true) per-tenant/serve-mode to enable
# the short-term backstop on genuine misses, where measuring shows it helps the
# entity-recall bucket without perturbing the deterministic A/B answers.
QUERY_DEFER_TO_CLASS_C = os.environ.get("QUERY_DEFER_TO_CLASS_C", "false").strip().lower() in ("true", "1", "yes")

# DOOR 2 — robustness net for the multi-hop walk DEFER. A well-formed possessive that
# DEFERS (unresolved-relation / known-gap) must NEVER be strictly WORSE than dropping
# the possessive: the bare query already proves the determine_path / fetch-all DB scope
# lane surfaces the fact. So on a defer, instead of HARD-returning facts=[], FALL
# THROUGH to that scope lane — the EXACT SAME lane the bare query takes (so the
# possessive is never penalised relative to the bare phrasing). PostgreSQL A/B stays
# authoritative there; the walk's ANSWER branch still short-circuits and wins above, so
# this only fires on a genuine miss. Gated ON by default (Door 1 carries the precise
# hit; Door 2 is the net) but flippable OFF if it ever perturbs the deterministic
# answer set. The stricter QUERY_DEFER_TO_CLASS_C remains as a separate (default-OFF)
# opt-in that ALSO falls through; either flag reaches the same lane.
QUERY_DEFER_FALLTHROUGH = os.environ.get("QUERY_DEFER_FALLTHROUGH", "true").strip().lower() in ("true", "1", "yes")


def _qdrant_fact_is_class_c(fact: dict, ab_facts_keys: set | None = None) -> bool:
    """Authoritative 'is this Qdrant-lane fact Class C?' predicate (TIER REALIGNMENT).

    The vector lane must contribute ONLY Class C (A/B are served by the deterministic
    postgres walk and are NEVER served from / deduped-against the vector). A Qdrant
    result is dropped from the lane iff its AUTHORITATIVE class is A or B.

    Class is decided, in order:
      1. store_context (rel_type == "context") → pure-vector Class-C memory, no Postgres
         backing; ALWAYS C (cannot be A/B by construction).
      2. If (source_table, fact_id) resolved in the `facts` table (passed in
         ``ab_facts_keys`` from the UUID-grounding step), the fact authoritatively lives
         in the A/B tier → NOT C.
      3. A facts-table-sourced point (source_table == "facts") is A/B even without a
         resolved key (the facts table holds only Class A + promoted Class B) → NOT C.
      4. Otherwise fall back to the read-back fact_class (payload value, or the
         source_table-derivation done in qdrant_semantic_search) → C iff class == "C".

    Goal is to ANSWER, not tier-purity: this only keeps A/B OFF the vector lane; a kept
    C fact still answers on the existing confidence gate downstream.
    """
    if fact.get("rel_type") == "context":
        return True
    _fid = fact.get("fact_id")
    _st = str(fact.get("source_table") or "facts")
    if _fid is not None and ab_facts_keys:
        try:
            _fid_int = int(_fid)
            # Authoritative: if this fact_id resolved in the `facts` table during the
            # UUID-grounding step, the row lives in the A/B tier — drop it regardless of
            # the point's own claimed source_table (the resolved table wins). Match on
            # either the full (source_table, id) key or the bare id under "facts".
            if (_st, _fid_int) in ab_facts_keys or ("facts", _fid_int) in ab_facts_keys:
                return False
        except (TypeError, ValueError):
            pass
    if _st == "facts":
        return False
    return (fact.get("fact_class") or "C") == "C"

# AXIS-SCOPED DETERMINISTIC WALK (DESIGN-hierarchy-ladder-and-growth.md §"Query model
# — axis-scoped deterministic walk, NOT a post-hoc gate"). When ON (default), the
# query resolves an AXIS (membership-vs-classification) and the deterministic walk
# fetches ONLY the chosen axis' rels — the walk's scope IS the filter. The post-hoc
# membership type-gate (_tax_edge_rels/_tax_node_types drop-loop) is RETIRED in this
# mode (bleed is impossible because the off-axis rels were never fetched). Set to
# false (0/no) to fall back to the legacy post-hoc gate behaviour. Fail-safe: any
# error in the axis path falls back to baseline so recall never breaks.
AXIS_SCOPED_QUERY = os.environ.get("AXIS_SCOPED_QUERY", "true").strip().lower() not in ("false", "0", "no")

# STRUCTURAL CORRECTION (DESIGN-hierarchy-ladder-and-growth.md §"user correction is REAL"):
# when a CORRECTION/RETRACTION statement NEGATES a nesting relationship between two GROUPS
# (both resolve to entity_taxonomies.taxonomy_name; rel is membership/nesting; negated) —
# e.g. "my pets are not part of my family" — it is NOT a fact retraction and NOT a junk
# does_not_* fact. The system ACTS on the structure: removes the child group from the
# parent's member_taxonomies, records it in severed_taxonomies (the durable, NOT-superseded
# lock the growth engine must respect), sets source='user_corrected', refreshes the overlay.
# Subject-agnostic (any groups). Default on; fail-safe: on any failure or non-match it falls
# back to the existing correction/retraction handling and never crashes.
STRUCTURAL_CORRECTION = os.environ.get("STRUCTURAL_CORRECTION", "true").strip().lower() not in ("false", "0", "no")

# CONCEPT-ANCHOR WALK (non-temporal analogue of the temporal event lane, 659d64b):
# a recall that NAMES a concept which is a real tenant entity ("what do I know about
# fences", "tell me about the fence") but resolves NO taxonomy pins the anchor to the
# USER (the "I" identity keyword) and falls into the small autobiographical DEFAULT
# scope ({pref_name, has_interest_in}). That floor FILTERS OUT the named concept's own
# facts (they are anchored to the fence entity, not the user). When this flag is on and
# the user-anchored default floor fires, we OR-IN the named concept entity's own facts —
# a plain `subject_id = ANY OR object_id = ANY` SQL walk (NOT a traversal engine) — so a
# NAMED concept surfaces its facts while the truly-scopeless floor ("hello") is preserved
# (it only fires when a concept resolves to a real entity). Fail-safe: any error → today's
# floor-only behaviour. Default on.
QUERY_CONCEPT_ANCHOR_WALK = os.environ.get(
    "QUERY_CONCEPT_ANCHOR_WALK", "true"
).strip().lower() not in ("false", "0", "no")

# PIECE 2 — NAME-INTENT SURFACING. When the recall query is a name question (the
# EXISTING _query_has_name_intent gate fires), the user's REGISTRY names live only in
# entity_aliases (no also_known_as/pref_name FACT exists for the schema owner), so the
# walk over `facts` returns nothing. This flag enables synthesizing the user's name(s)
# from the already-resolved registry aliases as the recall ANSWER. Default OFF = today's
# behavior (the name question returns "no relevant facts"). Reversible.
QUERY_NAME_INTENT_SURFACING = os.environ.get(
    "QUERY_NAME_INTENT_SURFACING", "true"
).strip().lower() not in ("false", "0", "no")

# PIECE 1 — RECALL WALK READS entity_attributes FOR TRAVERSED ENTITIES. The anchor walk
# already reads the ANCHOR's own attributes (occupation surfaces) but NOT the attributes
# of 1-hop graph neighbours reached via an edge (e.g. "my mother's birthday" — mother is
# reached via parent_of but her entity_attributes are never read). This flag enables
# reading traversed-entity attributes (sensitivity-aware: a foreign entity's
# sensitivity='sensitive' attributes are not surfaced). Default OFF = today's behavior.
QUERY_WALK_READS_ATTRIBUTES = os.environ.get(
    "QUERY_WALK_READS_ATTRIBUTES", "true"
).strip().lower() not in ("false", "0", "no")

# When false, /store_context is a no-op (no Qdrant write). Disables the Class C
# unstructured fallback path entirely. Default true (enabled).
_SHORT_TERM_MEMORY = os.environ.get("SHORT_TERM_MEMORY", "true").strip().lower() not in ("false", "0", "no")

# D4: Class C query-scoped HIT threshold. A Qdrant Class C fact is a genuine HIT (→ hit_count+1,
# expiry reset, promote-at-3 by re_embedder) only when its cosine score >= this STRICTER
# threshold (higher than the loose 0.3 inclusion threshold used to populate full scope) OR its
# subject/object is the resolved scope-anchor entity. Bulk/peripheral returns are no-ops
# (anti-noise guarantee). Config-driven, never hardcoded inline.
QUERY_CLASSC_HIT_THRESHOLD = float(os.environ.get("QUERY_CLASSC_HIT_THRESHOLD", "0.55"))

# Amount a Qdrant/Class C fact's rank score is demoted when the DB already has a confident
# answer (D3 rank-down instead of exclusion). Config-driven.
QUERY_QDRANT_RANKDOWN = float(os.environ.get("QUERY_QDRANT_RANKDOWN", "0.5"))

# Weight of content quality score in Qdrant rank-down blending. 0.25 = quality drives
# 25% of rank, cosine confidence drives 75%. Tunable without rebuild.
QUERY_QUALITY_WEIGHT = float(os.environ.get("QUERY_QUALITY_WEIGHT", "0.25"))

# Minimum GLiNER2 confidence for taxonomy classification in determine_path().
# Default 0.5 — avoids false positives (e.g. "Alex" firing on computer_system at 0.37).
_DETERMINE_PATH_TAXONOMY_CONF_THRESHOLD = float(
    os.environ.get("DETERMINE_PATH_TAXONOMY_CONF_THRESHOLD", "0.5")
)

# ── Possessive-relationship anchor resolution (PIECE A) ──────────────────────
# "what is my mother's age" → resolve the anchor "my mother" to the entity that
# FILLS that relationship (e.g. (user, child_of, helen) → helen), so the existing
# scoped walk answers "helen is 67". The word→rel_type mapping is SEEDED PER-TENANT
# (rel_type_aliases, copied FROM the public template at provisioning) and read ONLY
# from the tenant schema — NEVER public-qualified, never adding public to the path.
# inverse_rel_type is read from the per-tenant rel_types metadata (parent_of↔child_of),
# never hardcoded. Default OFF (staged): OFF == today's behavior exactly.
QUERY_POSSESSIVE_REL_ANCHOR = os.environ.get(
    "QUERY_POSSESSIVE_REL_ANCHOR", "true"
).strip().lower() not in ("false", "0", "no", "off")

# ── Walk-up-on-miss (PIECE B) ────────────────────────────────────────────────
# When the scoped walk finds NO direct fact and an anchor exists, climb the is-a
# ladder UP via _hierarchy_expand(direction="up") over per-tenant subclass_of/
# instance_of edges, then surface the parents' user-bound facts. Bounded depth,
# per-tenant only, fail-safe. Default OFF (staged): OFF == today's behavior.
QUERY_WALK_UP_ON_MISS = os.environ.get(
    "QUERY_WALK_UP_ON_MISS", "true"
).strip().lower() not in ("false", "0", "no", "off")
QUERY_WALK_UP_DEPTH = int(os.environ.get("QUERY_WALK_UP_DEPTH", "2"))

# ── End dprompt-41 ──────────────────────────────────────────────────────────

# ── Typed multi-hop deterministic walk (the query resolver) ──────────────────
# Replaces the brittle "precompute scope, then fetch" model for DECOMPOSABLE
# possessive/attribute chains ("my mother's age", "Helen's age", "my mother's
# mother's age", "how old is Helen") with a TYPED, MULTI-HOP, DETERMINISTIC WALK:
# the question is decomposed off SYNTAX (possessive 's / "of" / role-noun chaining)
# into ordered TYPED steps; each step resolves to an ENTITY (registry/anchor), a
# RELATIONAL hop (walk facts/staged_facts), or a SCALAR terminal (read
# entity_attributes). Typing comes from registry + rel_type METADATA (rel_type
# name, tail_types={SCALAR}, rel_type_aliases) — NEVER a hardcoded word-list. The
# walk STOPS THE INSTANT THE ANSWER IS FOUND, climbs the is-a hierarchy ONLY on a
# miss (bounded + visited-set), and every hop lands on a UUID. No LLM / cosine /
# ILIKE on the path — every hop is an indexed equality lookup. On a non-resolvable
# query (or flag-off) it returns None and the legacy path runs unchanged.
# Kill-switch, DEFAULT ON (flag-off == today's behavior exactly).
QUERY_MULTIHOP_WALK = os.environ.get(
    "QUERY_MULTIHOP_WALK", "true"
).strip().lower() not in ("false", "0", "no", "off")
# Bounded hierarchy climb depth for the answer-found-on-miss schema climb.
QUERY_MULTIHOP_CLIMB_DEPTH = int(os.environ.get("QUERY_MULTIHOP_CLIMB_DEPTH", "4"))

# TEMPORAL RECALL ORDERING (DESIGN-ingest-spine-and-temporal-recall.md §"PART 2 —
# RECALL-SIDE TEMPORAL ORDERING"). When the query carries temporal-ORDER intent
# (first/last/Nth) or a before/after/on PIVOT cue ("first issue AFTER my first
# service"), the walk resolves the pivot event's date by DETERMINISTIC SQL on the
# real event_date column, then filters/orders the candidate dated facts
# (WHERE event_date >/< :pivot ORDER BY event_date ASC/DESC [OFFSET/LIMIT]) and the
# MCP recall layer hands the model a PRE-SORTED, timestamp-prefixed evidence list so
# it never reorders (the documented temporal-inversion failure). PostgreSQL does the
# date math — no LLM date arithmetic, no cosine. Lean query: read-only filter/order,
# no cleanup. KILL-SWITCH, default ON; fail-safe — any error leaves the (already
# non-temporal) fact set unchanged so plain recall never regresses.
TEMPORAL_RECALL_ORDERING = os.environ.get(
    "TEMPORAL_RECALL_ORDERING", "true"
).strip().lower() not in ("false", "0", "no", "off")

# QUERY INTENT ROUTER (DESIGN — "bright enough to answer the question"). Route each
# recall into a small FINITE set of question-shape TEMPLATES, each a FIXED deterministic
# traversal; the intent layer picks the template + the topic-word (anchor hint) and
# relation-word (path), and the walk itself is pure SQL/graph — NO embeddings for durable
# A/B (vector stays the Class-C backstop). The four templates:
#   • scalar_lookup       — single-hop attribute ("what's the IP of box-x", "my dog's
#                           name") → the existing typed walk (resolve_typed_walk, Step 1.5)
#                           + _read_scalar_terminal / _read_preferred_alias readers.
#   • temporal_first_last — "when was my FIRST appt" / "where did I LAST live" → resolve
#                           the dated facts, order by event_date, return the SINGLE
#                           boundary (min=first / max=last). TKGQA get_first/get_last
#                           operator over the real valid-time event_date column.
#   • hierarchical_scope  — multi-hop up/down ("scope of the subnet box-x sits in", "tell
#                           me about my family") → the existing scoped L4 walk (allowed_rels
#                           + traversal depth via determine_path/QueryPath). Wired, not rebuilt.
#   • relational_walk     — 1-hop graph (DEFAULT) → the existing entity-centric path.
# The router is ADDITIVE + REVERSIBLE: it OBSERVES which template a question matches and
# (for temporal_first_last only) applies the get_first/get_last SLICE the existing ordering
# stops short of. Every other template falls through to today's behavior byte-for-byte. An
# unrecognised shape → relational_walk → unchanged. KILL-SWITCH, default ON; fail-safe.
QUERY_INTENT_ROUTER = os.environ.get(
    "QUERY_INTENT_ROUTER", "true"
).strip().lower() not in ("false", "0", "no", "off")

# TEMPORAL CALCULATION (P1 — deterministic interval-arithmetic operator library).
# Grounded in Allen's interval algebra + TimelineKGQA TAO + OWL-Time. We already have
# temporal STORAGE (event_date + granularity), ORDERING (pivot/ordinal) and BOUNDARY
# (get_first/get_last). What was missing is INTERVAL ARITHMETIC — "how long ago",
# "how long between X and Y", "did X happen before Y", "same week as", duration, Nth-
# between. This flag gates that calc layer: the LLM only DETECTS the calc intent (concise
# deterministic cues in _detect_temporal_query_intent); the MATH is pure Python date /
# timedelta over the REAL event_date column expanded to its half-open granule interval
# via _granule_range (the column picks the width). HARD CONSTRAINTS: no LLM doing math,
# no cosine/ILIKE scoring on the computation; GRANULARITY HONESTY (a year-granular date
# answers only year-level precision — surface the granule or MISS, never fabricate day
# precision); UNDATED ANCHOR → fail-loud MISS (return "no dated fact", never a guessed
# number — the case-law-date safety). ADDITIVE + REVERSIBLE: get_first/get_last, pivot,
# clock-selection all keep working byte-for-byte when no calc intent resolves. Default ON.
TEMPORAL_CALC = os.environ.get(
    "TEMPORAL_CALC", "true"
).strip().lower() not in ("false", "0", "no", "off")

# TEMPORAL GRANULE WALK (BUILD B — make the granule a WALKABLE PLACE). Keystone A reified
# each occurrence as its own entity hosting event_date at true granularity, so the timeline
# now has dated occurrences to walk. But the query path only ever FILTERED the candidate set
# the anchor walk already surfaced (_apply_clock_selection's year branch, _resolve_temporal_pivot
# resolving a pivot date) — it never FETCHED events by date-range. If the anchor walk didn't
# surface December's occurrences, nothing could be filtered IN. This flag gates the missing
# RANGE FETCH: _granule_member_walk ENTERS a derived granule PLACE (the half-open [gs, ge)
# interval from _granule_range) and gathers its co-located members straight from
# facts ∪ staged_facts WHERE event_date ∈ [gs, ge). Two wire-ins:
#   • "in <granule>" (in December / in 2024) → the clock-selection granule branch pulls the
#     granule's members via the walk and LINKS them (co-members), not just filters gated_facts.
#   • "after/before <pivot>" → after _resolve_temporal_pivot gets the pivot date, walk the
#     temporal NEIGHBORHOOD (open range past/before the pivot) so the ordinal/pivot rung has
#     the timeline even when the anchor walk never surfaced it.
# HARD LINE: the granule is a DERIVED computed PLACE (pure interval arithmetic) — NOT a stored
# node; the reified occurrences (memories) are what is filed at it. Deterministic interval math
# only — NO cosine/ILIKE for the walk, NO LLM. Per-tenant (search_path = tenant, no public).
# LEAN: traversal only — gathers reified occurrences with their dates; existing ordering /
# first-last / dedup consume them unchanged. ADDITIVE + REVERSIBLE: on disable/error the path
# falls back to today's filter behavior byte-for-byte. KILL-SWITCH, default ON; fail-safe.
TEMPORAL_GRANULE_WALK = os.environ.get(
    "TEMPORAL_GRANULE_WALK", "true"
).strip().lower() not in ("false", "0", "no", "off")

# QUERY RECURSIVE WALK (KEYSTONE C — the recursive query BRAIN). Keystones A (reified
# occurrences) and B (the walkable temporal granule, _granule_member_walk) gave the
# single-pass query path dated occurrences to walk and the operators to compute over
# them. What was missing is CHAINING: when answering a question needs a SUB-resolution
# ("the first issue AFTER the service" needs the SERVICE'S date resolved before the
# neighborhood walk can run; "how long between A and B" needs BOTH event dates), the
# single pass resolved at most one hinge and stopped. This flag gates the bounded
# RECURSIVE cross-hinge walk that decomposes a question into sub-resolutions, resolves
# each by RE-USING the existing resolvers (anchor/_resolve_temporal_pivot,
# B's _granule_member_walk, the temporal-calc operators) and recurses hop-by-hop —
# PLUS the metacognitive RETURN that distinguishes ANSWERED from "found >0 but did NOT
# answer" and returns ON CONFIDENCE (assert / hold+name-the-gap / grounded-piece),
# never confabulating a false absence.
#
# HARD CONSTRAINTS (inherited): bridges ONLY via REAL edges / the real event_date
# column (NO cosine / NO ILIKE scoring on the chain); bounded by QUERY_MULTIHOP_CLIMB_DEPTH
# with a visited-set cycle guard (mirrors _hierarchy_expand's depth-tracked pattern);
# the recursion is the A/B DETERMINISTIC deep pass — it does NOT elevate the Class-C
# vector dump (C still surfaces first as today, the A/B walk SUPERSEDES/strengthens).
# LEAN: the walk only TRAVERSES + decides confidence; it never cleans up / re-validates.
# Per-tenant (every resolver it reuses already binds search_path = tenant, no public).
# ADDITIVE + REVERSIBLE: only RUNS when a multi-hop decomposition resolves; on flag-off
# or ANY error it falls back to today's single-pass walk byte-for-byte. KILL-SWITCH,
# DEFAULT ON for test; fail-safe.
QUERY_RECURSIVE_WALK = os.environ.get(
    "QUERY_RECURSIVE_WALK", "true"
).strip().lower() not in ("false", "0", "no", "off")

# dprompt-152: Pattern loading helpers for intent classification
# Metadata-driven approach: patterns come from DB, not hardcoded

def _load_negation_patterns_cache() -> list:
    """
    Load global negation patterns from database at startup.

    Patterns are used by /classify-intent to enhance GLiNER2 prompt with
    real examples of retraction and correction language.

    Returns: list of (pattern_text, negation_type, confidence) tuples
    Non-fatal: returns [] if database unavailable
    """
    global _NEGATION_PATTERNS_CACHE
    try:
        dsn = os.environ.get("POSTGRES_DSN")
        if not dsn:
            log.debug("load_negation_patterns_cache.dsn_missing")
            return []

        with psycopg2.connect(dsn) as conn:
            with conn.cursor() as cur:
                # BOOT-TIME TEMPLATE READ (NOT a per-request, per-tenant path): this
                # populates a process-global language-level negation lexicon used only as
                # a fallback cue in _text_is_negated. There is no tenant context at process
                # boot, so it reads the public template's language-level global rows
                # (user_id all-zeros). It is read-only, makes no per-tenant decision, and
                # never writes — so it cannot pollute or leak across tenants. The actual
                # per-tenant negation routing is the spaCy∧LLM dual-gate (_spacy_cue_route)
                # at request time.
                cur.execute("""
                    SELECT pattern_text, negation_type, confidence
                    FROM public.negation_patterns
                    WHERE user_id = '00000000-0000-0000-0000-000000000000'::uuid
                    AND confidence >= 0.80
                    ORDER BY confidence DESC, negation_type ASC
                    LIMIT 25
                """)
                patterns = cur.fetchall()
                _NEGATION_PATTERNS_CACHE = patterns
                log.info("startup.negation_patterns_loaded", count=len(patterns))
                return patterns
    except Exception as e:
        log.warning("load_negation_patterns_cache.failed", error=str(e)[:100])
        return []


def _load_preference_patterns_cache() -> list:
    """
    Load global preference patterns from database at startup.

    Patterns signal user preferences ("I prefer to be called", "goes by", etc.)
    Used to boost STATEMENT confidence when preference signals present.

    Returns: list of (pattern_text, confidence, signal_type) tuples
    Non-fatal: returns [] if database unavailable
    """
    global _PREFERENCE_PATTERNS_CACHE
    try:
        dsn = os.environ.get("POSTGRES_DSN")
        if not dsn:
            log.debug("load_preference_patterns_cache.dsn_missing")
            return []

        with psycopg2.connect(dsn) as conn:
            with conn.cursor() as cur:
                # BOOT-TIME TEMPLATE READ (NOT a per-request, per-tenant path): populates
                # a process-global cache only for the startup count log. There is no tenant
                # at process boot, so it reads the public template. Read-only, no per-tenant
                # decision, no write — cannot pollute/leak across tenants. The per-tenant
                # preference routing reads <schema>.preference_patterns at request time
                # (see /classify-intent Layer 2c).
                cur.execute("""
                    SELECT pattern_text, base_confidence, signal_type
                    FROM public.preference_patterns
                    WHERE is_active = true
                    ORDER BY base_confidence DESC
                    LIMIT 20
                """)
                patterns = cur.fetchall()
                _PREFERENCE_PATTERNS_CACHE = patterns
                log.info("startup.preference_patterns_loaded", count=len(patterns))
                return patterns
    except Exception as e:
        log.warning("load_preference_patterns_cache.failed", error=str(e)[:100])
        return []


# NOTE: the legacy ``_match_db_correction`` DB-matching helper was removed (dead code — uncalled +
# schema-incompatible). The live correction/retraction routing is the spaCy∧LLM dual-gate below
# (``_spacy_cue_route`` + LLM corroboration); there is no DB-pattern pre-match seam in the live path.


# ── DUAL-GATE correction/retraction cue routing (NegEx-style; spaCy parse + LLM corroboration) ──
# GLiNER2 never judges negation. These CURATED, CLOSED cue inventories are the linguistic cue sets
# (NegEx tradition) the router intersects against the deterministic grammar facts from
# linguistics.analyze_directive(). They are a benchmark-gated WHOLE-SET — NEVER frequency-grown
# (that accretion is exactly what minted the 'i'm'@0.95 poison that dropped facts to retract).
_RETRACTION_CUE_LEMMAS: frozenset = frozenset({
    "forget", "delete", "remove", "erase", "drop", "discard", "scratch", "disregard",
    "ignore", "unlearn",
})
_CORRECTION_VERB_LEMMAS: frozenset = frozenset({"mean", "correct"})
_CORRECTION_MARKER_LEMMAS: frozenset = frozenset({
    "actually", "rather", "correction", "oops", "whoops",
})
# TEMPORAL-CESSATION adverbial cues — a CURATED, CLOSED inventory (NegEx tradition), benchmark-gated
# WHOLE-SET, NEVER frequency-grown. These are the lemmas spaCy yields for the cessation adverbials in
# "no longer X" (lemma "long"), "X anymore" (lemma "anymore") and "X no more" (lemma "more"). The
# router only treats them as a RETRACTION when analyze_directive() has ALSO confirmed the grammatical
# shape (a NEGATED ROOT predicate scoped by that advmod) — the cue set is the closed lexical half of a
# dependency-shape gate, not a phrase match. Mirrors _RETRACTION_CUE_LEMMAS' whole-set discipline.
_CESSATION_ADVMOD_LEMMAS: frozenset = frozenset({"long", "anymore", "more"})


def _spacy_cue_route(text: str) -> tuple:
    """Deterministic spaCy-parse cue route for the correction/retraction bypass.

    Returns ``(route, tier)``:
      - ("RETRACTION"|"CORRECTION", "confident") — an unambiguous dependency cue; route WITHOUT
        the LLM (deterministic, user-is-truth).
      - ("CORRECTION", "ambiguous") — a weak/standalone cue; the caller MUST corroborate with the
        LLM (agreement) before any destructive bypass.
      - (None, None) — no cue (or layer unavailable) → NO destructive bypass; caller falls through
        to GLiNER2.

    Pure grammar facts come from linguistics.analyze_directive(); the cue SETS + the verdict live
    HERE (the routing brain), keeping the linguistics layer free of word-lists. Fail-safe: any
    failure → (None, None) so a parse miss never routes a fact to supersede/delete.
    """
    try:
        from src.extraction.linguistics import analyze_directive
        d = analyze_directive(text)
    except Exception:
        return (None, None)
    if d is None:
        return (None, None)
    # RETRACTION: a curated imperative delete-verb, NOT negated ("forget X" — but not "don't forget").
    if d.imperative_root_lemma in _RETRACTION_CUE_LEMMAS and not d.imperative_root_negated:
        return ("RETRACTION", "confident")
    # RETRACTION (cessation): a NEGATED ROOT predicate scoped by a temporal-cessation adverbial
    # ("Rex is no longer my pet", "I do not work there anymore"). analyze_directive() already
    # confirmed the grammatical shape (negated predicate + ROOT advmod); we only check the advmod
    # lemma against the closed cessation-cue inventory. A grammatical removal — route deterministically.
    if d.cessation_advmod_lemmas & _CESSATION_ADVMOD_LEMMAS:
        return ("RETRACTION", "confident")
    _marker = bool(d.clause_initial_markers & _CORRECTION_MARKER_LEMMAS)
    # CORRECTION (confident): explicit 1st-person repair ("I meant …"), OR a repair marker that
    # co-occurs with contrastive negation ("Actually … Luna, not Bella").
    if d.root_verb_lemma in _CORRECTION_VERB_LEMMAS and d.root_subject_is_self:
        return ("CORRECTION", "confident")
    if d.has_contrastive_negation and _marker:
        return ("CORRECTION", "confident")
    # CORRECTION (ambiguous): a standalone marker ("Actually I do like pizza" — could be a NEW
    # statement) or standalone contrast ("she is 14, not 12") → needs LLM corroboration.
    if d.has_contrastive_negation or _marker:
        return ("CORRECTION", "ambiguous")
    return (None, None)


def _pin_scalar_attribute_to_known(cur, entity_id: str, corrected_attr: str,
                                   dsn: str = None, schema: str = None) -> str:
    """User-is-truth: a correction rectifies a KNOWN thing, so PIN the corrected scalar
    attribute to the entity's EXISTING stored attribute — never fork a divergent one. (The
    LLM correction-extraction said 'ip', but the fact lives under 'has_ip'; an un-pinned
    UPDATE matched 0 rows and silently lost the user's correction.) Deterministic — the
    entity's own stored attributes + canonical normalization (rung 1/2/3), NO cosine. Returns
    the attribute name to target. When it pins via morphology it GROWS a rel_type_alias so the
    next correction resolves exact (rung 3). Fail-safe → returns the corrected attr unchanged.
    """
    ca = (corrected_attr or "").strip().lower()
    if not ca:
        return corrected_attr
    try:
        cur.execute("SELECT DISTINCT attribute FROM entity_attributes WHERE entity_id = %s", (entity_id,))
        known = [r[0] for r in cur.fetchall() if r[0]]
    except Exception:
        return ca
    if not known or ca in known:
        return ca  # nothing known (genuinely new), or exact known → no pinning needed
    try:
        from src.ontology.canonical import resolve_canonical, normalize_rel, record_alias
        canon = (resolve_canonical(ca, dsn, schema) or {}).get("canonical")
        if canon and canon in known:
            return canon  # rung 2/3 resolved to a known attribute
        # Morphology fold: a bare corrected attr is the object-tail of a known compound
        # ('has_ip' endswith '_ip'), or they normalize identically. Pin + grow the alias.
        ca_norm = normalize_rel(ca) or ca
        for k in known:
            k_norm = normalize_rel(k) or k
            if k_norm == ca_norm or k_norm.endswith("_" + ca_norm) or ca_norm.endswith("_" + k_norm):
                try:
                    record_alias(ca, k, False, "user_corrected", dsn, schema)
                except Exception:
                    pass
                return k
    except Exception as e:
        log.debug("pin_scalar_attribute.failed", error=str(e)[:100])
    return ca  # no known match — treat as a new attribute (caller upserts; never silent-lose)


def _pin_rel_type_to_known(cur, subject_id: str, corrected_rel: str,
                           dsn: str = None, schema: str = None) -> str:
    """User-is-truth: a relationship correction rectifies a KNOWN edge, so PIN the extracted
    rel_type to a rel_type the subject ACTUALLY HOLDS — never an exact-string miss that loses the
    correction. (The LLM correction-extraction said 'sibling', but the stored edge is 'sibling_of';
    a bare exact-match lookup found 0 rows → "Old fact not found".) Deterministic — the canonical
    layer (rung 1/2/3) + the subject's own active rel_types, NO cosine. The rel-type sibling of
    _pin_scalar_attribute_to_known (which pins scalar ATTRIBUTES the same way). Returns the rel_type
    to target. When it pins via morphology it GROWS a rel_type_alias so the next correction resolves
    exact (rung 3). Fail-safe → returns the corrected rel unchanged.
    """
    cr = (corrected_rel or "").strip().lower()
    if not cr:
        return corrected_rel
    try:
        cur.execute(
            "SELECT DISTINCT rel_type FROM facts "
            "WHERE (subject_id = %s OR object_id = %s) AND superseded_at IS NULL "
            "  AND archived_at IS NULL",
            (subject_id, subject_id))
        known = [r[0] for r in cur.fetchall() if r[0]]
    except Exception:
        return cr
    if not known or cr in known:
        return cr  # nothing stored for this subject, or already an exact stored rel → no pin needed
    try:
        from src.ontology.canonical import resolve_canonical, normalize_rel, record_alias
        canon = (resolve_canonical(cr, dsn, schema) or {}).get("canonical")
        if canon and canon in known:
            return canon  # rung 2/3 resolved to a rel the subject actually holds
        # Morphology fold: the bare corrected rel is the head of a stored compound ('sibling' →
        # 'sibling_of'), or they normalize identically. Pin to the stored rel + grow the alias.
        cr_norm = normalize_rel(cr) or cr
        for k in known:
            k_norm = normalize_rel(k) or k
            if (k_norm == cr_norm
                    or k_norm.startswith(cr_norm + "_") or cr_norm.startswith(k_norm + "_")
                    or k_norm.endswith("_" + cr_norm) or cr_norm.endswith("_" + k_norm)):
                try:
                    record_alias(cr, k, False, "user_corrected", dsn, schema)
                except Exception:
                    pass
                return k
    except Exception as e:
        log.debug("pin_rel_type.failed", error=str(e)[:100])
    return cr  # no stored match — leave unchanged (caller's lookups fail-loud rather than corrupt)


def _update_pattern_cache(conn, user_id: str, pattern_text: str, intent_type: str, confirmed: bool) -> None:
    """Update intent_pattern_cache confidence after a confirmed or contradicted pattern fire.

    PER-TENANT: the cache lives in the user's own schema (public is template-only).
    Bind the tenant search_path so this self-growth write never lands in public.
    """
    try:
        with conn.cursor() as cur:
            from src.provisioning.schema_manager import derive_user_slug_from_uuid as _dslug
            cur.execute(f"SET search_path TO faultline_{_dslug(user_id)}")
            if confirmed:
                cur.execute("""
                    UPDATE intent_pattern_cache
                    SET confirmed_count = confirmed_count + 1,
                        last_fired_at = now(),
                        expires_at = CASE
                            WHEN confirmed_count + 1 >= 10 THEN NULL
                            ELSE GREATEST(expires_at, now()) + INTERVAL '7 days'
                        END,
                        is_permanent = (confirmed_count + 1 >= 10),
                        confidence = LEAST(1.0, confidence + 0.02)
                    WHERE (user_id = %s OR user_id = '__global__')
                      AND pattern_text = %s AND intent_type = %s
                """, (user_id, pattern_text, intent_type.lower()))
            else:
                cur.execute("""
                    UPDATE intent_pattern_cache
                    SET contradicted_count = contradicted_count + 1,
                        confidence = GREATEST(0.0, confidence - 0.10),
                        expires_at = CASE
                            WHEN is_permanent = false AND expires_at IS NOT NULL
                            THEN now() + ((expires_at - now()) / 2)
                            ELSE expires_at
                        END
                    WHERE (user_id = %s OR user_id = '__global__')
                      AND pattern_text = %s AND intent_type = %s
                """, (user_id, pattern_text, intent_type.lower()))
            conn.commit()
    except Exception as e:
        log.warning("pattern_cache.update_failed", error=str(e)[:80])


def _build_intent_descriptions_for_gliner2() -> dict:
    """
    Concise zero-shot intent descriptions for GLiNER2 classify_text (Pitfall 11).

    These are deliberately short, single-concept phrases with NO embedded examples or
    keyword lists — verbose/example-laden labels collapse GLiNER2 confidence and cause
    editing/usage statements ("My favorite editor is vim") to mis-score as CORRECTION.

    D1_HYBRID label set: benchmarked on fastino/gliner2-base-v1 (39 cases) at 87.2%
    accuracy / 0-of-10 false-CORRECTION / 20-of-20 STATEMENT, vs the prior verbose
    labels at 48.7% / 8-of-10 editor-usage false-CORRECTION. MUST stay byte-identical
    to the _INTENT_CLASSES seed in _check_and_seed() so seed and fallback never drift.

    Returns: dict[intent_name] -> description string
    """
    return {
        "QUERY": "asking a question",
        "STATEMENT": "stating a fact, preference, or habit",
        "RETRACTION": "deleting or forgetting information",
        "CORRECTION": "replacing a previously stated value with a different one",
    }


@asynccontextmanager
async def lifespan(app: FastAPI):
    global _gliner2_model, _rel_type_registry, _rel_type_constraint, _REL_TYPE_META, _LLM_URL, _EMBEDDING_API_URL, _http_client, _http_client_sync, _idempotency_mgr, _redis_client

    # dprompt-41: validate startup config (fail fast)
    _validate_startup_config()
    _LLM_URL = _get_llm_url()

    # Initialize persistent HTTP clients for pooled connections
    _http_client = httpx.AsyncClient(timeout=httpx.Timeout(30.0), limits=httpx.Limits(max_connections=100, max_keepalive_connections=20))
    _http_client_sync = httpx.Client(timeout=httpx.Timeout(30.0), limits=httpx.Limits(max_connections=100, max_keepalive_connections=20))
    log.info("startup.http_clients_initialized", async_client=True, sync_client=True)

    # dprompt-120: Initialize idempotency manager for /ingest deduplication
    # Prevents duplicate extraction LLM calls from OpenWebUI's multiple inlet invocations
    _idempotency_mgr = IdempotencyManager()
    log.info("startup.idempotency_manager_initialized", redis_url=_idempotency_mgr.redis_url[:30] if _idempotency_mgr.redis_url else "none")

    # dprompt-144: Initialize Redis client for intent classification queue
    _redis_client = _init_redis_client()
    if _redis_client:
        log.info("startup.redis_initialized", purpose="intent_classification_queue")

    # FIX-PROVISIONING: Start provisioning queue worker (dprompt-149)
    # Background task to process pending user schemas (polling interval from settings)
    async def _provisioning_worker():
        """Background task to process user schema provisioning queue."""
        from src.provisioning.provisioning_job import process_provisioning_queue
        poll_interval = settings.PROVISIONING_POLL_INTERVAL
        batch_size = settings.PROVISIONING_BATCH_SIZE
        log.info("provisioning_worker_config", poll_interval=poll_interval, batch_size=batch_size)
        while True:
            try:
                result = process_provisioning_queue(batch_size=batch_size)
                if result["provisioned"] > 0 or result["failed"] > 0:
                    log.info("provisioning_queue_processed",
                            provisioned=result["provisioned"],
                            failed=result["failed"],
                            skipped=result["skipped"])
            except Exception as e:
                log.error("provisioning_worker_error", error=str(e))
            await asyncio.sleep(poll_interval)

    asyncio.create_task(_provisioning_worker())
    log.info("startup.provisioning_worker_started")

    # FIX-PROVISIONING-HEARTBEAT: Start reaper job for detecting crashed workers
    # Runs independently, checks for stale heartbeats and marks jobs for retry
    async def _provisioning_reaper_worker():
        """Background task to detect and recover from crashed provisioning workers.

        Polls for stale heartbeats every HEARTBEAT_CHECK_INTERVAL seconds.
        If worker heartbeat is older than HEARTBEAT_TIMEOUT_MINUTES, marks job as error.
        This prevents jobs from hanging forever if worker process dies.
        """
        from src.provisioning.provisioning_job import reap_stale_provisioning_jobs

        # Configuration (env vars with defaults)
        check_interval = int(os.environ.get("HEARTBEAT_CHECK_INTERVAL", "60"))
        stale_minutes = int(os.environ.get("HEARTBEAT_TIMEOUT_MINUTES", "5"))

        log.info(
            "provisioning_reaper_config",
            check_interval=check_interval,
            stale_minutes=stale_minutes
        )

        while True:
            try:
                result = reap_stale_provisioning_jobs(stale_minutes=stale_minutes)
                if result["reaped_count"] > 0:
                    log.warning(
                        "provisioning_reaper_reaped_jobs",
                        count=result["reaped_count"],
                        user_ids=result["user_ids"]
                    )
            except Exception as e:
                log.error("provisioning_reaper_error", error=str(e))

            await asyncio.sleep(check_interval)

    asyncio.create_task(_provisioning_reaper_worker())
    log.info("startup.provisioning_reaper_started")

    qdrant_url = os.environ.get("QDRANT_URL", "http://qdrant:6333")
    default_collection = os.environ.get("QDRANT_COLLECTION", "faultline-test")
    log.info("startup.qdrant_collection_check", collection=default_collection)
    if ensure_collection(default_collection, qdrant_url):
        log.info("startup.qdrant_collection_ready", collection=default_collection)
    else:
        log.error("startup.qdrant_collection_failed", collection=default_collection)

    dsn = os.environ.get("POSTGRES_DSN")
    if dsn:
        _ensure_schema(dsn)  # apply pending migrations before reading the schema
        _validate_schema_columns(dsn)  # proactive column validation: fail fast on schema mismatch
        _refresh_rel_type_cache()  # dprompt-73b: load unified metadata cache at startup
        _refresh_scalar_rel_types_cache()  # metadata-driven scalar rel_types (replaces hardcoded set)
        _cleanup_entity_aliases_startup(dsn)  # remove corrupted string entity_ids from entity_aliases
        _normalize_entity_ids_startup(dsn)  # normalize string entity_ids to UUIDs
        _rel_type_registry = RelTypeRegistry(dsn)
        try:
            _rel_type_registry.get_valid_types()
            _REL_TYPE_META = _build_rel_type_meta(dsn)
            log.info("startup.rel_type_registry_ready",
                     count=len(_rel_type_registry._cache),
                     meta_len=len(_REL_TYPE_META))
        except Exception as e:
            log.error("startup.rel_type_registry_failed", error=str(e))

        # dprompt-125: Load rel_type aliases for LLM variation normalization
        global _REL_TYPE_ALIASES
        try:
            _REL_TYPE_ALIASES = _load_rel_type_aliases()
            log.info("startup.rel_type_aliases_loaded", alias_count=len(_REL_TYPE_ALIASES))
        except Exception as e:
            log.warning("startup.rel_type_aliases_failed", error=str(e))

        # BLOCKER-2: Initialize EntityTypeCache for database-driven validation
        try:
            initialize_entity_type_cache(dsn)
            log.info("startup.entity_type_cache_ready")
        except Exception as e:
            log.error("startup.entity_type_cache_failed", error=str(e))

        # dprompt-152: Load intent classification pattern caches
        # Patterns enhance GLiNER2 prompt with real examples from database
        # NOTE: _load_negation_patterns_cache() removed — _NEGATION_PATTERNS_CACHE is never
        # iterated for matching (dead in-memory path). The hot path reads intent_pattern_cache
        # directly from DB on each classify-intent call. The load call was emitting a
        # misleading "intent_pattern_caches_loaded" log with a stale count.
        _load_preference_patterns_cache()
        log.info("startup.intent_pattern_caches_loaded",
                preference_patterns=len(_PREFERENCE_PATTERNS_CACHE))

    log.info("startup.gliner2_loading")
    global _gliner2_model
    try:
        from gliner2 import GLiNER2
        _gliner2_model = GLiNER2.from_pretrained("fastino/gliner2-base-v1")
        log.info("startup.gliner2_ready")
    except Exception as e:
        log.error("startup.gliner2_failed", error=str(e))

    # dprompt-91: Load taxonomy cache for archive filtering
    log.info("startup.taxonomy_cache_loading")
    _db_for_cache = None
    try:
        _db_for_cache = psycopg2.connect(os.environ.get("POSTGRES_DSN"))
        _load_taxonomy_cache(_db_for_cache)
        _db_for_cache.commit()
    except Exception as e:
        if _db_for_cache:
            try:
                _db_for_cache.rollback()
            except Exception:
                pass
        log.error("startup.taxonomy_cache_init_failed", error=str(e))
    finally:
        if _db_for_cache:
            try:
                _db_for_cache.close()
            except Exception:
                pass

    yield
    # Cleanup on shutdown
    if _http_client:
        await _http_client.aclose()
    if _http_client_sync:
        _http_client_sync.close()
    if _redis_client:
        try:
            _redis_client.close()
        except Exception:
            pass
    from src.api.llm_calls import close_llm_http_client
    close_llm_http_client()
    _gliner2_model = None
    _rel_type_registry = None
    _http_client = None
    _http_client_sync = None
    _idempotency_mgr = None
    _redis_client = None

# ═══════════════════════════════════════════════════════════════════════
# dprompt-91: Archive Filtering — Module-Level Functions & Caching
# ═══════════════════════════════════════════════════════════════════════

# Historical keyword set for temporal query detection
_HISTORICAL_KEYWORDS = {
    "used to", "did i", "where was", "where was i", "my old",
    "previously", "before", "when did", "in the past", "back then",
    "used to live", "used to work", "my previous", "former", "earlier",
}

# Taxonomy cache: loaded at startup, reused across requests
_TAXONOMY_CACHE = {}

def _parse_postgres_array(arr) -> list:
    """Parse PostgreSQL ARRAY value. Handles both Python lists and string representations.
    PostgreSQL arrays come as '{item1,item2}' strings when no adapter is registered.
    Also handles psycopg2 list/array objects.
    """
    # Already a native Python list
    if isinstance(arr, list):
        return arr

    # None or empty
    if arr is None:
        return []

    # String representation '{item1,item2,item3}'
    if isinstance(arr, str):
        arr = arr.strip()
        if arr.startswith('{') and arr.endswith('}'):
            arr = arr[1:-1]  # Remove braces
        if not arr:
            return []
        return [item.strip() for item in arr.split(',')]

    # Fallback: try to convert to string and parse
    try:
        arr_str = str(arr).strip()
        if arr_str.startswith('{') and arr_str.endswith('}'):
            arr_str = arr_str[1:-1]
            if not arr_str:
                return []
            return [item.strip() for item in arr_str.split(',')]
    except Exception:
        pass

    # Last resort: empty list
    return []

def _load_taxonomy_cache(db) -> None:
    """Load entity_taxonomies into module-level cache at startup.
    Non-fatal if fails; system continues with empty cache (hard fail on usage).
    """
    global _TAXONOMY_CACHE
    try:
        with db.cursor() as cur:
            cur.execute(
                "SELECT taxonomy_name, member_entity_types, rel_types_defining_group, "
                "description, is_hierarchical, parent_rel_type "
                "FROM entity_taxonomies"
            )
            rows = cur.fetchall()
            for row in rows:
                try:
                    taxonomy_name = row[0]
                    try:
                        member_types = _parse_postgres_array(row[1])
                    except Exception as e:
                        log.warning("startup.taxonomy_parse_member_types_failed",
                                   taxonomy=taxonomy_name, input=row[1], error=str(e))
                        member_types = []

                    try:
                        rel_types = _parse_postgres_array(row[2])
                    except Exception as e:
                        log.warning("startup.taxonomy_parse_rel_types_failed",
                                   taxonomy=taxonomy_name, input=row[2], error=str(e))
                        rel_types = []

                    description = row[3]
                    is_hier = row[4]
                    parent_rel = row[5]

                    _TAXONOMY_CACHE[taxonomy_name] = {
                        "member_entity_types": member_types,
                        "rel_types_defining_group": rel_types,
                        "description": description,
                        "is_hierarchical": is_hier,
                        "parent_rel_type": parent_rel,
                    }
                except Exception as e:
                    import traceback
                    log.warning("startup.taxonomy_row_parse_failed",
                               taxonomy=row[0] if row else "unknown",
                               error=str(e),
                               traceback=traceback.format_exc())
                    continue

            log.info("startup.taxonomy_cache_loaded", count=len(_TAXONOMY_CACHE))
    except Exception as e:
        log.error("startup.taxonomy_cache_failed", error=str(e))

def detect_historical(query_lower: str) -> tuple[bool, float]:
    """Detect if query asks about archived (historical) facts.
    Returns (is_historical, confidence) where confidence = count of keyword matches.
    """
    confidence = 0.0
    for keyword in _HISTORICAL_KEYWORDS:
        if keyword in query_lower:
            confidence += 1.0

    is_historical = confidence > 0
    log.info("query.temporality_detection", is_historical=is_historical,
             confidence=confidence, query_lower=query_lower[:80])
    return (is_historical, confidence)

def determine_scope_multi_factor(db, user_id: str, facts: list[dict], query_lower: str = "") -> set[str]:
    """
    Determine scope (which taxonomies apply) using multi-factor analysis.

    Factors:
    1. rel_types in facts → match to entity_taxonomies.rel_types_defining_group
    2. entity_types of subjects/objects → validate against member_entity_types

    Returns: set of detected taxonomy_names (empty set if no matches)
    Queries database directly, no cache dependency — graceful fallback on error
    """

    detected_taxonomies = set()
    rel_types_in_facts = {f.get("rel_type") for f in facts if f.get("rel_type")}

    # Factor 1: GLiNER2 zero-shot classification of query against taxonomy descriptions.
    # Same pattern as /classify-intent — labels from entity_taxonomies.description (DB-driven),
    # description→name mapping post-call. Adding a new taxonomy row automatically participates.
    if query_lower:
        _gliner = get_gliner_model()
        if _gliner:
            try:
                with db.cursor() as cur:
                    cur.execute("SELECT taxonomy_name, description FROM entity_taxonomies WHERE description IS NOT NULL")
                    _tax_rows = cur.fetchall()
                if _tax_rows:
                    _desc_to_tax = {row[1]: row[0] for row in _tax_rows}
                    _gliner_result = _gliner.classify_text(
                        query_lower,
                        {"taxonomy": list(_desc_to_tax.keys())},
                        include_confidence=True,
                    )
                    _tax_hit = _gliner_result.get("taxonomy", {}) if isinstance(_gliner_result, dict) else {}
                    _hit_label = _tax_hit.get("label") if isinstance(_tax_hit, dict) else None
                    _hit_conf = float(_tax_hit.get("confidence", 0.0)) if isinstance(_tax_hit, dict) else 0.0
                    if _hit_label and _hit_conf >= 0.3 and _hit_label in _desc_to_tax:
                        detected_taxonomies.add(_desc_to_tax[_hit_label])
                        log.info("query.scope_gliner2_match",
                                 taxonomy=_desc_to_tax[_hit_label],
                                 confidence=round(_hit_conf, 3),
                                 query=query_lower[:50])
                    else:
                        log.debug("query.scope_gliner2_low_confidence",
                                  confidence=round(_hit_conf, 3), label=_hit_label)
            except Exception as _e:
                log.warning("query.scope_gliner2_failed",
                            error=str(_e), error_type=type(_e).__name__)

    # Factor 2: Fact-driven fallback — only when query-driven returned nothing.
    if not detected_taxonomies:
        for rel_type in rel_types_in_facts:
            if not rel_type:
                continue
            try:
                with db.cursor() as cur:
                    cur.execute(
                        "SELECT DISTINCT taxonomy_name FROM entity_taxonomies "
                        "WHERE %s = ANY(rel_types_defining_group)",
                        (rel_type,)
                    )
                    for row in cur.fetchall():
                        detected_taxonomies.add(row[0])
            except Exception as e:
                log.warning("query.scope_rel_type_match_failed", rel_type=rel_type, error=str(e))

    log.info("determine_scope.multi_factor",
             rel_types=list(rel_types_in_facts),
             detected_taxonomies=list(detected_taxonomies),
             user_id=user_id)

    return detected_taxonomies

def format_fact_for_injection(fact: dict, db, registry) -> str | None:
    """
    Convert raw fact to plain English prose for LLM injection.
    HARD CONSTRAINT: Facts for LLM must be human-readable, not machine-readable tuples.

    Example inputs:
    - {"subject_id": "uuid", "rel_type": "works_for", "object_id": "uuid"}
    - {"subject_id": "uuid", "rel_type": "age", "object_value": 45}

    Example outputs:
    - "${USER} works for Acme Inc."
    - "alice is 16 years old"
    """
    try:
        subject_id = fact.get("subject_id")
        rel_type = fact.get("rel_type")
        object_id = fact.get("object_id")
        object_value = fact.get("object_value")

        # Resolve subject display name
        subject_name = None
        if registry and subject_id:
            subject_name = registry.get_preferred_name(subject_id)
        subject_name = subject_name or (subject_id[:8] if subject_id else "Unknown")

        # Get rel_type label from database
        rel_label = rel_type
        if db and rel_type:
            try:
                with db.cursor() as cur:
                    cur.execute(
                        "SELECT label FROM rel_types WHERE rel_type = %s",
                        (rel_type,)
                    )
                    row = cur.fetchone()
                    if row and row[0]:
                        rel_label = row[0]
            except Exception:
                pass  # Fall back to rel_type name

        # Resolve object (UUID or scalar value)
        if object_value is not None:
            # Scalar fact
            object_repr = str(object_value)
        elif object_id:
            # Relationship fact
            object_name = None
            if registry:
                object_name = registry.get_preferred_name(object_id)
            object_repr = object_name or object_id[:8]
        else:
            return None

        # Format as natural English
        if subject_name and rel_label and object_repr:
            return f"{subject_name} {rel_label} {object_repr}."

        return None
    except Exception as e:
        log.warning("format_fact_for_injection_failed", fact_id=fact.get("id"), error=str(e))
        return None

def apply_archive_filter(db, query_lower: str, user_id: str,
                        facts: list[dict]) -> tuple[list[dict], dict]:
    """
    Apply archive filtering to facts using multi-factor scope + temporality.

    Returns (filtered_facts, metadata) where metadata contains:
    {
        "detected_taxonomies": [str],
        "is_historical": bool,
        "fact_count_before": int,
        "fact_count_after": int,
    }

    HARD FAIL if scope determination or archive filter fails.
    """
    try:
        # Phase 1: Detect temporality
        is_historical, temporal_confidence = detect_historical(query_lower)

        # Phase 2: Determine scope (multi-factor)
        detected_taxonomies = determine_scope_multi_factor(db, user_id, facts, query_lower)

        # Phase 3: Filter facts by scope + temporality
        filtered = []

        # Identity & scalar rel_types always pass scope filter (they're not taxonomy-scoped)
        # Metadata-driven: check if rel_type is scalar or identity via rel_types table
        def _is_identity_or_scalar_rel(rel_type: str) -> bool:
            """Check if rel_type should bypass taxonomy scope filter."""
            rt = rel_type.lower() if rel_type else ""
            rel_meta = _REL_TYPE_META.get(rt, {})

            # Layer 1: Metadata check
            # Scalar rel_types have tail_types = ['SCALAR']
            tail_types = rel_meta.get("tail_types", [])
            if tail_types and "SCALAR" in tail_types:
                return True
            # Identity rel_types: pref_name, also_known_as, same_as
            if rel_meta and rel_meta.get("category") == "identity":
                return True

            # Layer 2: Fallback for unknown rel_types (pattern-based)
            # Conservative: only bypass for known patterns, don't bypass novel rel_types
            identity_keywords = ("pref_name", "also_known_as", "same_as", "name")
            if any(kw in rt for kw in identity_keywords):
                log.info("is_identity.pattern_fallback", rel_type=rel_type, result=True)
                return True

            # Unknown rel_type — don't bypass scope (let taxonomy filter apply)
            return False

        for fact in facts:
            rel_type = fact.get("rel_type")

            if detected_taxonomies and not _is_identity_or_scalar_rel(rel_type):
                rel_in_taxonomy = False
                for taxonomy_name in detected_taxonomies:
                    if taxonomy_name in _TAXONOMY_CACHE:
                        rel_types_for_tax = _TAXONOMY_CACHE[taxonomy_name].get("rel_types_defining_group", [])
                        if rel_type in rel_types_for_tax:
                            rel_in_taxonomy = True
                            break
                if not rel_in_taxonomy:
                    continue

            archived_at = fact.get("archived_at")
            valid_until = fact.get("valid_until")

            if is_historical:
                if archived_at is None and valid_until is None:
                    continue
            else:
                if archived_at is not None or valid_until is not None:
                    continue

            filtered.append(fact)

        metadata = {
            "detected_taxonomies": list(detected_taxonomies),
            "is_historical": is_historical,
            "fact_count_before": len(facts),
            "fact_count_after": len(filtered),
        }

        log.info("archive_filter.temporal_scope",
                 scope="historical" if is_historical else "current",
                 count_before=len(facts),
                 count_after=len(filtered))

        if detected_taxonomies:
            log.info("archive_filter.scope_gate",
                     scope_type="targeted",
                     taxonomies=list(detected_taxonomies),
                     count_before=len(facts),
                     count_after=len(filtered))
        else:
            log.info("archive_filter.scope_gate",
                     scope_type="open",
                     taxonomies=[])

        return (filtered, metadata)

    except Exception as e:
        log.error("archive_filter.failed", error=str(e), user_id=user_id)
        raise


# ── dBug-027 & dBug-026: Metadata-driven validation and entity filtering ──

def _validate_rel_type_constraints(fact_dict: dict, rel_type_meta: dict, db) -> tuple[bool, str]:
    """
    Validate fact against rel_type metadata constraints (dprompt-97).

    Uses rel_types metadata to enforce:
    - head_types: subject entity_type must be in this list
    - tail_types: object entity_type must be in this list (SCALAR or entity type)
    - is_leaf_only: object cannot have children in hierarchy

    Returns (is_valid, reason) tuple.

    Treats "unknown" type as "type not yet determined" and skips validation,
    allowing downstream type enrichment to populate correct types.
    """
    if not rel_type_meta:
        return True, "no_metadata"

    subject_type = (fact_dict.get("subject_type") or "").upper().strip()
    object_type = (fact_dict.get("object_type") or "").upper().strip()
    tail_types = rel_type_meta.get("tail_types", [])
    head_types = rel_type_meta.get("head_types", [])
    rel_type = fact_dict.get("rel_type", "").lower()

    # Treat "unknown" as "type not yet determined" — skip validation and let ingest populate
    if subject_type == "UNKNOWN":
        subject_type = ""
    if object_type == "UNKNOWN":
        object_type = ""

    # Constraint 1: head_types — subject entity_type must be allowed
    if head_types and "ANY" not in head_types:
        if subject_type and subject_type not in [t.upper() for t in head_types]:
            return False, f"subject_type '{subject_type}' not in {head_types} for rel_type '{rel_type}'"

    # Constraint 2: tail_types — object entity_type must be allowed (CRITICAL FIX FOR BIDIRECTIONAL VALIDATION)
    if tail_types and "ANY" not in tail_types:
        if set(tail_types) != {"SCALAR"}:
            if object_type and object_type not in [t.upper() for t in tail_types]:
                return False, f"object_type '{object_type}' not in {tail_types} for rel_type '{rel_type}'"

    # Constraint 3: is_leaf_only — object cannot have children in hierarchy
    if rel_type_meta.get("is_leaf_only"):
        obj_id = fact_dict.get("object_id")
        if obj_id:
            try:
                with db.cursor() as cur:
                    cur.execute(
                        "SELECT COUNT(*) FROM facts WHERE subject_id = %s AND is_hierarchy_rel = true",
                        (obj_id,)
                    )
                    if cur.fetchone()[0] > 0:
                        return False, f"object {obj_id} has hierarchy children, cannot be leaf-only"
            except Exception as e:
                log.warning("validate_rel_type.leaf_check_failed", error=str(e))

    return True, "ok"

def _filter_extracted_entities(
    entities: list,
    hierarchy_entity_types: list = None
) -> list:
    """
    Filter GLiNER2 extracted entities to only valid named entity types (dprompt-97).

    dprompt-129: If hierarchy_entity_types provided, filter to only those types.
    Otherwise, use default VALID_ENTITY_TYPES (bac${LOCATION}ard compat).

    Rejects:
    - Stop words (the, a, and, prefers, called, someone, married, spouse, etc.)
    - Rel_types used as entity names (spouse, married_person, other_person)
    - Low-confidence extractions (< 0.6)
    - Single-letter noise

    Keeps:
    - Person, Organization, Location, Object, Event, Animal types (or hierarchy-specified types)
    """
    if not entities:
        return []

    # dprompt-129: Use hierarchy_entity_types if provided, else query database
    if hierarchy_entity_types:
        VALID_ENTITY_TYPES = set(hierarchy_entity_types)
    else:
        try:
            entity_type_cache = get_entity_type_cache()
            VALID_ENTITY_TYPES = entity_type_cache.get_valid_types()
        except Exception as e:
            log.warning(f"EntityTypeCache access failed, using fallback types: {e}")
            VALID_ENTITY_TYPES = {"person", "organization", "location", "object", "event", "animal"}

    REJECT_TYPES = {"concept", "unknown"}

    # English stop words + rel_types + attribute descriptors (comprehensive, no recursive matching)
    STOP_WORDS = {
        # Grammar
        "a", "an", "the", "is", "are", "was", "were", "be", "been", "being",
        "have", "has", "had", "do", "does", "did", "will", "would", "could",
        "should", "may", "might", "must", "can",
        # Pronouns
        "i", "me", "my", "we", "our", "he", "she", "it", "they", "them", "his", "her", "hers", "its", "their",
        # Common words
        "what", "which", "who", "when", "where", "why", "how", "and", "or", "but",
        "not", "no", "yes", "if", "as", "of", "to", "for", "from", "in", "on", "at", "by", "with",
        "about", "into", "through", "during", "before", "after", "above", "below", "up", "down", "out", "off", "over", "under",
        "again", "further", "then", "once", "just", "only", "very", "too", "so", "such", "same", "now", "here", "there",
        "this", "that", "these", "those", "more", "most", "all", "both", "each", "every", "few", "some",
        # Rel_types that should NOT be entities
        "spouse", "parent", "child", "sibling", "friend", "couple", "married", "married_person",
        "born", "died", "lived", "worked", "studied", "taught", "owned",
        # Attribute descriptors
        "tall", "short", "old", "young", "big", "small", "engineer", "doctor", "teacher", "worker",
        "person", "people", "member", "group", "family", "household", "company", "organization", "institution",
        # Preference markers
        "prefers", "prefer", "preferred", "preference", "likes", "like", "dislikes", "dislike", "loves", "love", "hates", "hate",
        # Generic markers
        "someone", "something", "anything", "everything", "nothing", "yet", "still", "already",
        "either", "neither", "own", "other", "another", "next", "last", "first", "second", "previous", "recent", "following",
        # Additional stop words
        "list", "instantly", "updated", "should", "called", "wifes", "she",
    }

    filtered = []
    for entity in entities:
        entity_type = entity.get("type", "unknown").lower().strip()  # Normalize case
        entity_name = entity.get("text", "").lower().strip()
        confidence = entity.get("confidence", 0.0)

        # Reject: invalid/reject type
        if entity_type in REJECT_TYPES:
            continue

        # Reject: not a valid entity type
        if entity_type not in VALID_ENTITY_TYPES:
            continue

        # Reject: stop word or rel_type used as entity
        if entity_name in STOP_WORDS:
            continue

        # Reject: low confidence
        if confidence < 0.6:
            continue

        # Reject: single letter (noise)
        if len(entity_name) < 2:
            continue

        # Accept: valid named entity
        filtered.append(entity)

    return filtered


